fn validate_lowered_ir_shape(
    report: &Value,
    node_lowerings: &[Value],
    edge_lowerings: &[Value],
    dependency_lowerings: &[Value],
    core_objects: &[Value],
    diagnostics: &mut Vec<Value>,
) {
    let graph_id = report
        .get("graph_id")
        .and_then(Value::as_str)
        .unwrap_or("unknown");
    validate_lowered_ir_object_shape(
        report,
        "report",
        graph_id,
        json!({"graphs": [graph_id]}),
        LOWERED_IR_ROOT_FIELDS,
        LOWERED_IR_ROOT_FIELDS,
        diagnostics,
    );
    validate_lowered_ir_nonempty_string_field(
        report,
        "report",
        graph_id,
        json!({"graphs": [graph_id]}),
        "lowerer_version",
        diagnostics,
    );

    for lowering in node_lowerings {
        let node_id = lowering
            .get("node_id")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        validate_lowered_ir_object_shape(
            lowering,
            "node",
            node_id,
            json!({"nodes": [node_id]}),
            LOWERED_IR_NODE_LOWERING_FIELDS,
            LOWERED_IR_NODE_LOWERING_FIELDS,
            diagnostics,
        );
        validate_lowered_ir_nonempty_string_field(
            lowering,
            "node",
            node_id,
            json!({"nodes": [node_id]}),
            "lowering_class",
            diagnostics,
        );
    }

    for lowering in edge_lowerings {
        let required_port_id = lowering
            .get("required_port_id")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let provided_port_id = lowering
            .get("provided_port_id")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let edge_ref = construct_graph_edge_ref_from_parts(required_port_id, provided_port_id);
        validate_lowered_ir_object_shape(
            lowering,
            "edge",
            &edge_ref,
            json!({"edges": [edge_ref]}),
            LOWERED_IR_EDGE_LOWERING_FIELDS,
            LOWERED_IR_EDGE_LOWERING_FIELDS,
            diagnostics,
        );
    }

    for lowering in dependency_lowerings {
        let dependency_ref = lowering
            .get("dependency_ref")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        validate_lowered_ir_object_shape(
            lowering,
            "dependency",
            dependency_ref,
            json!({"effect_dependencies": [dependency_ref]}),
            LOWERED_IR_DEPENDENCY_LOWERING_FIELDS,
            LOWERED_IR_DEPENDENCY_LOWERING_FIELDS,
            diagnostics,
        );
        validate_lowered_ir_enum_field(
            lowering,
            "dependency",
            dependency_ref,
            json!({"effect_dependencies": [dependency_ref]}),
            "preserved_predicate",
            &["succeeds", "fails", "completes"],
            diagnostics,
        );
    }

    for object in core_objects {
        let object_id = object
            .get("object_id")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        validate_lowered_ir_object_shape(
            object,
            "core_object",
            object_id,
            json!({"core_objects": [object_id]}),
            LOWERED_IR_CORE_OBJECT_REQUIRED_FIELDS,
            LOWERED_IR_CORE_OBJECT_FIELDS,
            diagnostics,
        );
        validate_lowered_ir_span_field(
            object,
            "core_object",
            object_id,
            json!({"core_objects": [object_id]}),
            "source_span",
            diagnostics,
        );
        validate_lowered_ir_entrypoint_ref_shape(object, object_id, diagnostics);
    }

    validate_lowered_ir_validator_shapes(report, diagnostics);
}

fn validate_lowered_ir_object_shape(
    value: &Value,
    owner_kind: &str,
    owner_id: &str,
    refs: Value,
    required: &[&str],
    allowed: &[&str],
    diagnostics: &mut Vec<Value>,
) {
    let Some(object) = value.as_object() else {
        diagnostics.push(lowered_ir_diagnostic(
            &format!("lowered_ir.{owner_kind}.object_expected"),
            format!("lowered IR {owner_kind} `{owner_id}` must be an object"),
            refs,
        ));
        return;
    };

    for field in required {
        if !object.contains_key(*field) {
            diagnostics.push(lowered_ir_diagnostic(
                &format!("lowered_ir.{owner_kind}.field_missing"),
                format!("lowered IR {owner_kind} `{owner_id}` is missing field `{field}`"),
                json!({"refs": refs.clone(), "field": field}),
            ));
        }
    }

    for field in object.keys() {
        if !allowed.iter().any(|allowed_field| allowed_field == field) {
            diagnostics.push(lowered_ir_diagnostic(
                &format!("lowered_ir.{owner_kind}.field_unknown"),
                format!("lowered IR {owner_kind} `{owner_id}` has unknown field `{field}`"),
                json!({"refs": refs.clone(), "field": field}),
            ));
        }
    }
}

fn validate_lowered_ir_nonempty_string_field(
    value: &Value,
    owner_kind: &str,
    owner_id: &str,
    refs: Value,
    field: &str,
    diagnostics: &mut Vec<Value>,
) {
    if !value.is_object() {
        return;
    }
    let Some(field_value) = value.get(field) else {
        return;
    };
    if field_value.as_str().is_some_and(|value| !value.is_empty()) {
        return;
    }
    diagnostics.push(lowered_ir_diagnostic(
        &format!("lowered_ir.{owner_kind}.{field}_invalid"),
        format!("lowered IR {owner_kind} `{owner_id}` field `{field}` must be a non-empty string"),
        json!({"refs": refs, "field": field}),
    ));
}

fn validate_lowered_ir_enum_field(
    value: &Value,
    owner_kind: &str,
    owner_id: &str,
    refs: Value,
    field: &str,
    allowed: &[&str],
    diagnostics: &mut Vec<Value>,
) {
    if !value.is_object() {
        return;
    }
    let Some(field_value) = value.get(field) else {
        return;
    };
    if field_value
        .as_str()
        .is_some_and(|value| allowed.iter().any(|allowed| allowed == &value))
    {
        return;
    }
    diagnostics.push(lowered_ir_diagnostic(
        &format!("lowered_ir.{owner_kind}.{field}_invalid"),
        format!(
            "lowered IR {owner_kind} `{owner_id}` field `{field}` must be one of {}",
            allowed.join(", ")
        ),
        json!({"refs": refs, "field": field}),
    ));
}

fn validate_lowered_ir_span_field(
    value: &Value,
    owner_kind: &str,
    owner_id: &str,
    refs: Value,
    field: &str,
    diagnostics: &mut Vec<Value>,
) {
    let Some(span) = value.get(field) else {
        return;
    };
    if let Err(reason) = validate_artifact_span_value(span) {
        diagnostics.push(lowered_ir_diagnostic(
            &format!("lowered_ir.{owner_kind}.{field}_invalid"),
            format!("lowered IR {owner_kind} `{owner_id}` has invalid `{field}`: {reason}"),
            json!({"refs": refs, "field": field}),
        ));
    }
}

fn validate_lowered_ir_string_ref_set_field(
    value: &Value,
    owner_kind: &str,
    owner_id: &str,
    refs: Value,
    field: &str,
    diagnostics: &mut Vec<Value>,
) {
    if !value.is_object() {
        return;
    }
    if let Err(reason) = validate_artifact_string_ref_set_field(value, field) {
        diagnostics.push(lowered_ir_diagnostic(
            &format!("lowered_ir.{owner_kind}.{field}_invalid"),
            format!("lowered IR {owner_kind} `{owner_id}` has invalid `{field}`: {reason}"),
            json!({"refs": refs, "field": field}),
        ));
    }
}

fn validate_lowered_ir_diagnostic_metadata(
    diagnostic: &Value,
    code: &str,
    diagnostics: &mut Vec<Value>,
) {
    if !diagnostic.is_object() {
        return;
    }
    if let Err(reason) = validate_artifact_diagnostic_metadata(diagnostic, false) {
        diagnostics.push(lowered_ir_diagnostic(
            "lowered_ir.diagnostic.metadata_invalid",
            format!("lowered IR diagnostic `{code}` has invalid metadata: {reason}"),
            json!({"diagnostics": [code]}),
        ));
    }
}

fn validate_lowered_ir_derived_fact_metadata(
    fact: &Value,
    predicate: &str,
    diagnostics: &mut Vec<Value>,
) {
    if !fact.is_object() {
        return;
    }
    if let Err(reason) = validate_artifact_derived_fact_metadata(fact) {
        diagnostics.push(lowered_ir_diagnostic(
            "lowered_ir.derived_fact.metadata_invalid",
            format!("lowered IR derived fact `{predicate}` has invalid metadata: {reason}"),
            json!({"derived_facts": [predicate]}),
        ));
    }
}

fn validate_lowered_ir_entrypoint_ref_shape(
    object: &Value,
    object_id: &str,
    diagnostics: &mut Vec<Value>,
) {
    let Some(refs) = object.get("entrypoint_refs") else {
        return;
    };
    let Some(refs) = refs.as_object() else {
        diagnostics.push(lowered_ir_diagnostic(
            "lowered_ir.core_object.entrypoint_refs_object",
            format!("core object `{object_id}` entrypoint_refs must be an object"),
            json!({"core_objects": [object_id]}),
        ));
        return;
    };

    let object_kind = object.get("object_kind").and_then(Value::as_str);
    let runtime_entrypoint = object.get("runtime_entrypoint").and_then(Value::as_str);
    let Some(allowed_keys) = lowered_ir_exact_entrypoint_ref_keys(object_kind, runtime_entrypoint)
    else {
        return;
    };

    for key in refs.keys() {
        if !allowed_keys.iter().any(|allowed| allowed == key) {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.core_object.entrypoint_ref_unknown",
                format!("core object `{object_id}` has unknown entrypoint ref `{key}`"),
                json!({"core_objects": [object_id], "field": key}),
            ));
        }
    }
}

fn validate_lowered_ir_validator_shapes(report: &Value, diagnostics: &mut Vec<Value>) {
    if let Some(facts) = report.get("derived_facts").and_then(Value::as_array) {
        for predicate in duplicate_artifact_derived_fact_predicates(facts) {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.derived_fact.duplicate",
                format!("lowered IR derived fact `{predicate}` is duplicated"),
                json!({"derived_facts": [predicate]}),
            ));
        }

        for (index, fact) in facts.iter().enumerate() {
            let predicate = fact
                .get("predicate")
                .and_then(Value::as_str)
                .map(str::to_owned)
                .unwrap_or_else(|| format!("derived_facts[{index}]"));
            validate_lowered_ir_object_shape(
                fact,
                "derived_fact",
                &predicate,
                json!({"derived_facts": [predicate.as_str()]}),
                ARTIFACT_DERIVED_FACT_FIELDS,
                ARTIFACT_DERIVED_FACT_FIELDS,
                diagnostics,
            );
            validate_lowered_ir_span_field(
                fact,
                "derived_fact",
                &predicate,
                json!({"derived_facts": [predicate.as_str()]}),
                "diagnostic_span",
                diagnostics,
            );
            validate_lowered_ir_string_ref_set_field(
                fact,
                "derived_fact",
                &predicate,
                json!({"derived_facts": [predicate.as_str()]}),
                "input_refs",
                diagnostics,
            );
            validate_lowered_ir_derived_fact_metadata(fact, &predicate, diagnostics);
        }
    }

    if let Some(report_diagnostics) = report.get("diagnostics").and_then(Value::as_array) {
        for (index, diagnostic) in report_diagnostics.iter().enumerate() {
            let code = diagnostic
                .get("code")
                .and_then(Value::as_str)
                .map(str::to_owned)
                .unwrap_or_else(|| format!("diagnostics[{index}]"));
            validate_lowered_ir_object_shape(
                diagnostic,
                "diagnostic",
                &code,
                json!({"diagnostics": [code.as_str()]}),
                ARTIFACT_DIAGNOSTIC_REQUIRED_FIELDS,
                ARTIFACT_DIAGNOSTIC_FIELDS,
                diagnostics,
            );
            validate_lowered_ir_span_field(
                diagnostic,
                "diagnostic",
                &code,
                json!({"diagnostics": [code.as_str()]}),
                "source_span",
                diagnostics,
            );
            validate_lowered_ir_diagnostic_metadata(diagnostic, &code, diagnostics);
        }
    }
}

fn lowered_ir_exact_entrypoint_ref_keys(
    object_kind: Option<&str>,
    runtime_entrypoint: Option<&str>,
) -> Option<&'static [&'static str]> {
    match (object_kind, runtime_entrypoint) {
        (Some("fact"), Some("fact_record")) => Some(&["fact", "schema"]),
        (Some("event"), Some("event_record")) => Some(&["event"]),
        (Some("signal_source"), Some("signal_source_template")) => Some(&["event"]),
        (Some("clock_source"), Some("clock_source_template")) => Some(&["event"]),
        (Some("schedule"), Some("schedule_template")) => Some(&["schedule"]),
        (Some("rule"), Some("rule_template")) => Some(&["rule", "fact", "graph"]),
        (Some("dependency"), Some("effect_dependency_template")) => {
            Some(&["upstream_effect", "predicate", "downstream_effect"])
        }
        (Some("projection"), Some("event_projection")) => Some(&["event", "fact"]),
        (Some("assertion"), Some("assertion_check")) => Some(&["assertion"]),
        (Some("diagnostic"), Some("diagnostic_record")) => Some(&["rule"]),
        _ => None,
    }
}

fn validate_lowered_ir_artifact(report: &Value, construct_graph: &Value) -> LoweredIrValidation {
    let empty = Vec::new();
    let graph_nodes = construct_graph
        .get("nodes")
        .and_then(Value::as_array)
        .unwrap_or(&empty);
    let graph_edges = construct_graph
        .get("edges")
        .and_then(Value::as_array)
        .unwrap_or(&empty);
    let graph_effect_dependencies = construct_graph
        .get("effect_dependencies")
        .and_then(Value::as_array)
        .unwrap_or(&empty);
    let node_ids = graph_nodes
        .iter()
        .filter_map(|node| node.get("node_id").and_then(Value::as_str))
        .collect::<BTreeSet<_>>();
    let edge_ids = graph_edges
        .iter()
        .filter_map(|edge| {
            Some((
                edge.get("required_port_id")?.as_str()?,
                edge.get("provided_port_id")?.as_str()?,
            ))
        })
        .collect::<BTreeSet<_>>();
    let dependency_refs = graph_effect_dependencies
        .iter()
        .filter_map(|dependency| dependency.get("dependency_ref").and_then(Value::as_str))
        .collect::<BTreeSet<_>>();
    let graph_nodes_by_id = graph_nodes
        .iter()
        .filter_map(|node| {
            node.get("node_id")
                .and_then(Value::as_str)
                .map(|node_id| (node_id.to_owned(), node))
        })
        .collect::<BTreeMap<_, _>>();
    let graph_effect_dependencies_by_ref = graph_effect_dependencies
        .iter()
        .filter_map(|dependency| {
            dependency
                .get("dependency_ref")
                .and_then(Value::as_str)
                .map(|dependency_ref| (dependency_ref.to_owned(), dependency))
        })
        .collect::<BTreeMap<_, _>>();
    let node_lowerings = report
        .get("node_lowerings")
        .and_then(Value::as_array)
        .unwrap_or(&empty);
    let edge_lowerings = report
        .get("edge_lowerings")
        .and_then(Value::as_array)
        .unwrap_or(&empty);
    let dependency_lowerings = report
        .get("dependency_lowerings")
        .and_then(Value::as_array)
        .unwrap_or(&empty);
    let core_objects = report
        .get("core_objects")
        .and_then(Value::as_array)
        .unwrap_or(&empty);
    let core_object_ids = core_objects
        .iter()
        .filter_map(|object| object.get("object_id").and_then(Value::as_str))
        .collect::<Vec<_>>();
    let core_objects_by_id = core_objects
        .iter()
        .filter_map(|object| {
            object
                .get("object_id")
                .and_then(Value::as_str)
                .map(|object_id| (object_id.to_owned(), object))
        })
        .collect::<BTreeMap<_, _>>();
    let mut diagnostics = Vec::new();
    let mut seen_core_objects = BTreeSet::new();
    let mut produced_owners = BTreeMap::<String, Vec<String>>::new();
    let mut lowered_node_ids = BTreeSet::new();
    let mut lowered_edge_refs = BTreeSet::new();
    let mut lowered_dependency_refs = BTreeSet::new();

    validate_lowered_ir_shape(
        report,
        node_lowerings,
        edge_lowerings,
        dependency_lowerings,
        core_objects,
        &mut diagnostics,
    );
    validate_lowered_ir_report_identity(report, construct_graph, &mut diagnostics);

    for object_id in core_object_ids {
        if !seen_core_objects.insert(object_id) {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.core_object.duplicate",
                format!("core object `{object_id}` is emitted more than once"),
                json!({"core_objects": [object_id]}),
            ));
        }
    }

    for lowering in node_lowerings {
        let Some(node_id) = lowering.get("node_id").and_then(Value::as_str) else {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.node_missing",
                "node lowering is missing node_id",
                json!({}),
            ));
            continue;
        };
        if !node_ids.contains(node_id) {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.node_unknown",
                format!("node lowering references unknown node `{node_id}`"),
                json!({"nodes": [node_id]}),
            ));
        }
        if !lowered_node_ids.insert(node_id.to_owned()) {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.node_duplicate",
                format!("node `{node_id}` is lowered more than once"),
                json!({"nodes": [node_id]}),
            ));
        }
        for field in [
            "produced_core_object_refs",
            "preserved_source_span_refs",
            "preserved_resource_refs",
            "preserved_capability_refs",
            "preserved_version_refs",
            "preserved_cardinality_refs",
            "preserved_provenance_refs",
            "preserved_terminal_binding_refs",
        ] {
            validate_lowered_ir_required_string_array_field(
                "node",
                node_id,
                lowering,
                field,
                &mut diagnostics,
                json!({"nodes": [node_id], "field": field}),
            );
        }
        for object_id in construct_graph_string_array(lowering, "produced_core_object_refs") {
            lowered_ir_record_produced_owner(
                &mut produced_owners,
                &mut diagnostics,
                object_id.clone(),
                lowered_ir_node_owner(node_id),
            );
            if let Some(node) = graph_nodes_by_id.get(node_id) {
                validate_lowered_ir_node_output_compatibility(
                    node_id,
                    node,
                    &object_id,
                    &core_objects_by_id,
                    &mut diagnostics,
                );
            }
        }
    }

    for lowering in edge_lowerings {
        let required_port_id = lowering
            .get("required_port_id")
            .and_then(Value::as_str)
            .unwrap_or("");
        let provided_port_id = lowering
            .get("provided_port_id")
            .and_then(Value::as_str)
            .unwrap_or("");
        if !edge_ids.contains(&(required_port_id, provided_port_id)) {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.edge_unknown",
                format!(
                    "edge lowering references unknown edge `{required_port_id}` -> `{provided_port_id}`"
                ),
                json!({"edges": [format!("{required_port_id}->{provided_port_id}")]}),
            ));
        }
        let edge_ref = construct_graph_edge_ref_from_parts(required_port_id, provided_port_id);
        if !lowered_edge_refs.insert(edge_ref.clone()) {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.edge_duplicate",
                format!("edge `{edge_ref}` is lowered more than once"),
                json!({"edges": [edge_ref]}),
            ));
        }
        for field in [
            "produced_core_object_refs",
            "preserved_type_refs",
            "preserved_resource_refs",
            "preserved_capability_refs",
            "preserved_version_refs",
            "preserved_span_refs",
            "preserved_cardinality_refs",
            "preserved_provenance_refs",
        ] {
            validate_lowered_ir_required_string_array_field(
                "edge",
                &edge_ref,
                lowering,
                field,
                &mut diagnostics,
                json!({"edges": [edge_ref], "field": field}),
            );
        }
        for object_id in construct_graph_string_array(lowering, "produced_core_object_refs") {
            lowered_ir_record_produced_owner(
                &mut produced_owners,
                &mut diagnostics,
                object_id,
                lowered_ir_edge_owner(required_port_id, provided_port_id),
            );
        }
    }

    for lowering in dependency_lowerings {
        let Some(dependency_ref) = lowering.get("dependency_ref").and_then(Value::as_str) else {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.dependency_missing",
                "dependency lowering is missing dependency_ref",
                json!({}),
            ));
            continue;
        };
        if !dependency_refs.contains(dependency_ref) {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.dependency_unknown",
                format!("dependency lowering references unknown dependency `{dependency_ref}`"),
                json!({"effect_dependencies": [dependency_ref]}),
            ));
        }
        if !lowered_dependency_refs.insert(dependency_ref.to_owned()) {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.dependency_duplicate",
                format!("dependency `{dependency_ref}` is lowered more than once"),
                json!({"effect_dependencies": [dependency_ref]}),
            ));
        }
        for field in [
            "produced_core_object_refs",
            "preserved_effect_refs",
            "preserved_span_refs",
            "preserved_provenance_refs",
        ] {
            validate_lowered_ir_required_string_array_field(
                "dependency",
                dependency_ref,
                lowering,
                field,
                &mut diagnostics,
                json!({"effect_dependencies": [dependency_ref], "field": field}),
            );
        }
        for object_id in construct_graph_string_array(lowering, "produced_core_object_refs") {
            lowered_ir_record_produced_owner(
                &mut produced_owners,
                &mut diagnostics,
                object_id,
                lowered_ir_dependency_owner(dependency_ref),
            );
        }
    }

    for node_id in &node_ids {
        if !lowered_node_ids.contains(*node_id) {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.node_unlowered",
                format!("construct graph node `{node_id}` has no node lowering"),
                json!({"nodes": [node_id]}),
            ));
        }
    }

    for (required_port_id, provided_port_id) in &edge_ids {
        let edge_ref = construct_graph_edge_ref_from_parts(required_port_id, provided_port_id);
        if !lowered_edge_refs.contains(&edge_ref) {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.edge_unlowered",
                format!("construct graph edge `{edge_ref}` has no edge lowering"),
                json!({"edges": [edge_ref]}),
            ));
        }
    }

    for dependency_ref in &dependency_refs {
        if !lowered_dependency_refs.contains(*dependency_ref) {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.dependency_unlowered",
                format!("construct graph dependency `{dependency_ref}` has no dependency lowering"),
                json!({"effect_dependencies": [dependency_ref]}),
            ));
        }
    }

    for object in core_objects {
        let Some(object_id) = object.get("object_id").and_then(Value::as_str) else {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.core_object.id_missing",
                "core object is missing object_id",
                json!({}),
            ));
            continue;
        };
        validate_lowered_ir_core_object_kind_and_entrypoint(object, object_id, &mut diagnostics);
        validate_lowered_ir_entrypoint_ref_values(
            object,
            object_id,
            &graph_nodes_by_id,
            &graph_effect_dependencies_by_ref,
            &mut diagnostics,
        );
        for field in ["resource_refs", "capability_refs", "version_refs"] {
            validate_lowered_ir_core_object_metadata_array_field(
                object_id,
                object,
                field,
                &mut diagnostics,
                json!({"core_objects": [object_id], "field": field}),
            );
        }
        let Some(owner_ref) = object.get("owner_ref").and_then(Value::as_str) else {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.core_object.owner_missing",
                format!("core object `{object_id}` is missing owner_ref"),
                json!({"core_objects": [object_id]}),
            ));
            continue;
        };
        match object.get("owner_kind").and_then(Value::as_str) {
            Some("node") => {
                if !node_ids.contains(owner_ref) {
                    diagnostics.push(lowered_ir_diagnostic(
                        "lowered_ir.core_object.owner_unknown",
                        format!(
                            "core object `{object_id}` references unknown owner node `{owner_ref}`"
                        ),
                        json!({"core_objects": [object_id], "nodes": [owner_ref]}),
                    ));
                } else {
                    validate_lowered_ir_core_object_owner(
                        object_id,
                        &lowered_ir_node_owner(owner_ref),
                        &produced_owners,
                        &mut diagnostics,
                        json!({"core_objects": [object_id], "nodes": [owner_ref]}),
                    );
                }
            }
            Some("edge") => {
                if !edge_ids.iter().any(|(required, provided)| {
                    construct_graph_edge_ref_from_parts(required, provided) == owner_ref
                }) {
                    diagnostics.push(lowered_ir_diagnostic(
                        "lowered_ir.core_object.owner_unknown",
                        format!(
                            "core object `{object_id}` references unknown owner edge `{owner_ref}`"
                        ),
                        json!({"core_objects": [object_id], "edges": [owner_ref]}),
                    ));
                } else {
                    validate_lowered_ir_core_object_owner(
                        object_id,
                        &format!("edge:{owner_ref}"),
                        &produced_owners,
                        &mut diagnostics,
                        json!({"core_objects": [object_id], "edges": [owner_ref]}),
                    );
                }
            }
            Some("dependency") => {
                if !dependency_refs.contains(owner_ref) {
                    diagnostics.push(lowered_ir_diagnostic(
                        "lowered_ir.core_object.owner_unknown",
                        format!(
                            "core object `{object_id}` references unknown owner dependency `{owner_ref}`"
                        ),
                        json!({"core_objects": [object_id], "effect_dependencies": [owner_ref]}),
                    ));
                } else {
                    validate_lowered_ir_core_object_owner(
                        object_id,
                        &lowered_ir_dependency_owner(owner_ref),
                        &produced_owners,
                        &mut diagnostics,
                        json!({"core_objects": [object_id], "effect_dependencies": [owner_ref]}),
                    );
                }
            }
            _ => {
                diagnostics.push(lowered_ir_diagnostic(
                    "lowered_ir.core_object.owner_kind",
                    format!("core object `{object_id}` has an invalid owner kind"),
                    json!({"core_objects": [object_id]}),
                ));
            }
        }
        if !produced_owners.contains_key(object_id) {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.core_object.unaccounted",
                format!(
                    "core object `{object_id}` is not listed by a node, edge, or dependency lowering"
                ),
                json!({"core_objects": [object_id]}),
            ));
        }
    }

    for object_id in produced_owners.keys() {
        if !seen_core_objects.contains(object_id.as_str()) {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.core_object.missing",
                format!("lowering references missing core object `{object_id}`"),
                json!({"core_objects": [object_id]}),
            ));
        }
    }

    let derived_facts = if diagnostics.is_empty() {
        lowered_ir_validation_facts(report, construct_graph)
    } else {
        Vec::new()
    };

    LoweredIrValidation {
        diagnostics,
        derived_facts,
    }
}

fn lowered_ir_validation_facts(report: &Value, construct_graph: &Value) -> Vec<Value> {
    let graph_id = report
        .get("graph_id")
        .and_then(Value::as_str)
        .unwrap_or("construct_graph:unknown");
    let empty = Vec::new();
    let node_lowerings = report
        .get("node_lowerings")
        .and_then(Value::as_array)
        .unwrap_or(&empty);
    let edge_lowerings = report
        .get("edge_lowerings")
        .and_then(Value::as_array)
        .unwrap_or(&empty);
    let dependency_lowerings = report
        .get("dependency_lowerings")
        .and_then(Value::as_array)
        .unwrap_or(&empty);
    let core_objects = report
        .get("core_objects")
        .and_then(Value::as_array)
        .unwrap_or(&empty);
    let core_objects_by_id = core_objects
        .iter()
        .filter_map(|object| {
            object
                .get("object_id")
                .and_then(Value::as_str)
                .map(|object_id| (object_id.to_owned(), object))
        })
        .collect::<BTreeMap<_, _>>();
    let graph_nodes = construct_graph
        .get("nodes")
        .and_then(Value::as_array)
        .unwrap_or(&empty);
    let graph_nodes_by_id = graph_nodes
        .iter()
        .filter_map(|node| {
            node.get("node_id")
                .and_then(Value::as_str)
                .map(|node_id| (node_id.to_owned(), node))
        })
        .collect::<BTreeMap<_, _>>();

    let mut facts = Vec::new();
    let mut coverage_refs = vec![graph_id.to_owned()];
    let mut owner_refs = vec![graph_id.to_owned()];
    let mut runtime_boundary_refs = vec![graph_id.to_owned()];
    let determinism_refs = lowered_ir_graph_determinism_refs(report);
    let mut report_complete_refs = lowered_ir_graph_report_root_refs(report);
    let mut no_runtime_input_refs = vec![lowered_ir_report_field_ref(report, "graph_id")];
    let mut node_lowering_refs = Vec::new();
    let mut edge_lowering_refs = Vec::new();
    let mut dependency_lowering_refs = Vec::new();
    let mut core_object_refs = Vec::new();

    for lowering in node_lowerings {
        let Some(node_id) = lowering.get("node_id").and_then(Value::as_str) else {
            continue;
        };
        node_lowering_refs.push(node_id.to_owned());
        report_complete_refs.push(lowered_ir_inventory_ref("node_lowering", node_id));
        let span = graph_nodes_by_id
            .get(node_id)
            .map_or_else(construct_graph_empty_span, |node| {
                construct_graph_span_from(node)
            });
        let mut refs = vec![graph_id.to_owned(), node_id.to_owned()];
        refs.extend(construct_graph_string_array(
            lowering,
            "produced_core_object_refs",
        ));
        facts.push(lowered_ir_fact(
            format!("lowered_ir.validator.node.lowered:{node_id}"),
            refs.clone(),
            span.clone(),
        ));
        let graph_node = graph_nodes_by_id.get(node_id).copied();
        if let Some(lowering_class) = lowering.get("lowering_class").and_then(Value::as_str) {
            facts.push(lowered_ir_fact(
                format!("lowered_ir.validator.node.lifecycle_inputs:{node_id}:{lowering_class}"),
                lowered_ir_node_lifecycle_input_refs(
                    graph_id,
                    node_id,
                    lowering,
                    graph_node,
                    &core_objects_by_id,
                ),
                span.clone(),
            ));
            for fact_field in LOWERED_IR_NODE_LIFECYCLE_INPUT_COMPONENT_FIELDS {
                facts.push(lowered_ir_fact(
                    format!(
                        "lowered_ir.validator.node.lifecycle_inputs.{fact_field}:{node_id}:{lowering_class}"
                    ),
                    lowered_ir_node_lifecycle_input_component_refs(
                        graph_id,
                        node_id,
                        lowering,
                        graph_node,
                        &core_objects_by_id,
                        fact_field,
                    ),
                    span.clone(),
                ));
            }
        }
        facts.push(lowered_ir_fact(
            format!("lowered_ir.validator.node.preservation:{node_id}"),
            lowered_ir_node_preservation_refs(graph_id, node_id, lowering),
            graph_nodes_by_id
                .get(node_id)
                .map_or_else(construct_graph_empty_span, |node| {
                    construct_graph_span_from(node)
                }),
        ));
        for (fact_field, report_field) in LOWERED_IR_NODE_PRESERVATION_COMPONENT_FIELDS {
            facts.push(lowered_ir_fact(
                format!("lowered_ir.validator.node.preservation.{fact_field}:{node_id}"),
                lowered_ir_node_preservation_component_refs(
                    graph_id,
                    node_id,
                    lowering,
                    report_field,
                ),
                graph_nodes_by_id
                    .get(node_id)
                    .map_or_else(construct_graph_empty_span, |node| {
                        construct_graph_span_from(node)
                    }),
            ));
        }
        facts.push(lowered_ir_fact(
            format!("lowered_ir.validator.node.output_compat:{node_id}"),
            lowered_ir_node_output_compat_refs(
                graph_id,
                node_id,
                lowering,
                graph_node,
                &core_objects_by_id,
            ),
            graph_nodes_by_id
                .get(node_id)
                .map_or_else(construct_graph_empty_span, |node| {
                    construct_graph_span_from(node)
                }),
        ));
        for fact_field in LOWERED_IR_NODE_OUTPUT_COMPAT_COMPONENT_FIELDS {
            facts.push(lowered_ir_fact(
                format!("lowered_ir.validator.node.output_compat.{fact_field}:{node_id}"),
                lowered_ir_node_output_compat_component_refs(
                    graph_id,
                    node_id,
                    lowering,
                    graph_node,
                    &core_objects_by_id,
                    fact_field,
                ),
                graph_nodes_by_id
                    .get(node_id)
                    .map_or_else(construct_graph_empty_span, |node| {
                        construct_graph_span_from(node)
                    }),
            ));
        }
        coverage_refs.push(node_id.to_owned());
    }

    for lowering in edge_lowerings {
        let required_port_id = lowering
            .get("required_port_id")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let provided_port_id = lowering
            .get("provided_port_id")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let edge_ref = construct_graph_edge_ref_from_parts(required_port_id, provided_port_id);
        edge_lowering_refs.push(edge_ref.clone());
        let mut refs = vec![
            graph_id.to_owned(),
            edge_ref.clone(),
            required_port_id.to_owned(),
            provided_port_id.to_owned(),
        ];
        refs.extend(construct_graph_string_array(
            lowering,
            "produced_core_object_refs",
        ));
        report_complete_refs.push(lowered_ir_inventory_ref("edge_lowering", &edge_ref));
        facts.push(lowered_ir_fact(
            format!("lowered_ir.validator.edge.lowered:{edge_ref}"),
            refs,
            construct_graph_empty_span(),
        ));
        facts.push(lowered_ir_fact(
            format!("lowered_ir.validator.edge.preservation:{edge_ref}"),
            lowered_ir_edge_preservation_refs(graph_id, &edge_ref, lowering),
            construct_graph_empty_span(),
        ));
        for (fact_field, report_field) in LOWERED_IR_EDGE_PRESERVATION_COMPONENT_FIELDS {
            facts.push(lowered_ir_fact(
                format!("lowered_ir.validator.edge.preservation.{fact_field}:{edge_ref}"),
                lowered_ir_edge_preservation_component_refs(
                    graph_id,
                    &edge_ref,
                    lowering,
                    report_field,
                ),
                construct_graph_empty_span(),
            ));
        }
        coverage_refs.push(edge_ref);
    }

    for lowering in dependency_lowerings {
        let Some(dependency_ref) = lowering.get("dependency_ref").and_then(Value::as_str) else {
            continue;
        };
        dependency_lowering_refs.push(dependency_ref.to_owned());
        report_complete_refs.push(lowered_ir_inventory_ref(
            "dependency_lowering",
            dependency_ref,
        ));
        let mut refs = vec![graph_id.to_owned(), dependency_ref.to_owned()];
        refs.extend(construct_graph_string_array(
            lowering,
            "produced_core_object_refs",
        ));
        facts.push(lowered_ir_fact(
            format!("lowered_ir.validator.dependency.lowered:{dependency_ref}"),
            refs,
            construct_graph_empty_span(),
        ));
        facts.push(lowered_ir_fact(
            format!("lowered_ir.validator.dependency.preservation:{dependency_ref}"),
            lowered_ir_dependency_preservation_refs(graph_id, dependency_ref, lowering),
            construct_graph_empty_span(),
        ));
        for (fact_field, report_field) in LOWERED_IR_DEPENDENCY_PRESERVATION_COMPONENT_FIELDS {
            facts.push(lowered_ir_fact(
                format!(
                    "lowered_ir.validator.dependency.preservation.{fact_field}:{dependency_ref}"
                ),
                lowered_ir_dependency_preservation_component_refs(
                    graph_id,
                    dependency_ref,
                    lowering,
                    report_field,
                ),
                construct_graph_empty_span(),
            ));
        }
        coverage_refs.push(dependency_ref.to_owned());
    }

    for object in core_objects {
        let Some(object_id) = object.get("object_id").and_then(Value::as_str) else {
            continue;
        };
        core_object_refs.push(object_id.to_owned());
        let object_kind = object
            .get("object_kind")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let runtime_entrypoint = object
            .get("runtime_entrypoint")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let owner_kind = object
            .get("owner_kind")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let owner_ref = object
            .get("owner_ref")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        report_complete_refs.push(lowered_ir_inventory_ref("core_object", object_id));
        no_runtime_input_refs.push(lowered_ir_runtime_object_ref(
            object_id,
            object_kind,
            runtime_entrypoint,
        ));
        let span = object
            .get("source_span")
            .cloned()
            .unwrap_or_else(construct_graph_empty_span);
        facts.push(lowered_ir_fact(
            format!(
                "lowered_ir.validator.core_object.entrypoint:{object_id}:{object_kind}:{runtime_entrypoint}"
            ),
            lowered_ir_core_object_entrypoint_refs(graph_id, object_id, object, object_kind, runtime_entrypoint),
            span.clone(),
        ));
        facts.push(lowered_ir_fact(
            format!("lowered_ir.validator.core_object.owner:{object_id}:{owner_kind}:{owner_ref}"),
            vec![
                graph_id.to_owned(),
                object_id.to_owned(),
                owner_kind.to_owned(),
                owner_ref.to_owned(),
            ],
            span,
        ));
        coverage_refs.push(object_id.to_owned());
        owner_refs.push(object_id.to_owned());
        owner_refs.push(owner_kind.to_owned());
        owner_refs.push(owner_ref.to_owned());
        runtime_boundary_refs.push(object_id.to_owned());
        runtime_boundary_refs.push(object_kind.to_owned());
        runtime_boundary_refs.push(runtime_entrypoint.to_owned());
    }

    facts.push(lowered_ir_fact(
        format!("lowered_ir.validator.graph.node_lowerings_unique:{graph_id}"),
        node_lowering_refs,
        construct_graph_empty_span(),
    ));
    facts.push(lowered_ir_fact(
        format!("lowered_ir.validator.graph.edge_lowerings_unique:{graph_id}"),
        edge_lowering_refs,
        construct_graph_empty_span(),
    ));
    facts.push(lowered_ir_fact(
        format!("lowered_ir.validator.graph.dependency_lowerings_unique:{graph_id}"),
        dependency_lowering_refs,
        construct_graph_empty_span(),
    ));
    facts.push(lowered_ir_fact(
        format!("lowered_ir.validator.graph.core_object_ids_unique:{graph_id}"),
        core_object_refs,
        construct_graph_empty_span(),
    ));
    facts.push(lowered_ir_fact(
        format!("lowered_ir.validator.graph.coverage:{graph_id}"),
        coverage_refs,
        construct_graph_empty_span(),
    ));
    facts.push(lowered_ir_fact(
        format!("lowered_ir.validator.graph.deterministic:{graph_id}"),
        determinism_refs,
        construct_graph_empty_span(),
    ));
    facts.push(lowered_ir_fact(
        format!("lowered_ir.validator.graph.report_complete:{graph_id}"),
        report_complete_refs,
        construct_graph_empty_span(),
    ));
    facts.push(lowered_ir_fact(
        format!("lowered_ir.validator.graph.owner_unique:{graph_id}"),
        owner_refs,
        construct_graph_empty_span(),
    ));
    facts.push(lowered_ir_fact(
        format!("lowered_ir.validator.graph.no_runtime_inputs:{graph_id}"),
        no_runtime_input_refs,
        construct_graph_empty_span(),
    ));
    facts.push(lowered_ir_fact(
        format!("lowered_ir.validator.graph.runtime_boundary:{graph_id}"),
        runtime_boundary_refs,
        construct_graph_empty_span(),
    ));

    facts
}

