fn lowered_ir_node_lifecycle_input_refs(
    graph_id: &str,
    node_id: &str,
    lowering: &Value,
    graph_node: Option<&Value>,
    core_objects_by_id: &BTreeMap<String, &Value>,
) -> Vec<String> {
    let mut refs = vec![graph_id.to_owned(), node_id.to_owned()];
    refs.extend(lowered_ir_optional_string_ref(lowering, "lowering_class"));
    if let Some(graph_node) = graph_node {
        refs.extend(lowered_ir_optional_string_ref(
            graph_node,
            "construct_family",
        ));
        refs.extend(lowered_ir_optional_string_ref(
            graph_node,
            "lifecycle_profile",
        ));
    }
    for object_id in construct_graph_string_array(lowering, "produced_core_object_refs") {
        refs.push(object_id.clone());
        if let Some(object) = core_objects_by_id.get(&object_id) {
            refs.extend(lowered_ir_optional_string_ref(object, "object_kind"));
            refs.extend(lowered_ir_optional_string_ref(object, "runtime_entrypoint"));
        }
    }
    refs
}

