fn validate_lowered_ir_entrypoint_ref_values(
    object: &Value,
    object_id: &str,
    graph_nodes_by_id: &BTreeMap<String, &Value>,
    graph_effect_dependencies_by_ref: &BTreeMap<String, &Value>,
    diagnostics: &mut Vec<Value>,
) {
    let Some(object_kind) = object.get("object_kind").and_then(Value::as_str) else {
        return;
    };
    let Some(runtime_entrypoint) = object.get("runtime_entrypoint").and_then(Value::as_str) else {
        return;
    };
    let Some(owner_kind) = object.get("owner_kind").and_then(Value::as_str) else {
        return;
    };
    let Some(owner_ref) = object.get("owner_ref").and_then(Value::as_str) else {
        return;
    };

    match (object_kind, runtime_entrypoint, owner_kind) {
        ("schedule", "schedule_template", "node") => {
            validate_lowered_ir_entrypoint_ref_expected(
                object,
                object_id,
                "schedule",
                owner_ref,
                diagnostics,
            );
        }
        ("signal_source", "signal_source_template", "node") => {
            // A `source … { observe; emit <signal> }` block admits a signal whose
            // name is decoupled from the source node's name; entrypoint-ref
            // presence is validated by the refs checker.
        }
        ("clock_source", "clock_source_template", "node") => {
            // Clock sources admit a signal whose name is decoupled from the source
            // name; entrypoint-ref presence is validated by the refs checker.
        }
        ("assertion", "assertion_check", "node") => {
            let assertion_ref = owner_ref
                .strip_prefix(ASSERTION_NODE_PREFIX)
                .unwrap_or(owner_ref);
            validate_lowered_ir_entrypoint_ref_expected(
                object,
                object_id,
                "assertion",
                assertion_ref,
                diagnostics,
            );
        }
        ("rule", "rule_template", "node") => {
            if let Some(rule_name) = graph_nodes_by_id
                .get(owner_ref)
                .and_then(|node| node.get("metadata"))
                .and_then(|metadata| metadata.get("rule_name"))
                .and_then(Value::as_str)
                .filter(|rule_name| !rule_name.is_empty())
            {
                validate_lowered_ir_entrypoint_ref_expected(
                    object,
                    object_id,
                    "rule",
                    rule_name,
                    diagnostics,
                );
            }
            if let Some(rule_ref) = owner_ref.strip_prefix(RULE_NODE_PREFIX) {
                let graph_ref = format!("{rule_ref}:graph");
                validate_lowered_ir_entrypoint_ref_expected(
                    object,
                    object_id,
                    "graph",
                    &graph_ref,
                    diagnostics,
                );
            }
        }
        ("fact", "fact_record", "node") => {
            let prefix = format!("core:fact:{owner_ref}:");
            let Some(fact_ref) = object_id.strip_prefix(&prefix) else {
                diagnostics.push(lowered_ir_diagnostic(
                    "lowered_ir.core_object.entrypoint_ref_mismatch",
                    format!(
                        "fact core object `{object_id}` does not encode owner node `{owner_ref}`"
                    ),
                    json!({"core_objects": [object_id], "nodes": [owner_ref]}),
                ));
                return;
            };
            validate_lowered_ir_entrypoint_ref_expected(
                object,
                object_id,
                "fact",
                fact_ref,
                diagnostics,
            );
            validate_lowered_ir_entrypoint_ref_expected(
                object,
                object_id,
                "schema",
                construct_fact_schema_ref(fact_ref),
                diagnostics,
            );
        }
        ("dependency", "effect_dependency_template", "dependency") => {
            let Some(dependency) = graph_effect_dependencies_by_ref.get(owner_ref) else {
                return;
            };
            for (key, field) in [
                ("upstream_effect", "upstream_node_id"),
                ("predicate", "predicate"),
                ("downstream_effect", "downstream_node_id"),
            ] {
                if let Some(expected) = dependency.get(field).and_then(Value::as_str) {
                    validate_lowered_ir_entrypoint_ref_expected(
                        object,
                        object_id,
                        key,
                        expected,
                        diagnostics,
                    );
                }
            }
        }
        _ => {}
    }
}

fn validate_lowered_ir_entrypoint_ref_expected(
    object: &Value,
    object_id: &str,
    key: &str,
    expected: &str,
    diagnostics: &mut Vec<Value>,
) {
    let Some(actual) = object
        .get("entrypoint_refs")
        .and_then(Value::as_object)
        .and_then(|refs| refs.get(key))
        .and_then(Value::as_str)
    else {
        return;
    };
    if actual == expected {
        return;
    }
    diagnostics.push(lowered_ir_diagnostic(
        "lowered_ir.core_object.entrypoint_ref_mismatch",
        format!(
            "core object `{object_id}` entrypoint ref `{key}` expected `{expected}`, got `{actual}`"
        ),
        json!({"core_objects": [object_id], "field": key}),
    ));
}

fn lowered_ir_forbidden_runtime_object_kind(object_kind: &str) -> bool {
    matches!(
        object_kind,
        "run"
            | "claim"
            | "terminal"
            | "cancellation"
            | "cancellation_request"
            | "cancellation_ack"
            | "retry"
            | "lease"
            | "provider_evidence"
            | "provider_run"
    )
}

