fn validate_construct_graph_shape(
    graph: &Value,
    nodes: &[Value],
    ports: &[Value],
    edges: &[Value],
    effect_dependencies: &[Value],
    diagnostics: &mut Vec<Value>,
) {
    let graph_id = json_str(graph, "graph_id").unwrap_or("unknown");
    validate_construct_graph_object_shape(
        graph,
        "graph",
        graph_id,
        "graphs",
        CONSTRUCT_GRAPH_ROOT_FIELDS,
        CONSTRUCT_GRAPH_ROOT_FIELDS,
        diagnostics,
    );
    validate_construct_graph_nonempty_string_field(
        graph,
        "graph",
        graph_id,
        "graphs",
        "platform_version",
        diagnostics,
    );

    for node in nodes {
        let node_id = json_str(node, "node_id").unwrap_or("unknown");
        validate_construct_graph_object_shape(
            node,
            "node",
            node_id,
            "nodes",
            &CONSTRUCT_GRAPH_NODE_FIELDS[..CONSTRUCT_GRAPH_NODE_FIELDS.len() - 1],
            CONSTRUCT_GRAPH_NODE_FIELDS,
            diagnostics,
        );
        for field in [
            "construct_id",
            "construct_family",
            "lowering_class",
            "lifecycle_profile",
            "owner",
            "lowering_output_kind",
        ] {
            validate_construct_graph_nonempty_string_field(
                node,
                "node",
                node_id,
                "nodes",
                field,
                diagnostics,
            );
        }
        validate_construct_graph_optional_object_field(
            node,
            "node",
            node_id,
            "nodes",
            "metadata",
            diagnostics,
        );
        validate_construct_graph_interface_shapes(
            node,
            node_id,
            "declared_required_interfaces",
            diagnostics,
        );
        validate_construct_graph_interface_shapes(
            node,
            node_id,
            "declared_provided_interfaces",
            diagnostics,
        );
    }

    for port in ports {
        let port_id = json_str(port, "port_id").unwrap_or("unknown");
        validate_construct_graph_object_shape(
            port,
            "port",
            port_id,
            "ports",
            CONSTRUCT_GRAPH_PORT_FIELDS,
            CONSTRUCT_GRAPH_PORT_FIELDS,
            diagnostics,
        );
        for field in [
            "owner_node_id",
            "direction",
            "kind",
            "type",
            "phase",
            "contract_version",
            "cardinality",
        ] {
            validate_construct_graph_nonempty_string_field(
                port,
                "port",
                port_id,
                "ports",
                field,
                diagnostics,
            );
        }
        validate_construct_graph_nullable_string_field(
            port,
            "port",
            port_id,
            "ports",
            "resource_identity",
            diagnostics,
        );
    }

    for edge in edges {
        let edge_ref = construct_graph_edge_ref(edge);
        validate_construct_graph_object_shape(
            edge,
            "edge",
            &edge_ref,
            "edges",
            CONSTRUCT_GRAPH_EDGE_FIELDS,
            CONSTRUCT_GRAPH_EDGE_FIELDS,
            diagnostics,
        );
        for field in [
            "required_port_id",
            "provider_node_id",
            "provided_port_id",
            "resolution_reason",
        ] {
            validate_construct_graph_nonempty_string_field(
                edge,
                "edge",
                &edge_ref,
                "edges",
                field,
                diagnostics,
            );
        }
        validate_construct_graph_nullable_string_field(
            edge,
            "edge",
            &edge_ref,
            "edges",
            "resource_key",
            diagnostics,
        );
    }

    for dependency in effect_dependencies {
        let dependency_ref = json_str(dependency, "dependency_ref").unwrap_or("unknown");
        validate_construct_graph_object_shape(
            dependency,
            "effect_dependency",
            dependency_ref,
            "effect_dependencies",
            CONSTRUCT_GRAPH_EFFECT_DEPENDENCY_FIELDS,
            CONSTRUCT_GRAPH_EFFECT_DEPENDENCY_FIELDS,
            diagnostics,
        );
        for field in [
            "rule_name",
            "upstream_node_id",
            "predicate",
            "downstream_node_id",
        ] {
            validate_construct_graph_nonempty_string_field(
                dependency,
                "effect_dependency",
                dependency_ref,
                "effect_dependencies",
                field,
                diagnostics,
            );
        }
    }

    validate_construct_graph_validator_shapes(graph, diagnostics);
}

fn validate_construct_graph_object_shape(
    value: &Value,
    owner_kind: &str,
    owner_id: &str,
    refs_key: &str,
    required: &[&str],
    allowed: &[&str],
    diagnostics: &mut Vec<Value>,
) {
    let Some(object) = value.as_object() else {
        diagnostics.push(construct_graph_diagnostic(
            format!("construct_graph.{owner_kind}.object_expected"),
            format!("construct graph {owner_kind} `{owner_id}` must be an object"),
            vec![(refs_key, vec![owner_id.to_owned()])],
            construct_graph_span_from(value),
        ));
        return;
    };

    for field in required {
        if !object.contains_key(*field) {
            diagnostics.push(construct_graph_diagnostic(
                format!("construct_graph.{owner_kind}.field_missing"),
                format!("construct graph {owner_kind} `{owner_id}` is missing field `{field}`"),
                vec![
                    (refs_key, vec![owner_id.to_owned()]),
                    ("fields", vec![(*field).to_owned()]),
                ],
                construct_graph_span_from(value),
            ));
        }
    }

    for field in object.keys() {
        if !allowed.iter().any(|allowed_field| allowed_field == field) {
            diagnostics.push(construct_graph_diagnostic(
                format!("construct_graph.{owner_kind}.field_unknown"),
                format!("construct graph {owner_kind} `{owner_id}` has unknown field `{field}`"),
                vec![
                    (refs_key, vec![owner_id.to_owned()]),
                    ("fields", vec![field.to_owned()]),
                ],
                construct_graph_span_from(value),
            ));
        }
    }

    validate_construct_graph_span_field(
        value,
        owner_kind,
        owner_id,
        refs_key,
        "source_span",
        diagnostics,
    );
}

fn validate_construct_graph_nonempty_string_field(
    value: &Value,
    owner_kind: &str,
    owner_id: &str,
    refs_key: &str,
    field: &str,
    diagnostics: &mut Vec<Value>,
) {
    if !value.is_object() {
        return;
    }
    let Some(field_value) = value.get(field) else {
        return;
    };
    if field_value.as_str().is_some_and(|value| !value.is_empty()) {
        return;
    }
    diagnostics.push(construct_graph_diagnostic(
        format!("construct_graph.{owner_kind}.{field}_invalid"),
        format!(
            "construct graph {owner_kind} `{owner_id}` field `{field}` must be a non-empty string"
        ),
        vec![
            (refs_key, vec![owner_id.to_owned()]),
            ("fields", vec![field.to_owned()]),
        ],
        construct_graph_span_from(value),
    ));
}

fn validate_construct_graph_nullable_string_field(
    value: &Value,
    owner_kind: &str,
    owner_id: &str,
    refs_key: &str,
    field: &str,
    diagnostics: &mut Vec<Value>,
) {
    if !value.is_object() {
        return;
    }
    let Some(field_value) = value.get(field) else {
        return;
    };
    if field_value.is_null() || field_value.is_string() {
        return;
    }
    diagnostics.push(construct_graph_diagnostic(
        format!("construct_graph.{owner_kind}.{field}_invalid"),
        format!(
            "construct graph {owner_kind} `{owner_id}` field `{field}` must be a string or null"
        ),
        vec![
            (refs_key, vec![owner_id.to_owned()]),
            ("fields", vec![field.to_owned()]),
        ],
        construct_graph_span_from(value),
    ));
}

fn validate_construct_graph_optional_object_field(
    value: &Value,
    owner_kind: &str,
    owner_id: &str,
    refs_key: &str,
    field: &str,
    diagnostics: &mut Vec<Value>,
) {
    if !value.is_object() {
        return;
    }
    let Some(field_value) = value.get(field) else {
        return;
    };
    if field_value.is_object() {
        return;
    }
    diagnostics.push(construct_graph_diagnostic(
        format!("construct_graph.{owner_kind}.{field}_invalid"),
        format!("construct graph {owner_kind} `{owner_id}` field `{field}` must be an object"),
        vec![
            (refs_key, vec![owner_id.to_owned()]),
            ("fields", vec![field.to_owned()]),
        ],
        construct_graph_span_from(value),
    ));
}

fn validate_construct_graph_interface_shapes(
    node: &Value,
    node_id: &str,
    field: &str,
    diagnostics: &mut Vec<Value>,
) {
    let Some(interfaces) = node.get(field) else {
        return;
    };
    let Some(interfaces) = interfaces.as_array() else {
        diagnostics.push(construct_graph_diagnostic(
            "construct_graph.interface.collection_invalid",
            format!("construct graph node `{node_id}` field `{field}` must be an array"),
            vec![
                ("nodes", vec![node_id.to_owned()]),
                ("fields", vec![field.to_owned()]),
            ],
            construct_graph_span_from(node),
        ));
        return;
    };
    for (index, interface) in interfaces.iter().enumerate() {
        let owner_id = format!("{node_id}.{field}[{index}]");
        validate_construct_graph_object_shape(
            interface,
            "interface",
            &owner_id,
            "nodes",
            CONSTRUCT_GRAPH_INTERFACE_FIELDS,
            CONSTRUCT_GRAPH_INTERFACE_FIELDS,
            diagnostics,
        );
        for interface_field in ["kind", "phase", "cardinality"] {
            validate_construct_graph_nonempty_string_field(
                interface,
                "interface",
                &owner_id,
                "nodes",
                interface_field,
                diagnostics,
            );
        }
        for interface_field in ["name", "type"] {
            validate_construct_graph_nullable_string_field(
                interface,
                "interface",
                &owner_id,
                "nodes",
                interface_field,
                diagnostics,
            );
        }
    }
}

fn validate_construct_graph_span_field(
    value: &Value,
    owner_kind: &str,
    owner_id: &str,
    refs_key: &str,
    field: &str,
    diagnostics: &mut Vec<Value>,
) {
    let Some(span) = value.get(field) else {
        return;
    };
    if let Err(reason) = validate_artifact_span_value(span) {
        diagnostics.push(construct_graph_diagnostic(
            format!("construct_graph.{owner_kind}.{field}_invalid"),
            format!("construct graph {owner_kind} `{owner_id}` has invalid `{field}`: {reason}"),
            vec![
                (refs_key, vec![owner_id.to_owned()]),
                ("fields", vec![field.to_owned()]),
            ],
            construct_graph_empty_span(),
        ));
    }
}

