fn validate_construct_graph_validator_shapes(graph: &Value, diagnostics: &mut Vec<Value>) {
    if let Some(facts) = graph.get("derived_facts").and_then(Value::as_array) {
        for predicate in duplicate_artifact_derived_fact_predicates(facts) {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.derived_fact.duplicate",
                format!("construct graph derived fact `{predicate}` is duplicated"),
                vec![("derived_facts", vec![predicate])],
                construct_graph_empty_span(),
            ));
        }

        for (index, fact) in facts.iter().enumerate() {
            let predicate = fact
                .get("predicate")
                .and_then(Value::as_str)
                .map(str::to_owned)
                .unwrap_or_else(|| format!("derived_facts[{index}]"));
            validate_construct_graph_object_shape(
                fact,
                "derived_fact",
                &predicate,
                "derived_facts",
                ARTIFACT_DERIVED_FACT_FIELDS,
                ARTIFACT_DERIVED_FACT_FIELDS,
                diagnostics,
            );
            validate_construct_graph_span_field(
                fact,
                "derived_fact",
                &predicate,
                "derived_facts",
                "diagnostic_span",
                diagnostics,
            );
            validate_construct_graph_string_ref_set_field(
                fact,
                "derived_fact",
                &predicate,
                "derived_facts",
                "input_refs",
                diagnostics,
            );
            validate_construct_graph_derived_fact_metadata(fact, &predicate, diagnostics);
        }
    }

    if let Some(report_diagnostics) = graph.get("diagnostics").and_then(Value::as_array) {
        for (index, diagnostic) in report_diagnostics.iter().enumerate() {
            let code = diagnostic
                .get("code")
                .and_then(Value::as_str)
                .map(str::to_owned)
                .unwrap_or_else(|| format!("diagnostics[{index}]"));
            validate_construct_graph_object_shape(
                diagnostic,
                "diagnostic",
                &code,
                "diagnostics",
                ARTIFACT_DIAGNOSTIC_REQUIRED_FIELDS,
                ARTIFACT_DIAGNOSTIC_FIELDS,
                diagnostics,
            );
            validate_construct_graph_diagnostic_metadata(diagnostic, &code, diagnostics);
        }
    }
}

fn validate_construct_graph_artifact(graph: &Value) -> ConstructGraphValidation {
    let Some(nodes) = graph.get("nodes").and_then(Value::as_array) else {
        return ConstructGraphValidation {
            diagnostics: vec![construct_graph_diagnostic(
                "construct_graph.nodes_missing",
                "construct graph is missing nodes",
                Vec::new(),
                construct_graph_empty_span(),
            )],
            derived_facts: Vec::new(),
        };
    };
    let Some(ports) = graph.get("ports").and_then(Value::as_array) else {
        return ConstructGraphValidation {
            diagnostics: vec![construct_graph_diagnostic(
                "construct_graph.ports_missing",
                "construct graph is missing ports",
                Vec::new(),
                construct_graph_empty_span(),
            )],
            derived_facts: Vec::new(),
        };
    };
    let Some(edges) = graph.get("edges").and_then(Value::as_array) else {
        return ConstructGraphValidation {
            diagnostics: vec![construct_graph_diagnostic(
                "construct_graph.edges_missing",
                "construct graph is missing edges",
                Vec::new(),
                construct_graph_empty_span(),
            )],
            derived_facts: Vec::new(),
        };
    };
    let Some(effect_dependencies) = graph.get("effect_dependencies").and_then(Value::as_array)
    else {
        return ConstructGraphValidation {
            diagnostics: vec![construct_graph_diagnostic(
                "construct_graph.effect_dependencies_missing",
                "construct graph is missing effect_dependencies",
                Vec::new(),
                construct_graph_empty_span(),
            )],
            derived_facts: Vec::new(),
        };
    };

    let mut diagnostics = Vec::new();
    let mut node_by_id = BTreeMap::<String, &Value>::new();
    let mut port_by_id = BTreeMap::<String, &Value>::new();

    validate_construct_graph_shape(
        graph,
        nodes,
        ports,
        edges,
        effect_dependencies,
        &mut diagnostics,
    );

    for node in nodes {
        let Some(node_id) = json_str(node, "node_id") else {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.node.id_missing",
                "construct graph node is missing node_id",
                Vec::new(),
                construct_graph_span_from(node),
            ));
            continue;
        };
        for field in [
            "required_ports",
            "produced_ports",
            "required_capabilities",
            "lowered_effect_capabilities",
            "allowed_core_object_kinds",
            "allowed_runtime_entrypoints",
        ] {
            validate_construct_graph_unique_string_array_field(
                node,
                field,
                "node",
                node_id,
                "nodes",
                &mut diagnostics,
            );
        }
        if node_by_id.insert(node_id.to_owned(), node).is_some() {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.node.duplicate",
                format!("construct graph node `{node_id}` is declared more than once"),
                vec![("nodes", vec![node_id.to_owned()])],
                construct_graph_span_from(node),
            ));
        }
    }

    for port in ports {
        let Some(port_id) = json_str(port, "port_id") else {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.port.id_missing",
                "construct graph port is missing port_id",
                Vec::new(),
                construct_graph_span_from(port),
            ));
            continue;
        };
        if port_by_id.insert(port_id.to_owned(), port).is_some() {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.port.duplicate",
                format!("construct graph port `{port_id}` is declared more than once"),
                vec![("ports", vec![port_id.to_owned()])],
                construct_graph_span_from(port),
            ));
        }
    }

    validate_construct_graph_node_ports(nodes, &node_by_id, &port_by_id, &mut diagnostics);
    validate_construct_graph_node_interfaces(nodes, &port_by_id, &mut diagnostics);
    validate_construct_graph_node_outputs(nodes, &mut diagnostics);
    validate_construct_graph_node_lifecycle_profiles(nodes, &mut diagnostics);
    validate_construct_graph_edges(edges, &node_by_id, &port_by_id, &mut diagnostics);
    validate_construct_graph_cardinality(&port_by_id, edges, &mut diagnostics);
    validate_construct_graph_effect_dependencies(
        effect_dependencies,
        &node_by_id,
        &mut diagnostics,
    );

    let derived_facts = if diagnostics.is_empty() {
        construct_graph_validation_facts(graph, nodes, ports, edges, effect_dependencies)
    } else {
        Vec::new()
    };

    ConstructGraphValidation {
        diagnostics,
        derived_facts,
    }
}

fn validate_construct_graph_node_ports(
    nodes: &[Value],
    node_by_id: &BTreeMap<String, &Value>,
    port_by_id: &BTreeMap<String, &Value>,
    diagnostics: &mut Vec<Value>,
) {
    for node in nodes {
        let Some(node_id) = json_str(node, "node_id") else {
            continue;
        };
        for port_id in construct_graph_string_array(node, "required_ports") {
            validate_construct_graph_node_port_ref(
                node_id,
                &port_id,
                "required",
                port_by_id,
                diagnostics,
                node,
            );
        }
        for port_id in construct_graph_string_array(node, "produced_ports") {
            validate_construct_graph_node_port_ref(
                node_id,
                &port_id,
                "produced",
                port_by_id,
                diagnostics,
                node,
            );
        }
    }

    for port in port_by_id.values() {
        let port_id = json_str(port, "port_id").unwrap_or("unknown");
        let Some(owner_node_id) = json_str(port, "owner_node_id") else {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.port.owner_missing",
                format!("construct graph port `{port_id}` is missing an owner node"),
                vec![("ports", vec![port_id.to_owned()])],
                construct_graph_span_from(port),
            ));
            continue;
        };
        let Some(owner_node) = node_by_id.get(owner_node_id) else {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.port.owner_unknown",
                format!(
                    "construct graph port `{port_id}` references unknown node `{owner_node_id}`"
                ),
                vec![
                    ("ports", vec![port_id.to_owned()]),
                    ("nodes", vec![owner_node_id.to_owned()]),
                ],
                construct_graph_span_from(port),
            ));
            continue;
        };
        let expected_list = match json_str(port, "direction") {
            Some("required") => "required_ports",
            Some("produced") => "produced_ports",
            _ => {
                diagnostics.push(construct_graph_diagnostic(
                    "construct_graph.port.direction_unknown",
                    format!("construct graph port `{port_id}` has an unknown direction"),
                    vec![("ports", vec![port_id.to_owned()])],
                    construct_graph_span_from(port),
                ));
                continue;
            }
        };
        if !construct_graph_string_array(owner_node, expected_list)
            .iter()
            .any(|listed| listed == port_id)
        {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.port.not_listed_by_owner",
                format!(
                    "construct graph port `{port_id}` is not listed in `{owner_node_id}` `{expected_list}`"
                ),
                vec![
                    ("ports", vec![port_id.to_owned()]),
                    ("nodes", vec![owner_node_id.to_owned()]),
                ],
                construct_graph_span_from(port),
            ));
        }
    }
}

fn validate_construct_graph_node_outputs(nodes: &[Value], diagnostics: &mut Vec<Value>) {
    for node in nodes {
        let node_id = json_str(node, "node_id").unwrap_or("unknown");
        let object_kinds = construct_graph_string_array(node, "allowed_core_object_kinds");
        let runtime_entrypoints = construct_graph_string_array(node, "allowed_runtime_entrypoints");
        let runtime_entrypoint_set = runtime_entrypoints
            .iter()
            .map(String::as_str)
            .collect::<BTreeSet<_>>();
        let mut expected_entrypoints = BTreeSet::<&str>::new();

        for object_kind in &object_kinds {
            if lowered_ir_forbidden_runtime_object_kind(object_kind) {
                diagnostics.push(construct_graph_diagnostic(
                    "construct_graph.node.output_runtime_state",
                    format!(
                        "construct graph node `{node_id}` allows runtime-owned core object kind `{object_kind}`"
                    ),
                    vec![("nodes", vec![node_id.to_owned()])],
                    construct_graph_span_from(node),
                ));
                continue;
            }
            let Some(expected_entrypoint) = lowered_ir_expected_runtime_entrypoint(object_kind)
            else {
                diagnostics.push(construct_graph_diagnostic(
                    "construct_graph.node.output_kind_unknown",
                    format!(
                        "construct graph node `{node_id}` allows unknown core object kind `{object_kind}`"
                    ),
                    vec![("nodes", vec![node_id.to_owned()])],
                    construct_graph_span_from(node),
                ));
                continue;
            };
            expected_entrypoints.insert(expected_entrypoint);
            if !lowered_ir_current_core_object_kind_supported(object_kind) {
                diagnostics.push(construct_graph_diagnostic(
                    "construct_graph.node.output_kind_unsupported",
                    format!(
                        "construct graph node `{node_id}` allows known core object kind `{object_kind}` before the current executable lowering/runtime handoff slice admits it"
                    ),
                    vec![("nodes", vec![node_id.to_owned()])],
                    construct_graph_span_from(node),
                ));
            }
        }

        for runtime_entrypoint in &runtime_entrypoints {
            if lowered_ir_forbidden_runtime_entrypoint(runtime_entrypoint) {
                diagnostics.push(construct_graph_diagnostic(
                    "construct_graph.node.output_runtime_state",
                    format!(
                        "construct graph node `{node_id}` allows runtime-owned entrypoint `{runtime_entrypoint}`"
                    ),
                    vec![("nodes", vec![node_id.to_owned()])],
                    construct_graph_span_from(node),
                ));
                continue;
            }
            if !lowered_ir_known_runtime_entrypoint(runtime_entrypoint) {
                diagnostics.push(construct_graph_diagnostic(
                    "construct_graph.node.runtime_entrypoint_unknown",
                    format!(
                        "construct graph node `{node_id}` allows unknown runtime entrypoint `{runtime_entrypoint}`"
                    ),
                    vec![("nodes", vec![node_id.to_owned()])],
                    construct_graph_span_from(node),
                ));
                continue;
            }
            if !lowered_ir_current_runtime_entrypoint_supported(runtime_entrypoint) {
                diagnostics.push(construct_graph_diagnostic(
                    "construct_graph.node.runtime_entrypoint_unsupported",
                    format!(
                        "construct graph node `{node_id}` allows known runtime entrypoint `{runtime_entrypoint}` before the current executable lowering/runtime handoff slice admits it"
                    ),
                    vec![("nodes", vec![node_id.to_owned()])],
                    construct_graph_span_from(node),
                ));
            }
            if !object_kinds.is_empty()
                && !expected_entrypoints.contains(runtime_entrypoint.as_str())
            {
                diagnostics.push(construct_graph_diagnostic(
                    "construct_graph.node.runtime_entrypoint_unmatched",
                    format!(
                        "construct graph node `{node_id}` allows runtime entrypoint `{runtime_entrypoint}` that is not produced by its allowed core object kinds"
                    ),
                    vec![("nodes", vec![node_id.to_owned()])],
                    construct_graph_span_from(node),
                ));
            }
        }

        for expected_entrypoint in expected_entrypoints {
            if !runtime_entrypoint_set.contains(expected_entrypoint) {
                diagnostics.push(construct_graph_diagnostic(
                    "construct_graph.node.runtime_entrypoint_missing",
                    format!(
                        "construct graph node `{node_id}` allows a core object kind whose runtime entrypoint `{expected_entrypoint}` is missing"
                    ),
                    vec![("nodes", vec![node_id.to_owned()])],
                    construct_graph_span_from(node),
                ));
            }
        }
    }
}

fn validate_construct_graph_node_lifecycle_profiles(nodes: &[Value], diagnostics: &mut Vec<Value>) {
    for node in nodes {
        let node_id = json_str(node, "node_id").unwrap_or("unknown");
        let Some(lowering_class) = json_str(node, "lowering_class") else {
            continue;
        };
        let Some(lifecycle_profile) = json_str(node, "lifecycle_profile") else {
            continue;
        };
        let Some(construct_family) = json_str(node, "construct_family") else {
            continue;
        };
        let Some(lowering) = PLATFORM_CONSTRUCT_CATALOG.lowering(lowering_class) else {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.node.lowering_class_unsupported",
                format!(
                    "construct graph node `{node_id}` uses unsupported lowering class `{lowering_class}`"
                ),
                vec![("nodes", vec![node_id.to_owned()])],
                construct_graph_span_from(node),
            ));
            continue;
        };
        if !lowering.compatible_families.contains(&construct_family) {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.node.lowering_family_mismatch",
                format!(
                    "construct graph node `{node_id}` lowering class `{lowering_class}` is incompatible with construct family `{construct_family}`"
                ),
                vec![("nodes", vec![node_id.to_owned()])],
                construct_graph_span_from(node),
            ));
        }
        if !lowering
            .lifecycle_profiles
            .iter()
            .any(|allowed_profile| allowed_profile == &lifecycle_profile)
        {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.node.lifecycle_profile_mismatch",
                format!(
                    "construct graph node `{node_id}` lowering class `{lowering_class}` does not allow lifecycle profile `{lifecycle_profile}`"
                ),
                vec![("nodes", vec![node_id.to_owned()])],
                construct_graph_span_from(node),
            ));
        }
    }
}

fn validate_construct_graph_node_interfaces(
    nodes: &[Value],
    port_by_id: &BTreeMap<String, &Value>,
    diagnostics: &mut Vec<Value>,
) {
    for node in nodes {
        let node_id = json_str(node, "node_id").unwrap_or("unknown");
        validate_construct_graph_node_interface_direction(
            node,
            node_id,
            "required",
            "declared_required_interfaces",
            "required_ports",
            port_by_id,
            diagnostics,
        );
        validate_construct_graph_node_interface_direction(
            node,
            node_id,
            "provided",
            "declared_provided_interfaces",
            "produced_ports",
            port_by_id,
            diagnostics,
        );
        validate_construct_graph_node_lowering_interfaces(node, node_id, diagnostics);
    }
}

fn validate_construct_graph_node_lowering_interfaces(
    node: &Value,
    node_id: &str,
    diagnostics: &mut Vec<Value>,
) {
    let Some(lowering_class) = json_str(node, "lowering_class") else {
        return;
    };
    let Some(lowering) = PLATFORM_CONSTRUCT_CATALOG.lowering(lowering_class) else {
        return;
    };
    for kind in lowering.required_interfaces {
        if !construct_graph_node_declares_interface(node, "declared_required_interfaces", kind) {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.interface.lowering_required_missing",
                format!(
                    "construct graph node `{node_id}` uses `{lowering_class}` lowering but declares no required `{kind}` interface"
                ),
                vec![("nodes", vec![node_id.to_owned()])],
                construct_graph_span_from(node),
            ));
        }
    }
    for kind in lowering.provided_interfaces {
        if !construct_graph_node_declares_interface(node, "declared_provided_interfaces", kind) {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.interface.lowering_provided_missing",
                format!(
                    "construct graph node `{node_id}` uses `{lowering_class}` lowering but declares no provided `{kind}` interface"
                ),
                vec![("nodes", vec![node_id.to_owned()])],
                construct_graph_span_from(node),
            ));
        }
    }
}

fn construct_graph_node_declares_interface(node: &Value, key: &str, kind: &str) -> bool {
    node.get(key)
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .any(|interface| json_str(interface, "kind") == Some(kind))
}

fn validate_construct_graph_node_interface_direction(
    node: &Value,
    node_id: &str,
    direction: &str,
    interface_key: &str,
    port_key: &str,
    port_by_id: &BTreeMap<String, &Value>,
    diagnostics: &mut Vec<Value>,
) {
    let port_ids = construct_graph_string_array(node, port_key);
    let ports = port_ids
        .iter()
        .filter_map(|port_id| port_by_id.get(port_id).copied())
        .collect::<Vec<_>>();
    let mut seen_interfaces = BTreeSet::new();
    for interface in node
        .get(interface_key)
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
    {
        let kind = json_str(interface, "kind").unwrap_or("unknown");
        if !seen_interfaces.insert(construct_graph_interface_signature(interface)) {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.interface.duplicate",
                format!(
                    "construct graph node `{node_id}` declares duplicate {direction} interface `{kind}`"
                ),
                vec![
                    ("nodes", vec![node_id.to_owned()]),
                    ("fields", vec![interface_key.to_owned()]),
                ],
                construct_graph_span_from(node),
            ));
        }
        if ports
            .iter()
            .any(|port| construct_graph_port_satisfies_interface(port, interface))
        {
            continue;
        }
        diagnostics.push(construct_graph_diagnostic(
            "construct_graph.interface.unsatisfied",
            format!(
                "construct graph node `{node_id}` declares {direction} interface `{kind}` but no {direction} port satisfies it"
            ),
            vec![("nodes", vec![node_id.to_owned()])],
            construct_graph_span_from(node),
        ));
    }
}

fn construct_graph_interface_signature(interface: &Value) -> Vec<String> {
    ["kind", "name", "type", "phase", "cardinality"]
        .into_iter()
        .map(|field| {
            interface
                .get(field)
                .map(Value::to_string)
                .unwrap_or_else(|| "<missing>".to_owned())
        })
        .collect()
}

fn construct_graph_port_satisfies_interface(port: &Value, interface: &Value) -> bool {
    let Some(kind) = json_str(interface, "kind") else {
        return false;
    };
    if json_str(port, "kind") != Some(kind) {
        return false;
    }
    if let Some(name) = json_str(interface, "name") {
        let port_type = json_str(port, "type");
        let resource_identity = port.get("resource_identity").and_then(Value::as_str);
        if port_type != Some(name) && resource_identity != Some(name) {
            return false;
        }
    }
    if let Some(type_ref) = json_str(interface, "type") {
        if json_str(port, "type") != Some(type_ref) {
            return false;
        }
    }
    let Some(interface_phase) = json_str(interface, "phase") else {
        return false;
    };
    if !construct_graph_interface_phase_matches_port(interface_phase, json_str(port, "phase")) {
        return false;
    }
    if json_str(interface, "cardinality") != json_str(port, "cardinality") {
        return false;
    }
    true
}

fn construct_graph_interface_phase_matches_port(
    interface_phase: &str,
    port_phase: Option<&str>,
) -> bool {
    matches!(
        (interface_phase, port_phase),
        (
            "compile/runtime" | "both",
            Some("compile" | "runtime" | "both")
        ) | ("compile", Some("compile" | "both"))
            | ("runtime", Some("runtime" | "both"))
    )
}

fn validate_construct_graph_node_port_ref(
    node_id: &str,
    port_id: &str,
    expected_direction: &str,
    port_by_id: &BTreeMap<String, &Value>,
    diagnostics: &mut Vec<Value>,
    node: &Value,
) {
    let Some(port) = port_by_id.get(port_id) else {
        diagnostics.push(construct_graph_diagnostic(
            "construct_graph.node.port_missing",
            format!("construct graph node `{node_id}` references missing port `{port_id}`"),
            vec![
                ("nodes", vec![node_id.to_owned()]),
                ("ports", vec![port_id.to_owned()]),
            ],
            construct_graph_span_from(node),
        ));
        return;
    };

    if json_str(port, "owner_node_id") != Some(node_id) {
        diagnostics.push(construct_graph_diagnostic(
            "construct_graph.node.port_owner_mismatch",
            format!("construct graph port `{port_id}` is not owned by node `{node_id}`"),
            vec![
                ("nodes", vec![node_id.to_owned()]),
                ("ports", vec![port_id.to_owned()]),
            ],
            construct_graph_span_from(port),
        ));
    }
    if json_str(port, "direction") != Some(expected_direction) {
        diagnostics.push(construct_graph_diagnostic(
            "construct_graph.node.port_direction_mismatch",
            format!(
                "construct graph node `{node_id}` lists port `{port_id}` as `{expected_direction}` but the port declares another direction"
            ),
            vec![
                ("nodes", vec![node_id.to_owned()]),
                ("ports", vec![port_id.to_owned()]),
            ],
            construct_graph_span_from(port),
        ));
    }
}

fn validate_construct_graph_edges(
    edges: &[Value],
    node_by_id: &BTreeMap<String, &Value>,
    port_by_id: &BTreeMap<String, &Value>,
    diagnostics: &mut Vec<Value>,
) {
    let mut seen_edges = BTreeSet::new();
    for edge in edges {
        let required_port_id = json_str(edge, "required_port_id").unwrap_or("unknown");
        let provider_node_id = json_str(edge, "provider_node_id").unwrap_or("unknown");
        let provided_port_id = json_str(edge, "provided_port_id").unwrap_or("unknown");
        let edge_ref = construct_graph_edge_ref(edge);
        if !seen_edges.insert(edge_ref.clone()) {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.edge.duplicate",
                format!("construct graph edge `{edge_ref}` is declared more than once"),
                vec![("edges", vec![edge_ref.clone()])],
                construct_graph_span_from(edge),
            ));
        }
        validate_construct_graph_unique_string_array_field(
            edge,
            "evidence",
            "edge",
            &edge_ref,
            "edges",
            diagnostics,
        );
        let required_port = port_by_id.get(required_port_id).copied();
        let provided_port = port_by_id.get(provided_port_id).copied();

        if required_port.is_none() {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.edge.required_port_missing",
                format!(
                    "construct graph edge `{edge_ref}` references missing required port `{required_port_id}`"
                ),
                vec![("ports", vec![required_port_id.to_owned()])],
                construct_graph_empty_span(),
            ));
        }
        if provided_port.is_none() {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.edge.provided_port_missing",
                format!(
                    "construct graph edge `{edge_ref}` references missing provided port `{provided_port_id}`"
                ),
                vec![("ports", vec![provided_port_id.to_owned()])],
                required_port.map_or_else(construct_graph_empty_span, construct_graph_span_from),
            ));
        }
        if !node_by_id.contains_key(provider_node_id) {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.edge.provider_node_missing",
                format!(
                    "construct graph edge `{edge_ref}` references missing provider node `{provider_node_id}`"
                ),
                vec![("nodes", vec![provider_node_id.to_owned()])],
                required_port.map_or_else(construct_graph_empty_span, construct_graph_span_from),
            ));
        }

        let Some(required_port) = required_port else {
            continue;
        };
        let Some(provided_port) = provided_port else {
            continue;
        };

        if json_str(required_port, "direction") != Some("required") {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.edge.required_not_required",
                format!("construct graph edge `{edge_ref}` starts from a non-required port"),
                vec![("ports", vec![required_port_id.to_owned()])],
                construct_graph_span_from(required_port),
            ));
        }
        if json_str(provided_port, "direction") != Some("produced") {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.edge.provided_not_produced",
                format!("construct graph edge `{edge_ref}` ends at a non-produced port"),
                vec![("ports", vec![provided_port_id.to_owned()])],
                construct_graph_span_from(provided_port),
            ));
        }
        if json_str(provided_port, "owner_node_id") != Some(provider_node_id) {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.edge.provider_owner_mismatch",
                format!(
                    "construct graph edge `{edge_ref}` provider node does not own provided port `{provided_port_id}`"
                ),
                vec![
                    ("nodes", vec![provider_node_id.to_owned()]),
                    ("ports", vec![provided_port_id.to_owned()]),
                ],
                construct_graph_span_from(provided_port),
            ));
        }

        validate_construct_graph_edge_compatibility(
            edge,
            required_port,
            provided_port,
            diagnostics,
        );
    }
}

fn validate_construct_graph_edge_compatibility(
    edge: &Value,
    required_port: &Value,
    provided_port: &Value,
    diagnostics: &mut Vec<Value>,
) {
    let required_port_id = json_str(edge, "required_port_id").unwrap_or("unknown");
    let provided_port_id = json_str(edge, "provided_port_id").unwrap_or("unknown");
    let edge_ref = construct_graph_edge_ref(edge);

    for (field, code) in [
        ("kind", "construct_graph.edge.kind_mismatch"),
        ("type", "construct_graph.edge.type_mismatch"),
        ("contract_version", "construct_graph.edge.version_mismatch"),
    ] {
        if json_str(required_port, field) != json_str(provided_port, field) {
            diagnostics.push(construct_graph_diagnostic(
                code,
                format!("construct graph edge `{edge_ref}` has incompatible port `{field}`"),
                vec![
                    ("ports", vec![required_port_id.to_owned()]),
                    ("ports", vec![provided_port_id.to_owned()]),
                ],
                construct_graph_span_from(required_port),
            ));
        }
    }

    if !construct_graph_phase_compatible(
        json_str(required_port, "phase"),
        json_str(provided_port, "phase"),
    ) {
        diagnostics.push(construct_graph_diagnostic(
            "construct_graph.edge.phase_mismatch",
            format!("construct graph edge `{edge_ref}` has incompatible port phases"),
            vec![
                ("ports", vec![required_port_id.to_owned()]),
                ("ports", vec![provided_port_id.to_owned()]),
            ],
            construct_graph_span_from(required_port),
        ));
    }

    if required_port.get("resource_identity") != provided_port.get("resource_identity") {
        diagnostics.push(construct_graph_diagnostic(
            "construct_graph.edge.resource_mismatch",
            format!("construct graph edge `{edge_ref}` has incompatible resource identities"),
            vec![
                ("ports", vec![required_port_id.to_owned()]),
                ("ports", vec![provided_port_id.to_owned()]),
            ],
            construct_graph_span_from(required_port),
        ));
    }
}

fn validate_construct_graph_cardinality(
    port_by_id: &BTreeMap<String, &Value>,
    edges: &[Value],
    diagnostics: &mut Vec<Value>,
) {
    let mut edges_by_required_port = BTreeMap::<String, Vec<&Value>>::new();
    for edge in edges {
        if let Some(required_port_id) = json_str(edge, "required_port_id") {
            edges_by_required_port
                .entry(required_port_id.to_owned())
                .or_default()
                .push(edge);
        }
    }

    for port in port_by_id.values() {
        if json_str(port, "direction") != Some("required") {
            continue;
        }
        let port_id = json_str(port, "port_id").unwrap_or("unknown");
        let port_edges = edges_by_required_port
            .get(port_id)
            .map(Vec::as_slice)
            .unwrap_or(&[]);
        match json_str(port, "cardinality").unwrap_or("exactly-one") {
            "exactly-one" => {
                if port_edges.len() != 1 {
                    diagnostics.push(construct_graph_diagnostic(
                        "construct_graph.cardinality.exactly_one",
                        format!(
                            "required port `{port_id}` expects exactly one provider but resolved {}",
                            port_edges.len()
                        ),
                        vec![("ports", vec![port_id.to_owned()])],
                        construct_graph_span_from(port),
                    ));
                }
                validate_construct_graph_scalar_edge_metadata(
                    port_id,
                    port,
                    port_edges,
                    diagnostics,
                );
            }
            "optional-one" => {
                if port_edges.len() > 1 {
                    diagnostics.push(construct_graph_diagnostic(
                        "construct_graph.cardinality.optional_one",
                        format!(
                            "required port `{port_id}` expects at most one provider but resolved {}",
                            port_edges.len()
                        ),
                        vec![("ports", vec![port_id.to_owned()])],
                        construct_graph_span_from(port),
                    ));
                }
                validate_construct_graph_scalar_edge_metadata(
                    port_id,
                    port,
                    port_edges,
                    diagnostics,
                );
            }
            "many" => validate_construct_graph_many_cardinality(
                port_id,
                port,
                port_edges,
                false,
                diagnostics,
            ),
            "named-many" => validate_construct_graph_many_cardinality(
                port_id,
                port,
                port_edges,
                true,
                diagnostics,
            ),
            other => diagnostics.push(construct_graph_diagnostic(
                "construct_graph.cardinality.unknown",
                format!("required port `{port_id}` declares unknown cardinality `{other}`"),
                vec![("ports", vec![port_id.to_owned()])],
                construct_graph_span_from(port),
            )),
        }
    }
}

fn validate_construct_graph_scalar_edge_metadata(
    port_id: &str,
    port: &Value,
    edges: &[&Value],
    diagnostics: &mut Vec<Value>,
) {
    for edge in edges {
        if !edge.get("order_index").is_none_or(Value::is_null)
            || !edge.get("resource_key").is_none_or(Value::is_null)
        {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.cardinality.scalar_edge_metadata",
                format!(
                    "required port `{port_id}` has scalar cardinality but its edge carries aggregate metadata"
                ),
                vec![("ports", vec![port_id.to_owned()])],
                construct_graph_span_from(port),
            ));
        }
    }
}

fn validate_construct_graph_many_cardinality(
    port_id: &str,
    port: &Value,
    edges: &[&Value],
    require_resource_key: bool,
    diagnostics: &mut Vec<Value>,
) {
    let mut order_indices = BTreeSet::new();
    let mut saw_invalid_order = false;
    let mut resource_keys = BTreeSet::new();

    for edge in edges {
        let edge_ref = construct_graph_edge_ref(edge);
        match edge.get("order_index").and_then(Value::as_u64) {
            Some(order_index) => {
                if !order_indices.insert(order_index) {
                    saw_invalid_order = true;
                    diagnostics.push(construct_graph_diagnostic(
                        "construct_graph.cardinality.order_duplicate",
                        format!("aggregate required port `{port_id}` uses order_index `{order_index}` more than once"),
                        vec![("ports", vec![port_id.to_owned()])],
                        construct_graph_span_from(port),
                    ));
                }
            }
            None => {
                saw_invalid_order = true;
                diagnostics.push(construct_graph_diagnostic(
                    "construct_graph.cardinality.order_missing",
                    format!("aggregate required port `{port_id}` edge `{edge_ref}` is missing order_index"),
                    vec![("ports", vec![port_id.to_owned()])],
                    construct_graph_span_from(port),
                ));
            }
        }

        match (require_resource_key, edge.get("resource_key").and_then(Value::as_str)) {
            (true, Some(resource_key)) if !resource_key.is_empty() => {
                if !resource_keys.insert(resource_key.to_owned()) {
                    diagnostics.push(construct_graph_diagnostic(
                        "construct_graph.cardinality.resource_key_duplicate",
                        format!(
                            "named-many required port `{port_id}` uses resource key `{resource_key}` more than once"
                        ),
                        vec![("ports", vec![port_id.to_owned()])],
                        construct_graph_span_from(port),
                    ));
                }
            }
            (true, _) => diagnostics.push(construct_graph_diagnostic(
                "construct_graph.cardinality.resource_key_missing",
                format!("named-many required port `{port_id}` edge `{edge_ref}` is missing resource_key"),
                vec![("ports", vec![port_id.to_owned()])],
                construct_graph_span_from(port),
            )),
            (false, Some(_)) => diagnostics.push(construct_graph_diagnostic(
                "construct_graph.cardinality.resource_key_unexpected",
                format!("many required port `{port_id}` edge `{edge_ref}` unexpectedly carries resource_key"),
                vec![("ports", vec![port_id.to_owned()])],
                construct_graph_span_from(port),
            )),
            (false, None) => {}
        }
    }

    if !saw_invalid_order {
        for expected in 0..edges.len() as u64 {
            if !order_indices.contains(&expected) {
                diagnostics.push(construct_graph_diagnostic(
                    "construct_graph.cardinality.order_not_contiguous",
                    format!(
                        "aggregate required port `{port_id}` order_index values must be contiguous from zero"
                    ),
                    vec![("ports", vec![port_id.to_owned()])],
                    construct_graph_span_from(port),
                ));
                break;
            }
        }
    }
}

fn validate_construct_graph_effect_dependencies(
    effect_dependencies: &[Value],
    node_by_id: &BTreeMap<String, &Value>,
    diagnostics: &mut Vec<Value>,
) {
    let mut seen = BTreeSet::new();
    for dependency in effect_dependencies {
        let dependency_ref = json_str(dependency, "dependency_ref").unwrap_or("unknown");
        validate_construct_graph_unique_string_array_field(
            dependency,
            "evidence",
            "effect_dependency",
            dependency_ref,
            "effect_dependencies",
            diagnostics,
        );
        if !seen.insert(dependency_ref.to_owned()) {
            diagnostics.push(construct_graph_diagnostic(
                "construct_graph.effect_dependency.duplicate",
                format!("effect dependency `{dependency_ref}` is declared more than once"),
                vec![("effect_dependencies", vec![dependency_ref.to_owned()])],
                construct_graph_span_from(dependency),
            ));
        }
        for (field, code) in [
            (
                "upstream_node_id",
                "construct_graph.effect_dependency.upstream_missing",
            ),
            (
                "downstream_node_id",
                "construct_graph.effect_dependency.downstream_missing",
            ),
        ] {
            let Some(node_id) = json_str(dependency, field) else {
                diagnostics.push(construct_graph_diagnostic(
                    code,
                    format!("effect dependency `{dependency_ref}` is missing `{field}`"),
                    vec![("effect_dependencies", vec![dependency_ref.to_owned()])],
                    construct_graph_span_from(dependency),
                ));
                continue;
            };
            if !node_by_id.contains_key(node_id) {
                diagnostics.push(construct_graph_diagnostic(
                    code,
                    format!(
                        "effect dependency `{dependency_ref}` references unknown node `{node_id}`"
                    ),
                    vec![
                        ("effect_dependencies", vec![dependency_ref.to_owned()]),
                        ("nodes", vec![node_id.to_owned()]),
                    ],
                    construct_graph_span_from(dependency),
                ));
            }
        }
        match json_str(dependency, "predicate") {
            Some("succeeds" | "fails" | "completes") => {}
            Some(predicate) => diagnostics.push(construct_graph_diagnostic(
                "construct_graph.effect_dependency.predicate_unknown",
                format!("effect dependency `{dependency_ref}` has unknown predicate `{predicate}`"),
                vec![("effect_dependencies", vec![dependency_ref.to_owned()])],
                construct_graph_span_from(dependency),
            )),
            None => diagnostics.push(construct_graph_diagnostic(
                "construct_graph.effect_dependency.predicate_missing",
                format!("effect dependency `{dependency_ref}` is missing predicate"),
                vec![("effect_dependencies", vec![dependency_ref.to_owned()])],
                construct_graph_span_from(dependency),
            )),
        }
    }
}

fn validate_construct_graph_unique_string_array_field(
    value: &Value,
    field: &str,
    owner_kind: &str,
    owner_id: &str,
    refs_key: &str,
    diagnostics: &mut Vec<Value>,
) {
    let Some(items) = value.get(field) else {
        return;
    };
    let Some(items) = items.as_array() else {
        diagnostics.push(construct_graph_diagnostic(
            format!("construct_graph.{owner_kind}.string_array_invalid"),
            format!("construct graph {owner_kind} `{owner_id}` field `{field}` must be an array"),
            vec![
                (refs_key, vec![owner_id.to_owned()]),
                ("fields", vec![field.to_owned()]),
            ],
            construct_graph_span_from(value),
        ));
        return;
    };
    let mut seen = BTreeSet::new();
    for item in items {
        let Some(item) = item.as_str().filter(|item| !item.is_empty()) else {
            diagnostics.push(construct_graph_diagnostic(
                format!("construct_graph.{owner_kind}.string_array_invalid"),
                format!(
                    "construct graph {owner_kind} `{owner_id}` field `{field}` must contain only non-empty strings"
                ),
                vec![
                    (refs_key, vec![owner_id.to_owned()]),
                    ("fields", vec![field.to_owned()]),
                ],
                construct_graph_span_from(value),
            ));
            return;
        };
        if !seen.insert(item) {
            diagnostics.push(construct_graph_diagnostic(
                format!("construct_graph.{owner_kind}.string_array_duplicate"),
                format!(
                    "construct graph {owner_kind} `{owner_id}` field `{field}` contains duplicate ref `{item}`"
                ),
                vec![
                    (refs_key, vec![owner_id.to_owned()]),
                    ("fields", vec![field.to_owned()]),
                ],
                construct_graph_span_from(value),
            ));
            return;
        }
    }
}

fn construct_graph_validation_facts(
    graph: &Value,
    nodes: &[Value],
    ports: &[Value],
    edges: &[Value],
    effect_dependencies: &[Value],
) -> Vec<Value> {
    let graph_id = graph
        .get("graph_id")
        .and_then(Value::as_str)
        .unwrap_or("unknown");
    let mut facts = Vec::new();
    let node_ids = nodes
        .iter()
        .filter_map(|node| json_str(node, "node_id").map(str::to_owned))
        .collect::<Vec<_>>();
    let port_ids = ports
        .iter()
        .filter_map(|port| json_str(port, "port_id").map(str::to_owned))
        .collect::<Vec<_>>();
    let edge_refs = edges
        .iter()
        .map(construct_graph_edge_ref)
        .collect::<Vec<_>>();
    let ports_by_id = ports
        .iter()
        .filter_map(|port| json_str(port, "port_id").map(|port_id| (port_id.to_owned(), port)))
        .collect::<BTreeMap<_, _>>();
    let dependency_refs = effect_dependencies
        .iter()
        .filter_map(|dependency| json_str(dependency, "dependency_ref").map(str::to_owned))
        .collect::<Vec<_>>();

    facts.push(construct_graph_fact(
        format!("validator.graph.node_ids_unique:{graph_id}"),
        "construct_graph_validator",
        node_ids.clone(),
        construct_graph_empty_span(),
    ));
    facts.push(construct_graph_fact(
        format!("validator.graph.port_ids_unique:{graph_id}"),
        "construct_graph_validator",
        port_ids.clone(),
        construct_graph_empty_span(),
    ));
    facts.push(construct_graph_fact(
        format!("validator.graph.edge_refs_unique:{graph_id}"),
        "construct_graph_validator",
        edge_refs.clone(),
        construct_graph_empty_span(),
    ));
    facts.push(construct_graph_fact(
        format!("validator.graph.effect_dependency_refs_unique:{graph_id}"),
        "construct_graph_validator",
        dependency_refs.clone(),
        construct_graph_empty_span(),
    ));

    for node in nodes {
        let Some(node_id) = json_str(node, "node_id") else {
            continue;
        };
        facts.push(construct_graph_fact(
            format!("validator.node.profile:{node_id}"),
            "construct_graph_validator",
            construct_graph_node_profile_refs(node),
            construct_graph_span_from(node),
        ));
        facts.push(construct_graph_fact(
            format!("validator.node.interfaces:{node_id}"),
            "construct_graph_validator",
            construct_graph_node_interface_refs(node),
            construct_graph_span_from(node),
        ));
        facts.push(construct_graph_fact(
            format!("validator.node.capabilities:{node_id}"),
            "construct_graph_validator",
            construct_graph_node_capability_refs(node),
            construct_graph_span_from(node),
        ));
        facts.push(construct_graph_fact(
            format!(
                "validator.node.output:{}:{}",
                node_id,
                json_str(node, "lowering_output_kind").unwrap_or("unknown")
            ),
            "construct_graph_validator",
            construct_graph_node_output_refs(node),
            construct_graph_span_from(node),
        ));
        let mut refs = vec![node_id.to_owned()];
        refs.extend(construct_graph_string_array(node, "required_ports"));
        refs.extend(construct_graph_string_array(node, "produced_ports"));
        facts.push(construct_graph_fact(
            format!("validator.node.ports_consistent:{node_id}"),
            "construct_graph_validator",
            refs,
            construct_graph_span_from(node),
        ));
    }

    for port in ports {
        let Some(port_id) = json_str(port, "port_id") else {
            continue;
        };
        let owner_node_id = json_str(port, "owner_node_id").unwrap_or("unknown");
        facts.push(construct_graph_fact(
            format!("validator.port.profile:{port_id}"),
            "construct_graph_validator",
            construct_graph_port_profile_refs(port),
            construct_graph_span_from(port),
        ));
        facts.push(construct_graph_fact(
            format!("validator.port.owner_consistent:{port_id}"),
            "construct_graph_validator",
            vec![port_id.to_owned(), owner_node_id.to_owned()],
            construct_graph_span_from(port),
        ));
    }

    let mut edges_by_required_port = BTreeMap::<String, Vec<&Value>>::new();
    for edge in edges {
        let edge_ref = construct_graph_edge_ref(edge);
        if let Some(required_port_id) = json_str(edge, "required_port_id") {
            edges_by_required_port
                .entry(required_port_id.to_owned())
                .or_default()
                .push(edge);
        }
        let required_port_id = json_str(edge, "required_port_id").unwrap_or("unknown");
        let provided_port_id = json_str(edge, "provided_port_id").unwrap_or("unknown");
        let refs = construct_graph_edge_validation_refs(
            edge,
            ports_by_id.get(required_port_id).copied(),
            ports_by_id.get(provided_port_id).copied(),
        );
        for predicate in [
            "validator.edge.endpoints_valid",
            "validator.edge.kind_compatible",
            "validator.edge.type_compatible",
            "validator.edge.phase_compatible",
            "validator.edge.version_compatible",
            "validator.edge.resource_compatible",
        ] {
            facts.push(construct_graph_fact(
                format!("{predicate}:{edge_ref}"),
                "construct_graph_validator",
                refs.clone(),
                construct_graph_empty_span(),
            ));
        }
    }

    for port in ports {
        if json_str(port, "direction") != Some("required") {
            continue;
        }
        let Some(port_id) = json_str(port, "port_id") else {
            continue;
        };
        let cardinality = json_str(port, "cardinality").unwrap_or("unknown");
        let refs = construct_graph_cardinality_fact_refs(
            port,
            edges_by_required_port
                .get(port_id)
                .map(Vec::as_slice)
                .unwrap_or(&[]),
        );
        facts.push(construct_graph_fact(
            format!("validator.cardinality.{cardinality}.satisfied:{port_id}"),
            "construct_graph_validator",
            refs,
            construct_graph_span_from(port),
        ));
    }

    for dependency in effect_dependencies {
        let dependency_ref = json_str(dependency, "dependency_ref").unwrap_or("unknown");
        let upstream_node_id = json_str(dependency, "upstream_node_id").unwrap_or("unknown");
        let predicate = json_str(dependency, "predicate").unwrap_or("unknown");
        let downstream_node_id = json_str(dependency, "downstream_node_id").unwrap_or("unknown");
        let refs = vec![
            dependency_ref.to_owned(),
            upstream_node_id.to_owned(),
            predicate.to_owned(),
            downstream_node_id.to_owned(),
        ];
        for fact in [
            "validator.effect_dependency.endpoints_valid",
            "validator.effect_dependency.predicate_valid",
            "validator.effect_dependency.source_span_preserved",
        ] {
            facts.push(construct_graph_fact(
                format!("{fact}:{dependency_ref}"),
                "construct_graph_validator",
                refs.clone(),
                construct_graph_span_from(dependency),
            ));
        }
    }

    let mut accepted_refs = vec![graph_id.to_owned()];
    accepted_refs.extend(node_ids.clone());
    accepted_refs.extend(port_ids);
    accepted_refs.extend(edge_refs);
    accepted_refs.extend(dependency_refs);
    facts.push(construct_graph_fact(
        format!("validator.graph.accepted:{graph_id}"),
        "construct_graph_validator",
        accepted_refs,
        construct_graph_empty_span(),
    ));
    for (fact_id, _) in CONSTRUCT_GRAPH_ADEQUACY_FACTS {
        facts.push(construct_graph_fact(
            format!("validator.graph.adequacy.{fact_id}:{graph_id}"),
            "construct_graph_validator",
            construct_graph_adequacy_refs(graph, fact_id),
            construct_graph_empty_span(),
        ));
    }

    facts
}

fn construct_graph_adequacy_refs(graph: &Value, fact_id: &str) -> Vec<String> {
    let mut refs = Vec::new();
    let Some((_, ref_specs)) = CONSTRUCT_GRAPH_ADEQUACY_FACTS
        .iter()
        .find(|(candidate, _)| *candidate == fact_id)
    else {
        return refs;
    };
    for ref_spec in *ref_specs {
        if let Some(field) = ref_spec.strip_prefix("root:") {
            refs.push(construct_graph_root_field_ref(graph, field));
        } else {
            refs.push(format!("construct_graph.{ref_spec}"));
        }
    }
    refs
}

fn construct_graph_root_field_ref(graph: &Value, field: &str) -> String {
    let value = graph
        .get(field)
        .and_then(Value::as_str)
        .unwrap_or("unknown");
    format!("construct_graph.root.{field}:{value}")
}

fn construct_graph_cardinality_fact_refs(port: &Value, edges: &[&Value]) -> Vec<String> {
    let port_id = json_str(port, "port_id").unwrap_or("unknown");
    let cardinality = json_str(port, "cardinality").unwrap_or("unknown");
    let mut refs = vec![port_id.to_owned()];
    for edge in edges {
        let edge_ref = construct_graph_edge_ref(edge);
        refs.push(edge_ref.clone());
        if matches!(cardinality, "many" | "named-many") {
            if let Some(order_index) = edge.get("order_index").and_then(Value::as_u64) {
                refs.push(format!("{edge_ref}#order_index:{order_index}"));
            }
        }
        if cardinality == "named-many" {
            if let Some(resource_key) = edge.get("resource_key").and_then(Value::as_str) {
                refs.push(format!("{edge_ref}#resource_key:{resource_key}"));
            }
        }
    }
    refs
}

fn construct_graph_edge_validation_refs(
    edge: &Value,
    required_port: Option<&Value>,
    provided_port: Option<&Value>,
) -> Vec<String> {
    let edge_ref = construct_graph_edge_ref(edge);
    let required_port_id = json_str(edge, "required_port_id").unwrap_or("unknown");
    let provider_node_id = json_str(edge, "provider_node_id").unwrap_or("unknown");
    let provided_port_id = json_str(edge, "provided_port_id").unwrap_or("unknown");
    let mut refs = vec![
        edge_ref.clone(),
        required_port_id.to_owned(),
        provider_node_id.to_owned(),
        provided_port_id.to_owned(),
    ];
    refs.extend(construct_graph_optional_labeled_ref(
        &edge_ref,
        "resolution_reason",
        json_str(edge, "resolution_reason"),
    ));
    for evidence in construct_graph_string_array(edge, "evidence") {
        refs.push(format!("{edge_ref}#evidence:{evidence}"));
    }
    if let Some(required_port) = required_port {
        refs.extend(construct_graph_port_validation_refs(
            "required",
            required_port,
        ));
    }
    if let Some(provided_port) = provided_port {
        refs.extend(construct_graph_port_validation_refs(
            "provided",
            provided_port,
        ));
    }
    refs
}

fn construct_graph_port_validation_refs(role: &str, port: &Value) -> Vec<String> {
    let port_id = json_str(port, "port_id").unwrap_or("unknown");
    let mut refs = Vec::new();
    for field in [
        "owner_node_id",
        "direction",
        "kind",
        "type",
        "phase",
        "contract_version",
        "cardinality",
    ] {
        refs.extend(construct_graph_optional_labeled_ref(
            port_id,
            &format!("{role}.{field}"),
            json_str(port, field),
        ));
    }
    refs.push(format!(
        "{port_id}#{role}.resource_identity:{}",
        json_str(port, "resource_identity").unwrap_or("<none>")
    ));
    refs
}

fn construct_graph_port_profile_refs(port: &Value) -> Vec<String> {
    let port_id = json_str(port, "port_id").unwrap_or("unknown");
    let mut refs = vec![port_id.to_owned()];
    for field in [
        "owner_node_id",
        "direction",
        "kind",
        "type",
        "phase",
        "contract_version",
        "cardinality",
    ] {
        refs.extend(construct_graph_optional_labeled_ref(
            port_id,
            field,
            json_str(port, field),
        ));
    }
    refs.push(format!(
        "{port_id}#resource_identity:{}",
        json_str(port, "resource_identity").unwrap_or("<none>")
    ));
    refs
}

fn construct_graph_optional_labeled_ref(
    owner: &str,
    label: &str,
    value: Option<&str>,
) -> Vec<String> {
    value
        .map(|value| vec![format!("{owner}#{label}:{value}")])
        .unwrap_or_default()
}

fn construct_graph_node_profile_refs(node: &Value) -> Vec<String> {
    construct_graph_node_string_refs(
        node,
        &[
            "node_id",
            "construct_id",
            "construct_family",
            "lowering_class",
            "lifecycle_profile",
            "owner",
            "lowering_output_kind",
        ],
    )
}

fn construct_graph_node_interface_refs(node: &Value) -> Vec<String> {
    let mut refs = construct_graph_node_string_refs(node, &["node_id"]);
    refs.extend(construct_graph_string_array(node, "required_ports"));
    refs.extend(construct_graph_string_array(node, "produced_ports"));
    for key in [
        "declared_required_interfaces",
        "declared_provided_interfaces",
    ] {
        refs.extend(construct_graph_interface_refs(node, key));
    }
    refs
}

fn construct_graph_node_capability_refs(node: &Value) -> Vec<String> {
    let mut refs = construct_graph_node_string_refs(node, &["node_id"]);
    refs.extend(construct_graph_string_array(node, "required_capabilities"));
    refs.extend(construct_graph_string_array(
        node,
        "lowered_effect_capabilities",
    ));
    refs
}

fn construct_graph_node_output_refs(node: &Value) -> Vec<String> {
    let mut refs = construct_graph_node_string_refs(node, &["node_id", "lowering_output_kind"]);
    refs.extend(construct_graph_string_array(
        node,
        "allowed_core_object_kinds",
    ));
    refs.extend(construct_graph_string_array(
        node,
        "allowed_runtime_entrypoints",
    ));
    refs
}

fn construct_graph_node_string_refs(node: &Value, keys: &[&str]) -> Vec<String> {
    keys.iter()
        .filter_map(|key| json_str(node, key).map(str::to_owned))
        .collect()
}

fn construct_graph_interface_refs(node: &Value, key: &str) -> Vec<String> {
    node.get(key)
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .flat_map(|interface| {
            ["kind", "name", "type", "phase", "cardinality"]
                .into_iter()
                .filter_map(|field| json_str(interface, field).map(str::to_owned))
        })
        .collect()
}

fn construct_graph_has_error_diagnostics(graph: &Value) -> bool {
    graph
        .get("diagnostics")
        .and_then(Value::as_array)
        .is_some_and(|diagnostics| {
            diagnostics.iter().any(|diagnostic| {
                diagnostic.get("severity").and_then(Value::as_str) == Some("error")
            })
        })
}

fn construct_graph_error_diagnostics(graph: &Value) -> Vec<Value> {
    graph
        .get("diagnostics")
        .and_then(Value::as_array)
        .map(|diagnostics| {
            diagnostics
                .iter()
                .filter(|diagnostic| {
                    diagnostic.get("severity").and_then(Value::as_str) == Some("error")
                })
                .cloned()
                .collect()
        })
        .unwrap_or_default()
}

fn construct_graph_fact(
    predicate: impl Into<String>,
    owner_subsystem: impl Into<String>,
    input_refs: Vec<String>,
    diagnostic_span: Value,
) -> Value {
    json!({
        "predicate": predicate.into(),
        "owner_subsystem": owner_subsystem.into(),
        "input_refs": canonical_input_refs(input_refs),
        "diagnostic_span": diagnostic_span,
    })
}

fn canonical_input_refs(input_refs: Vec<String>) -> Vec<String> {
    input_refs
        .into_iter()
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect()
}

fn construct_graph_diagnostic(
    code: impl Into<String>,
    message: impl Into<String>,
    refs: Vec<(&str, Vec<String>)>,
    source_span: Value,
) -> Value {
    let mut refs_json = serde_json::Map::new();
    for (key, values) in refs {
        refs_json
            .entry(key.to_owned())
            .and_modify(|existing: &mut Value| {
                if let Some(existing_values) = existing.as_array_mut() {
                    existing_values.extend(values.iter().cloned().map(Value::String));
                }
            })
            .or_insert_with(|| {
                Value::Array(values.into_iter().map(Value::String).collect::<Vec<_>>())
            });
    }
    json!({
        "code": code.into(),
        "severity": "error",
        "refs": Value::Object(refs_json),
        "source_span": source_span,
        "message": message.into(),
    })
}

fn construct_graph_string_array(value: &Value, key: &str) -> Vec<String> {
    value
        .get(key)
        .and_then(Value::as_array)
        .map(|values| {
            values
                .iter()
                .filter_map(Value::as_str)
                .map(str::to_owned)
                .collect()
        })
        .unwrap_or_default()
}

fn construct_graph_phase_compatible(required: Option<&str>, provided: Option<&str>) -> bool {
    match (required, provided) {
        (Some("both"), Some("both")) => true,
        (Some("both"), _) => false,
        (Some(required), Some("both")) => matches!(required, "compile" | "runtime"),
        (Some(required), Some(provided)) => required == provided,
        _ => false,
    }
}

fn construct_graph_edge_ref(edge: &Value) -> String {
    construct_graph_edge_ref_from_parts(
        json_str(edge, "required_port_id").unwrap_or("unknown"),
        json_str(edge, "provided_port_id").unwrap_or("unknown"),
    )
}

fn construct_graph_edge_ref_from_parts(required_port_id: &str, provided_port_id: &str) -> String {
    format!("{required_port_id}->{provided_port_id}")
}

fn construct_graph_span_from(value: &Value) -> Value {
    value
        .get("source_span")
        .cloned()
        .unwrap_or_else(construct_graph_empty_span)
}

fn validate_artifact_span_value(span: &Value) -> Result<(), String> {
    let Some(object) = span.as_object() else {
        return Err("span must be an object".to_owned());
    };

    for field in ["path", "start", "end"] {
        if !object.contains_key(field) {
            return Err(format!("missing `{field}`"));
        }
    }
    for field in object.keys() {
        if !["path", "start", "end", "construct"].contains(&field.as_str()) {
            return Err(format!("unknown field `{field}`"));
        }
    }

    for field in ["path", "construct"] {
        if let Some(value) = object.get(field) {
            if !(value.is_null() || value.is_string()) {
                return Err(format!("`{field}` must be a string or null"));
            }
        }
    }

    let start = object
        .get("start")
        .and_then(Value::as_u64)
        .ok_or_else(|| "`start` must be a nonnegative integer".to_owned())?;
    let end = object
        .get("end")
        .and_then(Value::as_u64)
        .ok_or_else(|| "`end` must be a nonnegative integer".to_owned())?;
    if end < start {
        return Err("`end` must be greater than or equal to `start`".to_owned());
    }

    Ok(())
}

fn validate_artifact_string_ref_set_field(value: &Value, field: &str) -> Result<(), String> {
    let Some(items) = value.get(field) else {
        return Err(format!("missing `{field}`"));
    };
    let Some(items) = items.as_array() else {
        return Err(format!("`{field}` must be an array"));
    };
    let mut seen = BTreeSet::new();
    for item in items {
        let Some(item) = item.as_str().filter(|item| !item.is_empty()) else {
            return Err(format!("`{field}` must contain only non-empty strings"));
        };
        if !seen.insert(item) {
            return Err(format!("`{field}` contains duplicate ref `{item}`"));
        }
    }
    Ok(())
}

fn validate_artifact_diagnostic_metadata(
    diagnostic: &Value,
    unique_ref_values: bool,
) -> Result<(), String> {
    let Some(object) = diagnostic.as_object() else {
        return Err("diagnostic must be an object".to_owned());
    };

    if let Some(code) = object.get("code") {
        if code.as_str().is_none_or(|value| value.is_empty()) {
            return Err("`code` must be a non-empty string".to_owned());
        }
    }

    if let Some(severity) = object.get("severity") {
        if severity.as_str().and_then(Severity::from_wire).is_none() {
            return Err("`severity` must be `error`, `warning`, `info`, or `hint`".to_owned());
        }
    }

    let Some(refs) = object.get("refs") else {
        return Ok(());
    };
    let Some(refs) = refs.as_object() else {
        return Err("`refs` must be an object".to_owned());
    };
    for (key, values) in refs {
        validate_artifact_string_ref_array_value(
            values,
            &format!("`refs.{key}`"),
            unique_ref_values,
        )?;
    }

    Ok(())
}

fn validate_artifact_derived_fact_metadata(fact: &Value) -> Result<(), String> {
    let Some(object) = fact.as_object() else {
        return Err("derived fact must be an object".to_owned());
    };

    for field in ["predicate", "owner_subsystem"] {
        if let Some(value) = object.get(field) {
            if value.as_str().is_none_or(|value| value.is_empty()) {
                return Err(format!("`{field}` must be a non-empty string"));
            }
        }
    }

    Ok(())
}

fn duplicate_artifact_derived_fact_predicates(facts: &[Value]) -> Vec<String> {
    let mut seen = BTreeSet::new();
    let mut duplicates = Vec::new();
    for (index, fact) in facts.iter().enumerate() {
        if seen.insert(canonical_json(fact)) {
            continue;
        }
        let predicate = fact
            .get("predicate")
            .and_then(Value::as_str)
            .map(str::to_owned)
            .unwrap_or_else(|| format!("derived_facts[{index}]"));
        duplicates.push(predicate);
    }
    duplicates.sort();
    duplicates.dedup();
    duplicates
}

fn validate_artifact_string_ref_array_value(
    values: &Value,
    label: &str,
    require_unique: bool,
) -> Result<(), String> {
    let Some(items) = values.as_array() else {
        return Err(format!("{label} must be an array"));
    };
    let mut seen = BTreeSet::new();
    for item in items {
        let Some(item) = item.as_str().filter(|item| !item.is_empty()) else {
            return Err(format!("{label} must contain only non-empty strings"));
        };
        if require_unique && !seen.insert(item) {
            return Err(format!("{label} contains duplicate ref `{item}`"));
        }
    }
    Ok(())
}

fn construct_graph_empty_span() -> Value {
    construct_graph_span(None, SourceSpan { start: 0, end: 0 }, None)
}

fn json_str<'a>(value: &'a Value, key: &str) -> Option<&'a str> {
    value.get(key).and_then(Value::as_str)
}

fn package_library_ids(registry: &ContractRegistry) -> BTreeSet<String> {
    registry
        .libraries
        .iter()
        .filter(|library| !library.standard && library.version != "unlocked")
        .map(|library| library.id.clone())
        .collect()
}

fn package_capability_contracts_for<'a>(
    registry: &'a ContractRegistry,
    package_library_ids: &'a BTreeSet<String>,
    capability: &'a str,
) -> impl Iterator<Item = &'a EffectContract> {
    registry.effect_contracts.iter().filter(move |contract| {
        contract.id == capability
            && contract.effect_kind == "capability.call"
            && package_library_ids.contains(&contract.library_id)
    })
}

fn construct_graph_span(path: Option<&str>, span: SourceSpan, construct: Option<&str>) -> Value {
    json!({
        "path": path.map(display_path),
        "start": span.start,
        "end": span.end,
        "construct": construct,
    })
}

fn construct_contract_node_id(contract: &EffectContract) -> String {
    format!(
        "contract:{}:{}:{}",
        contract.library_id, contract.id, contract.version
    )
}

fn construct_contract_capability_port_id(contract: &EffectContract, capability: &str) -> String {
    format!(
        "{}:produces:capability:{}",
        construct_contract_node_id(contract),
        capability
    )
}

fn construct_effect_node_id(rule: &IrRule, effect: &IrEffectNode) -> String {
    format!("effect:{}:{}", rule.name, effect.id)
}

fn construct_source_node_id(source_name: &str) -> String {
    format!("{SOURCE_DECLARATION_NODE_PREFIX}{source_name}")
}

/// The signal a `source` block admits, looked up by its construct-graph node id.
/// Used by the lowered-IR handoff to point the source's core object at the
/// emitted signal rather than the source's own name.
fn source_emitted_signal_by_node_id<'a>(ir: &'a IrProgram, node_id: &str) -> Option<&'a str> {
    let name = node_id.strip_prefix(SOURCE_DECLARATION_NODE_PREFIX)?;
    ir.sources
        .iter()
        .find(|source| source.name == name)
        .map(|source| source.emit_signal.as_str())
}

fn construct_assertion_id(assertion: &whipplescript_parser::IrAssertion) -> String {
    stable_hash_hex(assertion.expr.source.as_str())
}

fn construct_assertion_node_id(assertion_id: &str) -> String {
    format!("{ASSERTION_NODE_PREFIX}{assertion_id}")
}

fn construct_assertion_id_from_node_id(node_id: &str) -> Option<&str> {
    node_id.strip_prefix(ASSERTION_NODE_PREFIX)
}

fn construct_rule_ref(rule: &IrRule, when_index: usize) -> String {
    format!("{}:when{when_index}", rule.name)
}

fn construct_rule_node_id(rule: &IrRule, when_index: usize) -> String {
    format!("{RULE_NODE_PREFIX}{}", construct_rule_ref(rule, when_index))
}

fn construct_rule_entrypoint_refs_by_node_id(
    ir: &IrProgram,
) -> BTreeMap<String, (String, String, String)> {
    let mut refs = BTreeMap::new();
    for rule in &ir.rules {
        for (when_index, when) in rule.whens.iter().enumerate() {
            refs.insert(
                construct_rule_node_id(rule, when_index),
                (
                    rule.name.clone(),
                    rule_fact_key(&rule.name, when_index, &when.pattern),
                    rule_graph_key(&rule.name, when_index),
                ),
            );
        }
    }
    refs
}

fn construct_rule_fact_output_refs_by_node_id(ir: &IrProgram) -> BTreeMap<String, Vec<String>> {
    let mut refs = BTreeMap::new();
    for rule in &ir.rules {
        for when_index in 0..rule.whens.len() {
            refs.insert(
                construct_rule_node_id(rule, when_index),
                rule.metadata.fact_writes.clone(),
            );
        }
    }
    refs
}

fn construct_fact_schema_ref(fact_ref: &str) -> &str {
    fact_ref.strip_prefix("schema:").unwrap_or(fact_ref)
}

fn construct_rule_projection_read_ref(rule: &IrRule, read_index: usize) -> String {
    format!("rule:{}:read{read_index}", rule.name)
}

fn construct_assertion_projection_read_ref(assertion_id: &str, read_index: usize) -> String {
    format!("assertion:{assertion_id}:read{read_index}")
}

fn construct_projection_read_node_id(read_ref: &str) -> String {
    format!("{PROJECTION_READ_NODE_PREFIX}{read_ref}")
}

fn projection_read_kind(read: &IrProjectionRead) -> &'static str {
    match read.kind {
        QueryKind::Fact => "fact",
        QueryKind::Effect => "effect",
    }
}

fn projection_read_source(read: &IrProjectionRead) -> String {
    let prefix = match read.kind {
        QueryKind::Fact => read.head.clone(),
        QueryKind::Effect => format!("effect {}", read.head),
    };
    match &read.guard {
        Some(guard) => format!("{prefix} where {guard}"),
        None => prefix,
    }
}

fn construct_effect_dependency_ref(rule: &IrRule, dependency: &IrEffectDependency) -> String {
    format!(
        "dependency:{}:{}:{}:{}",
        rule.name,
        dependency.upstream,
        dependency_predicate_str(&dependency.predicate),
        dependency.downstream
    )
}

fn construct_effect_capability_port_id(node_id: &str, capability: &str) -> String {
    format!("{node_id}:requires:capability:{capability}")
}

fn construct_effect_handle_port_id(node_id: &str) -> String {
    format!("{node_id}:produces:effect_handle")
}

fn package_lock_digest(package_lock: Option<&LoadedPackageLock>) -> String {
    let Some(package_lock) = package_lock else {
        return "0".repeat(64);
    };
    let base_dir = package_lock
        .path
        .parent()
        .map(Path::to_path_buf)
        .unwrap_or_else(|| PathBuf::from("."));
    package_lock_digest_for_manifests(&package_lock.manifests, &base_dir)
}

fn package_lock_digest_for_manifests(manifests: &[PackageManifest], base_dir: &Path) -> String {
    let lock_json = package_lock_json(manifests, base_dir);
    sha256_hex(canonical_json(&lock_json).as_bytes())
}

fn source_metadata_targets_json(ir: &IrProgram) -> Value {
    let mut targets = serde_json::Map::new();
    for tag in &ir.source_tags {
        let key = source_metadata_target_key(&tag.target_kind, &tag.target);
        let entry = source_metadata_target_entry(&mut targets, &key, &tag.target_kind, &tag.target);
        if let Some(tags) = entry.get_mut("tags").and_then(Value::as_array_mut) {
            tags.push(Value::String(tag.name.clone()));
        }
    }
    for description in &ir.source_descriptions {
        let key = source_metadata_target_key(&description.target_kind, &description.target);
        let entry = source_metadata_target_entry(
            &mut targets,
            &key,
            &description.target_kind,
            &description.target,
        );
        entry.insert(
            "description".to_owned(),
            Value::String(description.value.clone()),
        );
    }
    Value::Object(targets)
}

fn source_metadata_target_entry<'a>(
    targets: &'a mut serde_json::Map<String, Value>,
    key: &str,
    target_kind: &str,
    target: &str,
) -> &'a mut serde_json::Map<String, Value> {
    let value = targets.entry(key.to_owned()).or_insert_with(|| {
        json!({
            "target_kind": target_kind,
            "target": target,
            "tags": [],
        })
    });
    value.as_object_mut().expect("metadata target is object")
}

fn source_metadata_target_key(target_kind: &str, target: &str) -> String {
    format!("{target_kind}:{target}")
}

fn parser_diagnostic_to_json(diagnostic: &Diagnostic) -> Value {
    let mut value = json!({
        "message": diagnostic.message,
        "suggestion": diagnostic.suggestion,
        "source_span": source_span_to_json(diagnostic.span),
    });
    // Related information (secondary spans) is omitted when empty so existing
    // diagnostic shapes are unchanged (spec/error-handling.md "Spans And Labels").
    if !diagnostic.related.is_empty() {
        let related: Vec<Value> = diagnostic
            .related
            .iter()
            .map(|info| {
                json!({
                    "message": info.message,
                    "source_span": source_span_to_json(info.span),
                })
            })
            .collect();
        value
            .as_object_mut()
            .expect("diagnostic json is object")
            .insert("related".to_owned(), Value::Array(related));
    }
    value
}

fn source_span_to_json(span: SourceSpan) -> Value {
    json!({
        "start": span.start,
        "end": span.end,
    })
}

/// `whip fmt [--check] <workflow.whip>...` — format WhippleScript source.
///
/// v0 limitation: the formatter rebuilds source from the AST, which does not yet
/// carry comments, so formatting a file that contains comments would drop them.
/// To stay strictly non-destructive, `fmt` refuses (does not write) any file that
/// contains comments and reports it as an error. Comment-preserving formatting is
/// the tracked follow-up (Stage P6, the comment-attachment design); the lexer
/// already captures comments via `lex_comments`, which this guard uses.
fn fmt(options: &CliOptions) -> ExitCode {
    let mut check_only = false;
    let mut paths = Vec::new();
    for arg in &options.args {
        match arg.as_str() {
            "--check" => check_only = true,
            other => paths.push(other.to_owned()),
        }
    }
    if paths.is_empty() {
        eprintln!("usage: whip fmt [--check] <workflow.whip>...");
        return ExitCode::from(2);
    }

    let mut failed = false;
    let mut needs_formatting = false;
    for path in &paths {
        let source = match fs::read_to_string(path) {
            Ok(source) => source,
            Err(error) => {
                eprintln!("failed to read `{path}`: {error}");
                failed = true;
                continue;
            }
        };

        // Top-level leading comments are preserved; a file whose comments cannot
        // be placed safely (trailing inline, or inside an item body) is refused
        // rather than having its comments dropped — strictly non-destructive.
        let formatted = if lex_comments(&source).is_empty() {
            match format_program(&source) {
                FormatOutput {
                    formatted: Some(formatted),
                    ..
                } => formatted,
                FormatOutput { diagnostics, .. } => {
                    for diagnostic in &diagnostics {
                        eprintln!("{path}: {}", diagnostic.message);
                    }
                    failed = true;
                    continue;
                }
            }
        } else {
            match format_program_preserving_comments(&source) {
                Some(formatted) => formatted,
                None => {
                    eprintln!(
                        "{path}: whip fmt cannot place a comment in this file (e.g. one trailing a declaration's opening-brace line, with no field on that line to attach to); skipped to avoid data loss"
                    );
                    failed = true;
                    continue;
                }
            }
        };

        if formatted == source {
            continue;
        }

        // Idempotency self-check: a second pass must not change the output. Some
        // body/nesting shapes are not yet idempotent; rather than write output a
        // second `whip fmt` would change (or that would mutate `"""..."""` string
        // content), refuse outright — strictly non-destructive, the original file
        // is left untouched. Re-format through the comment-preserving path so a
        // file whose comments we just preserved is not seen as "changed" merely
        // because the plain formatter would drop them. See memory
        // `project-fmt-nested-block-indent-bug`.
        let stable = format_program_preserving_comments(&formatted).as_deref() == Some(&*formatted);
        if !stable {
            eprintln!(
                "{path}: whip fmt cannot format this file idempotently yet (multi-line strings or nested record/complete blocks); skipped to avoid drift/corruption"
            );
            failed = true;
            continue;
        }

        if check_only {
            eprintln!("{path}: not formatted");
            needs_formatting = true;
        } else if let Err(error) = fs::write(path, &formatted) {
            eprintln!("failed to write `{path}`: {error}");
            failed = true;
        } else {
            println!("formatted {path}");
        }
    }

    if failed || (check_only && needs_formatting) {
        ExitCode::from(1)
    } else {
        ExitCode::SUCCESS
    }
}

/// `whip test [--json] <workflow.whip>` — run deterministic test scenarios
/// (spec/workflow-testing.md). v0 driver: executes scenarios that use only the
/// supported clauses (`given signal`, `run`, `expect workflow completed|failed`,
/// `expect rule …`); a scenario using any other clause (`stub`, `given
/// fact|input|clock`, projection/effect/diagnostic/`no` expects) is reported as an
/// **error**, never a pass — the harness never silently skips an assertion.
/// Parsed `whip test` flags (selection + reporting), separated from the global
/// `CliOptions` because they only apply to this command.
struct TestArgs {
    sources: Vec<String>,
    include: Vec<String>,
    exclude: Vec<String>,
    list: bool,
    pass_if_no_tests: bool,
}

/// Parse `whip test`'s command-specific args. `--store`/`--json`/`--input` are
/// already consumed by `CliOptions`, so the remaining tokens are the source
/// paths and the selection flags. Returns `Err` on a flag missing its value.
fn parse_test_args(args: &[String]) -> Result<TestArgs, String> {
    let mut parsed = TestArgs {
        sources: Vec::new(),
        include: Vec::new(),
        exclude: Vec::new(),
        list: false,
        pass_if_no_tests: false,
    };
    let mut iter = args.iter();
    while let Some(arg) = iter.next() {
        match arg.as_str() {
            "-i" | "--include" => {
                let Some(pattern) = iter.next() else {
                    return Err(format!("expected a pattern after `{arg}`"));
                };
                parsed.include.push(pattern.clone());
            }
            "-x" | "--exclude" => {
                let Some(pattern) = iter.next() else {
                    return Err(format!("expected a pattern after `{arg}`"));
                };
                parsed.exclude.push(pattern.clone());
            }
            "--list" => parsed.list = true,
            "--pass-if-no-tests" => parsed.pass_if_no_tests = true,
            other if other.starts_with('-') => {
                return Err(format!("unknown flag `{other}`"));
            }
            other => parsed.sources.push(other.to_owned()),
        }
    }
    Ok(parsed)
}

/// Full-string wildcard match where `*` matches any (possibly empty) run of
/// characters; every other character is literal. The classic backtracking
/// two-pointer matcher (`workflow-testing.md` defines `*` as the only wildcard).
fn glob_match(pattern: &str, text: &str) -> bool {
    let p: Vec<char> = pattern.chars().collect();
    let t: Vec<char> = text.chars().collect();
    let (mut pi, mut ti) = (0usize, 0usize);
    let (mut star, mut mark) = (None, 0usize);
    while ti < t.len() {
        if pi < p.len() && (p[pi] == t[ti]) {
            pi += 1;
            ti += 1;
        } else if pi < p.len() && p[pi] == '*' {
            star = Some(pi);
            mark = ti;
            pi += 1;
        } else if let Some(s) = star {
            pi = s + 1;
            mark += 1;
            ti = mark;
        } else {
            return false;
        }
    }
    while pi < p.len() && p[pi] == '*' {
        pi += 1;
    }
    pi == p.len()
}

/// Whether a scenario id matches a selection pattern. A pattern with `::`
/// splits into `<workflow>::<test>` (an empty side matches anything, so
/// `WorkflowName::` selects a whole workflow and `::test` selects by test name
/// across workflows); a pattern without `::` matches the test name alone.
fn test_id_matches(workflow: &str, name: &str, pattern: &str) -> bool {
    match pattern.split_once("::") {
        Some((wf_pat, test_pat)) => {
            (wf_pat.is_empty() || glob_match(wf_pat, workflow))
                && (test_pat.is_empty() || glob_match(test_pat, name))
        }
        None => glob_match(pattern, name),
    }
}

/// Recursively collect `.whip` files under `dir` (sorted for deterministic
/// ordering), skipping hidden entries and the `target` build directory.
fn collect_whip_files(dir: &Path, out: &mut Vec<String>) -> std::io::Result<()> {
    let mut entries: Vec<_> = std::fs::read_dir(dir)?.collect::<std::io::Result<Vec<_>>>()?;
    entries.sort_by_key(std::fs::DirEntry::file_name);
    for entry in entries {
        let name = entry.file_name();
        let name = name.to_string_lossy();
        if name.starts_with('.') || name == "target" {
            continue;
        }
        let path = entry.path();
        if path.is_dir() {
            collect_whip_files(&path, out)?;
        } else if path.extension().and_then(|ext| ext.to_str()) == Some("whip") {
            if let Some(text) = path.to_str() {
                out.push(text.to_owned());
            }
        }
    }
    Ok(())
}

/// Expand each `whip test` positional into concrete `.whip` files: a directory
/// is discovered recursively (`collect_whip_files`); a file passes through
/// verbatim (its existence/compilation is checked by the caller).
fn expand_test_sources(sources: &[String]) -> Result<Vec<String>, String> {
    let mut expanded = Vec::new();
    for source in sources {
        let path = Path::new(source);
        if path.is_dir() {
            collect_whip_files(path, &mut expanded)
                .map_err(|error| format!("{source}: failed to read directory: {error}"))?;
        } else {
            expanded.push(source.clone());
        }
    }
    Ok(expanded)
}

/// The canonical projection of an instance for replay comparison: terminal
/// status plus its active facts and effects, with volatile fields (event/fact/
/// effect ids, timestamps, revision epochs) excluded and every nested JSON value
/// re-parsed so `serde_json`'s sorted-key serialization makes the form stable.
/// Arrays are sorted by their canonical text so order is deterministic. Equality
/// is byte-equality of the serialized result (workflow-testing.md "replay
/// equality").
fn canonical_projection(store: &SqliteStore, instance_id: &str) -> Result<Value, StoreError> {
    let status = store
        .get_instance(instance_id)?
        .map(|instance| instance.status)
        .unwrap_or_default();
    let mut facts: Vec<Value> = store
        .list_facts(instance_id)?
        .into_iter()
        .map(|fact| {
            json!({
                "name": fact.name,
                "key": fact.key,
                "value": json_from_str(&fact.value_json),
                "provenance": fact.provenance_class,
            })
        })
        .collect();
    facts.sort_by_key(|value| value.to_string());
    let mut effects: Vec<Value> = store
        .list_effects(instance_id)?
        .into_iter()
        .map(|effect| {
            json!({
                "kind": effect.kind,
                "target": effect.target,
                "input": json_from_str(&effect.input_json),
                "status": effect.status,
                "created_by_rule": effect.created_by_rule,
                "profile": effect.profile,
                "policy_block_reason": effect.policy_block_reason,
                "policy_block": effect_policy_block_json(
                    &effect.status,
                    effect.policy_block_reason.as_deref(),
                    effect.policy_block_category.as_deref(),
                ),
                "cancel_requested": effect.cancel_requested,
            })
        })
        .collect();
    effects.sort_by_key(|value| value.to_string());
    Ok(json!({
        "status": status,
        "facts": facts,
        "effects": effects,
    }))
}

/// `whip test replay <instance-id>`: replay an instance's recorded event log
/// into a throwaway copy of the store and verify the reconstructed projections
/// are byte-identical to the live-built ones. This is the executable form of the
/// replay-equality invariant (workflow-testing.md) — a regression check that
/// event-replay derivation matches incremental stepping. The user's store is
/// never mutated (the rebuild runs on a temp copy). Exit 0 = equal, 1 = diverged,
/// 2 = setup error (no instance / unreadable store).
///
/// Note: this operates on a `--store` instance rather than a standalone
/// trace/event-log file + `--workflow` (the spec's eventual form); a portable
/// file-based trace format is a future extension.
fn test_replay_command(options: &CliOptions, args: &[String]) -> ExitCode {
    let Some(instance_id) = args.iter().find(|arg| !arg.starts_with('-')).cloned() else {
        eprintln!("usage: whip [--json] test replay <instance-id>");
        return ExitCode::from(2);
    };

    let original_store = match open_store(&options.store_path) {
        Ok(store) => store,
        Err(message) => {
            eprintln!("{message}");
            return ExitCode::from(2);
        }
    };
    match original_store.get_instance(&instance_id) {
        Ok(Some(_)) => {}
        Ok(None) => {
            eprintln!("instance `{instance_id}` not found in store");
            return ExitCode::from(2);
        }
        Err(error) => {
            eprintln!("{}", store_error(error));
            return ExitCode::from(2);
        }
    }
    let recorded = match canonical_projection(&original_store, &instance_id) {
        Ok(projection) => projection,
        Err(error) => {
            eprintln!("{}", store_error(error));
            return ExitCode::from(2);
        }
    };
    drop(original_store);

    // Rebuild on a throwaway copy so the user's store is never mutated.
    let temp = std::env::temp_dir().join(format!("whip-replay-{instance_id}.sqlite"));
    if let Err(error) = fs::copy(&options.store_path, &temp) {
        eprintln!("failed to copy store for replay: {error}");
        return ExitCode::from(2);
    }
    let replayed = (|| -> Result<Value, String> {
        let mut temp_store = open_store(&temp)?;
        temp_store
            .rebuild_projections(&instance_id)
            .map_err(store_error)?;
        canonical_projection(&temp_store, &instance_id).map_err(store_error)
    })();
    let _ = fs::remove_file(&temp);
    let replayed = match replayed {
        Ok(projection) => projection,
        Err(message) => {
            eprintln!("{message}");
            return ExitCode::from(2);
        }
    };

    let equal = serde_json::to_string(&recorded).ok() == serde_json::to_string(&replayed).ok();
    if options.json {
        let mut report = json!({
            "instance_id": instance_id,
            "replay": if equal { "equal" } else { "diverged" },
        });
        if !equal {
            report["recorded"] = recorded;
            report["replayed"] = replayed;
        }
        let _ = emit_json(report);
    } else if equal {
        println!("replay equal: `{instance_id}` re-projects identically from its event log");
    } else {
        println!(
            "replay DIVERGED: `{instance_id}` event-log re-projection differs from the recorded projection"
        );
    }
    if equal {
        ExitCode::SUCCESS
    } else {
        ExitCode::FAILURE
    }
}

fn test_command(options: &CliOptions) -> ExitCode {
    // `whip test replay <instance>` is a distinct subcommand (regression replay),
    // not a scenario run.
    if options.args.first().map(String::as_str) == Some("replay") {
        return test_replay_command(options, &options.args[1..]);
    }
    let test_args = match parse_test_args(&options.args) {
        Ok(parsed) => parsed,
        Err(message) => {
            eprintln!("{message}");
            eprintln!("usage: whip [--json] test <workflow.whip|dir>... [--list] [-i <pattern>]... [-x <pattern>]... [--pass-if-no-tests]");
            return ExitCode::from(2);
        }
    };
    if test_args.sources.is_empty() {
        eprintln!("usage: whip [--json] test <workflow.whip|dir>... [--list] [-i <pattern>]... [-x <pattern>]... [--pass-if-no-tests]");
        return ExitCode::from(2);
    }
    // A directory positional is discovered into its `.whip` files; explicit
    // files pass through. All discovered files must compile (honest by
    // construction — a malformed source is exit 2, never a silent skip).
    let sources = match expand_test_sources(&test_args.sources) {
        Ok(sources) => sources,
        Err(message) => {
            eprintln!("{message}");
            return ExitCode::from(2);
        }
    };
    // Compile every source up front. A compile error in any of them is a setup
    // problem (exit 2), distinct from a test that ran and failed an expectation
    // (exit 1), so we stop before running anything.
    let mut compiled: Vec<(String, String, IrProgram)> = Vec::new();
    for path in &sources {
        match compile_source_path_with_root(path, None) {
            Ok((source, ir)) => compiled.push((path.clone(), source, ir)),
            Err(error) => {
                let _ = report_compile_failure(path, error);
                return ExitCode::from(2);
            }
        }
    }

    let scenario_id = |ir: &IrProgram, test: &IrTest| {
        let workflow = test.workflow.as_deref().unwrap_or(ir.workflow.as_str());
        format!("{workflow}::{}", test.name)
    };

    // Selection across all sources: include patterns (any-match; empty = all)
    // minus exclude patterns (exclude overrides include), against
    // `<workflow>::<name>` ids. Each entry carries the path + source it came from
    // so a scenario is run against its own program text.
    let include = &test_args.include;
    let exclude = &test_args.exclude;
    let selected: Vec<(&str, &str, &IrProgram, &IrTest)> = compiled
        .iter()
        .flat_map(|(path, source, ir)| {
            ir.tests.iter().filter_map(move |test| {
                let workflow = test.workflow.as_deref().unwrap_or(ir.workflow.as_str());
                let included = include.is_empty()
                    || include
                        .iter()
                        .any(|pattern| test_id_matches(workflow, &test.name, pattern));
                let excluded = exclude
                    .iter()
                    .any(|pattern| test_id_matches(workflow, &test.name, pattern));
                (included && !excluded).then_some((path.as_str(), source.as_str(), ir, test))
            })
        })
        .collect();

    // `--list` enumerates the selected ids without running them (an authoring /
    // CI-introspection aid), and is always a success.
    if test_args.list {
        if options.json {
            let ids: Vec<Value> = selected
                .iter()
                .map(|(_, _, ir, test)| Value::String(scenario_id(ir, test)))
                .collect();
            let _ = emit_json(json!({ "tests": ids }));
        } else {
            for (_, _, ir, test) in &selected {
                println!("{}", scenario_id(ir, test));
            }
        }
        return ExitCode::SUCCESS;
    }

    let mut scenarios = Vec::new();
    let (mut passed, mut failed, mut invalid) = (0usize, 0usize, 0usize);
    for (path, source, ir, test) in &selected {
        let report = run_test_scenario(test, source, ir, path);
        match report.status {
            "passed" => passed += 1,
            "failed" => failed += 1,
            _ => invalid += 1,
        }
        if !options.json {
            let mark = match report.status {
                "passed" => "ok  ",
                "failed" => "FAIL",
                _ => "INVALID",
            };
            println!("{mark} {}", scenario_id(ir, test));
            for message in &report.messages {
                println!("       {message}");
            }
        }
        scenarios.push(report.value);
    }

    // Report-level status: `invalid` (a scenario could not run faithfully)
    // dominates `failed` (a scenario ran but an expectation did not hold), which
    // in turn dominates `passed`. An empty selection is `no_tests`, not a pass.
    let overall = if selected.is_empty() {
        "no_tests"
    } else if invalid > 0 {
        "invalid"
    } else if failed > 0 {
        "failed"
    } else {
        "passed"
    };
    if options.json {
        let _ = emit_json(json!({
            "schema": "whipplescript.test_report.v0",
            "status": overall,
            "summary": {
                "selected": selected.len(),
                "passed": passed,
                "failed": failed,
                "invalid": invalid,
                "skipped": 0,
            },
            "scenarios": scenarios,
        }));
    } else {
        println!("{passed} passed, {failed} failed, {invalid} invalid");
    }

    // Exit codes (`workflow-testing.md`): 0 passed · 1 failures · 2 setup
    // invalid (compile error above, or an unrunnable scenario) · 4 nothing
    // selected, unless `--pass-if-no-tests` downgrades that to success.
    if selected.is_empty() {
        if test_args.pass_if_no_tests {
            ExitCode::SUCCESS
        } else {
            ExitCode::from(4)
        }
    } else if invalid > 0 {
        ExitCode::from(2)
    } else if failed > 0 {
        ExitCode::from(1)
    } else {
        ExitCode::SUCCESS
    }
}

/// One scenario's machine-readable result (a `whipplescript.test_report.v0`
/// scenario object) plus the human-readable failure/error lines for non-JSON
/// output.
struct ScenarioReport {
    /// Summary bucket: `"passed"`, `"failed"`, or `"invalid"`.
    status: &'static str,
    value: Value,
    messages: Vec<String>,
}

/// The post-run world a scenario's `expect` clauses are judged against.
struct ScenarioWorld {
    instance_status: String,
    events: Vec<EventView>,
    facts: Vec<FactView>,
    effects: Vec<EffectView>,
    diagnostics: Vec<DiagnosticView>,
}

/// Build a terminal `invalid` scenario object: the harness could not run the
/// scenario faithfully (unsupported clause, conflicting stubs, or a runtime
/// error), so no `expect` clause is judged and the reason rides in
/// `diagnostics` — never a silent skip dressed up as a pass.
fn invalid_scenario(
    name: &str,
    workflow: &str,
    span: &Value,
    steps: &[Value],
    code: &str,
    message: String,
) -> ScenarioReport {
    let value = json!({
        "id": format!("{workflow}::{name}"),
        "status": "invalid",
        "workflow": workflow,
        "source_span": span,
        "steps": steps,
        "expectations": [],
        "diagnostics": [{
            "code": code,
            "severity": "error",
            "message": message.clone(),
        }],
        "dev_report_ref": null,
    });
    ScenarioReport {
        status: "invalid",
        value,
        messages: vec![message],
    }
}

/// Human-readable description of a `given`/`stub`/`run` step, or `None` for an
/// `expect` clause (which is reported under `expectations`, not `steps`).
fn describe_step(clause: &TestClause) -> Option<Value> {
    let (kind, description) = match clause {
        TestClause::Given(given) => (
            "given",
            match given {
                GivenClause::Input { .. } => "given input".to_owned(),
                GivenClause::Fact { ty, .. } => format!("given fact {}", ty.name),
                GivenClause::Signal { name, .. } => format!("given signal {name}"),
                GivenClause::Clock { at, .. } => format!("given clock at {:?}", at.value),
                GivenClause::Tracker { tracker, .. } => format!("given tracker {tracker} issue"),
                GivenClause::File { store, path, .. } => {
                    format!("given file {store} at {:?}", path.value)
                }
            },
        ),
        TestClause::Stub(stub) => (
            "stub",
            format!("stub {} {}", stub.surface.join(" "), stub.outcome),
        ),
        TestClause::Run(run) => ("run", describe_run(&run.kind)),
        TestClause::Expect(_) => return None,
    };
    Some(json!({ "kind": kind, "description": description }))
}

fn describe_run(kind: &RunKind) -> String {
    match kind {
        RunKind::UntilIdle => "run until idle".to_owned(),
        RunKind::UntilWorkflowCompleted => "run until workflow completed".to_owned(),
        RunKind::UntilWorkflowFailed => "run until workflow failed".to_owned(),
        RunKind::ForSteps(steps) => format!("run for {steps} steps"),
    }
}

fn describe_expect(target: &ExpectTarget) -> String {
    match target {
        ExpectTarget::WorkflowCompleted => "workflow completed".to_owned(),
        ExpectTarget::WorkflowFailed { .. } => "workflow failed".to_owned(),
        ExpectTarget::Rule { name, status } => match status {
            RuleStatus::Fired => format!("rule {} fired", name.name),
            RuleStatus::DidNotFire => format!("rule {} did not fire", name.name),
            RuleStatus::FiredTimes(count) => format!("rule {} fired {count} times", name.name),
        },
        ExpectTarget::Effect { name, status } => {
            let verb = match status {
                TestEffectStatus::Requested => "requested",
                TestEffectStatus::Completed => "completed",
                TestEffectStatus::Failed => "failed",
            };
            format!("effect {name} {verb}")
        }
        ExpectTarget::NoEffect { name } => format!("no {name}"),
        ExpectTarget::Projection(query) => match &query.kind {
            ProjQueryKind::Exists => format!("{} exists", query.noun),
            ProjQueryKind::Where { predicate } => {
                format!("{} where {predicate}", query.noun)
            }
            ProjQueryKind::Count { predicate, count } => {
                format!("{} count where {predicate} is {count}", query.noun)
            }
        },
        // Unsupported targets are rejected before any `expect` is described.
        ExpectTarget::Diagnostic { code } => format!("diagnostic {code}"),
    }
}

fn run_test_scenario(test: &IrTest, source: &str, ir: &IrProgram, path: &str) -> ScenarioReport {
    let workflow = test.workflow.clone().unwrap_or_else(|| ir.workflow.clone());
    let steps: Vec<Value> = test.clauses.iter().filter_map(describe_step).collect();
    let span = json!({ "start": test.span.start, "end": test.span.end });

    for clause in &test.clauses {
        let unsupported = match clause {
            // `succeeds`/`fails` are simulatable by the fixture; `stub coerce <fn>
            // returns { … }` injects a typed coerce output. `times_out`/`cancels`
            // are NOT simulatable by the shell-command agent fixture, so rather
            // than silently completing those (a lie) the harness reports them
            // unsupported.
            TestClause::Stub(stub) => {
                let coerce_returns = stub.surface.first().map(String::as_str) == Some("coerce")
                    && stub.outcome == "returns";
                match stub.outcome.as_str() {
                    "succeeds" | "fails" => None,
                    _ if coerce_returns => None,
                    _ => Some("stub outcome other than succeeds/fails (times_out/cancels not simulatable; only `coerce … returns { … }` injects output)"),
                }
            }
            TestClause::Given(GivenClause::Signal { .. })
            | TestClause::Given(GivenClause::Input { .. })
            | TestClause::Given(GivenClause::Fact { .. })
            | TestClause::Given(GivenClause::Clock { .. })
            | TestClause::Given(GivenClause::Tracker { .. })
            | TestClause::Given(GivenClause::File { .. }) => None,
            TestClause::Run(_) => None,
            // Every `expect` target is now evaluated.
            TestClause::Expect(_) => None,
        };
        if let Some(unsupported) = unsupported {
            return invalid_scenario(
                &test.name,
                &workflow,
                &span,
                &steps,
                "test.unsupported_clause",
                format!(
                    "scenario uses a clause the v0 harness does not execute yet: {unsupported}"
                ),
            );
        }
    }
    // Per-agent stub outcomes are supported (e.g. one agent succeeds while
    // another fails), so mixed outcomes across `stub agent ...` clauses are no
    // longer rejected — `scenario_agent_outcomes` keys them by agent.

    let world = match execute_scenario(test, source, ir, path) {
        Ok(world) => world,
        Err(message) => {
            return invalid_scenario(
                &test.name,
                &workflow,
                &span,
                &steps,
                "test.harness_error",
                message,
            )
        }
    };

    let mut expectations = Vec::new();
    let mut diagnostics = Vec::new();
    let mut messages = Vec::new();
    let mut any_failed = false;
    for clause in &test.clauses {
        if let TestClause::Expect(expect) = clause {
            let description = describe_expect(&expect.target);
            match evaluate_expect_v0(
                &expect.target,
                &world.instance_status,
                &world.events,
                &world.facts,
                &world.effects,
                &world.diagnostics,
            ) {
                Ok(()) => expectations.push(json!({
                    "description": description,
                    "status": "passed",
                })),
                Err(message) => {
                    any_failed = true;
                    expectations.push(json!({
                        "description": description,
                        "status": "failed",
                        "diagnostic_code": "test.expectation_failed",
                    }));
                    diagnostics.push(json!({
                        "code": "test.expectation_failed",
                        "severity": "error",
                        "message": message,
                    }));
                    messages.push(message);
                }
            }
        }
    }
    let status = if any_failed { "failed" } else { "passed" };
    ScenarioReport {
        status,
        value: json!({
            "id": format!("{workflow}::{}", test.name),
            "status": status,
            "workflow": workflow,
            "source_span": span,
            "steps": steps,
            "expectations": expectations,
            "diagnostics": diagnostics,
            "dev_report_ref": null,
        }),
        messages,
    }
}

fn scenario_store_path(name: &str) -> PathBuf {
    let nanos = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|elapsed| elapsed.as_nanos())
        .unwrap_or(0);
    std::env::temp_dir().join(format!(
        "whip-test-{}-{nanos}-{}.sqlite",
        std::process::id(),
        stable_hash_hex(name)
    ))
}

/// Evaluate a `given` record's field list into a JSON object, running each field
/// value through the same expression kernel the runtime uses. Seeded world state
/// is therefore built exactly as real admission would build it — no separate
/// literal parser to drift.
fn eval_given_record(
    fields: &[TestField],
    context: &str,
) -> Result<serde_json::Map<String, Value>, String> {
    let mut object = serde_json::Map::new();
    for field in fields {
        let expr = parse_expression(&field.value)
            .map_err(|error| format!("{context} field `{}`: {error}", field.name.name))?;
        let empty_ir = empty_ir_program();
        let scope = EvalScope {
            context: None,
            facts: &[],
            effects: &[],
            ir: &empty_ir,
            projection: None,
            projection_schema: None,
        };
        match eval_expr_value(&expr, &scope) {
            EvalValue::Json(value) => {
                object.insert(field.name.name.clone(), value);
            }
            _ => {
                return Err(format!(
                    "{context} field `{}` did not evaluate to a value",
                    field.name.name
                ))
            }
        }
    }
    Ok(object)
}

fn execute_scenario(
    test: &IrTest,
    source: &str,
    ir: &IrProgram,
    path: &str,
) -> Result<ScenarioWorld, String> {
    let store_path = scenario_store_path(&test.name);
    // Isolate the workspace-scoped builtin tracker per scenario so `given tracker`
    // seeding (and any queue effects) never touch the developer's real items
    // store; the projection (`project_queue_items` in `step_instance`) reads the
    // same path via this env var.
    let items_store_path = store_path.with_extension("items.sqlite");
    env::set_var("WHIPPLESCRIPT_ITEMS_STORE", &items_store_path);
    let store = SqliteStore::open(&store_path).map_err(store_error)?;
    let mut kernel = RuntimeKernel::new(store);

    // `given file <store> at <path> "<content>"` seeds deterministic fixture
    // files into a per-scenario temp dir and redirects the named file store's
    // root to it. The `read` then runs through the real worker against the
    // fixture (not the developer's real path), keeping `whip test` true-e2e and
    // isolated. The redirected root is baked into the effect input at commit
    // time, so only the `ir` handed to `step_instance` needs rewriting.
    let redirected_ir;
    let ir: &IrProgram = {
        let fixtures: Vec<(&str, &str, &str)> = test
            .clauses
            .iter()
            .filter_map(|clause| match clause {
                TestClause::Given(GivenClause::File {
                    store,
                    path,
                    content,
                    ..
                }) => Some((store.as_str(), path.value.as_str(), content.value.as_str())),
                _ => None,
            })
            .collect();
        if fixtures.is_empty() {
            ir
        } else {
            let fixture_root = store_path.with_extension("files");
            // Start from a clean slate so a prior run's fixtures never leak in.
            let _ = fs::remove_dir_all(&fixture_root);
            fs::create_dir_all(&fixture_root)
                .map_err(|error| format!("create fixture dir: {error}"))?;
            let mut clone = ir.clone();
            for (store, path, content) in fixtures {
                // Same scope boundary the runtime read enforces: a fixture path
                // must stay inside the store root.
                if Path::new(path).is_absolute()
                    || Path::new(path)
                        .components()
                        .any(|component| matches!(component, std::path::Component::ParentDir))
                {
                    return Err(format!(
                        "`given file {store} at {path:?}` escapes the store root"
                    ));
                }
                let full = fixture_root.join(path);
                if let Some(parent) = full.parent() {
                    fs::create_dir_all(parent)
                        .map_err(|error| format!("create fixture path: {error}"))?;
                }
                fs::write(&full, content).map_err(|error| format!("write fixture: {error}"))?;
                match clone
                    .file_stores
                    .iter_mut()
                    .find(|declared| declared.name == store)
                {
                    Some(declared) => {
                        declared.root = fixture_root.to_string_lossy().into_owned();
                    }
                    None => {
                        return Err(format!(
                            "`given file {store}` names a file store the workflow does not declare"
                        ));
                    }
                }
            }
            redirected_ir = clone;
            &redirected_ir
        }
    };

    let snapshot = ir.to_snapshot();
    let version = kernel
        .create_program_version_for_program(
            ProgramVersionInput {
                program_name: &ir.workflow,
                source_hash: &stable_hash_hex(source),
                ir_hash: &stable_hash_hex(&snapshot),
                compiler_version: whipplescript_core::version(),
            },
            ir,
        )
        .map_err(store_error)?;
    // `given input` seeds the workflow input the instance is created with.
    let mut input_json = "{}".to_owned();
    let mut input_seen = false;
    for clause in &test.clauses {
        if let TestClause::Given(GivenClause::Input { fields, .. }) = clause {
            if input_seen {
                return Err("a scenario may seed `given input` at most once".to_owned());
            }
            input_seen = true;
            input_json = Value::Object(eval_given_record(fields, "given input")?).to_string();
        }
    }
    // Seed input facts exactly as `whip run`/`dev` does: validate the seeded
    // input object against the workflow's input contracts, then derive the
    // declared input facts off the `started` event so input-driven rules fire.
    let input_value: Value = serde_json::from_str(&input_json)
        .map_err(|error| format!("given input is not valid JSON: {error}"))?;
    let input_facts = validate_workflow_start_input(ir, &input_value)?;
    let instance_id = kernel
        .create_instance(&version, &input_json)
        .map_err(store_error)?;
    let started_event = kernel
        .ingest_external_event(
            &instance_id,
            "external.started",
            &input_json,
            Some(&idempotency_key(&[&instance_id, "external.started"])),
        )
        .map_err(store_error)?;
    for fact in &input_facts {
        kernel
            .derive_fact(
                &instance_id,
                &fact.name,
                &fact.key,
                &fact.value_json,
                Some(&started_event.event_id),
                Some(&idempotency_key(&[
                    &instance_id,
                    "workflow.input",
                    &fact.key,
                    &fact.name,
                ])),
            )
            .map_err(store_error)?;
    }

    for clause in &test.clauses {
        match clause {
            TestClause::Given(GivenClause::Signal { name, fields, .. }) => {
                let payload_json =
                    Value::Object(eval_given_record(fields, &format!("given signal {name}"))?)
                        .to_string();
                let received = kernel
                    .ingest_external_event(
                        &instance_id,
                        name,
                        &payload_json,
                        Some(&idempotency_key(&[
                            &instance_id,
                            "signal",
                            name,
                            &payload_json,
                        ])),
                    )
                    .map_err(store_error)?;
                kernel
                    .derive_fact(
                        &instance_id,
                        name,
                        &received.event_id,
                        &payload_json,
                        Some(&received.event_id),
                        Some(&idempotency_key(&[
                            &instance_id,
                            "signal-fact",
                            &received.event_id,
                        ])),
                    )
                    .map_err(store_error)?;
            }
            // `given fact` seeds a pre-existing fact (no triggering signal), so
            // rules with `when <Fact>` patterns see it on the first step. The
            // key is the value digest, so identical seeded facts dedupe.
            TestClause::Given(GivenClause::Fact { ty, fields, .. }) => {
                let value_json = Value::Object(eval_given_record(
                    fields,
                    &format!("given fact {}", ty.name),
                )?)
                .to_string();
                let key = stable_hash_hex(&value_json);
                kernel
                    .derive_fact(
                        &instance_id,
                        &ty.name,
                        &key,
                        &value_json,
                        None,
                        Some(&idempotency_key(&[
                            &instance_id,
                            "given-fact",
                            &ty.name,
                            &key,
                        ])),
                    )
                    .map_err(store_error)?;
            }
            // `given tracker <name> issue { … }` seeds an existing issue into the
            // builtin tracker (the isolated per-scenario items store). The
            // workflow's queue projection (`step_instance` → `project_queue_items`)
            // then surfaces it as a `queue.item.ready` fact, exactly as a real
            // pre-existing issue would — going through the real projection path,
            // not a hand-seeded fact.
            TestClause::Given(GivenClause::Tracker {
                tracker, fields, ..
            }) => {
                let record = eval_given_record(fields, &format!("given tracker {tracker} issue"))?;
                let value = Value::Object(record);
                let title = value
                    .get("title")
                    .and_then(Value::as_str)
                    .unwrap_or_default();
                let body = value
                    .get("body")
                    .and_then(Value::as_str)
                    .unwrap_or_default();
                let labels = value
                    .get("labels")
                    .and_then(Value::as_array)
                    .map(|values| {
                        values
                            .iter()
                            .filter_map(Value::as_str)
                            .map(str::to_owned)
                            .collect::<Vec<_>>()
                    })
                    .unwrap_or_default();
                let mut tracker_store =
                    whipplescript_store::items::WorkItemStore::open(&items_store_path)
                        .map_err(store_error)?;
                tracker_store
                    .file_item(tracker, title, body, &labels, &value, Some("test-fixture"))
                    .map_err(store_error)?;
            }
            _ => {}
        }
    }
    drop(kernel);

    // Drive the instance per the scenario's `run` clause. One round is a
    // `step_instance` (drains rule evaluation/commits to idle — what `whip step`
    // does) followed by a `run_worker_once` (claims and settles queued effects
    // through the fixture provider, whose outcome the `stub` clauses configure).
    // Settled effects can enable further rules, so rounds repeat:
    //   - `run for N steps` runs exactly N rounds (stopping early only if the
    //     instance turns terminal), letting a test inspect an intermediate state.
    //   - `run until …` (idle / workflow completed / failed) drives to a fixed
    //     point: it stops when the instance turns terminal or the event log stops
    //     growing. The 100-round cap is a runaway guard, never a silent
    //     truncation — an unsettled workflow reports whatever state it reached and
    //     the expects judge it.
    let worker_options = WorkerOptions {
        instance_id: instance_id.clone(),
        provider: "fixture".to_owned(),
        exec_profile: ExecProfile::from_env(),
        script_manifest_path: None,
        package_lock_path: None,
        outcome: scenario_fixture_outcome(&test.clauses),
        variant: None,
        program_path: Some(PathBuf::from(path)),
        root: None,
        provider_config_paths: Vec::new(),
        max_child_iterations: 8,
        agent_outcomes: scenario_agent_outcomes(&test.clauses),
        coerce_outputs: scenario_coerce_outputs(&test.clauses),
        virtual_now: scenario_virtual_now(&test.clauses),
        work_unit_root: None,
    };
    let run_kind = scenario_run_kind(&test.clauses);
    let (max_rounds, drive_to_fixed_point) = match run_kind {
        RunKind::ForSteps(steps) => (steps as usize, false),
        _ => (100, true),
    };
    let mut previous_event_count = 0usize;
    for _ in 0..max_rounds {
        step_instance(&store_path, &instance_id, ir, Some(Path::new(path)), None)
            .map_err(store_error)?;
        run_worker_once(&store_path, &worker_options).map_err(store_error)?;
        let store = SqliteStore::open(&store_path).map_err(store_error)?;
        let status = store
            .status(&instance_id)
            .map_err(store_error)?
            .ok_or_else(|| "scenario instance vanished".to_owned())?
            .instance
            .status;
        let event_count = store.list_events(&instance_id).map_err(store_error)?.len();
        drop(store);
        // A terminal instance cannot progress, so stop under any run mode.
        if status != "running" {
            break;
        }
        // `run until …` also stops once the event log stops growing; `run for N
        // steps` runs its full count regardless of intermediate idleness.
        if drive_to_fixed_point && event_count == previous_event_count {
            break;
        }
        previous_event_count = event_count;
    }

    let store = SqliteStore::open(&store_path).map_err(store_error)?;
    let instance_status = store
        .status(&instance_id)
        .map_err(store_error)?
        .ok_or_else(|| "scenario instance vanished".to_owned())?
        .instance
        .status;
    let events = store.list_events(&instance_id).map_err(store_error)?;
    let facts = store.list_facts(&instance_id).map_err(store_error)?;
    let effects = store.list_effects(&instance_id).map_err(store_error)?;
    let diagnostics = store
        .list_diagnostics(Some(&instance_id))
        .map_err(store_error)?;
    drop(store);
    let _ = std::fs::remove_file(&store_path);

    Ok(ScenarioWorld {
        instance_status,
        events,
        facts,
        effects,
        diagnostics,
    })
}

/// Map a scenario's `stub` clauses onto the global fixture outcome that drives
/// effect settlement. `run_test_scenario` has already rejected unsupported and
/// mixed outcomes, so the first stub's outcome is authoritative; with no stubs
/// the default is a successful (`Completed`) settlement.
fn scenario_fixture_outcome(clauses: &[TestClause]) -> FixtureOutcome {
    for clause in clauses {
        if let TestClause::Stub(stub) = clause {
            // Only `succeeds`/`fails` reach here (others are rejected upstream as
            // unsupported), so the outcome is Completed unless the stub fails.
            return match stub.outcome.as_str() {
                "fails" => FixtureOutcome::Failed,
                _ => FixtureOutcome::Completed,
            };
        }
    }
    FixtureOutcome::Completed
}

/// Per-agent fixture outcomes from `stub agent <name> succeeds|fails` clauses, so
/// one scenario can stub different agents differently. The global
/// `scenario_fixture_outcome` still backs coerce/other effects and non-stubbed
/// agents; these entries override it for the named agents.
fn scenario_agent_outcomes(
    clauses: &[TestClause],
) -> std::collections::BTreeMap<String, FixtureOutcome> {
    let mut outcomes = std::collections::BTreeMap::new();
    for clause in clauses {
        if let TestClause::Stub(stub) = clause {
            if stub.surface.first().map(String::as_str) == Some("agent") {
                if let Some(name) = stub.surface.get(1) {
                    let outcome = if stub.outcome == "fails" {
                        FixtureOutcome::Failed
                    } else {
                        FixtureOutcome::Completed
                    };
                    outcomes.insert(name.clone(), outcome);
                }
            }
        }
    }
    outcomes
}

/// Injected coerce outputs from `stub coerce <fn> returns { … }` clauses, keyed by
/// coerce function name. The record payload is evaluated through the expression
/// kernel (the same evaluator `given` uses) into the JSON the fixture coerce will
/// return, so a test controls the typed result a workflow branches on.
fn scenario_coerce_outputs(clauses: &[TestClause]) -> std::collections::BTreeMap<String, String> {
    let mut outputs = std::collections::BTreeMap::new();
    for clause in clauses {
        if let TestClause::Stub(stub) = clause {
            if stub.surface.first().map(String::as_str) == Some("coerce")
                && stub.outcome == "returns"
            {
                if let (Some(name), Some(StubPayload::Record(fields))) =
                    (stub.surface.get(1), stub.payload.as_ref())
                {
                    if let Ok(object) = eval_given_record(fields, &format!("stub coerce {name}")) {
                        outputs.insert(name.clone(), Value::Object(object).to_string());
                    }
                }
            }
        }
    }
    outputs
}

/// The virtual evaluation clock set by `given clock at "…"`, or `None` to use
/// the wall clock. The grammar permits at most one; the first wins if repeated.
fn scenario_virtual_now(clauses: &[TestClause]) -> Option<String> {
    for clause in clauses {
        if let TestClause::Given(GivenClause::Clock { at, .. }) = clause {
            return Some(at.value.clone());
        }
    }
    None
}

/// The scenario's `run` directive, or `run until idle` when none is written.
/// The grammar permits at most one `run` clause; the first wins if more appear.
fn scenario_run_kind(clauses: &[TestClause]) -> RunKind {
    for clause in clauses {
        if let TestClause::Run(run) = clause {
            return run.kind.clone();
        }
    }
    RunKind::UntilIdle
}

/// Evaluate a `proj_query` predicate against one projection/fact row, reusing the
/// guard expression kernel restricted to the row's fields. Returns `Err` on a
/// predicate that cannot be parsed or does not evaluate to a boolean — never a
/// silent false.
fn evaluate_proj_predicate(predicate: &str, row: &Value) -> Result<bool, String> {
    let expr = parse_expression(predicate)
        .map_err(|error| format!("could not parse predicate `{predicate}`: {error}"))?;
    let empty_ir = empty_ir_program();
    let scope = EvalScope {
        context: None,
        facts: &[],
        effects: &[],
        ir: &empty_ir,
        projection: Some(row),
        projection_schema: None,
    };
    match guard_result(eval_expr_value(&expr, &scope)) {
        (GuardStatus::Matched, _, _) => Ok(true),
        (GuardStatus::False, _, _) => Ok(false),
        (GuardStatus::Error, _, error) => {
            Err(error.unwrap_or_else(|| "predicate did not evaluate to a boolean".to_owned()))
        }
    }
}

fn rule_committed_name(event: &EventView) -> Option<String> {
    serde_json::from_str::<Value>(&event.payload_json)
        .ok()?
        .get("rule")?
        .as_str()
        .map(str::to_owned)
}

fn evaluate_expect_v0(
    target: &ExpectTarget,
    instance_status: &str,
    events: &[EventView],
    facts: &[FactView],
    effects: &[EffectView],
    diagnostics: &[DiagnosticView],
) -> Result<(), String> {
    match target {
        ExpectTarget::WorkflowCompleted => {
            if instance_status == "completed" {
                Ok(())
            } else {
                Err(format!(
                    "expected workflow completed, got `{instance_status}`"
                ))
            }
        }
        ExpectTarget::WorkflowFailed { .. } => {
            if instance_status == "failed" {
                Ok(())
            } else {
                Err(format!("expected workflow failed, got `{instance_status}`"))
            }
        }
        ExpectTarget::Rule { name, status } => {
            let count = events
                .iter()
                .filter(|event| {
                    event.event_type == "rule.committed"
                        && rule_committed_name(event).as_deref() == Some(name.name.as_str())
                })
                .count();
            match status {
                RuleStatus::Fired => {
                    if count >= 1 {
                        Ok(())
                    } else {
                        Err(format!("expected rule `{}` to fire, it did not", name.name))
                    }
                }
                RuleStatus::DidNotFire => {
                    if count == 0 {
                        Ok(())
                    } else {
                        Err(format!(
                            "expected rule `{}` not to fire, it fired {count} time(s)",
                            name.name
                        ))
                    }
                }
                RuleStatus::FiredTimes(expected) => {
                    if count == *expected as usize {
                        Ok(())
                    } else {
                        Err(format!(
                            "expected rule `{}` to fire {expected} time(s), it fired {count}",
                            name.name
                        ))
                    }
                }
            }
        }
        ExpectTarget::Projection(query) => {
            // v0: project over recorded facts whose name matches the noun.
            let rows: Vec<Value> = facts
                .iter()
                .filter(|fact| fact.name == query.noun)
                .filter_map(|fact| serde_json::from_str::<Value>(&fact.value_json).ok())
                .collect();
            match &query.kind {
                ProjQueryKind::Exists => {
                    if rows.is_empty() {
                        Err(format!("expected at least one `{}`", query.noun))
                    } else {
                        Ok(())
                    }
                }
                ProjQueryKind::Where { predicate } => {
                    for row in &rows {
                        if evaluate_proj_predicate(predicate, row)? {
                            return Ok(());
                        }
                    }
                    Err(format!("expected a `{}` where `{predicate}`", query.noun))
                }
                ProjQueryKind::Count { predicate, count } => {
                    let mut matched = 0usize;
                    for row in &rows {
                        if evaluate_proj_predicate(predicate, row)? {
                            matched += 1;
                        }
                    }
                    if matched == *count as usize {
                        Ok(())
                    } else {
                        Err(format!(
                            "expected `{}` count where `{predicate}` to be {count}, got {matched}",
                            query.noun
                        ))
                    }
                }
            }
        }
        ExpectTarget::Effect { name, status } => {
            // Match effects by kind (the dotted surface, e.g. `agent.tell`).
            // `requested` = the effect was created at all (any status);
            // `completed`/`failed` require a matching terminal status.
            let matching = effects.iter().filter(|effect| &effect.kind == name);
            match status {
                TestEffectStatus::Requested => {
                    if matching.count() >= 1 {
                        Ok(())
                    } else {
                        Err(format!(
                            "expected effect `{name}` to be requested, it was not"
                        ))
                    }
                }
                TestEffectStatus::Completed => {
                    if matching.clone().any(|effect| effect.status == "completed") {
                        Ok(())
                    } else {
                        Err(format!(
                            "expected effect `{name}` to complete; statuses seen: {}",
                            effect_status_summary(effects, name)
                        ))
                    }
                }
                TestEffectStatus::Failed => {
                    if matching.clone().any(|effect| effect.status == "failed") {
                        Ok(())
                    } else {
                        Err(format!(
                            "expected effect `{name}` to fail; statuses seen: {}",
                            effect_status_summary(effects, name)
                        ))
                    }
                }
            }
        }
        ExpectTarget::NoEffect { name } => {
            let count = effects.iter().filter(|effect| &effect.kind == name).count();
            if count == 0 {
                Ok(())
            } else {
                Err(format!("expected no `{name}` effect, found {count}"))
            }
        }
        ExpectTarget::Diagnostic { code } => {
            if diagnostics
                .iter()
                .any(|diagnostic| diagnostic.code.as_deref() == Some(code.as_str()))
            {
                Ok(())
            } else {
                let seen: Vec<&str> = diagnostics
                    .iter()
                    .filter_map(|d| d.code.as_deref())
                    .collect();
                let seen = if seen.is_empty() {
                    "none".to_owned()
                } else {
                    seen.join(", ")
                };
                Err(format!(
                    "expected a diagnostic with code `{code}`; codes seen: {seen}"
                ))
            }
        }
    }
}

/// Summarize the statuses of effects matching `name`, for a failure message
/// (e.g. `queued, failed`). Empty when none were requested.
fn effect_status_summary(effects: &[EffectView], name: &str) -> String {
    let statuses: Vec<&str> = effects
        .iter()
        .filter(|effect| effect.kind == name)
        .map(|effect| effect.status.as_str())
        .collect();
    if statuses.is_empty() {
        "none requested".to_owned()
    } else {
        statuses.join(", ")
    }
}

fn compile(options: &CliOptions) -> ExitCode {
    let compile_options = match CompileOptions::parse(&options.args) {
        Ok(options) => options,
        Err(message) => {
            if options.json {
                let _ = emit_json(compile_json_error_report(
                    None,
                    "arguments",
                    Some(message),
                    None,
                    None,
                    None,
                ));
                return ExitCode::from(2);
            }
            eprintln!("{message}");
            return ExitCode::from(2);
        }
    };
    if compile_options.model_search && !options.json {
        eprintln!("compile --model-search requires --json because compile stdout is reserved for the IR snapshot");
        return ExitCode::from(2);
    }
    let (source, ir) = match compile_source_path_for_validation(
        &compile_options.program_path,
        compile_options.root.as_deref(),
    ) {
        Ok(compiled) => compiled,
        Err(error) => {
            if options.json {
                let _ = emit_json(compile_failure_json_report(
                    &compile_options.program_path,
                    error,
                ));
                return ExitCode::FAILURE;
            }
            return report_compile_failure(&compile_options.program_path, error);
        }
    };
    let compile_source = Path::new(&compile_options.program_path);
    let package_lock = match load_package_lock(
        compile_options.package_lock_path.as_deref(),
        std::slice::from_ref(&compile_source),
    ) {
        Ok(package_lock) => package_lock,
        Err(message) => {
            if options.json {
                let _ = emit_json(compile_json_error_report(
                    Some(&compile_options.program_path),
                    "package_lock",
                    Some(message),
                    None,
                    None,
                    None,
                ));
                return ExitCode::from(2);
            }
            eprintln!("{message}");
            return ExitCode::from(2);
        }
    };
    let contract_registry = match contract_registry_for_ir(package_lock.as_ref(), &ir) {
        Ok(registry) => registry,
        Err(message) => {
            if options.json {
                let _ = emit_json(compile_json_error_report(
                    Some(&compile_options.program_path),
                    "contract_registry",
                    Some(message),
                    None,
                    None,
                    None,
                ));
                return ExitCode::from(2);
            }
            eprintln!("{message}");
            return ExitCode::from(2);
        }
    };
    let package_contract = package_contract_json(package_lock.as_ref(), &contract_registry);
    let construct_graph = construct_graph_json(
        &compile_options.program_path,
        &source,
        &ir,
        &contract_registry,
        package_lock.as_ref(),
    );
    if construct_graph_has_error_diagnostics(&construct_graph) {
        if options.json {
            let _ = emit_json(compile_json_error_report(
                Some(&compile_options.program_path),
                "construct_graph",
                None,
                Some(construct_graph_error_diagnostics(&construct_graph)),
                Some(construct_graph),
                None,
            ));
            return ExitCode::FAILURE;
        }
        for diagnostic in construct_graph_error_diagnostics(&construct_graph) {
            eprintln!(
                "construct graph diagnostic {}: {}",
                diagnostic
                    .get("code")
                    .and_then(Value::as_str)
                    .unwrap_or("unknown"),
                diagnostic
                    .get("message")
                    .and_then(Value::as_str)
                    .unwrap_or("invalid construct graph")
            );
        }
        return ExitCode::from(1);
    }
    let lowered_ir_report = lowered_ir_report_json(
        &compile_options.program_path,
        &source,
        &ir,
        &construct_graph,
        package_lock.as_ref(),
    );
    if lowered_ir_report_has_error_diagnostics(&lowered_ir_report) {
        if options.json {
            let _ = emit_json(compile_json_error_report(
                Some(&compile_options.program_path),
                "lowered_ir_report",
                None,
                Some(lowered_ir_report_error_diagnostics(&lowered_ir_report)),
                Some(construct_graph),
                Some(lowered_ir_report),
            ));
            return ExitCode::FAILURE;
        }
        for diagnostic in lowered_ir_report_error_diagnostics(&lowered_ir_report) {
            eprintln!(
                "lowered IR diagnostic {}: {}",
                diagnostic
                    .get("code")
                    .and_then(Value::as_str)
                    .unwrap_or("unknown"),
                diagnostic
                    .get("message")
                    .and_then(Value::as_str)
                    .unwrap_or("invalid lowered IR report")
            );
        }
        return ExitCode::from(1);
    }
    let snapshot = ir.to_snapshot();

    if options.json {
        let mut report = json!({
            "schema": "whipplescript.compile_report.v0",
            "path": display_path(&compile_options.program_path),
            "workflow": ir.workflow.as_str(),
            "source_hash": stable_hash_hex(&source),
            "ir_hash": stable_hash_hex(&snapshot),
            "snapshot": snapshot,
            "source_metadata": source_metadata_json(&ir),
            "contract_registry": contract_registry_to_json(&contract_registry),
            "package_contract": package_contract,
            "construct_graph": construct_graph.clone(),
            "lowered_ir_report": lowered_ir_report.clone(),
        });
        let mut exit_code = ExitCode::SUCCESS;
        if compile_options.model_search {
            match run_model_search(
                &compile_options.program_path,
                &source,
                &ir,
                &construct_graph,
                &lowered_ir_report,
                &report,
            ) {
                Ok(model_report) => {
                    insert_model_search_fields(&mut report, &model_report);
                }
                Err(message) => {
                    insert_json_field(
                        &mut report,
                        "model_search",
                        json!({
                            "status": "error",
                            "message": message,
                        }),
                    );
                    exit_code = ExitCode::FAILURE;
                }
            }
        }
        let _ = emit_json(report);
        exit_code
    } else {
        print!("{snapshot}");
        ExitCode::SUCCESS
    }
}

/// The governance agent's command surface (DR-0028 D5): `gov sign` is the
/// privileged operation that produces a signed envelope; `gov verify` is the
/// unprivileged check the whip agent uses.
fn gov(options: &CliOptions) -> ExitCode {
    match options.args.first().map(String::as_str) {
        Some("sign") => gov_sign(options),
        Some("verify") => gov_verify(options),
        Some("escalate") => gov_escalate(options),
        Some("escalations") => gov_escalations(options),
        Some("agent") => gov_agent(options),
        _ => {
            eprintln!("usage: whip gov <sign|verify|escalate|escalations|agent> [args]");
            ExitCode::from(2)
        }
    }
}

fn gov_escalation_log() -> Result<PathBuf, ExitCode> {
    match env::var("WHIPPLESCRIPT_GOV_ESCALATIONS") {
        Ok(path) => Ok(PathBuf::from(path)),
        Err(_) => {
            eprintln!("set WHIPPLESCRIPT_GOV_ESCALATIONS to the escalation log path");
            Err(ExitCode::from(2))
        }
    }
}

/// `whip gov escalate <request>` — the whip side (unprivileged) files a low-integrity
/// request for the admin to review.
fn gov_escalate(options: &CliOptions) -> ExitCode {
    let Some(request) = options.args.get(1) else {
        eprintln!("usage: whip gov escalate <request>");
        return ExitCode::from(2);
    };
    let log = match gov_escalation_log() {
        Ok(log) => log,
        Err(code) => return code,
    };
    let from = env::var("WHIPPLESCRIPT_USER").unwrap_or_else(|_| "user".to_owned());
    match gov::file_escalation(&log, request, &from) {
        Ok(()) => {
            println!("escalation filed for admin review");
            ExitCode::SUCCESS
        }
        Err(message) => {
            eprintln!("{message}");
            ExitCode::from(1)
        }
    }
}

/// `whip agent` — the interactive whip agent loop (DR-0026/0028). UNPRIVILEGED: the
/// user-facing agent that authors and checks whips under the active envelope. It can
/// `check <file>` (run the IFC check) and `escalate <request>` (file a low-integrity
/// request for the admin), but it has NO path to signing governance — a `sign` is
/// refused. An LLM driver or a human user feeds it the same stdin.
fn whip_agent(_options: &CliOptions) -> ExitCode {
    use std::io::BufRead;
    println!("whip agent (unprivileged): check <file> | escalate <request> | quit");
    let stdin = std::io::stdin();
    for line in stdin.lock().lines() {
        let Ok(line) = line else {
            break;
        };
        let trimmed = line.trim();
        if trimmed == "quit" {
            break;
        } else if trimmed.is_empty() {
            continue;
        } else if let Some(path) = trimmed.strip_prefix("check ") {
            match std::fs::read_to_string(path.trim()) {
                Ok(source) => match whipplescript_parser::compile_program(&source).ir {
                    Some(ir) => {
                        let diagnostics = ifc::check_ifc_program(&ir);
                        if diagnostics.is_empty() {
                            println!("ok: no information-flow violations");
                        } else {
                            for diagnostic in diagnostics {
                                println!("- {}", diagnostic.message);
                            }
                        }
                    }
                    None => println!("compile error in {}", path.trim()),
                },
                Err(err) => println!("cannot read {}: {err}", path.trim()),
            }
        } else if let Some(request) = trimmed.strip_prefix("escalate ") {
            match env::var("WHIPPLESCRIPT_GOV_ESCALATIONS") {
                Ok(log) => {
                    let from = env::var("WHIPPLESCRIPT_USER").unwrap_or_else(|_| "user".to_owned());
                    match gov::file_escalation(std::path::Path::new(&log), request, &from) {
                        Ok(()) => println!("escalation filed for admin review"),
                        Err(message) => println!("{message}"),
                    }
                }
                Err(_) => println!("set WHIPPLESCRIPT_GOV_ESCALATIONS to escalate"),
            }
        } else if trimmed.starts_with("sign") {
            println!("refused: the whip agent cannot sign governance — escalate to the admin");
        } else {
            println!("unknown: {trimmed} (check <file> | escalate <request> | quit)");
        }
    }
    ExitCode::SUCCESS
}

/// `whip gov agent` — the interactive governance agent loop (DR-0028 D5). PRIVILEGED:
/// it refuses to start without governance privilege. It reads commands from stdin
/// (one per line) — the admin types them, or an LLM driver emits them; the loop is
/// the same. It accumulates a draft governance config from `grant`/`delegate`/`party`
/// lines, and acts on `show` / `sign <path>` / `escalations` / `quit`. The loop holds
/// the only path to signing, so the whip agent can never reach it.
fn gov_agent(_options: &CliOptions) -> ExitCode {
    use std::io::BufRead;
    if !gov::has_governance_privilege() {
        eprintln!("the governance agent requires admin/governance privilege (run via sudo)");
        return ExitCode::from(1);
    }
    let signer = env::var("WHIPPLESCRIPT_GOV_SIGNER").unwrap_or_else(|_| "admin".to_owned());
    let mut draft = String::new();
    let stdin = std::io::stdin();
    for line in stdin.lock().lines() {
        let Ok(line) = line else {
            break;
        };
        let trimmed = line.trim();
        if trimmed == "quit" {
            break;
        } else if trimmed.is_empty() {
            continue;
        } else if trimmed == "show" {
            match ifc::Envelope::from_dsl(&draft) {
                Ok(envelope) => println!("{}", envelope.to_canonical_json()),
                Err(message) => println!("draft error: {message}"),
            }
        } else if let Some(out) = trimmed.strip_prefix("sign ") {
            match gov::SignedEnvelope::sign(&draft, &signer) {
                Ok(signed) => match std::fs::write(out.trim(), signed.to_json()) {
                    Ok(()) => println!("signed and wrote {}", out.trim()),
                    Err(err) => println!("write error: {err}"),
                },
                Err(message) => println!("sign error: {message}"),
            }
        } else if trimmed == "escalations" {
            match env::var("WHIPPLESCRIPT_GOV_ESCALATIONS") {
                Ok(path) => match gov::list_escalations(std::path::Path::new(&path)) {
                    Ok(items) if items.is_empty() => println!("no pending escalations"),
                    Ok(items) => {
                        for escalation in items {
                            println!("- from {}: {}", escalation.from, escalation.request);
                        }
                    }
                    Err(message) => println!("{message}"),
                },
                Err(_) => println!("set WHIPPLESCRIPT_GOV_ESCALATIONS to review escalations"),
            }
        } else if trimmed.starts_with("grant ")
            || trimmed.starts_with("delegate ")
            || trimmed.starts_with("party ")
        {
            draft.push_str(trimmed);
            draft.push('\n');
            println!("ok");
        } else {
            println!(
                "unknown: {trimmed} (commands: grant/delegate/party <…>, show, sign <path>, \
                 escalations, quit)"
            );
        }
    }
    ExitCode::SUCCESS
}

/// `whip gov escalations` — the governance agent (privileged) reviews pending requests.
fn gov_escalations(options: &CliOptions) -> ExitCode {
    let _ = options;
    let log = match gov_escalation_log() {
        Ok(log) => log,
        Err(code) => return code,
    };
    match gov::list_escalations(&log) {
        Ok(items) if items.is_empty() => {
            println!("no pending escalations");
            ExitCode::SUCCESS
        }
        Ok(items) => {
            for escalation in items {
                println!("- from {}: {}", escalation.from, escalation.request);
            }
            ExitCode::SUCCESS
        }
        Err(message) => {
            eprintln!("{message}");
            ExitCode::from(1)
        }
    }
}

fn gov_sign(options: &CliOptions) -> ExitCode {
    let Some(config_path) = options.args.get(1) else {
        eprintln!("usage: whip gov sign <governance-config>");
        return ExitCode::from(2);
    };
    let config_text = match std::fs::read_to_string(config_path) {
        Ok(text) => text,
        Err(err) => {
            eprintln!("cannot read {config_path}: {err}");
            return ExitCode::from(2);
        }
    };
    let signer = env::var("WHIPPLESCRIPT_GOV_SIGNER").unwrap_or_else(|_| "admin".to_owned());
    match gov::SignedEnvelope::sign(&config_text, &signer) {
        Ok(signed) => {
            println!("{}", signed.to_json());
            ExitCode::SUCCESS
        }
        Err(message) => {
            eprintln!("{message}");
            ExitCode::from(1)
        }
    }
}

fn gov_verify(options: &CliOptions) -> ExitCode {
    let Some(signed_path) = options.args.get(1) else {
        eprintln!("usage: whip gov verify <signed-envelope>");
        return ExitCode::from(2);
    };
    let signed_text = match std::fs::read_to_string(signed_path) {
        Ok(text) => text,
        Err(err) => {
            eprintln!("cannot read {signed_path}: {err}");
            return ExitCode::from(2);
        }
    };
    match gov::SignedEnvelope::verify(&signed_text) {
        Ok(signer) => {
            println!("verified: signed by {signer}");
            ExitCode::SUCCESS
        }
        Err(message) => {
            eprintln!("{message}");
            ExitCode::from(1)
        }
    }
}

fn verify_report(options: &CliOptions) -> ExitCode {
    let verify_options = match VerifyReportOptions::parse(&options.args) {
        Ok(options) => options,
        Err(message) => {
            if options.json {
                let _ = emit_json(json!({
                    "status": "error",
                    "error": {"kind": "arguments", "message": message},
                }));
            } else {
                eprintln!("{message}");
            }
            return ExitCode::from(2);
        }
    };
    let mut failed = false;
    let mut reports = Vec::new();
    let mut verified_entries = Vec::new();
    for path in &verify_options.paths {
        match verify_report_path(path, verify_options.entry_index) {
            Ok(entries) => {
                if verify_options.emit.requires_lowered_ir()
                    && entries
                        .iter()
                        .any(|entry| entry.lowered_ir_report.is_none())
                {
                    failed = true;
                    let missing = entries
                        .iter()
                        .filter(|entry| entry.lowered_ir_report.is_none())
                        .map(|entry| entry.label.as_str())
                        .collect::<Vec<_>>()
                        .join(", ");
                    let missing_label = if missing.is_empty() {
                        "the selected verified artifact entry".to_owned()
                    } else if missing.contains(", ") {
                        format!("verified artifact entries {missing}")
                    } else {
                        format!("verified artifact entry {missing}")
                    };
                    let message = format!(
                        "`--emit {}` requires lowered_ir_report; missing lowered_ir_report in {}",
                        verify_options.emit.as_str(),
                        missing_label
                    );
                    if options.json || verify_options.emit != VerifyReportEmit::Summary {
                        reports.push(json!({
                            "path": display_path(path),
                            "status": "error",
                            "error": {
                                "kind": "artifact_report",
                                "message": message,
                            },
                        }));
                    } else {
                        eprintln!("{path}: {message}");
                    }
                    continue;
                }
                if options.json || verify_options.emit != VerifyReportEmit::Summary {
                    reports.push(json!({
                        "path": display_path(path),
                        "status": "ok",
                        "entries": entries
                            .iter()
                            .map(|entry| entry.label.as_str())
                            .collect::<Vec<_>>(),
                    }));
                } else {
                    for entry in &entries {
                        println!("validated artifact evidence for {}", entry.label);
                    }
                }
                verified_entries.extend(entries);
            }
            Err(message) => {
                failed = true;
                if options.json || verify_options.emit != VerifyReportEmit::Summary {
                    reports.push(json!({
                        "path": display_path(path),
                        "status": "error",
                        "error": {
                            "kind": "artifact_report",
                            "message": message,
                        },
                    }));
                } else {
                    eprintln!("{path}: {message}");
                }
            }
        }
    }
    if verify_options.emit != VerifyReportEmit::Summary {
        if failed {
            let _ = emit_json(json!({
                "schema": "whipplescript.verified_artifacts.v0",
                "status": "error",
                "emit": verify_options.emit.as_str(),
                "reports": reports,
            }));
        } else {
            let _ = emit_json(verified_report_artifacts_json(
                &verified_entries,
                verify_options.emit,
            ));
        }
    } else if options.json {
        let _ = emit_json(Value::Array(reports));
    }
    if failed {
        ExitCode::FAILURE
    } else {
        ExitCode::SUCCESS
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct VerifyReportOptions {
    entry_index: Option<usize>,
    emit: VerifyReportEmit,
    paths: Vec<String>,
}

impl VerifyReportOptions {
    fn parse(args: &[String]) -> Result<Self, String> {
        let mut entry_index = None;
        let mut emit = VerifyReportEmit::Summary;
        let mut paths = Vec::new();
        let mut index = 0;
        while index < args.len() {
            match args[index].as_str() {
                "--entry-index" => {
                    index += 1;
                    let Some(value) = args.get(index) else {
                        return Err("expected index after `--entry-index`".to_owned());
                    };
                    entry_index = Some(value.parse::<usize>().map_err(|_| {
                        format!("entry index `{value}` must be a non-negative integer")
                    })?);
                }
                "--emit" => {
                    index += 1;
                    let Some(value) = args.get(index) else {
                        return Err(
                            "expected construct-graph, lowered-ir, or artifacts after `--emit`"
                                .to_owned(),
                        );
                    };
                    emit = VerifyReportEmit::parse(value)?;
                }
                other if other.starts_with('-') => {
                    return Err(format!("unknown verify-report option `{other}`"));
                }
                value => paths.push(value.to_owned()),
            }
            index += 1;
        }
        if paths.is_empty() {
            return Err(
                "usage: whip verify-report [--entry-index <n>] [--emit construct-graph|lowered-ir|artifacts] <check-or-compile-or-artifacts-report.json>..."
                    .to_owned(),
            );
        }
        Ok(Self {
            entry_index,
            emit,
            paths,
        })
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum VerifyReportEmit {
    Summary,
    ConstructGraph,
    LoweredIrReport,
    Artifacts,
}

impl VerifyReportEmit {
    fn parse(value: &str) -> Result<Self, String> {
        match value {
            "construct-graph" => Ok(Self::ConstructGraph),
            "lowered-ir" => Ok(Self::LoweredIrReport),
            "artifacts" => Ok(Self::Artifacts),
            other => Err(format!(
                "unknown verify-report emit mode `{other}`; expected construct-graph, lowered-ir, or artifacts"
            )),
        }
    }

    fn as_str(self) -> &'static str {
        match self {
            Self::Summary => "summary",
            Self::ConstructGraph => "construct-graph",
            Self::LoweredIrReport => "lowered-ir",
            Self::Artifacts => "artifacts",
        }
    }

    fn requires_lowered_ir(self) -> bool {
        matches!(self, Self::LoweredIrReport | Self::Artifacts)
    }
}

#[derive(Clone, Debug, PartialEq)]
struct VerifiedReportEntry {
    label: String,
    report_path: String,
    report_schema: String,
    source_path: String,
    workflow: String,
    source_hash: String,
    ir_hash: String,
    snapshot: String,
    contract_registry: Value,
    package_contract: Value,
    construct_graph: Value,
    lowered_ir_report: Option<Value>,
}

fn verify_report_path(
    path: &str,
    entry_index: Option<usize>,
) -> Result<Vec<VerifiedReportEntry>, String> {
    let source = fs::read_to_string(path)
        .map_err(|error| format!("could not read report `{}`: {error}", display_path(path)))?;
    let report = serde_json::from_str::<Value>(&source)
        .map_err(|error| format!("could not parse report `{}`: {error}", display_path(path)))?;
    verify_report_value(&report, &display_path(path), entry_index)
}

fn verify_report_value(
    report: &Value,
    label: &str,
    entry_index: Option<usize>,
) -> Result<Vec<VerifiedReportEntry>, String> {
    match report {
        Value::Array(entries) => {
            verify_check_report_envelope(entries, label)?;
            verify_check_report_entries(entries, label, entry_index)
        }
        Value::Object(object)
            if object.get("schema").and_then(Value::as_str)
                == Some("whipplescript.verified_artifacts.v0") =>
        {
            verify_verified_artifact_bundle_entries(report, label, entry_index)
        }
        Value::Object(_) => {
            verify_compile_report_success_shape(report, label)?;
            verify_report_entry_artifacts(report, label)?;
            Ok(vec![verified_report_entry_from_value(
                report, label, label,
            )?])
        }
        _ => Err(format!(
            "{label} is not a check report array, compile report object, or verified artifact bundle"
        )),
    }
}

fn verify_verified_artifact_bundle_entries(
    bundle: &Value,
    label: &str,
    entry_index: Option<usize>,
) -> Result<Vec<VerifiedReportEntry>, String> {
    verify_report_schema(bundle, label, "whipplescript.verified_artifacts.v0")?;
    verify_report_object_fields(bundle, label, &["schema", "status", "emit", "entries"])?;
    if bundle.get("status").and_then(Value::as_str) != Some("ok") {
        return Err(format!("{label} verified artifact bundle was not ok"));
    }
    let emit = required_json_str(bundle, "emit", label)?;
    if !matches!(emit, "construct-graph" | "lowered-ir" | "artifacts") {
        return Err(format!(
            "{label}.emit must be `construct-graph`, `lowered-ir`, or `artifacts`, got `{emit}`"
        ));
    }
    let full_lowering_bundle = matches!(emit, "artifacts" | "lowered-ir");
    let entries = bundle
        .get("entries")
        .and_then(Value::as_array)
        .ok_or_else(|| format!("{label}.entries must be an array"))?;
    if entries.is_empty() {
        return Err(format!(
            "{label} did not contain any verified artifact entries"
        ));
    }
    if let Some(entry_index) = entry_index {
        let Some(entry) = entries.get(entry_index) else {
            return Err(format!(
                "--entry-index {entry_index} is out of range for {label} with {} entr{}",
                entries.len(),
                if entries.len() == 1 { "y" } else { "ies" }
            ));
        };
        let entry_label = format!("{label}.entries[{entry_index}]");
        verify_verified_artifact_bundle_entry(entry, &entry_label, emit)?;
        if full_lowering_bundle {
            verify_report_entry_artifacts(entry, &entry_label)?;
        } else {
            verify_report_entry_construct_graph_artifact(entry, &entry_label)?;
        }
        return Ok(vec![verified_report_entry_from_bundle_entry(
            entry,
            &entry_label,
            label,
        )?]);
    }

    let mut validated = Vec::new();
    for (index, entry) in entries.iter().enumerate() {
        let entry_label = format!("{label}.entries[{index}]");
        verify_verified_artifact_bundle_entry(entry, &entry_label, emit)?;
        if full_lowering_bundle {
            verify_report_entry_artifacts(entry, &entry_label)?;
        } else {
            verify_report_entry_construct_graph_artifact(entry, &entry_label)?;
        }
        validated.push(verified_report_entry_from_bundle_entry(
            entry,
            &entry_label,
            label,
        )?);
    }
    Ok(validated)
}

fn verify_report_object_fields(
    value: &Value,
    label: &str,
    allowed_fields: &[&str],
) -> Result<(), String> {
    let object = value
        .as_object()
        .ok_or_else(|| format!("{label} must be an object"))?;
    for field in object.keys() {
        if !allowed_fields
            .iter()
            .any(|allowed_field| allowed_field == field)
        {
            return Err(format!("{label} field `{field}` is not allowed"));
        }
    }
    Ok(())
}

fn verify_verified_artifact_bundle_entry(
    entry: &Value,
    label: &str,
    emit: &str,
) -> Result<(), String> {
    let allowed_fields = [
        "label",
        "report_path",
        "report_schema",
        "source_path",
        "workflow",
        "source_hash",
        "ir_hash",
        "snapshot",
        "contract_registry",
        "package_contract",
        "construct_graph",
        "lowered_ir_report",
    ];
    verify_report_object_fields(entry, label, &allowed_fields)?;
    if emit == "construct-graph" && entry.get("lowered_ir_report").is_some() {
        return Err(format!(
            "{label}.lowered_ir_report is not allowed in construct-graph bundles"
        ));
    }
    if matches!(emit, "lowered-ir" | "artifacts") && entry.get("lowered_ir_report").is_none() {
        return Err(format!(
            "{label}.lowered_ir_report is required for {emit} bundles"
        ));
    }
    for field in [
        "label",
        "report_path",
        "report_schema",
        "source_path",
        "workflow",
        "source_hash",
        "ir_hash",
        "snapshot",
    ] {
        required_json_str(entry, field, label)?;
    }
    let report_schema = required_json_str(entry, "report_schema", label)?;
    if !matches!(report_schema, CHECK_REPORT_SCHEMA | COMPILE_REPORT_SCHEMA) {
        return Err(format!(
            "{label}.report_schema must be `{CHECK_REPORT_SCHEMA}` or `{COMPILE_REPORT_SCHEMA}`, got `{report_schema}`"
        ));
    }
    verify_report_digest_field(entry, "source_hash", label)?;
    verify_report_digest_field(entry, "ir_hash", label)?;
    let snapshot = required_json_str(entry, "snapshot", label)?;
    let ir_hash = required_json_str(entry, "ir_hash", label)?;
    let recomputed_ir_hash = stable_hash_hex(snapshot);
    if ir_hash != recomputed_ir_hash {
        return Err(format!(
            "{label}.ir_hash must match the embedded snapshot hash; got `{ir_hash}`, expected `{recomputed_ir_hash}`"
        ));
    }
    let contract_registry = require_json_object_field(entry, "contract_registry", label)?;
    verify_contract_registry_shape(contract_registry, &format!("{label}.contract_registry"))?;
    let package_contract = require_json_object_field(entry, "package_contract", label)?;
    verify_package_contract_artifact(package_contract, contract_registry, label)?;
    Ok(())
}

fn verify_check_report_envelope(entries: &[Value], label: &str) -> Result<(), String> {
    for (index, entry) in entries.iter().enumerate() {
        let entry_label = format!("{label}[{index}]");
        if !entry.is_object() {
            return Err(format!("{entry_label} must be an object"));
        }
        verify_report_schema(entry, &entry_label, CHECK_REPORT_SCHEMA)?;
        let status = required_json_str(entry, "status", &entry_label)?;
        match status {
            "ok" => verify_check_report_success_shape(entry, &entry_label)?,
            "error" => verify_check_report_error_shape(entry, &entry_label)?,
            other => {
                return Err(format!(
                    "{entry_label}.status must be `ok` or `error`, got `{other}`"
                ))
            }
        }
    }
    Ok(())
}

fn verify_check_report_entries(
    entries: &[Value],
    label: &str,
    entry_index: Option<usize>,
) -> Result<Vec<VerifiedReportEntry>, String> {
    if let Some(entry_index) = entry_index {
        let Some(entry) = entries.get(entry_index) else {
            return Err(format!(
                "--entry-index {entry_index} is out of range for {label} with {} entr{}",
                entries.len(),
                if entries.len() == 1 { "y" } else { "ies" }
            ));
        };
        if entry.get("status").and_then(Value::as_str) != Some("ok") {
            return Err(format!("{label}[{entry_index}] was not ok"));
        }
        let entry_label = format!("{label}[{entry_index}]");
        verify_check_report_success_shape(entry, &entry_label)?;
        verify_report_entry_artifacts(entry, &entry_label)?;
        return Ok(vec![verified_report_entry_from_value(
            entry,
            &entry_label,
            label,
        )?]);
    }

    let mut validated = Vec::new();
    for (index, entry) in entries.iter().enumerate() {
        if entry.get("status").and_then(Value::as_str) != Some("ok") {
            continue;
        }
        let entry_label = format!("{label}[{index}]");
        verify_check_report_success_shape(entry, &entry_label)?;
        verify_report_entry_artifacts(entry, &entry_label)?;
        validated.push(verified_report_entry_from_value(
            entry,
            &entry_label,
            label,
        )?);
    }
    if validated.is_empty() {
        return Err(format!(
            "{label} did not contain any successful report entries"
        ));
    }
    Ok(validated)
}

fn verified_report_entry_from_value(
    entry: &Value,
    label: &str,
    report_path: &str,
) -> Result<VerifiedReportEntry, String> {
    let report_schema = required_json_str(entry, "schema", label)?.to_owned();
    let source_path = required_json_str(entry, "path", label)?.to_owned();
    let workflow = required_json_str(entry, "workflow", label)?.to_owned();
    let source_hash = required_json_str(entry, "source_hash", label)?.to_owned();
    let ir_hash = required_json_str(entry, "ir_hash", label)?.to_owned();
    let snapshot = required_json_str(entry, "snapshot", label)?.to_owned();
    let contract_registry = entry
        .get("contract_registry")
        .ok_or_else(|| format!("{label} has no contract_registry"))?
        .clone();
    let construct_graph = entry
        .get("construct_graph")
        .ok_or_else(|| format!("{label} has no construct_graph"))?
        .clone();
    let package_contract = entry
        .get("package_contract")
        .ok_or_else(|| format!("{label} has no package_contract"))?
        .clone();
    let lowered_ir_report = entry
        .get("lowered_ir_report")
        .ok_or_else(|| format!("{label} has no lowered_ir_report"))?
        .clone();
    Ok(VerifiedReportEntry {
        label: label.to_owned(),
        report_path: report_path.to_owned(),
        report_schema,
        source_path,
        workflow,
        source_hash,
        ir_hash,
        snapshot,
        contract_registry,
        package_contract,
        construct_graph,
        lowered_ir_report: Some(lowered_ir_report),
    })
}

fn verified_report_entry_from_bundle_entry(
    entry: &Value,
    label: &str,
    bundle_path: &str,
) -> Result<VerifiedReportEntry, String> {
    let report_schema = required_json_str(entry, "report_schema", label)?.to_owned();
    let source_path = required_json_str(entry, "source_path", label)?.to_owned();
    let workflow = required_json_str(entry, "workflow", label)?.to_owned();
    let source_hash = required_json_str(entry, "source_hash", label)?.to_owned();
    let ir_hash = required_json_str(entry, "ir_hash", label)?.to_owned();
    let snapshot = required_json_str(entry, "snapshot", label)?.to_owned();
    let contract_registry = entry
        .get("contract_registry")
        .ok_or_else(|| format!("{label} has no contract_registry"))?
        .clone();
    let package_contract = entry
        .get("package_contract")
        .ok_or_else(|| format!("{label} has no package_contract"))?
        .clone();
    let construct_graph = entry
        .get("construct_graph")
        .ok_or_else(|| format!("{label} has no construct_graph"))?
        .clone();
    let lowered_ir_report = entry.get("lowered_ir_report").cloned();
    Ok(VerifiedReportEntry {
        label: label.to_owned(),
        report_path: bundle_path.to_owned(),
        report_schema,
        source_path,
        workflow,
        source_hash,
        ir_hash,
        snapshot,
        contract_registry,
        package_contract,
        construct_graph,
        lowered_ir_report,
    })
}

fn verified_report_artifacts_json(
    entries: &[VerifiedReportEntry],
    emit: VerifyReportEmit,
) -> Value {
    let entries = entries
        .iter()
        .map(|entry| {
            let mut value = json!({
                "label": entry.label.as_str(),
                "report_path": entry.report_path.as_str(),
                "report_schema": entry.report_schema.as_str(),
                "source_path": entry.source_path.as_str(),
                "workflow": entry.workflow.as_str(),
                "source_hash": entry.source_hash.as_str(),
                "ir_hash": entry.ir_hash.as_str(),
                "snapshot": entry.snapshot.as_str(),
                "contract_registry": entry.contract_registry.clone(),
                "package_contract": entry.package_contract.clone(),
            });
            if matches!(
                emit,
                VerifyReportEmit::ConstructGraph
                    | VerifyReportEmit::LoweredIrReport
                    | VerifyReportEmit::Artifacts
            ) {
                insert_json_field(&mut value, "construct_graph", entry.construct_graph.clone());
            }
            if matches!(
                emit,
                VerifyReportEmit::LoweredIrReport | VerifyReportEmit::Artifacts
            ) {
                let lowered_ir_report = entry
                    .lowered_ir_report
                    .as_ref()
                    .expect("lowered IR artifact required for lowered-ir/artifacts emission");
                insert_json_field(&mut value, "lowered_ir_report", lowered_ir_report.clone());
            }
            value
        })
        .collect::<Vec<_>>();
    json!({
        "schema": "whipplescript.verified_artifacts.v0",
        "status": "ok",
        "emit": emit.as_str(),
        "entries": entries,
    })
}

fn verify_check_report_success_shape(entry: &Value, label: &str) -> Result<(), String> {
    verify_report_schema(entry, label, CHECK_REPORT_SCHEMA)?;
    if entry.get("status").and_then(Value::as_str) != Some("ok") {
        return Err(format!("{label} was not ok"));
    }
    verify_report_success_common_shape(entry, label)
}

fn verify_check_report_error_shape(entry: &Value, label: &str) -> Result<(), String> {
    verify_report_schema(entry, label, CHECK_REPORT_SCHEMA)?;
    if entry.get("status").and_then(Value::as_str) != Some("error") {
        return Err(format!("{label} was not error"));
    }
    required_json_str(entry, "path", label)?;
    let error = require_json_object_field(entry, "error", label)?;
    let kind = required_json_str(error, "kind", &format!("{label}.error"))?;
    if !matches!(
        kind,
        "io" | "diagnostics" | "package_lock" | "construct_graph" | "lowered_ir_report"
    ) {
        return Err(format!(
            "{label}.error.kind must be one of io, diagnostics, package_lock, construct_graph, lowered_ir_report; got `{kind}`"
        ));
    }
    if let Some(message) = error.get("message") {
        if !message.is_string() {
            return Err(format!("{label}.error.message must be a string"));
        }
    }
    if let Some(diagnostics) = error.get("diagnostics") {
        if !diagnostics.is_array() {
            return Err(format!("{label}.error.diagnostics must be an array"));
        }
    }
    Ok(())
}

fn verify_compile_report_success_shape(report: &Value, label: &str) -> Result<(), String> {
    verify_report_schema(report, label, COMPILE_REPORT_SCHEMA)?;
    match report.get("status").and_then(Value::as_str) {
        Some("error") => return Err(format!("{label} was not ok")),
        Some(status) => {
            return Err(format!(
                "{label}.status must be omitted for successful compile reports, got `{status}`"
            ))
        }
        None => {}
    }
    verify_report_success_common_shape(report, label)
}

fn verify_report_schema(report: &Value, label: &str, expected_schema: &str) -> Result<(), String> {
    let schema = required_json_str(report, "schema", label)?;
    if schema != expected_schema {
        return Err(format!(
            "{label}.schema must be `{expected_schema}`, got `{schema}`"
        ));
    }
    Ok(())
}

fn verify_report_success_common_shape(entry: &Value, label: &str) -> Result<(), String> {
    for field in ["path", "workflow", "source_hash", "ir_hash", "snapshot"] {
        required_json_str(entry, field, label)?;
    }
    verify_report_digest_field(entry, "source_hash", label)?;
    verify_report_digest_field(entry, "ir_hash", label)?;
    let snapshot = required_json_str(entry, "snapshot", label)?;
    let ir_hash = required_json_str(entry, "ir_hash", label)?;
    let recomputed_ir_hash = stable_hash_hex(snapshot);
    if ir_hash != recomputed_ir_hash {
        return Err(format!(
            "{label}.ir_hash must match the embedded snapshot hash; got `{ir_hash}`, expected `{recomputed_ir_hash}`"
        ));
    }
    require_json_object_field(entry, "source_metadata", label)?;
    let contract_registry = require_json_object_field(entry, "contract_registry", label)?;
    verify_contract_registry_shape(contract_registry, &format!("{label}.contract_registry"))?;
    let package_contract = require_json_object_field(entry, "package_contract", label)?;
    verify_package_contract_artifact(package_contract, contract_registry, label)?;
    Ok(())
}

fn verify_contract_registry_shape(registry: &Value, label: &str) -> Result<(), String> {
    verify_report_schema(registry, label, CONTRACT_REGISTRY_SCHEMA)?;
    for field in ["libraries", "constructs", "effect_contracts", "diagnostics"] {
        require_json_array_field(registry, field, label)?;
    }
    verify_contract_registry_schema_fragments(registry, label)?;
    verify_contract_registry_package_uniqueness(registry, label)?;
    verify_contract_registry_platform_vocabulary(registry, label)?;
    verify_contract_registry_construct_input_fields(registry, label)?;
    Ok(())
}

fn verify_contract_registry_schema_fragments(registry: &Value, label: &str) -> Result<(), String> {
    let package_library_ids = report_package_library_ids(registry);
    let contracts = require_json_array_field(registry, "effect_contracts", label)?;
    for (index, contract) in contracts.iter().enumerate() {
        let contract_label = format!("{label}.effect_contracts[{index}]");
        if !contract.is_object() {
            return Err(format!("{contract_label} must be an object"));
        }
        let Some(library_id) = contract.get("library_id").and_then(Value::as_str) else {
            continue;
        };
        if !package_library_ids.contains(library_id) {
            continue;
        }
        for field in ["input_schema", "output_schema"] {
            let Some(schema) = contract.get(field) else {
                continue;
            };
            if schema.is_null() {
                continue;
            }
            let Some(schema) = schema.as_str() else {
                return Err(format!("{contract_label}.{field} must be a string or null"));
            };
            let field_label = format!("{contract_label}.{field}");
            let mut errors = Vec::new();
            validate_package_schema_fragment_shape(schema, &field_label, &mut errors, 0);
            if !errors.is_empty() {
                return Err(errors.join("; "));
            }
        }
    }
    Ok(())
}

fn verify_contract_registry_package_uniqueness(
    registry: &Value,
    label: &str,
) -> Result<(), String> {
    let libraries = require_json_array_field(registry, "libraries", label)?;
    let mut package_libraries = BTreeSet::new();
    for (index, library) in libraries.iter().enumerate() {
        let library_label = format!("{label}.libraries[{index}]");
        if !library.is_object() {
            return Err(format!("{library_label} must be an object"));
        }
        let Some(id) = library.get("id").and_then(Value::as_str) else {
            continue;
        };
        let standard = library
            .get("standard")
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let version = library.get("version").and_then(Value::as_str);
        if standard || version == Some("unlocked") {
            continue;
        }
        if !package_libraries.insert(id.to_owned()) {
            return Err(format!(
                "{library_label}.id duplicates locked package library `{id}`"
            ));
        }
    }
    let package_library_ids = report_package_library_ids(registry);

    let contracts = require_json_array_field(registry, "effect_contracts", label)?;
    let mut effect_contracts = BTreeSet::new();
    for (index, contract) in contracts.iter().enumerate() {
        let contract_label = format!("{label}.effect_contracts[{index}]");
        if !contract.is_object() {
            return Err(format!("{contract_label} must be an object"));
        }
        let Some(library_id) = contract.get("library_id").and_then(Value::as_str) else {
            continue;
        };
        if !package_library_ids.contains(library_id) {
            continue;
        }
        let Some(id) = contract.get("id").and_then(Value::as_str) else {
            continue;
        };
        let Some(version) = contract.get("version").and_then(Value::as_str) else {
            continue;
        };
        if !effect_contracts.insert((id.to_owned(), version.to_owned())) {
            return Err(format!(
                "{contract_label} duplicates package effect contract `{id}` version `{version}`"
            ));
        }
    }

    let constructs = require_json_array_field(registry, "constructs", label)?;
    let mut construct_ids = BTreeSet::new();
    let mut construct_keywords = BTreeSet::new();
    for (index, construct) in constructs.iter().enumerate() {
        let construct_label = format!("{label}.constructs[{index}]");
        if !construct.is_object() {
            return Err(format!("{construct_label} must be an object"));
        }
        let Some(library_id) = construct.get("library_id").and_then(Value::as_str) else {
            continue;
        };
        if !package_library_ids.contains(library_id) {
            continue;
        }
        let id = construct.get("id").and_then(Value::as_str);
        let version = construct.get("version").and_then(Value::as_str);
        if let (Some(id), Some(version)) = (id, version) {
            if !construct_ids.insert((id.to_owned(), version.to_owned())) {
                return Err(format!(
                    "{construct_label} duplicates package construct `{id}` version `{version}`"
                ));
            }
        }
        let scope = construct.get("scope").and_then(Value::as_str);
        let keyword = construct.get("keyword").and_then(Value::as_str);
        if let (Some(scope), Some(keyword)) = (scope, keyword) {
            if !construct_keywords.insert((scope.to_owned(), keyword.to_owned())) {
                return Err(format!(
                    "{construct_label} duplicates package construct keyword `{keyword}` in scope `{scope}`"
                ));
            }
        }
        for field_name in ["fields", "requires", "provides"] {
            let mut entries = BTreeSet::new();
            for (entry_index, entry) in construct
                .get(field_name)
                .and_then(Value::as_array)
                .into_iter()
                .flatten()
                .enumerate()
            {
                let signature = match field_name {
                    "fields" => entry.get("name").and_then(Value::as_str).map(str::to_owned),
                    _ => Some(contract_registry_interface_signature(entry)),
                };
                let Some(signature) = signature else {
                    continue;
                };
                if !entries.insert(signature.clone()) {
                    return Err(format!(
                        "{construct_label}.{field_name}[{entry_index}] duplicates package construct {field_name} entry `{signature}`"
                    ));
                }
            }
        }
    }
    Ok(())
}

fn contract_registry_interface_signature(interface: &Value) -> String {
    ["kind", "name", "type", "phase", "cardinality"]
        .into_iter()
        .map(|field| {
            interface
                .get(field)
                .map(Value::to_string)
                .unwrap_or_else(|| "null".to_owned())
        })
        .collect::<Vec<_>>()
        .join("|")
}

fn verify_contract_registry_platform_vocabulary(
    registry: &Value,
    label: &str,
) -> Result<(), String> {
    let package_library_ids = report_package_library_ids(registry);
    let contracts = require_json_array_field(registry, "effect_contracts", label)?;
    let mut package_capability_call_contract_ids = BTreeSet::new();
    for (index, contract) in contracts.iter().enumerate() {
        let contract_label = format!("{label}.effect_contracts[{index}]");
        if !contract.is_object() {
            return Err(format!("{contract_label} must be an object"));
        }
        if !contract
            .get("library_id")
            .and_then(Value::as_str)
            .is_some_and(|library_id| package_library_ids.contains(library_id))
        {
            continue;
        }
        let Some(effect_kind) = contract.get("effect_kind").and_then(Value::as_str) else {
            continue;
        };
        if effect_kind != "capability.call" {
            return Err(format!(
                "{contract_label}.effect_kind uses unsupported package effect kind `{effect_kind}`; expected `capability.call`"
            ));
        }
        if let Some(id) = contract.get("id").and_then(Value::as_str) {
            package_capability_call_contract_ids.insert(id.to_owned());
        }
    }
    for (index, contract) in contracts.iter().enumerate() {
        let contract_label = format!("{label}.effect_contracts[{index}]");
        if !contract
            .get("library_id")
            .and_then(Value::as_str)
            .is_some_and(|library_id| package_library_ids.contains(library_id))
        {
            continue;
        }
        for capability in contract
            .get("required_capabilities")
            .and_then(Value::as_array)
            .into_iter()
            .flatten()
            .filter_map(Value::as_str)
        {
            if capability == "*" || package_capability_call_contract_ids.contains(capability) {
                continue;
            }
            return Err(format!(
                "{contract_label}.required_capabilities references `{capability}` but no matching package `capability.call` effect contract is declared"
            ));
        }
    }

    let constructs = require_json_array_field(registry, "constructs", label)?;
    for (index, construct) in constructs.iter().enumerate() {
        let construct_label = format!("{label}.constructs[{index}]");
        if !construct.is_object() {
            return Err(format!("{construct_label} must be an object"));
        }
        if !construct
            .get("library_id")
            .and_then(Value::as_str)
            .is_some_and(|library_id| package_library_ids.contains(library_id))
        {
            continue;
        }
        let Some(family) = construct.get("construct_family").and_then(Value::as_str) else {
            continue;
        };
        let Some(lowering_target) = construct.get("lowering_target").and_then(Value::as_str) else {
            continue;
        };
        let Some(scope) = construct.get("scope").and_then(Value::as_str) else {
            continue;
        };
        let Some(keyword) = construct.get("keyword").and_then(Value::as_str) else {
            continue;
        };
        let Some(lowering) = PLATFORM_CONSTRUCT_CATALOG.lowering(lowering_target) else {
            return Err(format!(
                "{construct_label}.lowering_target uses unsupported construct lowering `{lowering_target}`"
            ));
        };
        if PLATFORM_CONSTRUCT_CATALOG.family(family).is_none() {
            return Err(format!(
                "{construct_label}.construct_family uses unsupported construct family `{family}`"
            ));
        }
        if !lowering.compatible_families.contains(&family) {
            return Err(format!(
                "{construct_label} uses lowering_target `{lowering_target}` incompatible with construct_family `{family}`"
            ));
        }
        if !lowering.package_authorable {
            return Err(format!(
                "{construct_label}.lowering_target `{lowering_target}` is platform-internal and cannot be used by package constructs"
            ));
        }
        if let Some(required_scope) = lowering.required_scope {
            if scope != required_scope {
                return Err(format!(
                    "{construct_label}.scope `{scope}` is unsupported for lowering_target `{lowering_target}`; expected `{required_scope}`"
                ));
            }
        }
        if !PLATFORM_CONSTRUCT_CATALOG.contains_scope(scope) {
            return Err(format!(
                "{construct_label}.scope uses unsupported construct scope `{scope}`"
            ));
        }
        if let Some(error) = reserved_keyword_privilege_error(
            construct
                .get("library_id")
                .and_then(Value::as_str)
                .unwrap_or(""),
            keyword,
            family,
            scope,
            lowering_target,
        ) {
            return Err(format!("{construct_label}.keyword {error}"));
        }
        for (field_index, field) in construct
            .get("fields")
            .and_then(Value::as_array)
            .into_iter()
            .flatten()
            .enumerate()
        {
            let field_label = format!("{construct_label}.fields[{field_index}]");
            let Some(kind) = field.get("kind").and_then(Value::as_str) else {
                continue;
            };
            if !PLATFORM_CONSTRUCT_CATALOG.contains_field_kind(kind) {
                return Err(format!(
                    "{field_label}.kind uses unsupported construct field kind `{kind}`"
                ));
            }
        }
        for direction in ["requires", "provides"] {
            for (interface_index, interface) in construct
                .get(direction)
                .and_then(Value::as_array)
                .into_iter()
                .flatten()
                .enumerate()
            {
                let interface_label = format!("{construct_label}.{direction}[{interface_index}]");
                verify_contract_registry_construct_interface_vocabulary(
                    interface,
                    &interface_label,
                )?;
            }
        }
        verify_contract_registry_construct_lowering_interfaces(
            construct,
            lowering,
            &package_capability_call_contract_ids,
            &construct_label,
        )?;
    }
    Ok(())
}

fn reserved_keyword_privilege_error(
    library_id: &str,
    keyword: &str,
    construct_family: &str,
    scope: &str,
    lowering_target: &str,
) -> Option<String> {
    if !PLATFORM_CONSTRUCT_CATALOG.contains_reserved_keyword(keyword) {
        return None;
    }
    if PLATFORM_CONSTRUCT_CATALOG
        .reserved_keyword_privilege(
            library_id,
            keyword,
            construct_family,
            scope,
            lowering_target,
        )
        .is_some()
    {
        return None;
    }
    Some(format!(
        "uses reserved construct keyword `{keyword}` without platform catalog authorization for library `{library_id}` as {scope} {construct_family} lowering `{lowering_target}`"
    ))
}

fn verify_contract_registry_construct_interface_vocabulary(
    interface: &Value,
    label: &str,
) -> Result<(), String> {
    let Some(kind) = interface.get("kind").and_then(Value::as_str) else {
        return Ok(());
    };
    if !PLATFORM_CONSTRUCT_CATALOG.contains_interface_kind(kind) {
        return Err(format!(
            "{label}.kind uses unsupported construct interface kind `{kind}`"
        ));
    }
    let Some(phase) = interface.get("phase").and_then(Value::as_str) else {
        return Ok(());
    };
    if !PLATFORM_CONSTRUCT_CATALOG.contains_interface_phase(phase) {
        return Err(format!(
            "{label}.phase uses unsupported construct interface phase `{phase}`"
        ));
    }
    let Some(cardinality) = interface.get("cardinality").and_then(Value::as_str) else {
        return Ok(());
    };
    if !PLATFORM_CONSTRUCT_CATALOG.contains_interface_cardinality(cardinality) {
        return Err(format!(
            "{label}.cardinality uses unsupported construct interface cardinality `{cardinality}`"
        ));
    }
    if kind == CONSTRUCT_INTERFACE_CAPABILITY
        && interface.get("name").and_then(Value::as_str).is_none()
    {
        return Err(format!("{label} Capability interface must declare `name`"));
    }
    Ok(())
}

fn verify_contract_registry_construct_lowering_interfaces(
    construct: &Value,
    lowering: &PlatformConstructLowering,
    package_capability_call_contract_ids: &BTreeSet<String>,
    label: &str,
) -> Result<(), String> {
    for kind in lowering.required_interfaces {
        if !contract_registry_construct_declares_interface(construct, "requires", kind) {
            return Err(format!(
                "{label} uses lowering_target `{}` but declares no required `{kind}` interface",
                lowering.id
            ));
        }
    }
    for kind in lowering.provided_interfaces {
        if !contract_registry_construct_declares_interface(construct, "provides", kind) {
            return Err(format!(
                "{label} uses lowering_target `{}` but declares no provided `{kind}` interface",
                lowering.id
            ));
        }
    }
    if lowering.target_capability == ConstructTargetCapabilityPolicy::RequiredCapabilityCallContract
    {
        let Some(target_capability) = construct.get("target_capability").and_then(Value::as_str)
        else {
            return Err(format!(
                "{label} uses lowering_target `{}` but has no target_capability",
                lowering.id
            ));
        };
        if !package_capability_call_contract_ids.contains(target_capability) {
            return Err(format!(
                "{label} target_capability `{target_capability}` has no matching package `capability.call` effect contract"
            ));
        }
        if !construct
            .get("requires")
            .and_then(Value::as_array)
            .into_iter()
            .flatten()
            .any(|interface| {
                interface.get("kind").and_then(Value::as_str)
                    == Some(CONSTRUCT_INTERFACE_CAPABILITY)
                    && interface.get("name").and_then(Value::as_str) == Some(target_capability)
            })
        {
            return Err(format!(
                "{label} uses lowering_target `{}` to `{target_capability}` but declares no required Capability interface named `{target_capability}`",
                lowering.id
            ));
        }
    }
    // A `Forbidden` lowering (e.g. `typed_effect_call`) must NOT name a generic
    // `target_capability` the way `capability_call` does — its authority comes
    // from the typed effect contract + its required `Capability` interface, not a
    // capability-call target. (DR-0020 chain / `std.files`.)
    if lowering.target_capability == ConstructTargetCapabilityPolicy::Forbidden
        && construct
            .get("target_capability")
            .and_then(Value::as_str)
            .is_some()
    {
        return Err(format!(
            "{label} uses lowering_target `{}` which forbids a `target_capability`, but one is declared",
            lowering.id
        ));
    }
    Ok(())
}

fn contract_registry_construct_declares_interface(
    construct: &Value,
    direction: &str,
    kind: &str,
) -> bool {
    construct
        .get(direction)
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .any(|interface| interface.get("kind").and_then(Value::as_str) == Some(kind))
}

fn verify_contract_registry_construct_input_fields(
    registry: &Value,
    label: &str,
) -> Result<(), String> {
    let package_library_ids = report_package_library_ids(registry);
    let contracts = require_json_array_field(registry, "effect_contracts", label)?;
    let constructs = require_json_array_field(registry, "constructs", label)?;
    for (construct_index, construct) in constructs.iter().enumerate() {
        let construct_label = format!("{label}.constructs[{construct_index}]");
        if !construct.is_object() {
            return Err(format!("{construct_label} must be an object"));
        }
        let Some(library_id) = construct.get("library_id").and_then(Value::as_str) else {
            continue;
        };
        if !package_library_ids.contains(library_id) {
            continue;
        }
        if construct.get("lowering_target").and_then(Value::as_str)
            != Some(CONSTRUCT_LOWERING_CAPABILITY_CALL)
        {
            continue;
        }
        let Some(target_capability) = construct.get("target_capability").and_then(Value::as_str)
        else {
            continue;
        };
        let Some(contract) = contracts.iter().find(|contract| {
            contract.get("id").and_then(Value::as_str) == Some(target_capability)
                && contract.get("effect_kind").and_then(Value::as_str) == Some("capability.call")
                && contract
                    .get("library_id")
                    .and_then(Value::as_str)
                    .is_some_and(|id| package_library_ids.contains(id))
        }) else {
            continue;
        };
        let Some(input_fields) = contract
            .get("input_schema")
            .and_then(Value::as_str)
            .and_then(package_schema_top_level_object_fields)
        else {
            continue;
        };
        let mut construct_fields = BTreeMap::new();
        for field in construct
            .get("fields")
            .and_then(Value::as_array)
            .into_iter()
            .flatten()
        {
            let Some(name) = field.get("name").and_then(Value::as_str) else {
                continue;
            };
            let required = field
                .get("required")
                .and_then(Value::as_bool)
                .unwrap_or(true);
            construct_fields.insert(name.to_owned(), required);
        }
        for input_field in input_fields {
            match construct_fields.get(&input_field) {
                Some(true) => {}
                Some(false) => {
                    return Err(format!(
                        "{construct_label} lowers to `{target_capability}` but target input_schema field `{input_field}` is optional in the construct fields"
                    ))
                }
                None => {
                    return Err(format!(
                        "{construct_label} lowers to `{target_capability}` but target input_schema field `{input_field}` has no matching required construct field"
                    ))
                }
            }
        }
    }
    Ok(())
}

fn report_package_library_ids(registry: &Value) -> BTreeSet<String> {
    registry
        .get("libraries")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(|library| {
            let id = library.get("id").and_then(Value::as_str)?;
            let standard = library
                .get("standard")
                .and_then(Value::as_bool)
                .unwrap_or(false);
            let version = library.get("version").and_then(Value::as_str);
            (!standard && version != Some("unlocked")).then(|| id.to_owned())
        })
        .collect()
}

fn verify_package_contract_artifact(
    package_contract: &Value,
    contract_registry: &Value,
    label: &str,
) -> Result<(), String> {
    let package_contract_label = format!("{label}.package_contract");
    verify_report_schema(
        package_contract,
        &package_contract_label,
        PACKAGE_CONTRACT_SCHEMA,
    )?;
    let digest = required_json_str(
        package_contract,
        "package_contract_digest",
        &package_contract_label,
    )?;
    if !is_sha256_hex(digest) {
        return Err(format!(
            "{label}.package_contract.package_contract_digest must be a 64-character lowercase hex digest"
        ));
    }
    let lock_digest = required_json_str(
        package_contract,
        "package_lock_digest",
        &package_contract_label,
    )?;
    if !is_sha256_hex(lock_digest) {
        return Err(format!(
            "{label}.package_contract.package_lock_digest must be a 64-character lowercase hex digest"
        ));
    }
    require_json_array_field(package_contract, "manifests", &package_contract_label)?;
    let embedded_registry = require_json_object_field(
        package_contract,
        "contract_registry",
        &package_contract_label,
    )?;
    verify_contract_registry_shape(
        embedded_registry,
        &format!("{package_contract_label}.contract_registry"),
    )?;
    if embedded_registry != contract_registry {
        return Err(format!(
            "{label}.package_contract.contract_registry must match the report contract_registry"
        ));
    }
    verify_package_contract_platform(package_contract, label)?;
    verify_empty_diagnostics(
        package_contract,
        "diagnostics",
        &format!("{label}.package_contract"),
    )?;
    verify_empty_diagnostics(
        embedded_registry,
        "diagnostics",
        &format!("{label}.package_contract.contract_registry"),
    )?;
    verify_empty_diagnostics(
        contract_registry,
        "diagnostics",
        &format!("{label}.contract_registry"),
    )?;
    let mut digest_body = package_contract.clone();
    if let Some(object) = digest_body.as_object_mut() {
        object.remove("package_contract_digest");
    }
    let digest_input = canonical_json(&digest_body);
    let expected_digest = sha256_hex(digest_input.as_bytes());
    if digest != expected_digest {
        return Err(format!(
            "{label}.package_contract.package_contract_digest does not match the embedded package contract"
        ));
    }
    Ok(())
}

fn verify_package_contract_platform(package_contract: &Value, label: &str) -> Result<(), String> {
    let platform_version = required_json_str(
        package_contract,
        "platform_version",
        &format!("{label}.package_contract"),
    )?;
    let expected_version = whipplescript_core::version();
    if platform_version != expected_version {
        return Err(format!(
            "{label}.package_contract.platform_version must match verifier platform version `{expected_version}`, got `{platform_version}`"
        ));
    }
    let catalog = require_json_object_field(
        package_contract,
        "platform_construct_catalog",
        &format!("{label}.package_contract"),
    )?;
    let expected_catalog = platform_construct_catalog_json();
    if catalog != &expected_catalog {
        return Err(format!(
            "{label}.package_contract.platform_construct_catalog must match verifier platform catalog"
        ));
    }
    Ok(())
}

fn verify_empty_diagnostics(value: &Value, field: &str, owner: &str) -> Result<(), String> {
    let diagnostics = value
        .get(field)
        .and_then(Value::as_array)
        .ok_or_else(|| format!("{owner}.{field} must be an array"))?;
    if diagnostics.is_empty() {
        return Ok(());
    }
    Err(format!(
        "{owner}.{field} must be empty for verified artifact admission"
    ))
}

fn verify_report_digest_field(value: &Value, field: &str, owner: &str) -> Result<(), String> {
    let digest = required_json_str(value, field, owner)?;
    if digest.len() != 16
        || !digest
            .bytes()
            .all(|byte| byte.is_ascii_hexdigit() && !byte.is_ascii_uppercase())
    {
        return Err(format!("{owner}.{field} must be a 16-character hex digest"));
    }
    Ok(())
}

fn require_json_object_field<'a>(
    value: &'a Value,
    field: &str,
    owner: &str,
) -> Result<&'a Value, String> {
    let object = value
        .get(field)
        .ok_or_else(|| format!("{owner}.{field} must be an object"))?;
    if !object.is_object() {
        return Err(format!("{owner}.{field} must be an object"));
    }
    Ok(object)
}

fn require_json_array_field<'a>(
    value: &'a Value,
    field: &str,
    owner: &str,
) -> Result<&'a Vec<Value>, String> {
    value
        .get(field)
        .and_then(Value::as_array)
        .ok_or_else(|| format!("{owner}.{field} must be an array"))
}

fn verify_report_entry_construct_graph_artifact(entry: &Value, label: &str) -> Result<(), String> {
    let graph = entry
        .get("construct_graph")
        .ok_or_else(|| format!("{label} has no construct_graph"))?;
    if !graph.is_object() {
        return Err(format!("{label} construct_graph is not an object"));
    }
    verify_report_schema(
        graph,
        &format!("{label}.construct_graph"),
        CONSTRUCT_GRAPH_SCHEMA,
    )?;
    verify_report_construct_graph_artifact_identity(entry, graph, label)?;
    verify_report_construct_graph_collection_shapes(graph, label)?;

    let graph_errors = construct_graph_error_diagnostics(graph);
    if !graph_errors.is_empty() {
        return Err(format!(
            "{label} construct graph has validator errors: {}",
            diagnostic_code_summary(&graph_errors)
        ));
    }
    let graph_validation = validate_construct_graph_artifact(graph);
    if !graph_validation.diagnostics.is_empty() {
        return Err(format!(
            "{label} construct graph recomputation failed: {}",
            diagnostic_code_summary(&graph_validation.diagnostics)
        ));
    }
    verify_validator_fact_trace(
        graph,
        "construct_graph_validator",
        &graph_validation.derived_facts,
        "construct graph",
    )
    .map_err(|message| format!("{label} {message}"))?;
    verify_source_backed_construct_graph_if_available(entry, graph, label)?;

    Ok(())
}

fn verify_report_entry_artifacts(entry: &Value, label: &str) -> Result<(), String> {
    verify_report_entry_construct_graph_artifact(entry, label)?;
    let graph = entry
        .get("construct_graph")
        .ok_or_else(|| format!("{label} has no construct_graph"))?;
    let lowered = entry
        .get("lowered_ir_report")
        .ok_or_else(|| format!("{label} has no lowered_ir_report"))?;
    if !lowered.is_object() {
        return Err(format!("{label} lowered_ir_report is not an object"));
    }
    verify_report_schema(
        lowered,
        &format!("{label}.lowered_ir_report"),
        LOWERED_IR_REPORT_SCHEMA,
    )?;
    verify_report_lowered_ir_artifact_identity(entry, graph, lowered, label)?;
    verify_report_lowered_ir_collection_shapes(lowered, label)?;

    let lowered_errors = lowered_ir_report_error_diagnostics(lowered);
    if !lowered_errors.is_empty() {
        return Err(format!(
            "{label} lowered IR report has validator errors: {}",
            diagnostic_code_summary(&lowered_errors)
        ));
    }
    let lowered_validation = validate_lowered_ir_artifact(lowered, graph);
    if !lowered_validation.diagnostics.is_empty() {
        return Err(format!(
            "{label} lowered IR recomputation failed: {}",
            diagnostic_code_summary(&lowered_validation.diagnostics)
        ));
    }
    verify_validator_fact_trace(
        lowered,
        "lowered_ir_validator",
        &lowered_validation.derived_facts,
        "lowered IR report",
    )
    .map_err(|message| format!("{label} {message}"))?;
    verify_source_backed_lowered_ir_if_available(entry, graph, lowered, label)?;
    verify_model_search_ledger_if_present(entry, graph, lowered, label)?;

    Ok(())
}

struct SourceBackedArtifactContext {
    source_path: String,
    source: String,
    ir: IrProgram,
    registry: ContractRegistry,
    package_lock_digest: String,
    package_contract_digest: String,
}

fn verify_source_backed_construct_graph_if_available(
    entry: &Value,
    graph: &Value,
    label: &str,
) -> Result<(), String> {
    let Some(context) = source_backed_artifact_context_if_available(entry, graph, label)? else {
        return Ok(());
    };
    let expected = construct_graph_json_with_digests(
        &context.source_path,
        &context.source,
        &context.ir,
        &context.registry,
        &context.package_lock_digest,
        &context.package_contract_digest,
    );
    if canonical_json(graph) != canonical_json(&expected) {
        return Err(format!(
            "{label} source-backed construct_graph mismatch: got {}, expected {}",
            artifact_digest(graph),
            artifact_digest(&expected)
        ));
    }
    Ok(())
}

fn verify_source_backed_lowered_ir_if_available(
    entry: &Value,
    graph: &Value,
    lowered: &Value,
    label: &str,
) -> Result<(), String> {
    let Some(context) = source_backed_artifact_context_if_available(entry, graph, label)? else {
        return Ok(());
    };
    let expected = lowered_ir_report_json_with_digest(
        &context.source,
        &context.ir,
        graph,
        &context.package_lock_digest,
    );
    if canonical_json(lowered) != canonical_json(&expected) {
        return Err(format!(
            "{label} source-backed lowered_ir_report mismatch: got {}, expected {}",
            artifact_digest(lowered),
            artifact_digest(&expected)
        ));
    }
    Ok(())
}

fn source_backed_artifact_context_if_available(
    entry: &Value,
    graph: &Value,
    label: &str,
) -> Result<Option<SourceBackedArtifactContext>, String> {
    let Some(source_path) = report_source_path(entry) else {
        return Ok(None);
    };
    let metadata = match fs::metadata(source_path) {
        Ok(metadata) => metadata,
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => return Ok(None),
        Err(error) => {
            return Err(format!(
                "{label} source-backed artifact validation could not stat `{source_path}`: {error}"
            ));
        }
    };
    if !metadata.is_file() {
        return Ok(None);
    }
    let workflow = entry.get("workflow").and_then(Value::as_str);
    let (source, ir) =
        compile_source_path_for_validation(source_path, workflow).map_err(|error| {
            format!(
                "{label} source-backed artifact validation could not compile `{source_path}`: {}",
                compile_failure_summary(error)
            )
        })?;
    verify_source_backed_source_and_ir(entry, graph, &source, &ir, label, "artifact")?;

    let contract_registry = require_json_object_field(entry, "contract_registry", label)?;
    let registry = contract_registry_from_artifact_json(
        contract_registry,
        &format!("{label}.contract_registry"),
    )?;
    validate_construct_uses_against_registry(&ir, &registry, label)?;
    let package_contract = require_json_object_field(entry, "package_contract", label)?;
    let package_lock_digest = required_json_str(
        package_contract,
        "package_lock_digest",
        &format!("{label}.package_contract"),
    )?
    .to_owned();
    let package_contract_digest = required_json_str(
        package_contract,
        "package_contract_digest",
        &format!("{label}.package_contract"),
    )?
    .to_owned();
    Ok(Some(SourceBackedArtifactContext {
        source_path: source_path.to_owned(),
        source,
        ir,
        registry,
        package_lock_digest,
        package_contract_digest,
    }))
}

fn report_source_path(entry: &Value) -> Option<&str> {
    entry
        .get("path")
        .or_else(|| entry.get("source_path"))
        .and_then(Value::as_str)
}

fn verify_source_backed_source_and_ir(
    entry: &Value,
    graph: &Value,
    source: &str,
    ir: &IrProgram,
    label: &str,
    owner: &str,
) -> Result<(), String> {
    let report_source_hash = required_json_str(entry, "source_hash", label)?;
    let computed_source_hash = stable_hash_hex(source);
    if report_source_hash != computed_source_hash {
        return Err(format!(
            "{label} source-backed {owner} source_hash mismatch: got `{report_source_hash}`, expected `{computed_source_hash}`"
        ));
    }
    let graph_source_digest = required_json_str(graph, "source_digest", "construct_graph")?;
    let computed_source_digest = sha256_hex(source.as_bytes());
    if graph_source_digest != computed_source_digest {
        return Err(format!(
            "{label} source-backed {owner} construct_graph.source_digest mismatch: got `{graph_source_digest}`, expected `{computed_source_digest}`"
        ));
    }
    let snapshot = required_json_str(entry, "snapshot", label)?;
    let computed_snapshot = ir.to_snapshot();
    if snapshot != computed_snapshot {
        return Err(format!("{label} source-backed {owner} snapshot mismatch"));
    }
    let report_ir_hash = required_json_str(entry, "ir_hash", label)?;
    let computed_ir_hash = stable_hash_hex(&computed_snapshot);
    if report_ir_hash != computed_ir_hash {
        return Err(format!(
            "{label} source-backed {owner} ir_hash mismatch: got `{report_ir_hash}`, expected `{computed_ir_hash}`"
        ));
    }
    Ok(())
}

fn artifact_digest(value: &Value) -> String {
    sha256_hex(canonical_json(value).as_bytes())
}

fn verify_report_construct_graph_collection_shapes(
    graph: &Value,
    label: &str,
) -> Result<(), String> {
    for field in [
        "nodes",
        "ports",
        "edges",
        "effect_dependencies",
        "derived_facts",
        "diagnostics",
    ] {
        require_json_array_field(graph, field, &format!("{label}.construct_graph"))?;
    }
    Ok(())
}

fn verify_report_lowered_ir_collection_shapes(lowered: &Value, label: &str) -> Result<(), String> {
    for field in [
        "node_lowerings",
        "edge_lowerings",
        "dependency_lowerings",
        "core_objects",
        "derived_facts",
        "diagnostics",
    ] {
        require_json_array_field(lowered, field, &format!("{label}.lowered_ir_report"))?;
    }
    Ok(())
}

fn verify_report_construct_graph_artifact_identity(
    entry: &Value,
    graph: &Value,
    label: &str,
) -> Result<(), String> {
    let source_digest = required_json_str(graph, "source_digest", "construct_graph")?;
    if !is_sha256_hex(source_digest) {
        return Err(format!(
            "{label} construct_graph.source_digest must be a 64-character lowercase hex digest"
        ));
    }
    let graph_id = required_json_str(graph, "graph_id", "construct_graph")?;
    let expected_graph_id = format!("construct_graph:{source_digest}");
    if graph_id != expected_graph_id {
        return Err(format!(
            "{label} construct_graph.graph_id must be `{expected_graph_id}`, got `{graph_id}`"
        ));
    }
    let package_contract = require_json_object_field(entry, "package_contract", label)?;
    let graph_package_contract_digest =
        required_json_str(graph, "package_contract_digest", "construct_graph")?;
    let report_package_contract_digest = required_json_str(
        package_contract,
        "package_contract_digest",
        &format!("{label}.package_contract"),
    )?;
    if graph_package_contract_digest != report_package_contract_digest {
        return Err(format!(
            "{label} construct_graph.package_contract_digest does not match package_contract.package_contract_digest"
        ));
    }
    let graph_package_lock_digest =
        required_json_str(graph, "package_lock_digest", "construct_graph")?;
    let contract_package_lock_digest = required_json_str(
        package_contract,
        "package_lock_digest",
        &format!("{label}.package_contract"),
    )?;
    if graph_package_lock_digest != contract_package_lock_digest {
        return Err(format!(
            "{label} construct_graph.package_lock_digest does not match package_contract.package_lock_digest"
        ));
    }
    Ok(())
}

fn verify_report_lowered_ir_artifact_identity(
    entry: &Value,
    _graph: &Value,
    lowered: &Value,
    label: &str,
) -> Result<(), String> {
    let snapshot = required_json_str(entry, "snapshot", label)?;
    let lowered_graph_id = required_json_str(lowered, "graph_id", "lowered_ir_report")?;
    let accepted_program_digest =
        required_json_str(lowered, "accepted_program_digest", "lowered_ir_report")?;
    let expected_digest = sha256_hex(format!("{lowered_graph_id}\n{snapshot}").as_bytes());
    if accepted_program_digest != expected_digest {
        return Err(format!(
            "{label} lowered_ir_report.accepted_program_digest does not match graph_id + snapshot"
        ));
    }
    Ok(())
}

fn is_sha256_hex(value: &str) -> bool {
    value.len() == 64
        && value
            .bytes()
            .all(|byte| byte.is_ascii_hexdigit() && !byte.is_ascii_uppercase())
}

fn verify_model_search_ledger_if_present(
    entry: &Value,
    graph: &Value,
    lowered: &Value,
    label: &str,
) -> Result<(), String> {
    let Some(model_search) = entry.get("model_search") else {
        return Ok(());
    };
    if !model_search.is_object() {
        return Err(format!("{label} model_search is not an object"));
    }
    if model_search.get("status").and_then(Value::as_str) != Some("ok") {
        return Err(format!("{label} model_search status was not ok"));
    }
    let searches = required_json_usize(model_search, "searches", "model_search")?;
    let solutions = required_json_usize(model_search, "solutions", "model_search")?;
    let no_solutions = required_json_usize(model_search, "no_solutions", "model_search")?;
    let ir_searches = required_json_usize(model_search, "ir_searches", "model_search")?;
    let artifact_searches = required_json_usize(model_search, "artifact_searches", "model_search")?;
    let obligations = model_search
        .get("obligations")
        .and_then(Value::as_array)
        .ok_or_else(|| format!("{label} model_search.obligations is not an array"))?;

    if searches != obligations.len() {
        return Err(format!(
            "{label} model_search searches={searches} but obligation count is {}",
            obligations.len()
        ));
    }
    if searches != solutions + no_solutions {
        return Err(format!(
            "{label} model_search searches={searches} but solutions+no_solutions={}",
            solutions + no_solutions
        ));
    }
    if searches != ir_searches + artifact_searches {
        return Err(format!(
            "{label} model_search searches={searches} but ir+artifact={}",
            ir_searches + artifact_searches
        ));
    }

    let mut outcome_solutions = 0usize;
    let mut outcome_no_solutions = 0usize;
    let mut ir_count = 0usize;
    let mut construct_count = 0usize;
    let mut lowered_count = 0usize;
    let mut platform_catalog_count = 0usize;
    let mut ir_predicate_counts = BTreeMap::<String, usize>::new();
    let mut ir_endpoint_counts = BTreeMap::<(String, String, String), usize>::new();
    let mut ir_outcome_counts = BTreeMap::<(String, String, String, String), usize>::new();
    let mut ir_sequence = Vec::<(String, String, String, String)>::new();
    let mut ir_descriptions = Vec::<String>::new();
    let mut indexes_by_category = BTreeMap::<String, Vec<usize>>::new();
    let snapshot = required_json_str(entry, "snapshot", label)?;
    let snapshot_facts = IrSnapshotFacts::parse(snapshot);
    let expected_ir_searches = snapshot_facts.expected_ir_search_count();
    if ir_searches != expected_ir_searches {
        return Err(format!(
            "{label} model_search ir_searches={ir_searches} but snapshot implies {expected_ir_searches} generated IR searches"
        ));
    }
    for (index, obligation) in obligations.iter().enumerate() {
        let category = required_json_str(obligation, "category", "model_search obligation")?;
        if !matches!(
            category,
            "ir" | "artifact.construct_graph" | "artifact.lowered_ir" | "artifact.platform_catalog"
        ) {
            return Err(format!(
                "{label} model_search obligation[{index}] has unknown category `{category}`"
            ));
        }
        let obligation_index = required_json_usize(obligation, "index", "model_search obligation")?;
        if obligation_index == 0 {
            return Err(format!(
                "{label} model_search obligation[{index}] index must be positive"
            ));
        }
        let expected = required_json_str(obligation, "expected", "model_search obligation")?;
        let actual = required_json_str(obligation, "actual", "model_search obligation")?;
        if !matches!(expected, "solution" | "no_solution") {
            return Err(format!(
                "{label} model_search obligation[{index}] has invalid expected outcome `{expected}`"
            ));
        }
        if !matches!(actual, "solution" | "no_solution") {
            return Err(format!(
                "{label} model_search obligation[{index}] has invalid actual outcome `{actual}`"
            ));
        }
        if expected != actual {
            return Err(format!(
                "{label} model_search obligation[{index}] expected/actual mismatch"
            ));
        }
        if obligation.get("status").and_then(Value::as_str) != Some("ok") {
            return Err(format!(
                "{label} model_search obligation[{index}] status was not ok"
            ));
        }
        require_model_search_source_span(obligation)
            .map_err(|message| format!("{label} model_search obligation[{index}] {message}"))?;
        match actual {
            "solution" => outcome_solutions += 1,
            "no_solution" => outcome_no_solutions += 1,
            _ => {}
        }
        match category {
            "ir" => {
                verify_model_search_ir_obligation(obligation, index, label, &snapshot_facts)?;
                let predicate =
                    required_json_str(obligation, "predicate", "model_search IR obligation")?;
                let description =
                    required_json_str(obligation, "description", "model_search IR obligation")?;
                *ir_predicate_counts.entry(predicate.to_owned()).or_insert(0) += 1;
                let upstream =
                    required_json_str(obligation, "upstream", "model_search IR obligation")?;
                let downstream =
                    required_json_str(obligation, "downstream", "model_search IR obligation")?;
                if let Some((kind, expected_span)) = construct_graph_span_for_ir_obligation(
                    graph,
                    description,
                    upstream,
                    predicate,
                    downstream,
                ) {
                    let actual_span = obligation
                        .get("source_span")
                        .map(source_span_from_artifact_json)
                        .unwrap_or(SourceSpan { start: 0, end: 0 });
                    if actual_span != expected_span {
                        return Err(format!(
                            "{label} model_search IR {kind} obligation[{index}] source_span mismatch"
                        ));
                    }
                }
                *ir_endpoint_counts
                    .entry((
                        upstream.to_owned(),
                        predicate.to_owned(),
                        downstream.to_owned(),
                    ))
                    .or_insert(0) += 1;
                *ir_outcome_counts
                    .entry((
                        upstream.to_owned(),
                        predicate.to_owned(),
                        downstream.to_owned(),
                        actual.to_owned(),
                    ))
                    .or_insert(0) += 1;
                ir_sequence.push((
                    upstream.to_owned(),
                    predicate.to_owned(),
                    downstream.to_owned(),
                    actual.to_owned(),
                ));
                ir_descriptions.push(description.to_owned());
                ir_count += 1;
            }
            "artifact.construct_graph" => construct_count += 1,
            "artifact.lowered_ir" => lowered_count += 1,
            "artifact.platform_catalog" => platform_catalog_count += 1,
            _ => {}
        }
        indexes_by_category
            .entry(category.to_owned())
            .or_default()
            .push(obligation_index);
    }

    if outcome_solutions != solutions || outcome_no_solutions != no_solutions {
        return Err(format!(
            "{label} model_search outcome counters do not match obligations"
        ));
    }
    if ir_count != ir_searches {
        return Err(format!(
            "{label} model_search ir_searches={ir_searches} but obligations contain {ir_count}"
        ));
    }
    let expected_ir_predicate_counts = snapshot_facts.expected_ir_predicate_counts();
    if ir_predicate_counts != expected_ir_predicate_counts {
        return Err(format!(
            "{label} model_search IR predicate counts do not match snapshot: got {ir_predicate_counts:?}, expected {expected_ir_predicate_counts:?}"
        ));
    }
    let expected_ir_endpoint_counts = snapshot_facts.expected_ir_endpoint_counts();
    if ir_endpoint_counts != expected_ir_endpoint_counts {
        return Err(format!(
            "{label} model_search IR endpoint counts do not match snapshot: got {ir_endpoint_counts:?}, expected {expected_ir_endpoint_counts:?}"
        ));
    }
    let expected_ir_outcome_counts = snapshot_facts.expected_ir_outcome_counts();
    if ir_outcome_counts != expected_ir_outcome_counts {
        return Err(format!(
            "{label} model_search IR outcome counts do not match snapshot: got {ir_outcome_counts:?}, expected {expected_ir_outcome_counts:?}"
        ));
    }
    let expected_ir_sequence = snapshot_facts.expected_ir_sequence();
    if ir_sequence != expected_ir_sequence {
        let mismatch = ir_sequence
            .iter()
            .zip(expected_ir_sequence.iter())
            .position(|(actual, expected)| actual != expected)
            .map(|index| index + 1)
            .unwrap_or_else(|| ir_sequence.len().min(expected_ir_sequence.len()) + 1);
        return Err(format!(
            "{label} model_search IR obligation sequence does not match snapshot at row {mismatch}"
        ));
    }
    let expected_ir_descriptions = snapshot_facts.expected_ir_descriptions();
    if ir_descriptions != expected_ir_descriptions {
        let mismatch = ir_descriptions
            .iter()
            .zip(expected_ir_descriptions.iter())
            .position(|(actual, expected)| actual != expected)
            .map(|index| index + 1)
            .unwrap_or_else(|| ir_descriptions.len().min(expected_ir_descriptions.len()) + 1);
        return Err(format!(
            "{label} model_search IR obligation descriptions do not match snapshot at row {mismatch}"
        ));
    }
    if construct_count + lowered_count + platform_catalog_count != artifact_searches {
        return Err(format!(
            "{label} model_search artifact_searches={artifact_searches} but obligations contain {}",
            construct_count + lowered_count + platform_catalog_count
        ));
    }
    for (category, indexes) in indexes_by_category {
        let expected = (1..=indexes.len()).collect::<Vec<_>>();
        if indexes != expected {
            return Err(format!(
                "{label} model_search {category} obligation indexes are not 1..n"
            ));
        }
    }

    verify_model_search_ir_obligations_artifact(entry, obligations, ir_searches, label)?;
    verify_model_search_artifact_obligations_artifact(
        entry,
        obligations,
        artifact_searches,
        label,
    )?;
    verify_model_search_ir_obligations_from_source_if_available(
        entry,
        graph,
        obligations,
        ir_searches,
        label,
    )?;
    verify_model_search_artifact_obligations(
        obligations,
        "artifact.construct_graph",
        &construct_graph_artifact_expected_searches(graph),
        label,
    )?;
    verify_model_search_artifact_obligations(
        obligations,
        "artifact.lowered_ir",
        &lowered_ir_artifact_expected_searches(graph, lowered),
        label,
    )?;
    verify_model_search_artifact_obligations(
        obligations,
        "artifact.platform_catalog",
        &platform_catalog_artifact_expected_searches(graph, &platform_construct_catalog_json()),
        label,
    )?;
    Ok(())
}

fn verify_model_search_ir_obligations_from_source_if_available(
    entry: &Value,
    graph: &Value,
    obligations: &[Value],
    ir_searches: usize,
    label: &str,
) -> Result<(), String> {
    if ir_searches == 0 {
        return Ok(());
    }
    let Some(path) = entry.get("path").and_then(Value::as_str) else {
        return Ok(());
    };
    let metadata = match fs::metadata(path) {
        Ok(metadata) => metadata,
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => return Ok(()),
        Err(error) => {
            return Err(format!(
                "{label} source-backed model_search validation could not stat `{path}`: {error}"
            ));
        }
    };
    if !metadata.is_file() {
        return Ok(());
    }
    let workflow = entry.get("workflow").and_then(Value::as_str);
    let (source, ir) = compile_source_path_for_validation(path, workflow).map_err(|error| {
        format!(
            "{label} source-backed model_search validation could not compile `{path}`: {}",
            compile_failure_summary(error)
        )
    })?;
    let report_source_hash = required_json_str(entry, "source_hash", label)?;
    let computed_source_hash = stable_hash_hex(&source);
    if report_source_hash != computed_source_hash {
        return Err(format!(
            "{label} source-backed model_search source_hash mismatch: got `{report_source_hash}`, expected `{computed_source_hash}`"
        ));
    }
    let graph_source_digest = required_json_str(graph, "source_digest", "construct_graph")?;
    let computed_source_digest = sha256_hex(source.as_bytes());
    if graph_source_digest != computed_source_digest {
        return Err(format!(
            "{label} source-backed model_search construct_graph.source_digest mismatch: got `{graph_source_digest}`, expected `{computed_source_digest}`"
        ));
    }
    let snapshot = required_json_str(entry, "snapshot", label)?;
    let computed_snapshot = ir.to_snapshot();
    if snapshot != computed_snapshot {
        return Err(format!(
            "{label} source-backed model_search snapshot mismatch"
        ));
    }
    let report_ir_hash = required_json_str(entry, "ir_hash", label)?;
    let computed_ir_hash = stable_hash_hex(&computed_snapshot);
    if report_ir_hash != computed_ir_hash {
        return Err(format!(
            "{label} source-backed model_search ir_hash mismatch: got `{report_ir_hash}`, expected `{computed_ir_hash}`"
        ));
    }

    let (_maude, expected_searches) =
        generate_maude_model_search(&source, &ir, Path::new("/tmp/kernel.maude"));
    let ir_obligations = obligations
        .iter()
        .filter(|obligation| obligation.get("category").and_then(Value::as_str) == Some("ir"))
        .collect::<Vec<_>>();
    if expected_searches.len() != ir_searches || ir_obligations.len() != ir_searches {
        return Err(format!(
            "{label} source-backed model_search IR obligation count mismatch: got {}, expected {}",
            ir_obligations.len(),
            expected_searches.len()
        ));
    }
    for (index, (actual, expected)) in ir_obligations
        .iter()
        .zip(expected_searches.iter())
        .enumerate()
    {
        let display_index = index + 1;
        for (field, expected_value) in [
            ("description", expected.description.as_str()),
            ("upstream", expected.upstream.as_str()),
            ("predicate", expected.predicate),
            ("downstream", expected.downstream.as_str()),
            ("expected", expected.outcome.json_label()),
        ] {
            let actual_value =
                required_json_str(actual, field, "source-backed model_search IR obligation")?;
            if actual_value != expected_value {
                return Err(format!(
                    "{label} source-backed IR obligation[{display_index}] {field} mismatch: got `{actual_value}`, expected `{expected_value}`"
                ));
            }
        }
        let actual_span = actual
            .get("source_span")
            .map(source_span_from_artifact_json)
            .unwrap_or(SourceSpan { start: 0, end: 0 });
        if actual_span != expected.span {
            return Err(format!(
                "{label} source-backed IR obligation[{display_index}] source_span mismatch"
            ));
        }
    }
    Ok(())
}

fn compile_failure_summary(error: CompileFailure) -> String {
    match error {
        CompileFailure::Io(error) => format!("failed to read source: {error}"),
        CompileFailure::Diagnostics { diagnostics, .. } => diagnostics
            .iter()
            .map(|diagnostic| diagnostic.message.as_str())
            .collect::<Vec<_>>()
            .join("; "),
    }
}

fn verify_model_search_ir_obligations_artifact(
    entry: &Value,
    obligations: &[Value],
    ir_searches: usize,
    label: &str,
) -> Result<(), String> {
    if ir_searches == 0 {
        return Ok(());
    }
    let artifact = entry
        .get("ir_model_search_obligations")
        .ok_or_else(|| format!("{label} missing ir_model_search_obligations artifact"))?;
    if !artifact.is_object() {
        return Err(format!(
            "{label} ir_model_search_obligations is not an object"
        ));
    }
    let schema = required_json_str(artifact, "schema", "ir_model_search_obligations")?;
    if schema != "whipplescript.ir_model_search_obligations.v0" {
        return Err(format!(
            "{label} ir_model_search_obligations.schema must be whipplescript.ir_model_search_obligations.v0"
        ));
    }
    let artifact_source_hash =
        required_json_str(artifact, "source_hash", "ir_model_search_obligations")?;
    let report_source_hash = required_json_str(entry, "source_hash", label)?;
    if artifact_source_hash != report_source_hash {
        return Err(format!(
            "{label} ir_model_search_obligations.source_hash does not match report source_hash"
        ));
    }
    let artifact_ir_hash = required_json_str(artifact, "ir_hash", "ir_model_search_obligations")?;
    let report_ir_hash = required_json_str(entry, "ir_hash", label)?;
    if artifact_ir_hash != report_ir_hash {
        return Err(format!(
            "{label} ir_model_search_obligations.ir_hash does not match report ir_hash"
        ));
    }
    let generator = required_json_str(artifact, "generator", "ir_model_search_obligations")?;
    if generator.is_empty() {
        return Err(format!(
            "{label} ir_model_search_obligations.generator must be non-empty"
        ));
    }
    let artifact_obligations = artifact
        .get("obligations")
        .and_then(Value::as_array)
        .ok_or_else(|| {
            format!("{label} ir_model_search_obligations.obligations is not an array")
        })?;
    if artifact_obligations.len() != ir_searches {
        return Err(format!(
            "{label} ir_model_search_obligations count mismatch: got {}, expected {ir_searches}",
            artifact_obligations.len()
        ));
    }
    let ir_obligations = obligations
        .iter()
        .filter(|obligation| obligation.get("category").and_then(Value::as_str) == Some("ir"))
        .collect::<Vec<_>>();
    if ir_obligations.len() != artifact_obligations.len() {
        return Err(format!(
            "{label} model_search IR obligation count does not match ir_model_search_obligations"
        ));
    }
    for (index, (actual, expected)) in ir_obligations
        .iter()
        .zip(artifact_obligations.iter())
        .enumerate()
    {
        let display_index = index + 1;
        let expected_index =
            required_json_usize(expected, "index", "ir_model_search_obligations obligation")?;
        if expected_index != display_index {
            return Err(format!(
                "{label} ir_model_search_obligations[{display_index}].index must be {display_index}"
            ));
        }
        for field in [
            "description",
            "upstream",
            "predicate",
            "downstream",
            "expected",
        ] {
            verify_model_search_ir_artifact_field(actual, expected, field, display_index, label)?;
        }
        let actual_span = actual.get("source_span").ok_or_else(|| {
            format!("{label} model_search ir[{display_index}].source_span is missing")
        })?;
        let expected_span = expected.get("source_span").ok_or_else(|| {
            format!("{label} ir_model_search_obligations[{display_index}].source_span is missing")
        })?;
        if actual_span != expected_span {
            return Err(format!(
                "{label} model_search IR obligation mismatch for ir[{display_index}].source_span"
            ));
        }
    }
    Ok(())
}

fn verify_model_search_ir_artifact_field(
    actual_obligation: &Value,
    expected_obligation: &Value,
    field: &str,
    index: usize,
    label: &str,
) -> Result<(), String> {
    let actual = actual_obligation
        .get(field)
        .and_then(Value::as_str)
        .ok_or_else(|| format!("{label} model_search ir[{index}].{field} is not a string"))?;
    let expected = expected_obligation
        .get(field)
        .and_then(Value::as_str)
        .ok_or_else(|| {
            format!("{label} ir_model_search_obligations[{index}].{field} is not a string")
        })?;
    if actual != expected {
        return Err(format!(
            "{label} model_search IR obligation mismatch for ir[{index}].{field}: got `{actual}`, expected `{expected}`"
        ));
    }
    Ok(())
}

fn verify_model_search_artifact_obligations_artifact(
    entry: &Value,
    obligations: &[Value],
    artifact_searches: usize,
    label: &str,
) -> Result<(), String> {
    if artifact_searches == 0 {
        return Ok(());
    }
    let artifact = entry
        .get("artifact_model_search_obligations")
        .ok_or_else(|| format!("{label} missing artifact_model_search_obligations artifact"))?;
    if !artifact.is_object() {
        return Err(format!(
            "{label} artifact_model_search_obligations is not an object"
        ));
    }
    let schema = required_json_str(artifact, "schema", "artifact_model_search_obligations")?;
    if schema != "whipplescript.artifact_model_search_obligations.v0" {
        return Err(format!(
            "{label} artifact_model_search_obligations.schema must be whipplescript.artifact_model_search_obligations.v0"
        ));
    }
    let artifact_source_hash =
        required_json_str(artifact, "source_hash", "artifact_model_search_obligations")?;
    let report_source_hash = required_json_str(entry, "source_hash", label)?;
    if artifact_source_hash != report_source_hash {
        return Err(format!(
            "{label} artifact_model_search_obligations.source_hash does not match report source_hash"
        ));
    }
    let artifact_ir_hash =
        required_json_str(artifact, "ir_hash", "artifact_model_search_obligations")?;
    let report_ir_hash = required_json_str(entry, "ir_hash", label)?;
    if artifact_ir_hash != report_ir_hash {
        return Err(format!(
            "{label} artifact_model_search_obligations.ir_hash does not match report ir_hash"
        ));
    }
    let package_contract = entry
        .get("package_contract")
        .ok_or_else(|| format!("{label} missing package_contract"))?;
    let artifact_package_contract_digest = required_json_str(
        artifact,
        "package_contract_digest",
        "artifact_model_search_obligations",
    )?;
    let report_package_contract_digest = required_json_str(
        package_contract,
        "package_contract_digest",
        "package_contract",
    )?;
    if artifact_package_contract_digest != report_package_contract_digest {
        return Err(format!(
            "{label} artifact_model_search_obligations.package_contract_digest does not match report package_contract"
        ));
    }
    let graph = entry
        .get("construct_graph")
        .ok_or_else(|| format!("{label} missing construct_graph"))?;
    let artifact_graph_id = required_json_str(
        artifact,
        "construct_graph_id",
        "artifact_model_search_obligations",
    )?;
    let report_graph_id = required_json_str(graph, "graph_id", "construct_graph")?;
    if artifact_graph_id != report_graph_id {
        return Err(format!(
            "{label} artifact_model_search_obligations.construct_graph_id does not match report construct_graph"
        ));
    }
    let lowered = entry
        .get("lowered_ir_report")
        .ok_or_else(|| format!("{label} missing lowered_ir_report"))?;
    let artifact_accepted_program_digest = required_json_str(
        artifact,
        "accepted_program_digest",
        "artifact_model_search_obligations",
    )?;
    let report_accepted_program_digest =
        required_json_str(lowered, "accepted_program_digest", "lowered_ir_report")?;
    if artifact_accepted_program_digest != report_accepted_program_digest {
        return Err(format!(
            "{label} artifact_model_search_obligations.accepted_program_digest does not match lowered_ir_report"
        ));
    }
    let generator = required_json_str(artifact, "generator", "artifact_model_search_obligations")?;
    if generator.is_empty() {
        return Err(format!(
            "{label} artifact_model_search_obligations.generator must be non-empty"
        ));
    }
    let artifact_obligations = artifact
        .get("obligations")
        .and_then(Value::as_array)
        .ok_or_else(|| {
            format!("{label} artifact_model_search_obligations.obligations is not an array")
        })?;
    if artifact_obligations.len() != artifact_searches {
        return Err(format!(
            "{label} artifact_model_search_obligations count mismatch: got {}, expected {artifact_searches}",
            artifact_obligations.len()
        ));
    }
    let ledger_obligations = obligations
        .iter()
        .filter(|obligation| obligation.get("category").and_then(Value::as_str) != Some("ir"))
        .collect::<Vec<_>>();
    if ledger_obligations.len() != artifact_obligations.len() {
        return Err(format!(
            "{label} model_search artifact obligation count does not match artifact_model_search_obligations"
        ));
    }
    for (index, (actual, expected)) in ledger_obligations
        .iter()
        .zip(artifact_obligations.iter())
        .enumerate()
    {
        let display_index = index + 1;
        for field in [
            "category",
            "description",
            "upstream",
            "predicate",
            "downstream",
            "expected",
        ] {
            verify_model_search_artifact_artifact_field(
                actual,
                expected,
                field,
                display_index,
                label,
            )?;
        }
        let actual_index =
            required_json_usize(actual, "index", "model_search artifact obligation")?;
        let expected_index = required_json_usize(
            expected,
            "index",
            "artifact_model_search_obligations obligation",
        )?;
        let category = actual
            .get("category")
            .and_then(Value::as_str)
            .unwrap_or("artifact");
        if actual_index != expected_index {
            return Err(format!(
                "{label} model_search artifact obligation mismatch for {category}[{display_index}].index"
            ));
        }
        let actual_span = actual.get("source_span").ok_or_else(|| {
            format!("{label} model_search artifact[{display_index}].source_span is missing")
        })?;
        let expected_span = expected.get("source_span").ok_or_else(|| {
            format!(
                "{label} artifact_model_search_obligations[{display_index}].source_span is missing"
            )
        })?;
        if actual_span != expected_span {
            return Err(format!(
                "{label} model_search artifact obligation mismatch for {category}[{display_index}].source_span"
            ));
        }
    }
    Ok(())
}

fn verify_model_search_artifact_artifact_field(
    actual_obligation: &Value,
    expected_obligation: &Value,
    field: &str,
    index: usize,
    label: &str,
) -> Result<(), String> {
    let actual = actual_obligation
        .get(field)
        .and_then(Value::as_str)
        .ok_or_else(|| format!("{label} model_search artifact[{index}].{field} is not a string"))?;
    let expected = expected_obligation
        .get(field)
        .and_then(Value::as_str)
        .ok_or_else(|| {
            format!("{label} artifact_model_search_obligations[{index}].{field} is not a string")
        })?;
    if actual != expected {
        let category = actual_obligation
            .get("category")
            .and_then(Value::as_str)
            .unwrap_or("artifact");
        return Err(format!(
            "{label} model_search artifact obligation mismatch for {category}[{index}].{field}: got `{actual}`, expected `{expected}`"
        ));
    }
    Ok(())
}

fn verify_model_search_ir_obligation(
    obligation: &Value,
    index: usize,
    label: &str,
    snapshot_facts: &IrSnapshotFacts,
) -> Result<(), String> {
    for field in ["description", "upstream", "predicate", "downstream"] {
        let value = required_json_str(obligation, field, "model_search IR obligation")?;
        if value.is_empty() {
            return Err(format!(
                "{label} model_search ir obligation[{index}].{field} must be non-empty"
            ));
        }
    }
    let predicate = required_json_str(obligation, "predicate", "model_search IR obligation")?;
    if !matches!(
        predicate,
        "guard-true"
            | "guard-false"
            | "guard-error"
            | "succeeds"
            | "fails"
            | "completes"
            | "terminal-branch-match"
            | "terminal-branch-miss"
            | "terminal-branch-guard-false"
            | "terminal-exhaustive-miss"
            | "assertion-read-only"
            | "revision-active-rule"
            | "revision-stale-rule"
            | "revision-effect-attribution"
            | "revision-completes-cancelled"
    ) {
        return Err(format!(
            "{label} model_search ir obligation[{index}] has unknown generated predicate `{predicate}`"
        ));
    }
    let upstream = required_json_str(obligation, "upstream", "model_search IR obligation")?;
    let downstream = required_json_str(obligation, "downstream", "model_search IR obligation")?;
    if !snapshot_facts.supports_obligation(predicate, upstream, downstream) {
        return Err(format!(
            "{label} model_search ir obligation[{index}] is not supported by the embedded snapshot"
        ));
    }
    Ok(())
}

#[derive(Debug, Default)]
struct IrSnapshotFacts {
    rule_order: Vec<String>,
    rules: BTreeMap<String, IrSnapshotRuleFacts>,
    assertion_count: usize,
}

#[derive(Debug, Default)]
struct IrSnapshotRuleFacts {
    when_count: usize,
    guarded_when_count: usize,
    effects: BTreeSet<String>,
    effects_ordered: Vec<String>,
    dependencies: BTreeSet<(String, String, String)>,
    dependencies_ordered: Vec<(String, String, String)>,
    terminal_branch_count: usize,
    guarded_terminal_branch_count: usize,
    terminal_branches_guarded: Vec<bool>,
    terminal_branches: Vec<(String, bool)>,
}

impl IrSnapshotFacts {
    fn parse(snapshot: &str) -> Self {
        let mut facts = Self::default();
        let mut section = "";
        let mut current_rule: Option<String> = None;
        let mut current_rule_subsection = "";

        for line in snapshot.lines() {
            if !line.starts_with(' ') {
                section = line.split_whitespace().next().unwrap_or("");
                current_rule = None;
                current_rule_subsection = "";
                continue;
            }
            if section == "assertions" {
                if line.strip_prefix("  assert ").is_some() {
                    facts.assertion_count += 1;
                }
                continue;
            }
            if section != "rules" {
                continue;
            }
            if let Some(rule_name) = line.strip_prefix("  rule ") {
                current_rule = Some(rule_name.to_owned());
                if !facts.rules.contains_key(rule_name) {
                    facts.rule_order.push(rule_name.to_owned());
                    facts.rules.insert(rule_name.to_owned(), Default::default());
                }
                current_rule_subsection = "";
                continue;
            }
            let Some(rule_name) = current_rule.as_deref() else {
                continue;
            };
            let Some(rule) = facts.rules.get_mut(rule_name) else {
                continue;
            };
            if let Some(when) = line.strip_prefix("    when ") {
                rule.when_count += 1;
                if when.contains(" where ") {
                    rule.guarded_when_count += 1;
                }
                current_rule_subsection = "";
                continue;
            }
            match line {
                "    effects" => {
                    current_rule_subsection = "effects";
                    continue;
                }
                "    dependencies" => {
                    current_rule_subsection = "dependencies";
                    continue;
                }
                "    terminal_branches" => {
                    current_rule_subsection = "terminal_branches";
                    continue;
                }
                _ => {}
            }
            if line.starts_with("    ") && !line.starts_with("      ") {
                current_rule_subsection = "";
                continue;
            }
            let Some(value) = line.strip_prefix("      ") else {
                continue;
            };
            match current_rule_subsection {
                "effects" => {
                    if let Some(effect_id) = value.split_whitespace().next() {
                        if rule.effects.insert(effect_id.to_owned()) {
                            rule.effects_ordered.push(effect_id.to_owned());
                        }
                    }
                }
                "dependencies" => {
                    if let Some((upstream, predicate, downstream)) =
                        parse_snapshot_dependency(value)
                    {
                        rule.dependencies_ordered.push((
                            upstream.clone(),
                            predicate.clone(),
                            downstream.clone(),
                        ));
                        rule.dependencies.insert((upstream, predicate, downstream));
                    }
                }
                "terminal_branches" if value.starts_with("case ") => {
                    rule.terminal_branch_count += 1;
                    let tag = value.split_whitespace().nth(2).unwrap_or("_").to_owned();
                    let guarded = !value.contains(" guard=-");
                    rule.terminal_branches_guarded.push(guarded);
                    rule.terminal_branches.push((tag, guarded));
                    if guarded {
                        rule.guarded_terminal_branch_count += 1;
                    }
                }
                _ => {}
            }
        }
        facts
    }

    fn supports_obligation(&self, predicate: &str, upstream: &str, downstream: &str) -> bool {
        match predicate {
            "guard-true" | "guard-false" => {
                downstream == "ruleCommitEvt" && self.rule_has_guarded_when(upstream)
            }
            "guard-error" => {
                matches!(downstream, "diagnostic" | "ruleCommitEvt")
                    && self.rule_has_guarded_when(upstream)
            }
            "succeeds" | "fails" | "completes" => {
                self.has_dependency(upstream, predicate, downstream)
            }
            "terminal-branch-match" | "terminal-branch-miss" => {
                downstream == "ruleCommitEvt" && self.rule_has_terminal_branch(upstream)
            }
            "terminal-branch-guard-false" => {
                downstream == "ruleCommitEvt" && self.rule_has_guarded_terminal_branch(upstream)
            }
            "terminal-exhaustive-miss" => {
                downstream == "diagnostic" && self.rule_has_terminal_branch(upstream)
            }
            "assertion-read-only" => downstream == "ruleCommitEvt" && self.has_assertion(upstream),
            "revision-active-rule" | "revision-stale-rule" => self
                .rules
                .get(upstream)
                .is_some_and(|rule| rule.when_count > 0 && rule.effects.contains(downstream)),
            "revision-effect-attribution" => {
                downstream == "effectVersion"
                    && self
                        .rules
                        .values()
                        .any(|rule| rule.effects.contains(upstream))
            }
            "revision-completes-cancelled" => {
                self.has_dependency(upstream, "completes", downstream)
            }
            _ => false,
        }
    }

    fn expected_ir_search_count(&self) -> usize {
        self.expected_ir_outcome_counts().values().sum()
    }

    fn expected_ir_predicate_counts(&self) -> BTreeMap<String, usize> {
        let mut counts = BTreeMap::<String, usize>::new();
        for ((_, predicate, _, _), count) in self.expected_ir_outcome_counts() {
            Self::add_count(&mut counts, &predicate, count);
        }
        counts
    }

    fn expected_ir_endpoint_counts(&self) -> BTreeMap<(String, String, String), usize> {
        let mut counts = BTreeMap::<(String, String, String), usize>::new();
        for ((upstream, predicate, downstream, _), count) in self.expected_ir_outcome_counts() {
            Self::add_endpoint_count(&mut counts, &upstream, &predicate, &downstream, count);
        }
        counts
    }

    fn expected_ir_outcome_counts(&self) -> BTreeMap<(String, String, String, String), usize> {
        let mut counts = BTreeMap::<(String, String, String, String), usize>::new();
        for (_, upstream, predicate, downstream, outcome) in self.expected_ir_rows() {
            *counts
                .entry((upstream, predicate, downstream, outcome))
                .or_insert(0) += 1;
        }
        counts
    }

    fn expected_ir_sequence(&self) -> Vec<(String, String, String, String)> {
        self.expected_ir_rows()
            .into_iter()
            .map(|(_, upstream, predicate, downstream, outcome)| {
                (upstream, predicate, downstream, outcome)
            })
            .collect()
    }

    fn expected_ir_descriptions(&self) -> Vec<String> {
        self.expected_ir_rows()
            .into_iter()
            .map(|(description, _, _, _, _)| description)
            .collect()
    }

    fn expected_ir_rows(&self) -> Vec<(String, String, String, String, String)> {
        let mut sequence = Vec::new();
        for rule_name in &self.rule_order {
            let Some(rule) = self.rules.get(rule_name) else {
                continue;
            };
            for _ in 0..rule.guarded_when_count {
                sequence.push((
                    format!("{rule_name} true guard commits rule"),
                    rule_name.clone(),
                    "guard-true".to_owned(),
                    "ruleCommitEvt".to_owned(),
                    "solution".to_owned(),
                ));
                sequence.push((
                    format!("{rule_name} false guard cannot commit rule"),
                    rule_name.clone(),
                    "guard-false".to_owned(),
                    "ruleCommitEvt".to_owned(),
                    "no_solution".to_owned(),
                ));
                sequence.push((
                    format!("{rule_name} guard error emits diagnostic"),
                    rule_name.clone(),
                    "guard-error".to_owned(),
                    "diagnostic".to_owned(),
                    "solution".to_owned(),
                ));
                sequence.push((
                    format!("{rule_name} guard error cannot commit rule"),
                    rule_name.clone(),
                    "guard-error".to_owned(),
                    "ruleCommitEvt".to_owned(),
                    "no_solution".to_owned(),
                ));
            }
            for (upstream, predicate, downstream) in &rule.dependencies_ordered {
                sequence.push((
                    format!(
                        "{upstream} --{predicate}--> {downstream} cannot run before upstream terminal"
                    ),
                    upstream.clone(),
                    predicate.clone(),
                    downstream.clone(),
                    "no_solution".to_owned(),
                ));
                sequence.push((
                    format!(
                        "{upstream} --{predicate}--> {downstream} releases after satisfying terminal"
                    ),
                    upstream.clone(),
                    predicate.clone(),
                    downstream.clone(),
                    "solution".to_owned(),
                ));
                if matches!(predicate.as_str(), "succeeds" | "fails") {
                    sequence.push((
                        format!(
                            "{upstream} --{predicate}--> {downstream} does not release after non-satisfying terminal"
                        ),
                        upstream.clone(),
                        predicate.clone(),
                        downstream.clone(),
                        "no_solution".to_owned(),
                    ));
                }
            }
            if rule.when_count > 0 {
                if let Some(first_effect) = rule.effects_ordered.first() {
                    sequence.push((
                        format!("{rule_name} active revision scoped rule commits"),
                        rule_name.clone(),
                        "revision-active-rule".to_owned(),
                        first_effect.clone(),
                        "solution".to_owned(),
                    ));
                    sequence.push((
                        format!("{rule_name} stale revision scoped rule cannot commit"),
                        rule_name.clone(),
                        "revision-stale-rule".to_owned(),
                        first_effect.clone(),
                        "no_solution".to_owned(),
                    ));
                    sequence.push((
                        format!("{first_effect} old effect keeps revision attribution"),
                        first_effect.clone(),
                        "revision-effect-attribution".to_owned(),
                        "effectVersion".to_owned(),
                        "no_solution".to_owned(),
                    ));
                    for (upstream, predicate, downstream) in &rule.dependencies_ordered {
                        if predicate == "completes" {
                            sequence.push((
                                format!(
                                    "{upstream} --completes--> {downstream} releases after revision cancellation"
                                ),
                                upstream.clone(),
                                "revision-completes-cancelled".to_owned(),
                                downstream.clone(),
                                "solution".to_owned(),
                            ));
                        }
                    }
                }
            }
            for (tag, guarded) in &rule.terminal_branches {
                sequence.push((
                    format!("{rule_name} terminal {tag} branch commits on matching tag"),
                    rule_name.clone(),
                    "terminal-branch-match".to_owned(),
                    "ruleCommitEvt".to_owned(),
                    "solution".to_owned(),
                ));
                sequence.push((
                    format!("{rule_name} terminal {tag} branch misses on other tag"),
                    rule_name.clone(),
                    "terminal-branch-miss".to_owned(),
                    "ruleCommitEvt".to_owned(),
                    "no_solution".to_owned(),
                ));
                if *guarded {
                    sequence.push((
                        format!("{rule_name} terminal {tag} false guard cannot commit"),
                        rule_name.clone(),
                        "terminal-branch-guard-false".to_owned(),
                        "ruleCommitEvt".to_owned(),
                        "no_solution".to_owned(),
                    ));
                }
                sequence.push((
                    format!("{rule_name} terminal {tag} exhaustive miss diagnoses"),
                    rule_name.clone(),
                    "terminal-exhaustive-miss".to_owned(),
                    "diagnostic".to_owned(),
                    "solution".to_owned(),
                ));
            }
        }
        for assertion_index in 1..=self.assertion_count {
            let assertion = format!("assertion{assertion_index}");
            for result in ["aPass", "aFail", "aError"] {
                sequence.push((
                    format!("assertion {assertion_index} {result} cannot mutate runtime state"),
                    assertion.clone(),
                    "assertion-read-only".to_owned(),
                    "ruleCommitEvt".to_owned(),
                    "no_solution".to_owned(),
                ));
            }
        }
        sequence
    }

    fn add_count(counts: &mut BTreeMap<String, usize>, key: &str, amount: usize) {
        if amount > 0 {
            *counts.entry(key.to_owned()).or_insert(0) += amount;
        }
    }

    fn add_endpoint_count(
        counts: &mut BTreeMap<(String, String, String), usize>,
        upstream: &str,
        predicate: &str,
        downstream: &str,
        amount: usize,
    ) {
        if amount > 0 {
            *counts
                .entry((
                    upstream.to_owned(),
                    predicate.to_owned(),
                    downstream.to_owned(),
                ))
                .or_insert(0) += amount;
        }
    }

    fn rule_has_guarded_when(&self, rule_name: &str) -> bool {
        self.rules
            .get(rule_name)
            .is_some_and(|rule| rule.guarded_when_count > 0)
    }

    fn rule_has_terminal_branch(&self, rule_name: &str) -> bool {
        self.rules
            .get(rule_name)
            .is_some_and(|rule| rule.terminal_branch_count > 0)
    }

    fn rule_has_guarded_terminal_branch(&self, rule_name: &str) -> bool {
        self.rules
            .get(rule_name)
            .is_some_and(|rule| rule.guarded_terminal_branch_count > 0)
    }

    fn has_dependency(&self, upstream: &str, predicate: &str, downstream: &str) -> bool {
        self.rules.values().any(|rule| {
            rule.dependencies.contains(&(
                upstream.to_owned(),
                predicate.to_owned(),
                downstream.to_owned(),
            ))
        })
    }

    fn has_assertion(&self, upstream: &str) -> bool {
        upstream
            .strip_prefix("assertion")
            .and_then(|index| index.parse::<usize>().ok())
            .is_some_and(|index| index > 0 && index <= self.assertion_count)
    }
}

fn parse_snapshot_dependency(value: &str) -> Option<(String, String, String)> {
    let (upstream, rest) = value.split_once(" --")?;
    let (predicate, downstream) = rest.split_once("--> ")?;
    Some((
        upstream.to_owned(),
        predicate.to_owned(),
        downstream.to_owned(),
    ))
}

fn verify_model_search_artifact_obligations(
    obligations: &[Value],
    category: &str,
    expected: &[ExpectedSearch],
    label: &str,
) -> Result<(), String> {
    let actual = obligations
        .iter()
        .filter(|obligation| obligation.get("category").and_then(Value::as_str) == Some(category))
        .collect::<Vec<_>>();
    if actual.len() != expected.len() {
        return Err(format!(
            "{label} model_search {category} obligation count mismatch: got {}, expected {}",
            actual.len(),
            expected.len()
        ));
    }
    for (index, (actual, expected)) in actual.iter().zip(expected.iter()).enumerate() {
        let display_index = index + 1;
        verify_model_search_obligation_field(
            actual,
            "description",
            &expected.description,
            category,
            display_index,
            label,
        )?;
        verify_model_search_obligation_field(
            actual,
            "upstream",
            &expected.upstream,
            category,
            display_index,
            label,
        )?;
        verify_model_search_obligation_field(
            actual,
            "predicate",
            expected.predicate,
            category,
            display_index,
            label,
        )?;
        verify_model_search_obligation_field(
            actual,
            "downstream",
            &expected.downstream,
            category,
            display_index,
            label,
        )?;
        let actual_span = actual
            .get("source_span")
            .map(source_span_from_artifact_json)
            .unwrap_or(SourceSpan { start: 0, end: 0 });
        if actual_span != expected.span {
            return Err(format!(
                "{label} model_search artifact obligation mismatch for {category}[{display_index}].source_span"
            ));
        }
    }
    Ok(())
}

fn verify_model_search_obligation_field(
    obligation: &Value,
    field: &str,
    expected: &str,
    category: &str,
    index: usize,
    label: &str,
) -> Result<(), String> {
    let actual = obligation
        .get(field)
        .and_then(Value::as_str)
        .ok_or_else(|| {
            format!("{label} model_search {category}[{index}].{field} is not a string")
        })?;
    if actual != expected {
        return Err(format!(
            "{label} model_search artifact obligation mismatch for {category}[{index}].{field}: got `{actual}`, expected `{expected}`"
        ));
    }
    Ok(())
}

fn require_model_search_source_span(obligation: &Value) -> Result<(), String> {
    let span = obligation
        .get("source_span")
        .ok_or_else(|| "missing source_span".to_owned())?;
    let start = span
        .get("start")
        .and_then(Value::as_u64)
        .ok_or_else(|| "invalid source_span.start".to_owned())?;
    let end = span
        .get("end")
        .and_then(Value::as_u64)
        .ok_or_else(|| "invalid source_span.end".to_owned())?;
    if end < start {
        return Err("invalid source_span range".to_owned());
    }
    Ok(())
}

fn required_json_usize(value: &Value, field: &str, owner: &str) -> Result<usize, String> {
    value
        .get(field)
        .and_then(Value::as_u64)
        .and_then(|value| usize::try_from(value).ok())
        .ok_or_else(|| format!("{owner}.{field} must be a non-negative integer"))
}

fn required_json_str<'a>(value: &'a Value, field: &str, owner: &str) -> Result<&'a str, String> {
    value
        .get(field)
        .and_then(Value::as_str)
        .ok_or_else(|| format!("{owner}.{field} must be a string"))
}

fn verify_validator_fact_trace(
    artifact: &Value,
    owner_subsystem: &str,
    expected_facts: &[Value],
    artifact_name: &str,
) -> Result<(), String> {
    let actual_facts = artifact
        .get("derived_facts")
        .and_then(Value::as_array)
        .ok_or_else(|| format!("{artifact_name} is missing derived_facts"))?;
    let expected_by_predicate =
        validator_facts_by_predicate(expected_facts, owner_subsystem, artifact_name)?;
    let actual_owned = actual_facts
        .iter()
        .filter(|fact| fact.get("owner_subsystem").and_then(Value::as_str) == Some(owner_subsystem))
        .cloned()
        .collect::<Vec<_>>();
    let actual_by_predicate =
        validator_facts_by_predicate(&actual_owned, owner_subsystem, artifact_name)?;

    let missing = expected_by_predicate
        .keys()
        .filter(|predicate| !actual_by_predicate.contains_key(*predicate))
        .cloned()
        .collect::<Vec<_>>();
    if !missing.is_empty() {
        return Err(format!(
            "{artifact_name} derived_facts missing validator predicate(s): {}",
            preview_strings(&missing)
        ));
    }
    let extra = actual_by_predicate
        .keys()
        .filter(|predicate| !expected_by_predicate.contains_key(*predicate))
        .cloned()
        .collect::<Vec<_>>();
    if !extra.is_empty() {
        return Err(format!(
            "{artifact_name} derived_facts unexpected validator predicate(s): {}",
            preview_strings(&extra)
        ));
    }

    for (predicate, expected) in expected_by_predicate {
        let actual = actual_by_predicate
            .get(&predicate)
            .expect("missing predicates were checked above");
        if actual != &expected {
            return Err(format!(
                "{artifact_name} validator predicate `{predicate}` does not match recomputed evidence"
            ));
        }
    }
    Ok(())
}

fn validator_facts_by_predicate(
    facts: &[Value],
    owner_subsystem: &str,
    artifact_name: &str,
) -> Result<BTreeMap<String, Value>, String> {
    let mut by_predicate = BTreeMap::<String, Value>::new();
    let mut duplicates = Vec::new();
    for fact in facts {
        if fact.get("owner_subsystem").and_then(Value::as_str) != Some(owner_subsystem) {
            continue;
        }
        let Some(predicate) = fact.get("predicate").and_then(Value::as_str) else {
            return Err(format!(
                "{artifact_name} has validator fact without predicate"
            ));
        };
        if by_predicate
            .insert(predicate.to_owned(), fact.clone())
            .is_some()
        {
            duplicates.push(predicate.to_owned());
        }
    }
    if !duplicates.is_empty() {
        duplicates.sort();
        duplicates.dedup();
        return Err(format!(
            "{artifact_name} derived_facts duplicate validator predicate(s): {}",
            preview_strings(&duplicates)
        ));
    }
    Ok(by_predicate)
}

fn diagnostic_code_summary(diagnostics: &[Value]) -> String {
    let codes = diagnostics
        .iter()
        .filter_map(|diagnostic| diagnostic.get("code").and_then(Value::as_str))
        .map(str::to_owned)
        .collect::<Vec<_>>();
    if codes.is_empty() {
        format!("{} diagnostic(s)", diagnostics.len())
    } else {
        preview_strings(&codes)
    }
}

fn preview_strings(values: &[String]) -> String {
    let mut preview = values
        .iter()
        .take(8)
        .cloned()
        .collect::<Vec<_>>()
        .join(", ");
    if values.len() > 8 {
        preview.push_str(&format!(", ... ({} total)", values.len()));
    }
    preview
}

fn compile_failure_json_report(path: &str, error: CompileFailure) -> Value {
    match error {
        CompileFailure::Io(error) => {
            compile_json_error_report(Some(path), "io", Some(error.to_string()), None, None, None)
        }
        CompileFailure::Diagnostics {
            source: _,
            diagnostics,
        } => compile_json_error_report(
            Some(path),
            "diagnostics",
            None,
            Some(
                diagnostics
                    .iter()
                    .map(parser_diagnostic_to_json)
                    .collect::<Vec<_>>(),
            ),
            None,
            None,
        ),
    }
}

fn compile_json_error_report(
    path: Option<&str>,
    kind: &str,
    message: Option<String>,
    diagnostics: Option<Vec<Value>>,
    construct_graph: Option<Value>,
    lowered_ir_report: Option<Value>,
) -> Value {
    let mut error = serde_json::Map::new();
    error.insert("kind".to_owned(), Value::String(kind.to_owned()));
    if let Some(message) = message {
        error.insert("message".to_owned(), Value::String(message));
    }
    if let Some(diagnostics) = diagnostics {
        error.insert("diagnostics".to_owned(), Value::Array(diagnostics));
    }

    let mut report = serde_json::Map::new();
    report.insert(
        "schema".to_owned(),
        Value::String("whipplescript.compile_report.v0".to_owned()),
    );
    report.insert("status".to_owned(), Value::String("error".to_owned()));
    if let Some(path) = path {
        report.insert("path".to_owned(), Value::String(display_path(path)));
    }
    report.insert("error".to_owned(), Value::Object(error));
    if let Some(construct_graph) = construct_graph {
        report.insert("construct_graph".to_owned(), construct_graph);
    }
    if let Some(lowered_ir_report) = lowered_ir_report {
        report.insert("lowered_ir_report".to_owned(), lowered_ir_report);
    }
    Value::Object(report)
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct CompileOptions {
    model_search: bool,
    program_path: String,
    root: Option<String>,
    package_lock_path: Option<PathBuf>,
}

impl CompileOptions {
    fn parse(args: &[String]) -> Result<Self, String> {
        let mut model_search = false;
        let mut program_path = None;
        let mut root = None;
        let mut package_lock_path = None;
        let mut index = 0;
        while index < args.len() {
            match args[index].as_str() {
                "--model-search" => model_search = true,
                "--root" => {
                    index += 1;
                    let Some(value) = args.get(index) else {
                        return Err("expected workflow name after `--root`".to_owned());
                    };
                    root = Some(value.clone());
                }
                "--package-lock" => {
                    index += 1;
                    let Some(value) = args.get(index) else {
                        return Err("expected path after `--package-lock`".to_owned());
                    };
                    package_lock_path = Some(PathBuf::from(value));
                }
                other if other.starts_with('-') => {
                    return Err(format!("unknown compile option `{other}`"));
                }
                value if program_path.is_none() => program_path = Some(value.to_owned()),
                _ => {
                    return Err(
                        "usage: whip compile [--model-search] <workflow.whip> [--root Workflow]"
                            .to_owned(),
                    )
                }
            }
            index += 1;
        }
        let Some(program_path) = program_path else {
            return Err(
                "usage: whip compile [--model-search] <workflow.whip> [--root Workflow]".to_owned(),
            );
        };
        Ok(Self {
            model_search,
            program_path,
            root,
            package_lock_path,
        })
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct ReviseOptions {
    instance_id: String,
    program_path: String,
    root: Option<String>,
    dry_run: bool,
    cancellation_policy: String,
}

impl ReviseOptions {
    fn parse(args: &[String]) -> Result<Self, String> {
        let mut instance_id = None;
        let mut program_path = None;
        let mut root = None;
        let mut dry_run = false;
        let mut cancellation_policy = "keep".to_owned();
        let mut index = 0;
        while index < args.len() {
            match args[index].as_str() {
                "--root" => {
                    index += 1;
                    let Some(value) = args.get(index) else {
                        return Err("expected workflow name after `--root`".to_owned());
                    };
                    root = Some(value.clone());
                }
                "--dry-run" => dry_run = true,
                "--cancel" => {
                    index += 1;
                    let Some(value) = args.get(index) else {
                        return Err("expected policy after `--cancel`".to_owned());
                    };
                    cancellation_policy = match value.as_str() {
                        "keep" => "keep".to_owned(),
                        "queued" | "cancel_queued" | "cancel-queued" => "queued".to_owned(),
                        "running" | "request_running" | "request-running" => "running".to_owned(),
                        other => {
                            return Err(format!(
                                "unknown revision cancellation policy `{other}`; expected keep, queued, or running"
                            ));
                        }
                    };
                }
                other if other.starts_with('-') => {
                    return Err(format!("unknown revise option `{other}`"));
                }
                value if instance_id.is_none() => instance_id = Some(value.to_owned()),
                value if program_path.is_none() => program_path = Some(value.to_owned()),
                _ => {
                    return Err(
                        "usage: whip revise <instance> <workflow.whip> [--root Workflow] [--dry-run] [--cancel keep|queued|running]"
                            .to_owned(),
                    );
                }
            }
            index += 1;
        }
        let Some(instance_id) = instance_id else {
            return Err(
                "usage: whip revise <instance> <workflow.whip> [--root Workflow] [--dry-run] [--cancel keep|queued|running]"
                    .to_owned(),
            );
        };
        let Some(program_path) = program_path else {
            return Err(
                "usage: whip revise <instance> <workflow.whip> [--root Workflow] [--dry-run] [--cancel keep|queued|running]"
                    .to_owned(),
            );
        };
        Ok(Self {
            instance_id,
            program_path,
            root,
            dry_run,
            cancellation_policy,
        })
    }
}

fn revise(options: &CliOptions) -> ExitCode {
    let revise_options = match ReviseOptions::parse(&options.args) {
        Ok(options) => options,
        Err(message) => {
            eprintln!("{message}");
            return ExitCode::from(2);
        }
    };
    let store = match open_store(&options.store_path) {
        Ok(store) => store,
        Err(message) => {
            eprintln!("{message}");
            return ExitCode::FAILURE;
        }
    };
    let (source, ir) = match compile_source_path_with_root(
        &revise_options.program_path,
        revise_options.root.as_deref(),
    ) {
        Ok(compiled) => compiled,
        Err(error) => {
            if let Err(store_error) =
                persist_revision_source_bundle_diagnostic(&store, &revise_options, &error)
            {
                return report_store_error(
                    "failed to record revision source diagnostic",
                    store_error,
                );
            }
            return report_compile_failure(&revise_options.program_path, error);
        }
    };
    let snapshot = ir.to_snapshot();
    let source_hash = stable_hash_hex(&source);
    let ir_hash = stable_hash_hex(&snapshot);
    let analysis_summary_json = program_analysis_summary_json(&ir);
    let candidate_label = format!("candidate:{ir_hash}");

    let compatibility = match store.analyze_revision_candidate(
        &revise_options.instance_id,
        RevisionCandidate {
            candidate_version_id: &candidate_label,
            program_name: &ir.workflow,
            analysis_summary_json: &analysis_summary_json,
        },
    ) {
        Ok(report) => report,
        Err(error) => return report_store_error("failed to analyze revision", error),
    };
    let impact = match store.revision_cancellation_impact(
        &revise_options.instance_id,
        &revise_options.cancellation_policy,
    ) {
        Ok(impact) => impact,
        Err(error) => return report_store_error("failed to analyze cancellation impact", error),
    };
    let agent_impact = match revision_agent_impact(&store, &revise_options.instance_id, &ir) {
        Ok(impact) => impact,
        Err(error) => return report_store_error("failed to analyze agent impact", error),
    };

    if revise_options.dry_run {
        return emit_revision_dry_run(
            options,
            &revise_options,
            &ir,
            &source_hash,
            &ir_hash,
            &compatibility,
            &impact,
            &agent_impact,
        );
    }

    if !compatibility.compatible {
        if let Err(error) = persist_revision_compatibility_diagnostics(
            &store,
            &revise_options.instance_id,
            &compatibility,
        ) {
            return report_store_error("failed to record revision diagnostics", error);
        }
        emit_revision_report(
            options,
            &revise_options,
            &ir,
            &source_hash,
            &ir_hash,
            &compatibility,
            &impact,
            &agent_impact,
            None,
        );
        return ExitCode::FAILURE;
    }

    let mut kernel = RuntimeKernel::new(store);
    let version = match kernel.create_program_version_for_program(
        ProgramVersionInput {
            program_name: &ir.workflow,
            source_hash: &source_hash,
            ir_hash: &ir_hash,
            compiler_version: whipplescript_core::version(),
        },
        &ir,
    ) {
        Ok(version) => version,
        Err(error) => {
            eprintln!(
                "failed to create candidate program version: {}",
                store_error(error)
            );
            return ExitCode::FAILURE;
        }
    };
    let mut store = kernel.into_store();
    let activation_policy = json!({
        "source_path": display_path(&revise_options.program_path),
        "root_workflow": &ir.workflow,
        "source_hash": &source_hash,
        "ir_hash": &ir_hash,
        "compatibility": revision_compatibility_to_json(&compatibility),
        "cancellation": revision_cancellation_impact_to_json(&impact),
        "agent_impact": revision_agent_impact_to_json(&agent_impact),
    })
    .to_string();
    let activation = match store.activate_revision(RevisionActivation {
        instance_id: &revise_options.instance_id,
        from_version_id: &compatibility.active_version_id,
        to_version_id: &version.version_id,
        activation_policy_json: &activation_policy,
        cancellation_policy: &revise_options.cancellation_policy,
        idempotency_key: Some(&idempotency_key(&[
            &revise_options.instance_id,
            "revision",
            &compatibility.active_version_id,
            &version.version_id,
        ])),
    }) {
        Ok(revision) => revision,
        Err(error) => return report_store_error("failed to activate revision", error),
    };

    emit_revision_report(
        options,
        &revise_options,
        &ir,
        &source_hash,
        &ir_hash,
        &compatibility,
        &impact,
        &agent_impact,
        Some(&activation),
    );
    ExitCode::SUCCESS
}

const PACKAGE_LOCK_SCHEMA: &str = "whipplescript.package_lock.v0";
const PACKAGE_MANIFEST_SCHEMA: &str = "whipplescript.package_manifest.v0";

#[derive(Clone, Debug, Eq, PartialEq)]
struct PackageManifest {
    path: PathBuf,
    manifest_json: String,
    manifest_sha256: String,
    package_id: String,
    name: String,
    version: String,
    registry: ContractRegistry,
    /// `@tool` workflows this package exports for cross-package invocation
    /// (DR-0025). Derived + convergence-checked when the manifest is loaded, so a
    /// non-`@tool`/non-convergent export fails manifest validation on both the
    /// producer (`whip package`) and the consumer (`use`) side.
    workflow_tools: Vec<PackageWorkflowTool>,
}

/// A `@tool` workflow exported by a package (DR-0025 cross-package attestation):
/// the tool name, the resolved source path it is driven from, and the derived
/// input/output JSON schemas (canonical JSON strings) that make up its tool
/// contract.
#[derive(Clone, Debug, Eq, PartialEq)]
struct PackageWorkflowTool {
    name: String,
    source: PathBuf,
    input_schema: String,
    output_schema: String,
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct PackageCapabilityContract {
    input_schema: Option<String>,
    output_schema: Option<String>,
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct PackageProviderContract {
    capability: String,
    provider_kind: String,
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct LoadedPackageLock {
    path: PathBuf,
    manifests: Vec<PackageManifest>,
}

impl LoadedPackageLock {
    fn capability_contract(&self, capability: &str) -> Option<&EffectContract> {
        self.manifests
            .iter()
            .flat_map(|manifest| manifest.registry.effect_contracts.iter())
            .find(|contract| contract.id == capability && contract.effect_kind == "capability.call")
    }

    fn registry_for_ir(&self, ir: &IrProgram) -> Result<ContractRegistry, String> {
        let packages = self
            .manifests
            .iter()
            .map(|manifest| (manifest.name.as_str(), manifest))
            .collect::<BTreeMap<_, _>>();
        let imported = ir
            .uses
            .iter()
            .map(|use_decl| use_decl.name.as_str())
            .collect::<BTreeSet<_>>();
        let mut missing = Vec::new();
        let mut registry = ir.contract_registry();
        for library in imported {
            if library.starts_with("std.") {
                continue;
            }
            let Some(manifest) = packages.get(library).copied() else {
                missing.push(library.to_owned());
                continue;
            };
            registry.merge(manifest.registry.clone());
        }
        if !missing.is_empty() {
            return Err(format!(
                "package lock `{}` does not include imported {}",
                self.path.display(),
                missing
                    .iter()
                    .map(|name| format!("`{name}`"))
                    .collect::<Vec<_>>()
                    .join(", ")
            ));
        }
        validate_construct_uses(Some(self), ir, &registry)?;
        Ok(registry)
    }
}

fn contract_registry_for_ir(
    package_lock: Option<&LoadedPackageLock>,
    ir: &IrProgram,
) -> Result<ContractRegistry, String> {
    match package_lock {
        Some(lock) => lock.registry_for_ir(ir),
        None => {
            let registry = ir.contract_registry();
            validate_construct_uses(None, ir, &registry)?;
            Ok(registry)
        }
    }
}

fn validate_construct_uses(
    package_lock: Option<&LoadedPackageLock>,
    ir: &IrProgram,
    registry: &ContractRegistry,
) -> Result<(), String> {
    let uses = ir.construct_uses();
    let Some(package_lock) = package_lock else {
        // Without a lock, both a non-`std.` import and a package-owned construct
        // use are unsatisfiable. Name every blocker so a workflow that imports a
        // package without (yet) using a construct is still reported.
        //
        // EXCEPTION (1929 OPTION A): standard-library constructs are built into
        // the compiler, not fetched from a supply chain, so they are exempt from
        // the lock requirement. A construct use is exempt only when the (built-in)
        // registry authorizes it AND its owning library is `standard` — keying on a
        // recognized built-in registration, not a name, so a third-party package
        // cannot bypass the lock by claiming the std namespace. Modeled in
        // `models/maude/std-construct-authorization.maude`.
        let mut blockers = BTreeSet::new();
        for use_decl in &ir.uses {
            if !use_decl.name.starts_with("std.") {
                blockers.insert(format!("import `{}`", use_decl.name));
            }
        }
        for form in &uses {
            if construct_use_is_standard_builtin(registry, form) {
                continue;
            }
            blockers.insert(format!("construct `{}`", form.keyword));
        }
        if blockers.is_empty() {
            return Ok(());
        }
        return Err(format!(
            "{} requires a package lock; run `whip package sync` to create `{DEFAULT_PACKAGE_LOCK_FILE}`, or pass `--package-lock <path>`",
            blockers.into_iter().collect::<Vec<_>>().join(", ")
        ));
    };
    if uses.is_empty() {
        return Ok(());
    }
    for use_form in uses {
        let Some(form) = registry_construct_for_use(registry, use_form) else {
            return Err(format!(
                "package lock `{}` does not authorize `{}` as a {} {} construct lowering to `{}`",
                package_lock.path.display(),
                use_form.keyword,
                use_form.scope,
                use_form.construct_family,
                use_form.target_capability
            ));
        };
        if !registry.effect_contracts.iter().any(|contract| {
            contract.id == use_form.target_capability && contract.effect_kind == "capability.call"
        }) {
            return Err(format!(
                "construct `{}` lowers to `{}` but the locked registry has no matching `capability.call` effect contract",
                form.id, use_form.target_capability
            ));
        }
    }
    Ok(())
}

/// Whether a construct use is authorized by a standard-library built-in (1929
/// OPTION A): the registry must hold a matching construct registration AND a
/// matching `capability.call` effect contract, both owned by a `standard` library.
/// This is the lock exemption — keyed on a real built-in registration, never on a
/// name alone, so a third-party package cannot bypass the lock by claiming the std
/// namespace.
fn construct_use_is_standard_builtin(
    registry: &ContractRegistry,
    use_form: &IrConstructUse,
) -> bool {
    let Some(form) = registry_construct_for_use(registry, use_form) else {
        return false;
    };
    let library_is_standard = registry
        .libraries
        .iter()
        .any(|library| library.id == form.library_id && library.standard);
    if !library_is_standard {
        return false;
    }
    registry.effect_contracts.iter().any(|contract| {
        contract.id == use_form.target_capability
            && contract.effect_kind == "capability.call"
            && contract.library_id == form.library_id
    })
}

fn registry_construct_for_use<'a>(
    registry: &'a ContractRegistry,
    use_form: &IrConstructUse,
) -> Option<&'a ConstructRegistration> {
    registry.constructs.iter().find(|form| {
        form.keyword == use_form.keyword
            && form.scope == use_form.scope
            && form.construct_family == use_form.construct_family
            && form.lowering_target == use_form.lowering_target
            && form.target_capability.as_deref() == Some(use_form.target_capability.as_str())
    })
}

fn package(options: &CliOptions) -> ExitCode {
    let Some(command) = options.args.first().map(String::as_str) else {
        eprintln!("usage: whip package catalog | whip package check <manifest.json>... | whip package lock [--output <path>] <manifest.json>... | whip package sync [--file <whip.packages.json>] [--output <whip.lock>] [--check-only]");
        return ExitCode::from(2);
    };
    match command {
        "catalog" => package_catalog(&options.args[1..]),
        "check" => package_check(options, &options.args[1..]),
        "lock" => package_lock(options, &options.args[1..]),
        "sync" => package_sync(options, &options.args[1..]),
        other => {
            eprintln!("unknown package command `{other}`; expected catalog, check, lock, or sync");
            ExitCode::from(2)
        }
    }
}

fn package_catalog(args: &[String]) -> ExitCode {
    if !args.is_empty() {
        eprintln!("usage: whip package catalog");
        return ExitCode::from(2);
    }
    emit_json(platform_construct_catalog_json())
}

fn package_check(options: &CliOptions, args: &[String]) -> ExitCode {
    if args.is_empty() {
        eprintln!("usage: whip package check <manifest.json>...");
        return ExitCode::from(2);
    }
    let manifests = match load_package_manifests(args.iter().map(PathBuf::from).collect()) {
        Ok(manifests) => manifests,
        Err(message) => {
            if options.json {
                let _ = emit_json(json!({
                    "schema": "whipplescript.package_check.v0",
                    "status": "error",
                    "error": {"kind": "package_manifest", "message": message},
                }));
            } else {
                eprintln!("{message}");
            }
            return ExitCode::from(2);
        }
    };
    let registry = package_registry(&manifests);
    let diagnostics = registry.validate();
    let base_dir = std::env::current_dir().unwrap_or_else(|_| PathBuf::from("."));
    let package_lock_digest = package_lock_digest_for_manifests(&manifests, &base_dir);
    let package_contract =
        package_contract_json_from_manifests(&manifests, &package_lock_digest, &registry);
    if options.json {
        let code = if diagnostics.is_empty() {
            ExitCode::SUCCESS
        } else {
            ExitCode::FAILURE
        };
        let _ = emit_json(json!({
            "schema": "whipplescript.package_check.v0",
            "status": if diagnostics.is_empty() { "ok" } else { "error" },
            "platform_construct_catalog": platform_construct_catalog_json(),
            "manifests": manifests.iter().map(package_manifest_summary_json).collect::<Vec<_>>(),
            "contract_registry": contract_registry_to_json(&registry),
            "package_contract": package_contract,
        }));
        return code;
    }

    for manifest in &manifests {
        println!(
            "{} {}@{} {}",
            manifest.path.display(),
            manifest.name,
            manifest.version,
            manifest.manifest_sha256
        );
    }
    for diagnostic in &diagnostics {
        eprintln!("diagnostic {}: {}", diagnostic.code, diagnostic.message);
    }
    if diagnostics.is_empty() {
        ExitCode::SUCCESS
    } else {
        ExitCode::FAILURE
    }
}

fn package_lock(options: &CliOptions, args: &[String]) -> ExitCode {
    let mut output = None;
    let mut paths = Vec::new();
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--output" | "-o" => {
                index += 1;
                let Some(path) = args.get(index) else {
                    eprintln!("expected path after `--output`");
                    return ExitCode::from(2);
                };
                output = Some(PathBuf::from(path));
            }
            other if other.starts_with('-') => {
                eprintln!("unknown package lock option `{other}`");
                return ExitCode::from(2);
            }
            path => paths.push(PathBuf::from(path)),
        }
        index += 1;
    }
    if paths.is_empty() {
        eprintln!("usage: whip package lock [--output <path>] <manifest.json>...");
        return ExitCode::from(2);
    }
    let manifests = match load_package_manifests(paths) {
        Ok(manifests) => manifests,
        Err(message) => {
            eprintln!("{message}");
            return ExitCode::from(2);
        }
    };
    let registry = package_registry(&manifests);
    let diagnostics = registry.validate();
    if !diagnostics.is_empty() {
        for diagnostic in diagnostics {
            eprintln!("diagnostic {}: {}", diagnostic.code, diagnostic.message);
        }
        return ExitCode::FAILURE;
    }
    // Source paths are recorded relative to the lock's own directory so the
    // lock stays portable. When emitting to stdout there is no lock directory,
    // so fall back to the current directory.
    let base_dir = match &output {
        Some(path) => path
            .parent()
            .filter(|parent| !parent.as_os_str().is_empty())
            .map(Path::to_path_buf)
            .unwrap_or_else(|| PathBuf::from(".")),
        None => std::env::current_dir().unwrap_or_else(|_| PathBuf::from(".")),
    };
    let lock_json = package_lock_json(&manifests, &base_dir);
    let lock_text = canonical_lock_text(&lock_json);
    if let Some(path) = output {
        if let Some(parent) = path.parent() {
            if !parent.as_os_str().is_empty() {
                if let Err(error) = fs::create_dir_all(parent) {
                    eprintln!(
                        "failed to create package lock directory `{}`: {error}",
                        parent.display()
                    );
                    return ExitCode::FAILURE;
                }
            }
        }
        if let Err(error) = fs::write(&path, lock_text) {
            eprintln!("failed to write package lock `{}`: {error}", path.display());
            return ExitCode::FAILURE;
        }
        if options.json {
            emit_json(lock_json)
        } else {
            println!("wrote {}", path.display());
            ExitCode::SUCCESS
        }
    } else {
        print!("{lock_text}");
        ExitCode::SUCCESS
    }
}

const PACKAGE_SET_SCHEMA: &str = "whipplescript.package_set.v0";
const PACKAGE_SYNC_SCHEMA: &str = "whipplescript.package_sync.v0";
const DEFAULT_PACKAGE_SET_FILE: &str = "whip.packages.json";
const DEFAULT_PACKAGE_LOCK_FILE: &str = "whip.lock";

#[derive(Debug)]
struct PackageSyncDiagnostic {
    code: &'static str,
    message: String,
}

#[derive(Debug)]
struct PackageSyncResolution {
    package_set_path: PathBuf,
    package_lock_path: PathBuf,
    lock_json: Value,
    lock_text: String,
    package_lock_digest: String,
}

/// `whip package sync [--file <whip.packages.json>] [--output <whip.lock>] [--check-only]`
///
/// Reads the project intent file, validates referenced manifests and their
/// merged contract registry, and writes a deterministic, portable lock. With
/// `--check-only` it writes nothing and succeeds only when the regenerated lock
/// is byte-identical to the file on disk.
fn package_sync(options: &CliOptions, args: &[String]) -> ExitCode {
    let mut file = None;
    let mut output = None;
    let mut check_only = false;
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--file" | "-f" => {
                index += 1;
                let Some(path) = args.get(index) else {
                    eprintln!("expected path after `--file`");
                    return ExitCode::from(2);
                };
                file = Some(PathBuf::from(path));
            }
            "--output" | "-o" => {
                index += 1;
                let Some(path) = args.get(index) else {
                    eprintln!("expected path after `--output`");
                    return ExitCode::from(2);
                };
                output = Some(PathBuf::from(path));
            }
            "--check-only" => check_only = true,
            other => {
                eprintln!("unknown package sync option `{other}`");
                return ExitCode::from(2);
            }
        }
        index += 1;
    }

    match resolve_package_sync(file, output) {
        Ok(resolution) => package_sync_success(options, &resolution, check_only),
        Err(diagnostics) => package_sync_failure(options, diagnostics),
    }
}

/// Discover and validate the package set, then build the would-be lock. Returns
/// stable diagnostics on any failure so callers can render text or JSON output.
fn resolve_package_sync(
    file: Option<PathBuf>,
    output: Option<PathBuf>,
) -> Result<PackageSyncResolution, Vec<PackageSyncDiagnostic>> {
    let package_set_path = match file {
        Some(path) => {
            if !path.exists() {
                return Err(vec![PackageSyncDiagnostic {
                    code: "package_set.missing",
                    message: format!("package set `{}` does not exist", path.display()),
                }]);
            }
            path
        }
        None => match discover_ancestor_file(DEFAULT_PACKAGE_SET_FILE) {
            Some(path) => path,
            None => {
                return Err(vec![PackageSyncDiagnostic {
                    code: "package_set.missing",
                    message: format!(
                        "no `{DEFAULT_PACKAGE_SET_FILE}` found in the current directory or any ancestor"
                    ),
                }]);
            }
        },
    };

    let project_root = package_set_path
        .parent()
        .filter(|parent| !parent.as_os_str().is_empty())
        .map(Path::to_path_buf)
        .unwrap_or_else(|| PathBuf::from("."));

    let package_lock_path = output.unwrap_or_else(|| project_root.join(DEFAULT_PACKAGE_LOCK_FILE));

    let manifests = read_package_set(&package_set_path, &project_root)?;

    let registry = package_registry(&manifests);
    let contract_diagnostics = registry.validate();
    if !contract_diagnostics.is_empty() {
        return Err(contract_diagnostics
            .into_iter()
            .map(|diagnostic| PackageSyncDiagnostic {
                code: "package_contract.invalid",
                message: format!("{}: {}", diagnostic.code, diagnostic.message),
            })
            .collect());
    }

    // Lock source paths are recorded relative to the lock's directory.
    let lock_base_dir = package_lock_path
        .parent()
        .filter(|parent| !parent.as_os_str().is_empty())
        .map(Path::to_path_buf)
        .unwrap_or_else(|| PathBuf::from("."));
    let lock_json = package_lock_json(&manifests, &lock_base_dir);
    let lock_text = canonical_lock_text(&lock_json);
    let package_lock_digest = sha256_hex(canonical_json(&lock_json).as_bytes());

    Ok(PackageSyncResolution {
        package_set_path,
        package_lock_path,
        lock_json,
        lock_text,
        package_lock_digest,
    })
}

/// Search the current directory and its ancestors for `name`, returning the
/// first match.
fn discover_ancestor_file(name: &str) -> Option<PathBuf> {
    let start = std::env::current_dir().ok()?;
    discover_ancestor_file_from(&start, name)
}

/// Search for `name` in `start` and each of its ancestors. A relative `start` is
/// resolved against the current directory so the walk terminates at the
/// filesystem root rather than at the empty relative path.
fn discover_ancestor_file_from(start: &Path, name: &str) -> Option<PathBuf> {
    let start = if start.is_absolute() {
        start.to_path_buf()
    } else {
        std::env::current_dir().ok()?.join(start)
    };
    let mut dir = start.as_path();
    loop {
        let candidate = dir.join(name);
        if candidate.exists() {
            return Some(candidate);
        }
        dir = dir.parent()?;
    }
}

/// Parse and validate the package set, resolve each `path` source relative to
/// `project_root`, load each manifest, and check the optional identity
/// assertions.
fn read_package_set(
    package_set_path: &Path,
    project_root: &Path,
) -> Result<Vec<PackageManifest>, Vec<PackageSyncDiagnostic>> {
    let text = fs::read_to_string(package_set_path).map_err(|error| {
        vec![PackageSyncDiagnostic {
            code: "package_set.missing",
            message: format!(
                "failed to read package set `{}`: {error}",
                package_set_path.display()
            ),
        }]
    })?;
    let value = serde_json::from_str::<Value>(&text).map_err(|error| {
        vec![PackageSyncDiagnostic {
            code: "package_set.invalid_schema",
            message: format!(
                "failed to parse package set `{}`: {error}",
                package_set_path.display()
            ),
        }]
    })?;

    let mut problems = Vec::new();
    validate_package_set_closed_shape(&value, &mut problems);
    if !problems.is_empty() {
        return Err(problems
            .into_iter()
            .map(|message| PackageSyncDiagnostic {
                code: "package_set.invalid_schema",
                message,
            })
            .collect());
    }

    let packages = value
        .get("packages")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();

    let mut manifests = Vec::new();
    let mut diagnostics = Vec::new();
    let mut seen_names = BTreeSet::new();
    for (position, entry) in packages.iter().enumerate() {
        let label = format!("package set packages[{position}]");
        let name = entry
            .get("name")
            .and_then(Value::as_str)
            .unwrap_or_default()
            .to_owned();
        if !seen_names.insert(name.clone()) {
            diagnostics.push(PackageSyncDiagnostic {
                code: "package_set.duplicate_name",
                message: format!("{label} duplicates package name `{name}`"),
            });
            continue;
        }
        let source_path = entry
            .get("source")
            .and_then(|source| source.get("path"))
            .and_then(Value::as_str)
            .unwrap_or_default();
        if !is_portable_relative_path(source_path) {
            diagnostics.push(PackageSyncDiagnostic {
                code: "package_source.nonportable_path",
                message: format!(
                    "{label} source.path `{source_path}` must be project-relative and must not contain `..`"
                ),
            });
            continue;
        }
        let resolved = project_root.join(source_path);
        if let Err(message) = ensure_within_project_root(project_root, &resolved) {
            diagnostics.push(PackageSyncDiagnostic {
                code: "package_source.escapes_project",
                message: format!("{label} {message}"),
            });
            continue;
        }
        let manifest = match load_package_manifest(&resolved) {
            Ok(manifest) => manifest,
            Err(message) => {
                diagnostics.push(PackageSyncDiagnostic {
                    code: "package_manifest.invalid",
                    message,
                });
                continue;
            }
        };
        if manifest.name != name {
            diagnostics.push(PackageSyncDiagnostic {
                code: "package_set.identity_mismatch",
                message: format!(
                    "{label} expects package name `{name}` but manifest `{}` declares `{}`",
                    resolved.display(),
                    manifest.name
                ),
            });
            continue;
        }
        if let Some(expected_id) = entry.get("package_id").and_then(Value::as_str) {
            if manifest.package_id != expected_id {
                diagnostics.push(PackageSyncDiagnostic {
                    code: "package_set.identity_mismatch",
                    message: format!(
                        "{label} expects package_id `{expected_id}` but manifest declares `{}`",
                        manifest.package_id
                    ),
                });
                continue;
            }
        }
        if let Some(expected_version) = entry.get("version").and_then(Value::as_str) {
            if manifest.version != expected_version {
                diagnostics.push(PackageSyncDiagnostic {
                    code: "package_set.identity_mismatch",
                    message: format!(
                        "{label} expects version `{expected_version}` but manifest declares `{}`",
                        manifest.version
                    ),
                });
                continue;
            }
        }
        manifests.push(manifest);
    }

    if !diagnostics.is_empty() {
        return Err(diagnostics);
    }

    if let Err(message) = validate_loaded_package_set(&manifests, "package set") {
        return Err(message
            .lines()
            .map(|line| PackageSyncDiagnostic {
                code: "package_set.duplicate_name",
                message: line.to_owned(),
            })
            .collect());
    }

    Ok(manifests)
}

/// Reject sources that escape the project root after canonical resolution. When
/// canonicalization is unavailable (e.g. the manifest is missing) the lexical
/// portability check already ran, so this only tightens the symlink case.
fn ensure_within_project_root(project_root: &Path, resolved: &Path) -> Result<(), String> {
    let canonical_root = match project_root.canonicalize() {
        Ok(root) => root,
        Err(_) => return Ok(()),
    };
    let canonical_target = match resolved.canonicalize() {
        Ok(target) => target,
        Err(_) => return Ok(()),
    };
    if canonical_target.starts_with(&canonical_root) {
        Ok(())
    } else {
        Err(format!(
            "source `{}` escapes the project root `{}`",
            resolved.display(),
            project_root.display()
        ))
    }
}

fn validate_package_set_closed_shape(value: &Value, problems: &mut Vec<String>) {
    let Some(object) = value.as_object() else {
        problems.push("package set must be a JSON object".to_owned());
        return;
    };
    match object.get("schema").and_then(Value::as_str) {
        Some(PACKAGE_SET_SCHEMA) => {}
        Some(other) => problems.push(format!(
            "package set schema must be `{PACKAGE_SET_SCHEMA}`; got `{other}`"
        )),
        None => problems.push("package set must have a `schema` string".to_owned()),
    }
    for key in object.keys() {
        if key != "schema" && key != "packages" {
            problems.push(format!("package set has unexpected field `{key}`"));
        }
    }
    let Some(packages) = object.get("packages") else {
        problems.push("package set must have a `packages` array".to_owned());
        return;
    };
    let Some(packages) = packages.as_array() else {
        problems.push("package set `packages` must be an array".to_owned());
        return;
    };
    for (position, entry) in packages.iter().enumerate() {
        let label = format!("package set packages[{position}]");
        let Some(entry) = entry.as_object() else {
            problems.push(format!("{label} must be an object"));
            continue;
        };
        for key in entry.keys() {
            if !matches!(key.as_str(), "name" | "package_id" | "version" | "source") {
                problems.push(format!("{label} has unexpected field `{key}`"));
            }
        }
        match entry.get("name").and_then(Value::as_str) {
            Some(name) if !name.is_empty() => {}
            _ => problems.push(format!("{label}.name must be a non-empty string")),
        }
        match entry.get("source").and_then(Value::as_object) {
            Some(source) => {
                for key in source.keys() {
                    if key != "type" && key != "path" {
                        problems.push(format!("{label}.source has unexpected field `{key}`"));
                    }
                }
                match source.get("type").and_then(Value::as_str) {
                    Some("path") => {}
                    Some(other) => {
                        problems.push(format!("{label}.source.type must be `path`; got `{other}`"))
                    }
                    None => {
                        problems.push(format!("{label}.source.type must be a non-empty string"))
                    }
                }
                match source.get("path").and_then(Value::as_str) {
                    Some(path) if !path.is_empty() => {}
                    _ => problems.push(format!("{label}.source.path must be a non-empty string")),
                }
            }
            None => problems.push(format!("{label}.source must be an object")),
        }
    }
}

fn package_sync_success(
    options: &CliOptions,
    resolution: &PackageSyncResolution,
    check_only: bool,
) -> ExitCode {
    if check_only {
        let current = fs::read_to_string(&resolution.package_lock_path).ok();
        let identical = current.as_deref() == Some(resolution.lock_text.as_str());
        if identical {
            if options.json {
                return emit_json(package_sync_report_json(resolution, "ok", &[]));
            }
            println!(
                "package lock `{}` is up to date",
                resolution.package_lock_path.display()
            );
            return ExitCode::SUCCESS;
        }
        let message = match current {
            Some(_) => format!(
                "package lock `{}` is out of date; run `whip package sync`",
                resolution.package_lock_path.display()
            ),
            None => format!(
                "package lock `{}` is missing; run `whip package sync`",
                resolution.package_lock_path.display()
            ),
        };
        let diagnostics = vec![PackageSyncDiagnostic {
            code: "package_sync.lock_changed",
            message,
        }];
        if options.json {
            return emit_json(package_sync_report_json(resolution, "error", &diagnostics));
        }
        for diagnostic in &diagnostics {
            eprintln!("diagnostic {}: {}", diagnostic.code, diagnostic.message);
        }
        return ExitCode::FAILURE;
    }

    if let Some(parent) = resolution.package_lock_path.parent() {
        if !parent.as_os_str().is_empty() {
            if let Err(error) = fs::create_dir_all(parent) {
                eprintln!(
                    "failed to create package lock directory `{}`: {error}",
                    parent.display()
                );
                return ExitCode::FAILURE;
            }
        }
    }
    if let Err(error) = write_lock_atomically(&resolution.package_lock_path, &resolution.lock_text)
    {
        eprintln!(
            "failed to write package lock `{}`: {error}",
            resolution.package_lock_path.display()
        );
        return ExitCode::FAILURE;
    }
    if options.json {
        return emit_json(package_sync_report_json(resolution, "ok", &[]));
    }
    println!("wrote {}", resolution.package_lock_path.display());
    ExitCode::SUCCESS
}

fn package_sync_failure(options: &CliOptions, diagnostics: Vec<PackageSyncDiagnostic>) -> ExitCode {
    if options.json {
        let report = json!({
            "schema": PACKAGE_SYNC_SCHEMA,
            "status": "error",
            "package_set_path": "",
            "package_lock_path": "",
            "packages": [],
            "package_lock_digest": "0".repeat(64),
            "diagnostics": diagnostics
                .iter()
                .map(|diagnostic| json!({
                    "code": diagnostic.code,
                    "message": diagnostic.message,
                }))
                .collect::<Vec<_>>(),
        });
        return emit_json(report);
    }
    for diagnostic in &diagnostics {
        eprintln!("diagnostic {}: {}", diagnostic.code, diagnostic.message);
    }
    ExitCode::FAILURE
}

fn package_sync_report_json(
    resolution: &PackageSyncResolution,
    status: &str,
    diagnostics: &[PackageSyncDiagnostic],
) -> Value {
    let packages = resolution
        .lock_json
        .get("packages")
        .cloned()
        .unwrap_or_else(|| Value::Array(Vec::new()));
    json!({
        "schema": PACKAGE_SYNC_SCHEMA,
        "status": status,
        "package_set_path": resolution.package_set_path.display().to_string(),
        "package_lock_path": resolution.package_lock_path.display().to_string(),
        "packages": packages,
        "package_lock_digest": resolution.package_lock_digest,
        "diagnostics": diagnostics
            .iter()
            .map(|diagnostic| json!({
                "code": diagnostic.code,
                "message": diagnostic.message,
            }))
            .collect::<Vec<_>>(),
    })
}

/// Write `text` to `path` atomically: render to a sibling temp file in the same
/// directory and rename it over the target so a crash mid-write cannot corrupt
/// an existing good lock.
fn write_lock_atomically(path: &Path, text: &str) -> std::io::Result<()> {
    let dir = path
        .parent()
        .filter(|parent| !parent.as_os_str().is_empty());
    let file_name = path
        .file_name()
        .map(|name| name.to_string_lossy().into_owned())
        .unwrap_or_else(|| DEFAULT_PACKAGE_LOCK_FILE.to_owned());
    let temp_name = format!(".{file_name}.{}.tmp", std::process::id());
    let temp_path = match dir {
        Some(dir) => dir.join(temp_name),
        None => PathBuf::from(temp_name),
    };
    fs::write(&temp_path, text)?;
    match fs::rename(&temp_path, path) {
        Ok(()) => Ok(()),
        Err(error) => {
            let _ = fs::remove_file(&temp_path);
            Err(error)
        }
    }
}

fn load_package_manifests(paths: Vec<PathBuf>) -> Result<Vec<PackageManifest>, String> {
    let mut manifests = paths
        .into_iter()
        .map(|path| load_package_manifest(&path))
        .collect::<Result<Vec<_>, _>>()?;
    manifests.sort_by(|left, right| left.name.cmp(&right.name));
    validate_loaded_package_set(&manifests, "package inputs")?;
    Ok(manifests)
}

fn validate_loaded_package_set(manifests: &[PackageManifest], owner: &str) -> Result<(), String> {
    let mut package_ids = BTreeSet::new();
    let mut names = BTreeSet::new();
    let mut problems = Vec::new();
    for manifest in manifests {
        if !package_ids.insert(manifest.package_id.clone()) {
            problems.push(format!(
                "{owner} include package_id `{}` more than once",
                manifest.package_id
            ));
        }
        if !names.insert(manifest.name.clone()) {
            problems.push(format!(
                "{owner} include package name `{}` more than once",
                manifest.name
            ));
        }
    }
    if problems.is_empty() {
        Ok(())
    } else {
        Err(problems.join("\n"))
    }
}

fn load_package_manifest(path: &Path) -> Result<PackageManifest, String> {
    let manifest_json = fs::read_to_string(path).map_err(|error| {
        format!(
            "failed to read package manifest `{}`: {error}",
            path.display()
        )
    })?;
    package_manifest_from_json(path, manifest_json)
}

fn package_manifest_from_json(
    path: &Path,
    manifest_json: String,
) -> Result<PackageManifest, String> {
    let value = serde_json::from_str::<Value>(&manifest_json).map_err(|error| {
        format!(
            "failed to parse package manifest `{}`: {error}",
            path.display()
        )
    })?;
    let schema = required_json_string(&value, "schema", "package manifest")?;
    if schema != PACKAGE_MANIFEST_SCHEMA {
        return Err(format!(
            "package manifest `{}` has unsupported schema `{schema}`; expected `{PACKAGE_MANIFEST_SCHEMA}`",
            path.display()
        ));
    }
    validate_package_manifest_closed_shape(path, &value)?;
    let package_id = required_json_string(&value, "package_id", "package manifest")?;
    let name = required_json_string(&value, "name", "package manifest")?;
    let version = required_json_string(&value, "version", "package manifest")?;

    validate_package_manifest_identity_uniqueness(path, &value)?;
    let capabilities = package_capability_contracts(path, &value)?;
    let providers = package_provider_contracts(path, &value)?;
    let registry =
        package_manifest_registry(path, &value, &name, &version, &capabilities, &providers)?;
    validate_package_manifest_consistency(path, &value, &capabilities, &providers, &registry)?;
    let workflow_tools = package_manifest_workflow_tools(path, &value)?;

    Ok(PackageManifest {
        path: path.to_path_buf(),
        manifest_sha256: sha256_hex(manifest_json.as_bytes()),
        manifest_json,
        package_id,
        name,
        version,
        registry,
        workflow_tools,
    })
}

/// Parse, validate, and derive the attestation for a package's exported `@tool`
/// workflows (DR-0025). Each entry names a workflow and a source path relative to
/// the manifest; the source is compiled (with `root = name`) and convergence-
/// checked here, so a non-`@tool`/non-convergent export fails manifest loading on
/// both the producer and the consumer. The input/output contracts are derived
/// into JSON schemas — the cross-package tool contract a consumer checks against.
fn package_manifest_workflow_tools(
    path: &Path,
    value: &Value,
) -> Result<Vec<PackageWorkflowTool>, String> {
    let Some(entries) = value.get("workflow_tools") else {
        return Ok(Vec::new());
    };
    let entries = entries.as_array().ok_or_else(|| {
        format!(
            "package manifest `{}` field `workflow_tools` must be an array",
            path.display()
        )
    })?;
    let manifest_dir = path.parent().unwrap_or_else(|| Path::new("."));
    let mut tools = Vec::new();
    let mut seen = BTreeSet::new();
    for entry in entries {
        let name = required_json_string(entry, "name", "workflow_tools entry")?;
        let source_rel = required_json_string(entry, "source", "workflow_tools entry")?;
        if !seen.insert(name.clone()) {
            return Err(format!(
                "package manifest `{}` exports workflow tool `{name}` more than once",
                path.display()
            ));
        }
        let source = manifest_dir.join(&source_rel);
        let (_, ir) =
            compile_source_path_for_validation(source.to_str().unwrap_or_default(), Some(&name))
                .map_err(|error| {
                    format!(
                        "package manifest `{}` workflow tool `{name}`: {}",
                        path.display(),
                        child_compile_error(&name, error)
                    )
                })?;
        if ir.workflow != name {
            return Err(format!(
                "package manifest `{}` workflow tool `{name}`: source `{}` declares workflow `{}`",
                path.display(),
                source.display(),
                ir.workflow
            ));
        }
        let is_tool = ir.source_tags.iter().any(|tag| {
            tag.target_kind == "workflow" && tag.target == ir.workflow && tag.name == "tool"
        });
        if !is_tool {
            return Err(format!(
                "package manifest `{}` exports `{name}` as a workflow tool, but it is not tagged `@tool`",
                path.display()
            ));
        }
        let input_schema = ir
            .workflow_contracts
            .iter()
            .find(|contract| contract.kind == IrWorkflowContractKind::Input)
            .map(|contract| {
                whipplescript_kernel::coerce_native::json_schema_for_type(&contract.ty, &ir.schemas)
            })
            .unwrap_or_else(|| json!({ "type": "object", "additionalProperties": false }));
        let output_schema = ir
            .workflow_contracts
            .iter()
            .find(|contract| contract.kind == IrWorkflowContractKind::Output)
            .map(|contract| {
                whipplescript_kernel::coerce_native::json_schema_for_type(&contract.ty, &ir.schemas)
            })
            .unwrap_or_else(|| json!({ "type": "object", "additionalProperties": false }));
        tools.push(PackageWorkflowTool {
            name,
            source,
            input_schema: input_schema.to_string(),
            output_schema: output_schema.to_string(),
        });
    }
    Ok(tools)
}

fn validate_package_manifest_consistency(
    path: &Path,
    value: &Value,
    capabilities: &BTreeMap<String, PackageCapabilityContract>,
    providers: &[PackageProviderContract],
    registry: &ContractRegistry,
) -> Result<(), String> {
    let declared_capabilities = capabilities.keys().cloned().collect::<BTreeSet<_>>();
    let mut provider_kinds_by_capability = BTreeMap::<String, BTreeSet<String>>::new();
    let mut problems = Vec::new();

    for provider in providers {
        provider_kinds_by_capability
            .entry(provider.capability.clone())
            .or_default()
            .insert(provider.provider_kind.clone());
        validate_declared_capability(
            path,
            &declared_capabilities,
            &provider.capability,
            &format!("provider `{}`", provider.provider_kind),
            &mut problems,
        );
    }

    for contract in &registry.effect_contracts {
        if contract.effect_kind != "capability.call" {
            problems.push(format!(
                "effect contract `{}` uses unsupported effect_kind `{}`; packages currently support only `capability.call`",
                contract.id, contract.effect_kind
            ));
        }
        validate_declared_capability(
            path,
            &declared_capabilities,
            &contract.id,
            &format!("effect contract `{}`", contract.id),
            &mut problems,
        );
        for capability in &contract.required_capabilities {
            validate_declared_capability(
                path,
                &declared_capabilities,
                capability,
                &format!("effect contract `{}` required_capabilities", contract.id),
                &mut problems,
            );
        }
    }

    for form in &registry.constructs {
        let family = PLATFORM_CONSTRUCT_CATALOG.family(&form.construct_family);
        let lowering = PLATFORM_CONSTRUCT_CATALOG.lowering(&form.lowering_target);
        if family.is_none() {
            problems.push(format!(
                "construct `{}` uses unsupported construct_family `{}`; expected one of {}",
                form.id,
                form.construct_family,
                quoted_platform_values(PLATFORM_CONSTRUCT_CATALOG.family_ids())
            ));
        }
        match lowering {
            Some(lowering) => {
                if family.is_some()
                    && !lowering
                        .compatible_families
                        .contains(&form.construct_family.as_str())
                {
                    let expected = quoted_platform_values(
                        PLATFORM_CONSTRUCT_CATALOG
                            .lowerings_for_family(&form.construct_family)
                            .filter(|lowering| lowering.package_authorable)
                            .map(|lowering| lowering.id),
                    );
                    if form.lowering_target == CONSTRUCT_LOWERING_CAPABILITY_CALL {
                        problems.push(format!(
                            "construct `{}` uses capability_call lowering but construct_family is `{}`; expected `{}`",
                            form.id, form.construct_family, CONSTRUCT_FAMILY_EFFECT_OPERATION
                        ));
                    } else {
                        problems.push(format!(
                            "construct `{}` is a {} but uses lowering_target `{}`; expected one of {}",
                            form.id, form.construct_family, form.lowering_target, expected
                        ));
                    }
                }
                if !lowering.package_authorable {
                    problems.push(format!(
                        "construct `{}` uses platform-internal lowering_target `{}`; package constructs must use an authorable platform lowering",
                        form.id, form.lowering_target
                    ));
                }
                if let Some(required_scope) = lowering.required_scope {
                    if form.scope != required_scope {
                        problems.push(format!(
                            "construct `{}` uses {} lowering in unsupported scope `{}`; {} forms are currently {} only",
                            form.id,
                            lowering.id,
                            form.scope,
                            lowering.id,
                            required_scope
                        ));
                    }
                }
                match lowering.target_capability {
                    ConstructTargetCapabilityPolicy::Forbidden => {
                        if form.target_capability.is_some() {
                            problems.push(format!(
                                "construct `{}` is {} but declares target_capability",
                                form.id, lowering.id
                            ));
                        }
                    }
                    ConstructTargetCapabilityPolicy::RequiredCapabilityCallContract => {
                        let Some(target_capability) = form.target_capability.as_deref() else {
                            problems.push(format!(
                                "construct `{}` uses {} lowering but has no target_capability",
                                form.id, lowering.id
                            ));
                            continue;
                        };
                        validate_declared_capability(
                            path,
                            &declared_capabilities,
                            target_capability,
                            &format!("construct `{}` target_capability", form.id),
                            &mut problems,
                        );
                        let target_contract = registry.effect_contracts.iter().find(|contract| {
                            contract.id == target_capability
                                && contract.effect_kind == "capability.call"
                        });
                        if let Some(contract) = target_contract {
                            validate_construct_input_schema_fields(form, contract, &mut problems);
                        } else {
                            problems.push(format!(
                                "construct `{}` lowers to `{target_capability}` but no matching `capability.call` effect contract is declared",
                                form.id
                            ));
                        }
                    }
                }
            }
            None => {
                problems.push(format!(
                    "construct `{}` uses unsupported lowering_target `{}`; expected one of {}",
                    form.id,
                    form.lowering_target,
                    quoted_platform_values(
                        PLATFORM_CONSTRUCT_CATALOG
                            .lowerings
                            .iter()
                            .filter(|lowering| lowering.package_authorable)
                            .map(|lowering| lowering.id),
                    )
                ));
            }
        }
        if !PLATFORM_CONSTRUCT_CATALOG.contains_scope(&form.scope) {
            problems.push(format!(
                "construct `{}` uses unsupported scope `{}`; expected one of {}",
                form.id,
                form.scope,
                quoted_platform_values(PLATFORM_CONSTRUCT_CATALOG.scopes.iter().copied())
            ));
        }
        if let Some(error) = reserved_keyword_privilege_error(
            &form.library_id,
            &form.keyword,
            &form.construct_family,
            &form.scope,
            &form.lowering_target,
        ) {
            problems.push(format!("construct `{}` {error}", form.id));
        }
        for field in &form.fields {
            if !PLATFORM_CONSTRUCT_CATALOG.contains_field_kind(&field.kind) {
                problems.push(format!(
                    "construct `{}` field `{}` uses unsupported kind `{}`; expected one of {}",
                    form.id,
                    field.name,
                    field.kind,
                    quoted_platform_values(PLATFORM_CONSTRUCT_CATALOG.field_kinds.iter().copied())
                ));
            }
        }
        validate_construct_interface_records(path, form, &declared_capabilities, &mut problems);
        if let Some(lowering) = lowering {
            validate_construct_lowering_interfaces(form, lowering, &mut problems);
        }
    }

    for profile in value
        .get("profiles")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
    {
        let profile_name = optional_json_string(profile, "name")
            .or_else(|| optional_json_string(profile, "id"))
            .unwrap_or_else(|| "<unnamed>".to_owned());
        for capability in
            optional_json_string_array(profile, "allowed_capabilities").unwrap_or_default()
        {
            validate_declared_capability(
                path,
                &declared_capabilities,
                &capability,
                &format!("profile `{profile_name}` allowed_capabilities"),
                &mut problems,
            );
        }
    }

    for binding in value
        .get("bindings")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
    {
        let binding_name =
            optional_json_string(binding, "id").unwrap_or_else(|| "<unnamed>".to_owned());
        let capability = match required_json_string(binding, "capability", "binding") {
            Ok(capability) => capability,
            Err(message) => {
                problems.push(format!("{message} in `{}`", path.display()));
                continue;
            }
        };
        validate_declared_capability(
            path,
            &declared_capabilities,
            &capability,
            &format!("binding `{binding_name}`"),
            &mut problems,
        );
        let provider_kind = match required_json_string(binding, "provider", "binding") {
            Ok(provider_kind) => provider_kind,
            Err(message) => {
                problems.push(format!("{message} in `{}`", path.display()));
                continue;
            }
        };
        match provider_kinds_by_capability.get(&capability) {
            Some(kinds) if kinds.contains(&provider_kind) => {}
            Some(kinds) => problems.push(format!(
                "binding `{binding_name}` in `{}` references provider `{provider_kind}` for capability `{capability}`, but declared providers for that capability are: {}",
                path.display(),
                kinds.iter()
                    .map(|kind| format!("`{kind}`"))
                    .collect::<Vec<_>>()
                    .join(", ")
            )),
            None => problems.push(format!(
                "binding `{binding_name}` in `{}` references capability `{capability}` without a provider",
                path.display()
            )),
        }
    }

    if problems.is_empty() {
        Ok(())
    } else {
        Err(format!(
            "package manifest `{}` has invalid package contracts:\n- {}",
            path.display(),
            problems.join("\n- ")
        ))
    }
}

fn validate_package_manifest_closed_shape(path: &Path, value: &Value) -> Result<(), String> {
    let mut problems = Vec::new();
    validate_manifest_object_fields(
        value,
        "package manifest",
        &[
            "schema",
            "package_id",
            "name",
            "version",
            "libraries",
            "capabilities",
            "providers",
            "profiles",
            "bindings",
            "workflow_tools",
        ],
        &mut problems,
    );
    validate_manifest_required_fields(
        value,
        "package manifest",
        &["schema", "package_id", "name", "version"],
        &mut problems,
    );
    validate_manifest_array_objects(
        value,
        "package manifest",
        "workflow_tools",
        &mut problems,
        |tool, label, problems| {
            validate_manifest_object_fields(tool, &label, &["name", "source"], problems);
            validate_manifest_required_fields(tool, &label, &["name", "source"], problems);
            validate_manifest_string_fields(tool, &label, &["name", "source"], problems);
        },
    );
    validate_manifest_string_fields(
        value,
        "package manifest",
        &["schema", "package_id", "name", "version"],
        &mut problems,
    );

    validate_manifest_array_objects(
        value,
        "package manifest",
        "libraries",
        &mut problems,
        |library, label, problems| {
            validate_manifest_object_fields(
                library,
                &label,
                &[
                    "id",
                    "version",
                    "standard",
                    "effect_contracts",
                    "effects",
                    "constructs",
                ],
                problems,
            );
            validate_manifest_required_fields(library, &label, &["id"], problems);
            validate_manifest_string_fields(library, &label, &["id", "version"], problems);
            validate_manifest_bool_fields(library, &label, &["standard"], problems);
            for field in ["effect_contracts", "effects"] {
                validate_manifest_array_objects(
                    library,
                    &label,
                    field,
                    problems,
                    |contract, label, problems| {
                        validate_manifest_object_fields(
                            contract,
                            &label,
                            &[
                                "id",
                                "effect_kind",
                                "core_effect_kind",
                                "source_forms",
                                "input_schema",
                                "output_schema",
                                "required_capabilities",
                                "provider_kinds",
                                "projected_facts",
                                "validation",
                            ],
                            problems,
                        );
                        validate_manifest_required_fields(contract, &label, &["id"], problems);
                        validate_manifest_string_fields(
                            contract,
                            &label,
                            &["id", "effect_kind", "core_effect_kind", "validation"],
                            problems,
                        );
                        validate_manifest_string_array_fields(
                            contract,
                            &label,
                            &[
                                "source_forms",
                                "required_capabilities",
                                "provider_kinds",
                                "projected_facts",
                            ],
                            problems,
                        );
                    },
                );
            }
            validate_manifest_array_objects(
                library,
                &label,
                "constructs",
                problems,
                |construct, label, problems| {
                    validate_manifest_object_fields(
                        construct,
                        &label,
                        &[
                            "id",
                            "construct_family",
                            "keyword",
                            "scope",
                            "fields",
                            "requires",
                            "provides",
                            "lowering_target",
                            "target_capability",
                        ],
                        problems,
                    );
                    validate_manifest_required_fields(
                        construct,
                        &label,
                        &["id", "construct_family", "keyword"],
                        problems,
                    );
                    validate_manifest_string_fields(
                        construct,
                        &label,
                        &[
                            "id",
                            "construct_family",
                            "keyword",
                            "scope",
                            "lowering_target",
                            "target_capability",
                        ],
                        problems,
                    );
                    validate_manifest_array_objects(
                        construct,
                        &label,
                        "fields",
                        problems,
                        |field, label, problems| {
                            validate_manifest_object_fields(
                                field,
                                &label,
                                &["name", "kind", "required"],
                                problems,
                            );
                            validate_manifest_required_fields(
                                field,
                                &label,
                                &["name", "kind"],
                                problems,
                            );
                            validate_manifest_string_fields(
                                field,
                                &label,
                                &["name", "kind"],
                                problems,
                            );
                            validate_manifest_bool_fields(field, &label, &["required"], problems);
                        },
                    );
                    for direction in ["requires", "provides"] {
                        validate_manifest_array_objects(
                            construct,
                            &label,
                            direction,
                            problems,
                            |interface, label, problems| {
                                validate_manifest_object_fields(
                                    interface,
                                    &label,
                                    &["kind", "name", "type", "type_ref", "phase", "cardinality"],
                                    problems,
                                );
                                validate_manifest_required_fields(
                                    interface,
                                    &label,
                                    &["kind"],
                                    problems,
                                );
                                validate_manifest_string_fields(
                                    interface,
                                    &label,
                                    &["kind", "name", "type", "type_ref", "phase", "cardinality"],
                                    problems,
                                );
                            },
                        );
                    }
                },
            );
        },
    );

    validate_manifest_array_objects(
        value,
        "package manifest",
        "capabilities",
        &mut problems,
        |capability, label, problems| {
            validate_manifest_object_fields(
                capability,
                &label,
                &[
                    "id",
                    "description",
                    "schema",
                    "input_schema",
                    "output_schema",
                ],
                problems,
            );
            validate_manifest_required_fields(capability, &label, &["id"], problems);
            validate_manifest_string_fields(capability, &label, &["id", "description"], problems);
        },
    );
    validate_manifest_array_objects(
        value,
        "package manifest",
        "providers",
        &mut problems,
        |provider, label, problems| {
            validate_manifest_object_fields(
                provider,
                &label,
                &[
                    "id",
                    "provider_kind",
                    "capability",
                    "effect_kind",
                    "core_effect_kind",
                    "config",
                ],
                problems,
            );
            validate_manifest_required_fields(
                provider,
                &label,
                &["id", "provider_kind", "capability"],
                problems,
            );
            validate_manifest_string_fields(
                provider,
                &label,
                &[
                    "id",
                    "provider_kind",
                    "capability",
                    "effect_kind",
                    "core_effect_kind",
                ],
                problems,
            );
        },
    );
    validate_manifest_array_objects(
        value,
        "package manifest",
        "profiles",
        &mut problems,
        |profile, label, problems| {
            validate_manifest_object_fields(
                profile,
                &label,
                &[
                    "id",
                    "name",
                    "description",
                    "enforcement_mode",
                    "allowed_capabilities",
                    "config",
                ],
                problems,
            );
            validate_manifest_required_fields(
                profile,
                &label,
                &["id", "name", "allowed_capabilities"],
                problems,
            );
            validate_manifest_string_fields(
                profile,
                &label,
                &["id", "name", "description", "enforcement_mode"],
                problems,
            );
            validate_manifest_string_array_fields(
                profile,
                &label,
                &["allowed_capabilities"],
                problems,
            );
        },
    );
    validate_manifest_array_objects(
        value,
        "package manifest",
        "bindings",
        &mut problems,
        |binding, label, problems| {
            validate_manifest_object_fields(
                binding,
                &label,
                &["id", "program_id", "capability", "provider", "config"],
                problems,
            );
            validate_manifest_required_fields(
                binding,
                &label,
                &["id", "capability", "provider"],
                problems,
            );
            validate_manifest_string_fields(
                binding,
                &label,
                &["id", "capability", "provider"],
                problems,
            );
            validate_manifest_nullable_string_fields(binding, &label, &["program_id"], problems);
        },
    );

    if problems.is_empty() {
        Ok(())
    } else {
        Err(format!(
            "package manifest `{}` does not match closed package schema:\n- {}",
            path.display(),
            problems.join("\n- ")
        ))
    }
}

fn validate_manifest_object_fields(
    value: &Value,
    label: &str,
    allowed_fields: &[&str],
    problems: &mut Vec<String>,
) {
    let Some(object) = value.as_object() else {
        problems.push(format!("{label} must be an object"));
        return;
    };
    let allowed = allowed_fields.iter().copied().collect::<BTreeSet<_>>();
    for key in object.keys() {
        if !allowed.contains(key.as_str()) {
            problems.push(format!("{label} field `{key}` is not allowed"));
        }
    }
}

fn validate_manifest_required_fields(
    value: &Value,
    label: &str,
    required_fields: &[&str],
    problems: &mut Vec<String>,
) {
    let Some(object) = value.as_object() else {
        return;
    };
    for field in required_fields {
        if !object.contains_key(*field) {
            problems.push(format!("{label} missing required field `{field}`"));
        }
    }
}

fn validate_manifest_string_fields(
    value: &Value,
    label: &str,
    fields: &[&str],
    problems: &mut Vec<String>,
) {
    let Some(object) = value.as_object() else {
        return;
    };
    for field in fields {
        if object
            .get(*field)
            .is_some_and(|value| value.as_str().is_none_or(|string| string.trim().is_empty()))
        {
            problems.push(format!(
                "{label} field `{field}` must be a non-empty string"
            ));
        }
    }
}

fn validate_manifest_nullable_string_fields(
    value: &Value,
    label: &str,
    fields: &[&str],
    problems: &mut Vec<String>,
) {
    let Some(object) = value.as_object() else {
        return;
    };
    for field in fields {
        if object
            .get(*field)
            .is_some_and(|value| !value.is_null() && value.as_str().is_none())
        {
            problems.push(format!("{label} field `{field}` must be a string or null"));
        }
    }
}

fn validate_manifest_bool_fields(
    value: &Value,
    label: &str,
    fields: &[&str],
    problems: &mut Vec<String>,
) {
    let Some(object) = value.as_object() else {
        return;
    };
    for field in fields {
        if object.get(*field).is_some_and(|value| !value.is_boolean()) {
            problems.push(format!("{label} field `{field}` must be a boolean"));
        }
    }
}

fn validate_manifest_string_array_fields(
    value: &Value,
    label: &str,
    fields: &[&str],
    problems: &mut Vec<String>,
) {
    let Some(object) = value.as_object() else {
        return;
    };
    for field in fields {
        let Some(value) = object.get(*field) else {
            continue;
        };
        let Some(items) = value.as_array() else {
            problems.push(format!("{label} field `{field}` must be an array"));
            continue;
        };
        for (index, item) in items.iter().enumerate() {
            if item.as_str().is_none_or(|string| string.trim().is_empty()) {
                problems.push(format!(
                    "{label}.{field}[{index}] must be a non-empty string"
                ));
            }
        }
    }
}

fn validate_manifest_array_objects<F>(
    value: &Value,
    parent_label: &str,
    field: &str,
    problems: &mut Vec<String>,
    mut validate_item: F,
) where
    F: FnMut(&Value, String, &mut Vec<String>),
{
    let Some(items) = value.get(field) else {
        return;
    };
    let Some(items) = items.as_array() else {
        problems.push(format!("{parent_label}.{field} must be an array"));
        return;
    };
    for (index, item) in items.iter().enumerate() {
        let label = format!("{parent_label}.{field}[{index}]");
        if !item.is_object() {
            problems.push(format!("{label} must be an object"));
            continue;
        }
        validate_item(item, label, problems);
    }
}

fn validate_package_manifest_identity_uniqueness(path: &Path, value: &Value) -> Result<(), String> {
    let mut problems = Vec::new();
    validate_unique_manifest_collection_ids(value, "libraries", "library", &mut problems);
    validate_unique_manifest_collection_ids(value, "capabilities", "capability", &mut problems);
    validate_unique_manifest_collection_ids(value, "providers", "provider", &mut problems);
    validate_unique_manifest_collection_ids(value, "profiles", "profile", &mut problems);
    validate_unique_manifest_collection_ids(value, "bindings", "binding", &mut problems);

    let mut effect_contract_ids = BTreeMap::<String, String>::new();
    let mut construct_ids = BTreeMap::<String, String>::new();
    for (index, library) in value
        .get("libraries")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .enumerate()
    {
        let library_label =
            optional_json_string(library, "id").unwrap_or_else(|| format!("#{index}"));
        if library.get("effect_contracts").is_some() && library.get("effects").is_some() {
            problems.push(format!(
                "library `{library_label}` declares both `effect_contracts` and `effects`; use `effect_contracts`"
            ));
        }
        for field in ["effect_contracts", "effects"] {
            for contract in library
                .get(field)
                .and_then(Value::as_array)
                .into_iter()
                .flatten()
            {
                let Some(contract_id) = optional_json_string(contract, "id") else {
                    continue;
                };
                let owner = format!("library `{library_label}` {field}");
                validate_unique_manifest_package_id(
                    "effect contract",
                    &contract_id,
                    owner,
                    &mut effect_contract_ids,
                    &mut problems,
                );
                for array_field in [
                    "source_forms",
                    "required_capabilities",
                    "provider_kinds",
                    "projected_facts",
                ] {
                    validate_unique_manifest_string_array(
                        contract,
                        array_field,
                        &format!("effect contract `{contract_id}`"),
                        &mut problems,
                    );
                }
            }
        }
        for construct in library
            .get("constructs")
            .and_then(Value::as_array)
            .into_iter()
            .flatten()
        {
            let Some(construct_id) = optional_json_string(construct, "id") else {
                continue;
            };
            validate_unique_manifest_package_id(
                "construct",
                &construct_id,
                format!("library `{library_label}` constructs"),
                &mut construct_ids,
                &mut problems,
            );
        }
    }

    for profile in value
        .get("profiles")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
    {
        let profile_label = optional_json_string(profile, "id")
            .or_else(|| optional_json_string(profile, "name"))
            .unwrap_or_else(|| "<unnamed>".to_owned());
        validate_unique_manifest_string_array(
            profile,
            "allowed_capabilities",
            &format!("profile `{profile_label}`"),
            &mut problems,
        );
    }

    if problems.is_empty() {
        Ok(())
    } else {
        Err(format!(
            "package manifest `{}` has duplicate or ambiguous package identities:\n- {}",
            path.display(),
            problems.join("\n- ")
        ))
    }
}

fn validate_unique_manifest_collection_ids(
    value: &Value,
    collection: &str,
    label: &str,
    problems: &mut Vec<String>,
) {
    let mut ids = BTreeSet::new();
    for item in value
        .get(collection)
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
    {
        let Some(id) = optional_json_string(item, "id") else {
            continue;
        };
        if !ids.insert(id.clone()) {
            problems.push(format!("{label} `{id}` is declared more than once"));
        }
    }
}

fn validate_unique_manifest_package_id(
    label: &str,
    id: &str,
    owner: String,
    seen: &mut BTreeMap<String, String>,
    problems: &mut Vec<String>,
) {
    if let Some(previous_owner) = seen.insert(id.to_owned(), owner.clone()) {
        problems.push(format!(
            "{label} `{id}` is declared more than once ({previous_owner} and {owner})"
        ));
    }
}

fn validate_unique_manifest_string_array(
    value: &Value,
    field: &str,
    owner: &str,
    problems: &mut Vec<String>,
) {
    let mut seen = BTreeSet::new();
    for item in value
        .get(field)
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(Value::as_str)
        .filter(|item| !item.trim().is_empty())
    {
        if !seen.insert(item) {
            problems.push(format!(
                "{owner} declares `{field}` value `{item}` more than once"
            ));
        }
    }
}

fn quoted_platform_values<'a>(values: impl IntoIterator<Item = &'a str>) -> String {
    values
        .into_iter()
        .map(|value| format!("`{value}`"))
        .collect::<Vec<_>>()
        .join(", ")
}

fn validate_construct_interface_records(
    path: &Path,
    form: &ConstructRegistration,
    declared_capabilities: &BTreeSet<String>,
    problems: &mut Vec<String>,
) {
    for (direction, interfaces) in [
        ("requires", form.requires.as_slice()),
        ("provides", form.provides.as_slice()),
    ] {
        for interface in interfaces {
            if !PLATFORM_CONSTRUCT_CATALOG.contains_interface_kind(&interface.kind) {
                problems.push(format!(
                    "construct `{}` {direction} interface uses unsupported kind `{}`; expected one of {}",
                    form.id,
                    interface.kind,
                    quoted_platform_values(PLATFORM_CONSTRUCT_CATALOG.interface_kinds.iter().copied())
                ));
            }
            if !PLATFORM_CONSTRUCT_CATALOG.contains_interface_phase(&interface.phase) {
                problems.push(format!(
                    "construct `{}` {direction} interface `{}` uses unsupported phase `{}`; expected one of {}",
                    form.id,
                    interface.kind,
                    interface.phase,
                    quoted_platform_values(PLATFORM_CONSTRUCT_CATALOG.interface_phases.iter().copied())
                ));
            }
            if !PLATFORM_CONSTRUCT_CATALOG.contains_interface_cardinality(&interface.cardinality) {
                problems.push(format!(
                    "construct `{}` {direction} interface `{}` uses unsupported cardinality `{}`; expected one of {}",
                    form.id,
                    interface.kind,
                    interface.cardinality,
                    quoted_platform_values(PLATFORM_CONSTRUCT_CATALOG.interface_cardinalities.iter().copied())
                ));
            }
            if interface.kind == CONSTRUCT_INTERFACE_CAPABILITY {
                match interface.name.as_deref() {
                    Some(capability) => validate_declared_capability(
                        path,
                        declared_capabilities,
                        capability,
                        &format!("construct `{}` {direction} Capability interface", form.id),
                        problems,
                    ),
                    None => problems.push(format!(
                        "construct `{}` {direction} Capability interface must declare `name`",
                        form.id
                    )),
                }
            }
        }
    }
}

fn validate_construct_input_schema_fields(
    form: &ConstructRegistration,
    contract: &EffectContract,
    problems: &mut Vec<String>,
) {
    let Some(input_fields) = contract
        .input_schema
        .as_deref()
        .and_then(package_schema_top_level_object_fields)
    else {
        return;
    };
    let construct_fields = form
        .fields
        .iter()
        .map(|field| (field.name.as_str(), field.required))
        .collect::<BTreeMap<_, _>>();

    for input_field in input_fields {
        match construct_fields.get(input_field.as_str()) {
            Some(true) => {}
            Some(false) => problems.push(format!(
                "construct `{}` lowers to `{}` but target input_schema field `{}` is optional in the construct fields",
                form.id, contract.id, input_field
            )),
            None => problems.push(format!(
                "construct `{}` lowers to `{}` but target input_schema field `{}` has no matching required construct field",
                form.id, contract.id, input_field
            )),
        }
    }
}

fn package_schema_top_level_object_fields(schema: &str) -> Option<BTreeSet<String>> {
    match serde_json::from_str::<Value>(schema).ok()? {
        Value::Object(fields) => Some(fields.keys().cloned().collect()),
        _ => None,
    }
}

fn validate_construct_lowering_interfaces(
    form: &ConstructRegistration,
    lowering: &PlatformConstructLowering,
    problems: &mut Vec<String>,
) {
    for kind in lowering.required_interfaces {
        if !form
            .requires
            .iter()
            .any(|interface| interface.kind == *kind)
        {
            problems.push(format!(
                "construct `{}` uses {} lowering but declares no required `{kind}` interface",
                form.id, lowering.id
            ));
        }
    }
    for kind in lowering.provided_interfaces {
        if !form
            .provides
            .iter()
            .any(|interface| interface.kind == *kind)
        {
            problems.push(format!(
                "construct `{}` uses {} lowering but declares no provided `{kind}` interface",
                form.id, lowering.id
            ));
        }
    }
    if lowering.target_capability == ConstructTargetCapabilityPolicy::RequiredCapabilityCallContract
    {
        let Some(target_capability) = form.target_capability.as_deref() else {
            return;
        };
        if !form.requires.iter().any(|interface| {
            interface.kind == CONSTRUCT_INTERFACE_CAPABILITY
                && interface.name.as_deref() == Some(target_capability)
        }) {
            problems.push(format!(
                "construct `{}` uses {} lowering to `{target_capability}` but declares no required Capability interface named `{target_capability}`",
                form.id, lowering.id
            ));
        }
    }
}

fn validate_declared_capability(
    path: &Path,
    declared_capabilities: &BTreeSet<String>,
    capability: &str,
    owner: &str,
    problems: &mut Vec<String>,
) {
    if capability == "*" || declared_capabilities.contains(capability) {
        return;
    }
    problems.push(format!(
        "{owner} in `{}` references undeclared capability `{capability}`",
        path.display()
    ));
}

fn package_capability_contracts(
    path: &Path,
    value: &Value,
) -> Result<BTreeMap<String, PackageCapabilityContract>, String> {
    let mut capabilities = BTreeMap::new();
    for capability in value
        .get("capabilities")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
    {
        let capability_name = required_json_string(capability, "id", "capability")?;
        let schema = capability.get("schema").unwrap_or(&Value::Null);
        let contract = PackageCapabilityContract {
            input_schema: json_schema_fragment(capability.get("input_schema"))
                .or_else(|| json_schema_fragment(schema.get("input"))),
            output_schema: json_schema_fragment(capability.get("output_schema"))
                .or_else(|| json_schema_fragment(schema.get("output"))),
        };
        validate_package_schema_fragment_contract(
            path,
            &format!("capability `{capability_name}`"),
            "input_schema",
            contract.input_schema.as_deref(),
        )?;
        validate_package_schema_fragment_contract(
            path,
            &format!("capability `{capability_name}`"),
            "output_schema",
            contract.output_schema.as_deref(),
        )?;
        if capabilities
            .insert(capability_name.clone(), contract)
            .is_some()
        {
            return Err(format!(
                "package manifest `{}` declares capability `{capability_name}` more than once",
                path.display()
            ));
        }
    }
    Ok(capabilities)
}

fn package_provider_contracts(
    path: &Path,
    value: &Value,
) -> Result<Vec<PackageProviderContract>, String> {
    let mut providers = Vec::new();
    for provider in value
        .get("providers")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
    {
        providers.push(PackageProviderContract {
            capability: required_json_string(provider, "capability", "provider")
                .map_err(|message| format!("{} in `{}`", message, path.display()))?,
            provider_kind: required_json_string(provider, "provider_kind", "provider")
                .map_err(|message| format!("{} in `{}`", message, path.display()))?,
        });
    }
    Ok(providers)
}

fn package_manifest_registry(
    path: &Path,
    value: &Value,
    name: &str,
    version: &str,
    capabilities: &BTreeMap<String, PackageCapabilityContract>,
    providers: &[PackageProviderContract],
) -> Result<ContractRegistry, String> {
    let mut registry = ContractRegistry::default();
    let libraries = value.get("libraries").and_then(Value::as_array);

    if let Some(libraries) = libraries {
        for library in libraries {
            let library_id = optional_json_string(library, "id").unwrap_or_else(|| name.to_owned());
            let library_version =
                optional_json_string(library, "version").unwrap_or_else(|| version.to_owned());
            registry.upsert_library(LibraryRegistration {
                id: library_id.clone(),
                version: library_version.clone(),
                standard: library
                    .get("standard")
                    .and_then(Value::as_bool)
                    .unwrap_or(false),
            });
            for contract in library
                .get("effect_contracts")
                .or_else(|| library.get("effects"))
                .and_then(Value::as_array)
                .into_iter()
                .flatten()
            {
                registry.upsert_effect_contract(package_effect_contract(
                    path,
                    contract,
                    &library_id,
                    &library_version,
                    capabilities,
                    providers,
                )?);
            }
            for construct in library
                .get("constructs")
                .and_then(Value::as_array)
                .into_iter()
                .flatten()
            {
                registry.upsert_construct(package_construct(
                    path,
                    construct,
                    &library_id,
                    &library_version,
                )?);
            }
        }
    }

    if registry.libraries.is_empty() {
        registry.upsert_library(LibraryRegistration {
            id: name.to_owned(),
            version: version.to_owned(),
            standard: false,
        });
    }

    if registry.effect_contracts.is_empty() {
        for capability in derived_capability_names(capabilities, providers) {
            let contract_json = json!({"id": capability});
            registry.upsert_effect_contract(package_effect_contract(
                path,
                &contract_json,
                name,
                version,
                capabilities,
                providers,
            )?);
        }
    }

    Ok(registry)
}

fn package_construct(
    path: &Path,
    value: &Value,
    library_id: &str,
    version: &str,
) -> Result<ConstructRegistration, String> {
    let id = required_json_string(value, "id", "construct")
        .map_err(|message| format!("{} in `{}`", message, path.display()))?;
    let construct_family = required_json_string(value, "construct_family", "construct")
        .map_err(|message| format!("{} in `{}`", message, path.display()))?;
    let keyword = required_json_string(value, "keyword", "construct")
        .map_err(|message| format!("{} in `{}`", message, path.display()))?;
    let scope = optional_json_string(value, "scope").unwrap_or_else(|| "top_level".to_owned());
    let lowering_target = optional_json_string(value, "lowering_target")
        .unwrap_or_else(|| CONSTRUCT_LOWERING_METADATA_ONLY.to_owned());
    let target_capability = optional_json_string(value, "target_capability");
    let fields = value
        .get("fields")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .map(|field| package_construct_field(path, field, &id))
        .collect::<Result<Vec<_>, _>>()?;
    let requires = package_construct_interfaces(path, value, "requires", &id)?;
    let provides = package_construct_interfaces(path, value, "provides", &id)?;

    Ok(ConstructRegistration {
        id,
        library_id: library_id.to_owned(),
        version: version.to_owned(),
        construct_family,
        keyword,
        scope,
        fields,
        requires,
        provides,
        lowering_target,
        target_capability,
    })
}

fn package_construct_field(
    path: &Path,
    value: &Value,
    form_id: &str,
) -> Result<ConstructField, String> {
    let owner = format!("construct `{form_id}` field");
    let name = required_json_string(value, "name", &owner)
        .map_err(|message| format!("{} in `{}`", message, path.display()))?;
    let kind = required_json_string(value, "kind", &owner)
        .map_err(|message| format!("{} in `{}`", message, path.display()))?;
    Ok(ConstructField {
        name,
        kind,
        required: value
            .get("required")
            .and_then(Value::as_bool)
            .unwrap_or(true),
    })
}

fn package_construct_interfaces(
    path: &Path,
    value: &Value,
    direction: &str,
    construct_id: &str,
) -> Result<Vec<ConstructInterface>, String> {
    value
        .get(direction)
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .map(|interface| package_construct_interface(path, interface, direction, construct_id))
        .collect()
}

fn package_construct_interface(
    path: &Path,
    value: &Value,
    direction: &str,
    construct_id: &str,
) -> Result<ConstructInterface, String> {
    let owner = format!("construct `{construct_id}` {direction} interface");
    let kind = required_json_string(value, "kind", &owner)
        .map_err(|message| format!("{} in `{}`", message, path.display()))?;
    let name = optional_json_string(value, "name");
    let type_ref =
        optional_json_string(value, "type").or_else(|| optional_json_string(value, "type_ref"));
    let phase = optional_json_string(value, "phase")
        .unwrap_or_else(|| CONSTRUCT_INTERFACE_PHASE_COMPILE_RUNTIME.to_owned());
    let cardinality = optional_json_string(value, "cardinality")
        .unwrap_or_else(|| CONSTRUCT_INTERFACE_CARDINALITY_EXACTLY_ONE.to_owned());

    Ok(ConstructInterface {
        kind,
        name,
        type_ref,
        phase,
        cardinality,
    })
}

fn derived_capability_names(
    capabilities: &BTreeMap<String, PackageCapabilityContract>,
    providers: &[PackageProviderContract],
) -> BTreeSet<String> {
    let mut names = capabilities.keys().cloned().collect::<BTreeSet<_>>();
    for provider in providers {
        names.insert(provider.capability.clone());
    }
    names
}

fn package_effect_contract(
    path: &Path,
    value: &Value,
    library_id: &str,
    version: &str,
    capabilities: &BTreeMap<String, PackageCapabilityContract>,
    providers: &[PackageProviderContract],
) -> Result<EffectContract, String> {
    let id = required_json_string(value, "id", "effect contract")
        .map_err(|message| format!("{} in `{}`", message, path.display()))?;
    let capability_contract = capabilities.get(&id);
    let output_schema = json_schema_fragment(value.get("output_schema"))
        .or_else(|| capability_contract.and_then(|contract| contract.output_schema.clone()));
    let input_schema = json_schema_fragment(value.get("input_schema"))
        .or_else(|| capability_contract.and_then(|contract| contract.input_schema.clone()));
    validate_package_schema_fragment_contract(
        path,
        &format!("effect contract `{id}`"),
        "input_schema",
        input_schema.as_deref(),
    )?;
    validate_package_schema_fragment_contract(
        path,
        &format!("effect contract `{id}`"),
        "output_schema",
        output_schema.as_deref(),
    )?;
    let source_forms = optional_json_string_array(value, "source_forms")
        .filter(|forms| !forms.is_empty())
        .unwrap_or_else(|| vec![format!("call {id}")]);
    let required_capabilities = optional_json_string_array(value, "required_capabilities")
        .filter(|capabilities| !capabilities.is_empty())
        .unwrap_or_else(|| vec![id.clone()]);
    let provider_kinds = optional_json_string_array(value, "provider_kinds")
        .filter(|kinds| !kinds.is_empty())
        .unwrap_or_else(|| {
            providers
                .iter()
                .filter(|provider| provider.capability == id)
                .map(|provider| provider.provider_kind.clone())
                .collect()
        });
    let projected_facts =
        optional_json_string_array(value, "projected_facts").unwrap_or_else(|| {
            if output_schema.is_some() {
                vec!["effect.output".to_owned()]
            } else {
                Vec::new()
            }
        });
    let validation = package_validation_mode(value, output_schema.is_some())?;

    Ok(EffectContract {
        id,
        library_id: library_id.to_owned(),
        version: version.to_owned(),
        effect_kind: optional_json_string_any(value, &["effect_kind", "core_effect_kind"])
            .unwrap_or_else(|| "capability.call".to_owned()),
        source_forms,
        input_schema,
        output_schema,
        required_capabilities,
        provider_kinds,
        projected_facts,
        validation,
    })
}

fn package_validation_mode(
    value: &Value,
    has_output_schema: bool,
) -> Result<TypedOutputValidation, String> {
    match value.get("validation").and_then(Value::as_str) {
        Some("none") => Ok(TypedOutputValidation::None),
        Some("runtime_boundary") | Some("runtime") => Ok(TypedOutputValidation::RuntimeBoundary),
        Some(other) => Err(format!(
            "effect contract validation must be `none` or `runtime_boundary`, got `{other}`"
        )),
        None if has_output_schema => Ok(TypedOutputValidation::RuntimeBoundary),
        None => Ok(TypedOutputValidation::None),
    }
}

fn validate_package_schema_fragment_contract(
    path: &Path,
    owner: &str,
    field: &str,
    schema: Option<&str>,
) -> Result<(), String> {
    let Some(schema) = schema else {
        return Ok(());
    };
    let mut errors = Vec::new();
    validate_package_schema_fragment_shape(schema, field, &mut errors, 0);
    if errors.is_empty() {
        Ok(())
    } else {
        Err(format!(
            "{owner} in `{}` has invalid {field}: {}",
            path.display(),
            errors.join("; ")
        ))
    }
}

fn validate_package_schema_fragment_shape(
    schema: &str,
    label: &str,
    errors: &mut Vec<String>,
    depth: usize,
) {
    if depth > 32 {
        errors.push(format!("{label} exceeded package schema recursion limit"));
        return;
    }
    match serde_json::from_str::<Value>(schema) {
        Ok(fragment) => validate_package_schema_shape_value(&fragment, label, errors, depth + 1),
        Err(_) => validate_package_schema_type_name(schema, label, errors),
    }
}

fn validate_package_schema_shape_value(
    schema: &Value,
    label: &str,
    errors: &mut Vec<String>,
    depth: usize,
) {
    if depth > 32 {
        errors.push(format!("{label} exceeded package schema recursion limit"));
        return;
    }
    match schema {
        Value::String(name) => validate_package_schema_type_name(name, label, errors),
        Value::Object(fields) => {
            for (field, field_schema) in fields {
                if field.trim().is_empty() {
                    errors.push(format!("{label} contains an empty field name"));
                    continue;
                }
                validate_package_schema_shape_value(
                    field_schema,
                    &format!("{label}.{field}"),
                    errors,
                    depth + 1,
                );
            }
        }
        Value::Array(items) if items.len() == 1 => {
            validate_package_schema_shape_value(&items[0], &format!("{label}[]"), errors, depth + 1)
        }
        Value::Array(_) => errors.push(format!("{label} uses unsupported package tuple schema")),
        Value::Bool(_) | Value::Number(_) | Value::Null => errors.push(format!(
            "{label} uses unsupported package schema fragment `{schema}`"
        )),
    }
}

fn validate_package_schema_type_name(name: &str, label: &str, errors: &mut Vec<String>) {
    if !matches!(
        name,
        "json"
            | "any"
            | "string"
            | "int"
            | "integer"
            | "float"
            | "number"
            | "bool"
            | "boolean"
            | "null"
    ) {
        errors.push(format!("{label} uses unsupported package type `{name}`"));
    }
}

fn package_registry(manifests: &[PackageManifest]) -> ContractRegistry {
    let mut registry = ContractRegistry::default();
    for manifest in manifests {
        registry.merge(manifest.registry.clone());
    }
    registry
}

fn package_manifest_summary_json(manifest: &PackageManifest) -> Value {
    json!({
        "path": manifest.path.display().to_string(),
        "package_id": manifest.package_id,
        "name": manifest.name,
        "version": manifest.version,
        "manifest_sha256": manifest.manifest_sha256,
    })
}

/// Compute a portable, project-relative, `/`-separated path for `target`
/// relative to `base_dir`. Falls back to the lexical relation when canonical
/// resolution is unavailable (e.g. the manifest is not yet on disk in tests).
fn portable_relative_path(base_dir: &Path, target: &Path) -> String {
    let canonical_base = base_dir.canonicalize().ok();
    let canonical_target = target.canonicalize().ok();
    let relative = match (canonical_base.as_deref(), canonical_target.as_deref()) {
        (Some(base), Some(target)) => target.strip_prefix(base).ok().map(Path::to_path_buf),
        _ => None,
    }
    .or_else(|| target.strip_prefix(base_dir).ok().map(Path::to_path_buf))
    .unwrap_or_else(|| target.to_path_buf());
    relative
        .components()
        .filter_map(|component| match component {
            std::path::Component::Normal(part) => Some(part.to_string_lossy().into_owned()),
            std::path::Component::CurDir => None,
            std::path::Component::ParentDir => Some("..".to_owned()),
            std::path::Component::RootDir | std::path::Component::Prefix(_) => None,
        })
        .collect::<Vec<_>>()
        .join("/")
}

/// Build the portable `whipplescript.package_lock.v0` body for `manifests`,
/// recording `source.path` relative to `base_dir`. Packages are sorted by
/// `name`, then `package_id`, matching the canonical lock ordering.
fn package_lock_json(manifests: &[PackageManifest], base_dir: &Path) -> Value {
    let mut packages = manifests
        .iter()
        .map(|manifest| {
            (
                manifest.name.clone(),
                manifest.package_id.clone(),
                json!({
                    "package_id": manifest.package_id,
                    "name": manifest.name,
                    "version": manifest.version,
                    "source": {
                        "type": "path",
                        "path": portable_relative_path(base_dir, &manifest.path),
                    },
                    "manifest_sha256": manifest.manifest_sha256,
                }),
            )
        })
        .collect::<Vec<_>>();
    packages.sort_by(|left, right| left.0.cmp(&right.0).then_with(|| left.1.cmp(&right.1)));
    json!({
        "schema": PACKAGE_LOCK_SCHEMA,
        "packages": packages
            .into_iter()
            .map(|(_, _, package)| package)
            .collect::<Vec<_>>(),
    })
}

/// Render `value` as the canonical on-disk lock form: object keys sorted,
/// 2-space indentation, LF line endings, exactly one trailing newline, and
/// non-ASCII emitted as UTF-8 rather than `\uXXXX` escapes.
fn canonical_lock_text(value: &Value) -> String {
    let mut text = String::new();
    write_canonical_pretty(value, 0, &mut text);
    text.push('\n');
    text
}

fn write_canonical_pretty(value: &Value, indent: usize, out: &mut String) {
    match value {
        Value::Object(object) => {
            if object.is_empty() {
                out.push_str("{}");
                return;
            }
            let mut entries = object.iter().collect::<Vec<_>>();
            entries.sort_by_key(|(left, _)| *left);
            out.push_str("{\n");
            let child_indent = indent + 1;
            for (position, (key, child)) in entries.iter().enumerate() {
                push_indent(child_indent, out);
                out.push_str(&canonical_json_string(key));
                out.push_str(": ");
                write_canonical_pretty(child, child_indent, out);
                if position + 1 != entries.len() {
                    out.push(',');
                }
                out.push('\n');
            }
            push_indent(indent, out);
            out.push('}');
        }
        Value::Array(items) => {
            if items.is_empty() {
                out.push_str("[]");
                return;
            }
            out.push_str("[\n");
            let child_indent = indent + 1;
            for (position, child) in items.iter().enumerate() {
                push_indent(child_indent, out);
                write_canonical_pretty(child, child_indent, out);
                if position + 1 != items.len() {
                    out.push(',');
                }
                out.push('\n');
            }
            push_indent(indent, out);
            out.push(']');
        }
        Value::String(string) => out.push_str(&canonical_json_string(string)),
        other => out.push_str(&serde_json::to_string(other).unwrap_or_else(|_| other.to_string())),
    }
}

fn push_indent(indent: usize, out: &mut String) {
    for _ in 0..indent {
        out.push_str("  ");
    }
}

/// Encode a JSON string with minimal escaping, emitting non-ASCII as UTF-8
/// rather than `\uXXXX`. serde_json already avoids `\uXXXX` for printable
/// non-ASCII, so this delegates to it.
fn canonical_json_string(value: &str) -> String {
    serde_json::to_string(value).unwrap_or_else(|_| format!("{value:?}"))
}

fn validate_package_lock_closed_shape(path: &Path, value: &Value) -> Result<(), String> {
    let mut problems = Vec::new();
    validate_manifest_object_fields(
        value,
        "package lock",
        &["schema", "packages"],
        &mut problems,
    );
    validate_manifest_required_fields(
        value,
        "package lock",
        &["schema", "packages"],
        &mut problems,
    );
    validate_manifest_string_fields(value, "package lock", &["schema"], &mut problems);
    validate_manifest_array_objects(
        value,
        "package lock",
        "packages",
        &mut problems,
        |package, label, problems| {
            validate_manifest_object_fields(
                package,
                &label,
                &["package_id", "name", "version", "source", "manifest_sha256"],
                problems,
            );
            validate_manifest_required_fields(
                package,
                &label,
                &["package_id", "name", "version", "source", "manifest_sha256"],
                problems,
            );
            validate_manifest_string_fields(
                package,
                &label,
                &["package_id", "name", "version", "manifest_sha256"],
                problems,
            );
            validate_package_lock_source_shape(package, &label, problems);
            if let Some(hash) = package.get("manifest_sha256").and_then(Value::as_str) {
                if !is_sha256_hex(hash) {
                    problems.push(format!(
                        "{label} field `manifest_sha256` must be a 64-character lowercase hex digest"
                    ));
                }
            }
        },
    );

    if problems.is_empty() {
        Ok(())
    } else {
        Err(format!(
            "package lock `{}` does not match closed package lock schema:\n- {}",
            path.display(),
            problems.join("\n- ")
        ))
    }
}

/// Validate a lock entry's `source` object: it must be a closed object with a
/// `path`-type and a non-empty, portable, project-relative `path` string.
fn validate_package_lock_source_shape(package: &Value, label: &str, problems: &mut Vec<String>) {
    let Some(source) = package.get("source") else {
        // Missing-field reporting is handled by the required-fields check.
        return;
    };
    let Some(source) = source.as_object() else {
        problems.push(format!("{label} field `source` must be an object"));
        return;
    };
    for key in source.keys() {
        if key != "type" && key != "path" {
            problems.push(format!("{label}.source has unexpected field `{key}`"));
        }
    }
    match source.get("type").and_then(Value::as_str) {
        Some("path") => {}
        Some(other) => problems.push(format!("{label}.source.type must be `path`; got `{other}`")),
        None => problems.push(format!("{label}.source.type must be a non-empty string")),
    }
    match source.get("path").and_then(Value::as_str) {
        Some(value) if !value.is_empty() => {
            if !is_portable_relative_path(value) {
                problems.push(format!(
                    "{label}.source.path must be a portable project-relative path; got `{value}`"
                ));
            }
        }
        _ => problems.push(format!("{label}.source.path must be a non-empty string")),
    }
}

/// A portable source path is project-relative: it is not absolute, contains no
/// `..` segments, and uses no Windows drive prefix.
fn is_portable_relative_path(path: &str) -> bool {
    if path.is_empty() {
        return false;
    }
    if path.starts_with('/') || path.starts_with('\\') {
        return false;
    }
    let mut chars = path.chars();
    if let (Some(first), Some(second)) = (chars.next(), chars.next()) {
        if first.is_ascii_alphabetic() && second == ':' {
            return false;
        }
    }
    !path.split(['/', '\\']).any(|segment| segment == "..")
}

fn load_package_lock(
    explicit: Option<&Path>,
    source_paths: &[&Path],
) -> Result<Option<LoadedPackageLock>, String> {
    resolve_package_lock_path(explicit, source_paths)?
        .as_deref()
        .map(load_package_lock_file)
        .transpose()
}

/// Resolve which `whip.lock` a command should load, per the spec's lock-discovery
/// order: an explicit `--package-lock` wins; otherwise search from each source
/// file's directory upward; otherwise search from the current directory upward;
/// otherwise proceed without a lock (the no-lock guard rejects non-`std.` package
/// use downstream). If the sources imply more than one distinct lock, the user
/// must disambiguate with `--package-lock`.
fn resolve_package_lock_path(
    explicit: Option<&Path>,
    source_paths: &[&Path],
) -> Result<Option<PathBuf>, String> {
    if let Some(explicit) = explicit {
        return Ok(Some(explicit.to_path_buf()));
    }
    let mut discovered = BTreeSet::new();
    for source in source_paths {
        if let Some(dir) = source.parent().filter(|dir| !dir.as_os_str().is_empty()) {
            if let Some(found) = discover_ancestor_file_from(dir, DEFAULT_PACKAGE_LOCK_FILE) {
                discovered.insert(found);
            }
        }
    }
    if discovered.len() > 1 {
        return Err(format!(
            "source files imply different `{DEFAULT_PACKAGE_LOCK_FILE}` files ({}); pass `--package-lock <path>` to choose one",
            discovered
                .iter()
                .map(|path| format!("`{}`", path.display()))
                .collect::<Vec<_>>()
                .join(", ")
        ));
    }
    if let Some(found) = discovered.into_iter().next() {
        return Ok(Some(found));
    }
    Ok(discover_ancestor_file(DEFAULT_PACKAGE_LOCK_FILE))
}

fn load_package_lock_file(path: &Path) -> Result<LoadedPackageLock, String> {
    let text = fs::read_to_string(path)
        .map_err(|error| format!("failed to read package lock `{}`: {error}", path.display()))?;
    let value = serde_json::from_str::<Value>(&text)
        .map_err(|error| format!("failed to parse package lock `{}`: {error}", path.display()))?;
    let schema = value.get("schema").and_then(Value::as_str);
    if schema != Some(PACKAGE_LOCK_SCHEMA) {
        return Err(format!(
            "package lock `{}` must have schema `{PACKAGE_LOCK_SCHEMA}`",
            path.display()
        ));
    }
    validate_package_lock_closed_shape(path, &value)?;
    let packages = value
        .get("packages")
        .and_then(Value::as_array)
        .ok_or_else(|| format!("package lock `{}` must have packages array", path.display()))?;
    let base_dir = path.parent().unwrap_or_else(|| Path::new(""));
    let mut manifests = Vec::new();
    for package in packages {
        let source = package
            .get("source")
            .and_then(Value::as_object)
            .ok_or_else(|| {
                format!(
                    "package lock `{}` entry must have a `source` object",
                    path.display()
                )
            })?;
        let source_path = source
            .get("path")
            .and_then(Value::as_str)
            .filter(|value| !value.is_empty())
            .ok_or_else(|| {
                format!(
                    "package lock `{}` entry must have a non-empty `source.path`",
                    path.display()
                )
            })?;
        // Enforce the same portability check at load time as at write time so a
        // crafted lock cannot widen file access via absolute or `..` paths.
        if !is_portable_relative_path(source_path) {
            return Err(format!(
                "package lock `{}` entry has nonportable `source.path` `{source_path}`",
                path.display()
            ));
        }
        let resolved_path = base_dir.join(source_path);
        // `source.path` is resolved relative to the lock file's own directory, so a
        // lock that does not sit at the project root cannot reach its manifests.
        // Make that the actionable hint rather than a bare file-not-found.
        let manifest = load_package_manifest(&resolved_path).map_err(|error| {
            format!(
                "{error}\n  (package lock `{}` resolves `source.path` relative to its own directory; keep the lock at the project root)",
                path.display()
            )
        })?;
        let expected_name = required_json_string(package, "name", "package lock entry")?;
        let expected_version = required_json_string(package, "version", "package lock entry")?;
        let expected_package_id =
            required_json_string(package, "package_id", "package lock entry")?;
        let expected_hash = required_json_string(package, "manifest_sha256", "package lock entry")?;
        if manifest.name != expected_name
            || manifest.version != expected_version
            || manifest.package_id != expected_package_id
            || manifest.manifest_sha256 != expected_hash
        {
            return Err(format!(
                "package lock `{}` entry for `{}` does not match manifest `{}`",
                path.display(),
                expected_name,
                resolved_path.display()
            ));
        }
        manifests.push(manifest);
    }
    manifests.sort_by(|left, right| left.name.cmp(&right.name));
    validate_loaded_package_set(&manifests, &format!("package lock `{}`", path.display()))?;
    Ok(LoadedPackageLock {
        path: path.to_path_buf(),
        manifests,
    })
}

fn required_json_string(value: &Value, field: &str, owner: &str) -> Result<String, String> {
    value
        .get(field)
        .and_then(Value::as_str)
        .filter(|value| !value.trim().is_empty())
        .map(str::to_owned)
        .ok_or_else(|| format!("{owner} must have non-empty `{field}` string"))
}

fn optional_json_string(value: &Value, field: &str) -> Option<String> {
    value
        .get(field)
        .and_then(Value::as_str)
        .filter(|value| !value.trim().is_empty())
        .map(str::to_owned)
}

fn optional_json_string_any(value: &Value, fields: &[&str]) -> Option<String> {
    fields
        .iter()
        .find_map(|field| optional_json_string(value, field))
}

fn optional_json_string_array(value: &Value, field: &str) -> Option<Vec<String>> {
    value.get(field).and_then(Value::as_array).map(|items| {
        items
            .iter()
            .filter_map(Value::as_str)
            .filter(|item| !item.trim().is_empty())
            .map(str::to_owned)
            .collect::<Vec<_>>()
    })
}

fn json_schema_fragment(value: Option<&Value>) -> Option<String> {
    match value {
        Some(Value::String(schema)) if !schema.trim().is_empty() => Some(schema.clone()),
        Some(Value::Null) | None => None,
        Some(schema) => Some(schema.to_string()),
    }
}

fn register_locked_packages(
    store: &SqliteStore,
    package_lock: Option<&LoadedPackageLock>,
) -> Result<(), StoreError> {
    let Some(package_lock) = package_lock else {
        return Ok(());
    };
    for manifest in &package_lock.manifests {
        store.register_package_manifest(&manifest.manifest_json)?;
    }
    Ok(())
}

fn persist_revision_compatibility_diagnostics(
    store: &SqliteStore,
    instance_id: &str,
    compatibility: &RevisionCompatibilityReport,
) -> Result<(), StoreError> {
    let diagnostic_json = compatibility
        .diagnostics
        .iter()
        .map(revision_compatibility_diagnostic_to_json)
        .collect::<Vec<_>>();
    let payload = json!({
        "instance_id": instance_id,
        "active_version_id": compatibility.active_version_id,
        "candidate_version_id": compatibility.candidate_version_id,
        "compatible": false,
        "diagnostics": diagnostic_json,
    })
    .to_string();
    let event = store.append_event(NewEvent {
        instance_id,
        event_type: "workflow.revision_rejected",
        payload_json: &payload,
        source: "cli",
        causation_id: None,
        correlation_id: Some(&compatibility.candidate_version_id),
        idempotency_key: None,
    })?;

    let mut diagnostic_ids = Vec::new();
    for diagnostic in &compatibility.diagnostics {
        let subject_id = diagnostic
            .subject
            .as_deref()
            .unwrap_or(&compatibility.candidate_version_id)
            .to_owned();
        let idempotency_key = idempotency_key(&[
            instance_id,
            "revision-compatibility",
            &compatibility.candidate_version_id,
            &diagnostic.code,
            &subject_id,
        ]);
        let diagnostic_id = store.record_diagnostic(DiagnosticRecord {
            instance_id: Some(instance_id),
            program_id: None,
            program_version_id: None,
            severity: Severity::Error,
            code: Some(&diagnostic.code),
            message: &diagnostic.message,
            source_span_json: diagnostic.source_span_json.as_deref(),
            subject_type: Some("revision_compatibility"),
            subject_id: Some(&subject_id),
            event_id: Some(&event.event_id),
            effect_id: None,
            run_id: None,
            assertion_id: None,
            evidence_ids_json: "[]",
            artifact_ids_json: "[]",
            causation_id: Some(&event.event_id),
            correlation_id: Some(&compatibility.candidate_version_id),
            idempotency_key: Some(&idempotency_key),
        })?;
        diagnostic_ids.push(diagnostic_id);
    }

    let evidence_metadata = json!({
        "event_id": event.event_id,
        "active_version_id": compatibility.active_version_id,
        "candidate_version_id": compatibility.candidate_version_id,
        "diagnostic_ids": diagnostic_ids,
        "diagnostics": diagnostic_json,
    })
    .to_string();
    let evidence_id = store.record_evidence(EvidenceRecord {
        instance_id,
        kind: "workflow.revision.compatibility_rejected",
        subject_type: "revision_candidate",
        subject_id: &compatibility.candidate_version_id,
        causation_id: Some(&event.event_id),
        correlation_id: Some(&compatibility.candidate_version_id),
        summary: Some("workflow revision rejected by compatibility diagnostics"),
        metadata_json: &evidence_metadata,
    })?;
    store.link_evidence(EvidenceLink {
        evidence_id: &evidence_id,
        instance_id,
        target_type: "event",
        target_id: &event.event_id,
        relation: "rejected",
    })?;
    for diagnostic_id in &diagnostic_ids {
        store.link_evidence(EvidenceLink {
            evidence_id: &evidence_id,
            instance_id,
            target_type: "diagnostic",
            target_id: diagnostic_id,
            relation: "compatibility_diagnostic",
        })?;
    }
    Ok(())
}

fn persist_revision_source_bundle_diagnostic(
    store: &SqliteStore,
    revise_options: &ReviseOptions,
    error: &CompileFailure,
) -> Result<(), StoreError> {
    let CompileFailure::Io(error) = error else {
        return Ok(());
    };
    let subject_id = display_path(&revise_options.program_path);
    let idempotency_key = idempotency_key(&[
        &revise_options.instance_id,
        "revision-source-bundle",
        &subject_id,
    ]);
    let message = format!("failed to read revision source bundle `{subject_id}`: {error}");
    store.record_diagnostic(DiagnosticRecord {
        instance_id: Some(&revise_options.instance_id),
        program_id: None,
        program_version_id: None,
        severity: Severity::Error,
        code: Some("revision.source_bundle_unavailable"),
        message: &message,
        source_span_json: None,
        subject_type: Some("revision_source_bundle"),
        subject_id: Some(&subject_id),
        event_id: None,
        effect_id: None,
        run_id: None,
        assertion_id: None,
        evidence_ids_json: "[]",
        artifact_ids_json: "[]",
        causation_id: None,
        correlation_id: Some(&revise_options.instance_id),
        idempotency_key: Some(&idempotency_key),
    })?;
    Ok(())
}

fn run(options: &CliOptions) -> ExitCode {
    let run_options = match RunOptions::parse(&options.args) {
        Ok(options) => options,
        Err(message) => {
            eprintln!("{message}");
            return ExitCode::from(2);
        }
    };
    let started = match start_workflow_instance(
        &run_options.program_path,
        run_options.root.as_deref(),
        run_options.package_lock_path.as_deref(),
        options.input_json.as_deref(),
        options,
    ) {
        Ok(started) => started,
        Err(code) => return code,
    };

    if options.json {
        emit_json(json!({
            "instance_id": started.instance_id,
            "program_id": started.program_id,
            "version_id": started.version_id,
            "workflow": started.workflow,
            "store": options.store_path.display().to_string(),
        }))
    } else {
        println!("started {}", started.instance_id);
        println!("workflow {}", started.workflow);
        println!("store {}", options.store_path.display());
        ExitCode::SUCCESS
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct RunOptions {
    program_path: String,
    root: Option<String>,
    package_lock_path: Option<PathBuf>,
}

impl RunOptions {
    fn parse(args: &[String]) -> Result<Self, String> {
        let mut program_path = None;
        let mut root = None;
        let mut package_lock_path = None;
        let mut index = 0;
        while index < args.len() {
            match args[index].as_str() {
                "--root" => {
                    index += 1;
                    let Some(value) = args.get(index) else {
                        return Err("expected workflow name after `--root`".to_owned());
                    };
                    root = Some(value.clone());
                }
                "--package-lock" => {
                    index += 1;
                    let Some(value) = args.get(index) else {
                        return Err("expected path after `--package-lock`".to_owned());
                    };
                    package_lock_path = Some(PathBuf::from(value));
                }
                other if other.starts_with('-') => {
                    return Err(format!("unknown run option `{other}`"));
                }
                value if program_path.is_none() => program_path = Some(value.to_owned()),
                _ => {
                    return Err(
                        "usage: whip run <workflow.whip> [--root Workflow] [--input JSON]"
                            .to_owned(),
                    )
                }
            }
            index += 1;
        }
        let Some(program_path) = program_path else {
            return Err(
                "usage: whip run <workflow.whip> [--root Workflow] [--input JSON]".to_owned(),
            );
        };
        Ok(Self {
            program_path,
            root,
            package_lock_path,
        })
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct StartedWorkflow {
    instance_id: String,
    program_id: String,
    version_id: String,
    workflow: String,
}

fn start_workflow_instance(
    path: &str,
    root: Option<&str>,
    package_lock_path: Option<&Path>,
    input_json: Option<&str>,
    options: &CliOptions,
) -> Result<StartedWorkflow, ExitCode> {
    let input_json = input_json.unwrap_or("{}");
    let input_value = match serde_json::from_str::<Value>(input_json) {
        Ok(value) => value,
        Err(error) => {
            eprintln!("invalid `--input` JSON: {error}");
            return Err(ExitCode::from(2));
        }
    };
    let input_json = input_value.to_string();
    let (source, ir) = match compile_source_path_with_root(path, root) {
        Ok(compiled) => compiled,
        Err(error) => return Err(report_compile_failure(path, error)),
    };
    let input_facts = match validate_workflow_start_input(&ir, &input_value) {
        Ok(facts) => facts,
        Err(message) => {
            eprintln!("{message}");
            return Err(ExitCode::from(2));
        }
    };
    let snapshot = ir.to_snapshot();
    let run_source = Path::new(path);
    let package_lock = match load_package_lock(package_lock_path, std::slice::from_ref(&run_source))
    {
        Ok(package_lock) => package_lock,
        Err(message) => {
            eprintln!("{message}");
            return Err(ExitCode::from(2));
        }
    };
    if let Err(message) = contract_registry_for_ir(package_lock.as_ref(), &ir) {
        eprintln!("{message}");
        return Err(ExitCode::from(2));
    }
    let store = match open_store(&options.store_path) {
        Ok(store) => store,
        Err(message) => {
            eprintln!("{message}");
            return Err(ExitCode::FAILURE);
        }
    };
    if let Err(error) = register_locked_packages(&store, package_lock.as_ref()) {
        eprintln!("failed to register locked packages: {}", store_error(error));
        return Err(ExitCode::FAILURE);
    }
    let mut kernel = RuntimeKernel::new(store);
    let version = match kernel.create_program_version_for_program(
        ProgramVersionInput {
            program_name: &ir.workflow,
            source_hash: &stable_hash_hex(&source),
            ir_hash: &stable_hash_hex(&snapshot),
            compiler_version: whipplescript_core::version(),
        },
        &ir,
    ) {
        Ok(version) => version,
        Err(error) => {
            eprintln!("failed to create program version: {}", store_error(error));
            return Err(ExitCode::FAILURE);
        }
    };
    let instance_id = match kernel.create_instance(&version, &input_json) {
        Ok(instance_id) => instance_id,
        Err(error) => {
            eprintln!("failed to create instance: {}", store_error(error));
            return Err(ExitCode::FAILURE);
        }
    };
    let started_event = match kernel.ingest_external_event(
        &instance_id,
        "external.started",
        &input_json,
        Some(&idempotency_key(&[&instance_id, "external.started"])),
    ) {
        Ok(event) => event,
        Err(error) => {
            eprintln!("failed to write start event: {}", store_error(error));
            return Err(ExitCode::FAILURE);
        }
    };
    for fact in input_facts {
        if let Err(error) = kernel.derive_fact(
            &instance_id,
            &fact.name,
            &fact.key,
            &fact.value_json,
            Some(&started_event.event_id),
            Some(&idempotency_key(&[
                &instance_id,
                "workflow.input",
                &fact.key,
                &fact.name,
            ])),
        ) {
            eprintln!("failed to seed workflow input: {}", store_error(error));
            return Err(ExitCode::FAILURE);
        }
    }
    Ok(StartedWorkflow {
        instance_id,
        program_id: version.program_id,
        version_id: version.version_id,
        workflow: ir.workflow,
    })
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct WorkflowInputFact {
    name: String,
    key: String,
    value_json: String,
}

fn validate_workflow_start_input(
    ir: &IrProgram,
    input: &Value,
) -> Result<Vec<WorkflowInputFact>, String> {
    let contracts = ir
        .workflow_contracts
        .iter()
        .filter(|contract| contract.kind == IrWorkflowContractKind::Input)
        .collect::<Vec<_>>();
    if contracts.is_empty() {
        return Ok(Vec::new());
    }
    // A readable shape hint, e.g. `{ "ticket": <ref<TicketRequest>> }`, so a caller
    // who omits the input-name nesting can see the expected object at a glance.
    let expected_shape = format!(
        "{{ {} }}",
        contracts
            .iter()
            .map(|contract| format!("\"{}\": <{}>", contract.name, contract.ty.display_label()))
            .collect::<Vec<_>>()
            .join(", ")
    );
    let Some(object) = input.as_object() else {
        return Err(format!(
            "workflow `{}` expects an input object keyed by declared input names: {expected_shape}",
            ir.workflow,
        ));
    };

    let mut errors = Vec::new();
    let contracts_by_name = contracts
        .iter()
        .map(|contract| (contract.name.as_str(), *contract))
        .collect::<BTreeMap<_, _>>();
    for key in object.keys() {
        if !contracts_by_name.contains_key(key.as_str()) {
            errors.push(format!("unexpected workflow input `{key}`"));
        }
    }

    let mut facts = Vec::new();
    for contract in contracts {
        let Some(value) = object.get(&contract.name) else {
            errors.push(format!(
                "missing workflow input `{}` (expected `{}`)",
                contract.name,
                contract.ty.display_label()
            ));
            continue;
        };
        validate_json_for_ir_type(ir, value, &contract.ty, &contract.name, &mut errors);
        facts.push(WorkflowInputFact {
            name: workflow_input_fact_name(contract),
            key: contract.name.clone(),
            value_json: value.to_string(),
        });
    }

    if errors.is_empty() {
        Ok(facts)
    } else {
        Err(format!(
            "invalid workflow input for `{}`: {}; expected input object {expected_shape}",
            ir.workflow,
            errors.join("; "),
        ))
    }
}

fn workflow_input_fact_name(contract: &IrWorkflowContract) -> String {
    match &contract.ty {
        IrType::Ref(name) => name.clone(),
        other => ir_type_name(other),
    }
}

fn validate_json_for_ir_type(
    ir: &IrProgram,
    value: &Value,
    ty: &IrType,
    path: &str,
    errors: &mut Vec<String>,
) {
    match ty {
        IrType::Primitive(primitive) => validate_json_for_primitive(value, primitive, path, errors),
        IrType::LiteralString(expected) => {
            if value.as_str() != Some(expected.as_str()) {
                errors.push(format!("{path} must be literal {expected:?}"));
            }
        }
        IrType::Ref(name) => validate_json_for_ref(ir, value, name, path, errors),
        IrType::AgentRef(agents) => match value.as_str() {
            Some(agent) if agents.iter().any(|candidate| candidate == agent) => {}
            Some(_) => errors.push(format!(
                "{path} must name one of these agents: {}",
                agents.join(", ")
            )),
            None => errors.push(format!("{path} must be an agent name string")),
        },
        IrType::Object(fields) => validate_json_for_object(ir, value, fields, path, errors),
        IrType::Optional(inner) => {
            if !value.is_null() {
                validate_json_for_ir_type(ir, value, inner, path, errors);
            }
        }
        IrType::Array(inner) => match value.as_array() {
            Some(items) => {
                for (index, item) in items.iter().enumerate() {
                    validate_json_for_ir_type(ir, item, inner, &format!("{path}[{index}]"), errors);
                }
            }
            None => errors.push(format!("{path} must be an array")),
        },
        IrType::Map(inner) => match value.as_object() {
            Some(map) => {
                for (key, item) in map {
                    validate_json_for_ir_type(ir, item, inner, &format!("{path}.{key}"), errors);
                }
            }
            None => errors.push(format!("{path} must be an object map")),
        },
        IrType::Union(types) => {
            if !types
                .iter()
                .any(|candidate| json_matches_ir_type(ir, value, candidate))
            {
                errors.push(format!(
                    "{path} must match one of: {}",
                    types
                        .iter()
                        .map(ir_type_name)
                        .collect::<Vec<_>>()
                        .join(" | ")
                ));
            }
        }
    }
}

fn validate_json_for_primitive(
    value: &Value,
    primitive: &IrPrimitiveType,
    path: &str,
    errors: &mut Vec<String>,
) {
    let valid = match primitive {
        IrPrimitiveType::String
        | IrPrimitiveType::Duration
        | IrPrimitiveType::Time
        | IrPrimitiveType::Image
        | IrPrimitiveType::Audio
        | IrPrimitiveType::Pdf
        | IrPrimitiveType::Video => value.is_string(),
        IrPrimitiveType::Int => value.as_i64().is_some(),
        IrPrimitiveType::Float => value.as_f64().is_some(),
        IrPrimitiveType::Bool => value.is_boolean(),
        IrPrimitiveType::Null => value.is_null(),
    };
    if !valid {
        errors.push(format!(
            "{path} must be {}",
            ir_type_name(&IrType::Primitive(primitive.clone()))
        ));
    }
}

fn validate_json_for_ref(
    ir: &IrProgram,
    value: &Value,
    name: &str,
    path: &str,
    errors: &mut Vec<String>,
) {
    if let Some(class) = ir.schemas.iter().find_map(|schema| match schema {
        IrSchema::Class(class) if class.name == name => Some(class),
        _ => None,
    }) {
        validate_json_for_object(ir, value, &class.fields, path, errors);
        return;
    }
    if let Some(enum_decl) = ir.schemas.iter().find_map(|schema| match schema {
        IrSchema::Enum(enum_decl) if enum_decl.name == name => Some(enum_decl),
        _ => None,
    }) {
        match value.as_str() {
            Some(variant)
                if enum_decl
                    .variants
                    .iter()
                    .any(|candidate| candidate == variant) => {}
            Some(_) => errors.push(format!(
                "{path} must be one of: {}",
                enum_decl.variants.join(", ")
            )),
            None => errors.push(format!("{path} must be a string enum variant")),
        }
        return;
    }
    errors.push(format!("{path} references unknown type `{name}`"));
}

fn validate_json_for_object(
    ir: &IrProgram,
    value: &Value,
    fields: &[whipplescript_parser::IrClassField],
    path: &str,
    errors: &mut Vec<String>,
) {
    let Some(object) = value.as_object() else {
        errors.push(format!("{path} must be an object"));
        return;
    };
    for key in object.keys() {
        if !fields.iter().any(|field| field.name == *key) {
            errors.push(format!("{path}.{key} is not declared"));
        }
    }
    for field in fields {
        let field_path = format!("{path}.{}", field.name);
        // Family B conditional required-presence (discriminated-families-design.md
        // §5.7): a `when <disc> is "<lit>"` field is required only when its
        // discriminant equals the literal. An inapplicable sibling (the discriminant
        // names a different value) is neither required nor rejected nor validated —
        // soundness needs only positive presence, and this admits the
        // all-keys-present webhook shape.
        if let Some((disc, lit)) = &field.presence_condition {
            let applicable = object
                .get(disc)
                .and_then(Value::as_str)
                .is_some_and(|value| value == lit);
            if !applicable {
                continue;
            }
        }
        match object.get(&field.name) {
            Some(value) => validate_json_for_ir_type(ir, value, &field.ty, &field_path, errors),
            None if matches!(field.ty, IrType::Optional(_)) => {}
            None => errors.push(format!("{field_path} is required")),
        }
    }
}

fn json_matches_ir_type(ir: &IrProgram, value: &Value, ty: &IrType) -> bool {
    let mut errors = Vec::new();
    validate_json_for_ir_type(ir, value, ty, "$", &mut errors);
    errors.is_empty()
}

/// Self-contained structural schema embedded in a parsing effect's input so
/// the worker can validate ingested bytes without the program IR
/// (spec/json-ingestion.md). The effect carries its own contract, which also
/// keeps replay independent of later source edits.
fn ingest_shape_json(ir: &IrProgram, ty: &IrType, depth: usize) -> Value {
    if depth > 8 {
        return json!("json");
    }
    let object_fields = |fields: &[whipplescript_parser::IrClassField]| -> Value {
        Value::Object(
            fields
                .iter()
                .map(|field| {
                    (
                        field.name.clone(),
                        ingest_shape_json(ir, &field.ty, depth + 1),
                    )
                })
                .collect(),
        )
    };
    match ty {
        IrType::Primitive(primitive) => {
            json!(ir_type_name(&IrType::Primitive(primitive.clone())))
        }
        IrType::LiteralString(value) => json!({ "literal": value }),
        IrType::AgentRef(_) => json!("string"),
        IrType::Ref(name) => {
            for schema in &ir.schemas {
                match schema {
                    IrSchema::Class(class) if class.name == *name => {
                        return json!({ "class": name, "fields": object_fields(&class.fields) });
                    }
                    IrSchema::Enum(decl) if decl.name == *name => {
                        return json!({ "enum": decl.variants });
                    }
                    _ => {}
                }
            }
            json!("json")
        }
        IrType::Object(fields) => json!({ "fields": object_fields(fields) }),
        IrType::Optional(inner) => json!({ "optional": ingest_shape_json(ir, inner, depth + 1) }),
        IrType::Array(inner) => json!({ "array": ingest_shape_json(ir, inner, depth + 1) }),
        IrType::Map(inner) => json!({ "map": ingest_shape_json(ir, inner, depth + 1) }),
        IrType::Union(types) => json!({
            "union": types
                .iter()
                .map(|candidate| ingest_shape_json(ir, candidate, depth + 1))
                .collect::<Vec<_>>()
        }),
    }
}

/// Deterministic fixture value for an embedded structural shape: literal
/// fields yield their literal (which is how a variant fixture carries its
/// `variant` tag), enums pick the first variant, scalars get stable
/// placeholders (spec/sum-types.md fixture).
fn fixture_value_for_shape(shape: &Value) -> Value {
    match shape {
        Value::String(primitive) => match primitive.as_str() {
            "int" => json!(1),
            "float" => json!(0.5),
            "bool" => json!(true),
            "null" => Value::Null,
            "time" => json!("2026-01-01T00:00:00Z"),
            "json" => json!({}),
            _ => json!("fixture"),
        },
        Value::Object(map) => {
            if let Some(literal) = map.get("literal") {
                return literal.clone();
            }
            if let Some(variants) = map.get("enum").and_then(Value::as_array) {
                return variants
                    .first()
                    .cloned()
                    .unwrap_or_else(|| json!("fixture"));
            }
            if let Some(inner) = map.get("optional") {
                return fixture_value_for_shape(inner);
            }
            if let Some(inner) = map.get("array") {
                return json!([fixture_value_for_shape(inner)]);
            }
            if let Some(inner) = map.get("map") {
                return json!({ "fixture": fixture_value_for_shape(inner) });
            }
            if let Some(options) = map.get("union").and_then(Value::as_array) {
                return options
                    .first()
                    .map(fixture_value_for_shape)
                    .unwrap_or_else(|| json!({}));
            }
            if let Some(fields) = map.get("fields").and_then(Value::as_object) {
                return Value::Object(
                    fields
                        .iter()
                        .map(|(name, field_shape)| {
                            (name.clone(), fixture_value_for_shape(field_shape))
                        })
                        .collect(),
                );
            }
            json!({})
        }
        _ => json!("fixture"),
    }
}

/// Validates ingested JSON against the embedded structural shape — the
/// worker-side mirror of `validate_json_for_ir_type`, reading the contract
/// the effect carries instead of the program IR.
fn validate_ingest_value(value: &Value, shape: &Value, path: &str, errors: &mut Vec<String>) {
    match shape {
        Value::String(primitive) => {
            let valid = match primitive.as_str() {
                "int" => value.as_i64().is_some(),
                "float" => value.as_f64().is_some(),
                "bool" => value.is_boolean(),
                "null" => value.is_null(),
                "time" => value
                    .as_str()
                    .is_some_and(whipplescript_parser::body::is_iso8601_instant),
                "json" => true,
                // string plus media/duration primitives serialize as strings
                _ => value.is_string(),
            };
            if !valid {
                errors.push(format!("{path} must be {primitive}"));
            }
        }
        Value::Object(map) => {
            if let Some(literal) = map.get("literal") {
                if value != literal {
                    errors.push(format!("{path} must be literal {literal}"));
                }
            } else if let Some(variants) = map.get("enum").and_then(Value::as_array) {
                if !variants.iter().any(|candidate| candidate == value) {
                    errors.push(format!(
                        "{path} must be one of: {}",
                        variants
                            .iter()
                            .filter_map(Value::as_str)
                            .collect::<Vec<_>>()
                            .join(", ")
                    ));
                }
            } else if let Some(inner) = map.get("optional") {
                if !value.is_null() {
                    validate_ingest_value(value, inner, path, errors);
                }
            } else if let Some(inner) = map.get("array") {
                match value.as_array() {
                    Some(items) => {
                        for (index, item) in items.iter().enumerate() {
                            validate_ingest_value(item, inner, &format!("{path}[{index}]"), errors);
                        }
                    }
                    None => errors.push(format!("{path} must be an array")),
                }
            } else if let Some(inner) = map.get("map") {
                match value.as_object() {
                    Some(entries) => {
                        for (key, item) in entries {
                            validate_ingest_value(item, inner, &format!("{path}.{key}"), errors);
                        }
                    }
                    None => errors.push(format!("{path} must be an object map")),
                }
            } else if let Some(options) = map.get("union").and_then(Value::as_array) {
                let matches_any = options.iter().any(|option| {
                    let mut probe = Vec::new();
                    validate_ingest_value(value, option, path, &mut probe);
                    probe.is_empty()
                });
                if !matches_any {
                    errors.push(format!("{path} matches no arm of the declared union"));
                }
            } else if let Some(fields) = map.get("fields").and_then(Value::as_object) {
                let label = map
                    .get("class")
                    .and_then(Value::as_str)
                    .map(|class| format!(" ({class})"))
                    .unwrap_or_default();
                let Some(object) = value.as_object() else {
                    errors.push(format!("{path} must be an object{label}"));
                    return;
                };
                for key in object.keys() {
                    if !fields.contains_key(key) {
                        errors.push(format!("{path}.{key} is not declared{label}"));
                    }
                }
                for (name, field_shape) in fields {
                    let field_path = format!("{path}.{name}");
                    match object.get(name) {
                        Some(field_value) => {
                            validate_ingest_value(field_value, field_shape, &field_path, errors)
                        }
                        None if field_shape.get("optional").is_some() => {}
                        None => errors.push(format!("{field_path} is required")),
                    }
                }
            }
        }
        _ => {}
    }
}

fn step(options: &CliOptions) -> ExitCode {
    let step_options = match StepOptions::parse(&options.args) {
        Ok(options) => options,
        Err(message) => {
            eprintln!("{message}");
            return ExitCode::from(2);
        }
    };
    let (source, ir) = match compile_source_path_with_root(
        &step_options.program_path,
        step_options.root.as_deref(),
    ) {
        Ok(compiled) => compiled,
        Err(error) => return report_compile_failure(&step_options.program_path, error),
    };
    let active_version_id = match validate_step_program_version(
        &options.store_path,
        &step_options.instance_id,
        &step_options.program_path,
        &source,
        &ir,
    ) {
        Ok(active_version_id) => active_version_id,
        Err(error) => return report_store_error("failed to validate step program", error),
    };
    match step_instance(
        &options.store_path,
        &step_options.instance_id,
        &ir,
        Some(Path::new(&step_options.program_path)),
        Some(&active_version_id),
    ) {
        Ok(report) if options.json => emit_json(step_report_to_json(&report)),
        Ok(report) => {
            println!(
                "step {} committed_rules={} facts={} consumed={} effects={}",
                report.instance_id,
                report.committed_rules,
                report.facts_created,
                report.facts_consumed,
                report.effects_created
            );
            for guard in report
                .guard_reports
                .iter()
                .filter(|guard| guard.status == GuardStatus::Error)
            {
                eprintln!(
                    "guard error in rule {}: {}{}",
                    guard.rule,
                    guard.expr,
                    guard
                        .error
                        .as_deref()
                        .map(|error| format!(" ({error})"))
                        .unwrap_or_default()
                );
            }
            ExitCode::SUCCESS
        }
        Err(error) => report_store_error("failed to step instance", error),
    }
}

fn validate_step_program_version(
    store_path: &Path,
    instance_id: &str,
    program_path: &str,
    source: &str,
    ir: &IrProgram,
) -> Result<String, StoreError> {
    let store = SqliteStore::open(store_path)?;
    let instance = store
        .get_instance(instance_id)?
        .ok_or_else(|| StoreError::Conflict("instance does not exist".to_owned()))?;
    let active_version = store
        .get_program_version(&instance.version_id)?
        .ok_or_else(|| StoreError::Conflict("active program version does not exist".to_owned()))?;
    let snapshot = ir.to_snapshot();
    let source_hash = stable_hash_hex(source);
    let ir_hash = stable_hash_hex(&snapshot);
    if source_hash != active_version.source_hash || ir_hash != active_version.ir_hash {
        let message = format!(
            "step program `{program_path}` does not match active version {} at epoch {} (expected source_hash={} ir_hash={}, got source_hash={} ir_hash={}); activate the candidate with `whip revise` before stepping it",
            active_version.version_id,
            instance.revision_epoch,
            active_version.source_hash,
            active_version.ir_hash,
            source_hash,
            ir_hash
        );
        persist_stale_step_program_diagnostic(
            &store,
            instance_id,
            program_path,
            &active_version.version_id,
            instance.revision_epoch,
            &message,
        )?;
        return Err(StoreError::Conflict(message));
    }
    Ok(active_version.version_id)
}

fn persist_stale_step_program_diagnostic(
    store: &SqliteStore,
    instance_id: &str,
    program_path: &str,
    active_version_id: &str,
    revision_epoch: i64,
    message: &str,
) -> Result<(), StoreError> {
    let subject_id = display_path(program_path);
    let revision_epoch = revision_epoch.to_string();
    let idempotency_key = idempotency_key(&[
        instance_id,
        "stale-step-program",
        active_version_id,
        &subject_id,
        &revision_epoch,
    ]);
    store.record_diagnostic(DiagnosticRecord {
        instance_id: Some(instance_id),
        program_id: None,
        program_version_id: Some(active_version_id),
        severity: Severity::Error,
        code: Some("revision.stale_program_path"),
        message,
        source_span_json: None,
        subject_type: Some("program_path"),
        subject_id: Some(&subject_id),
        event_id: None,
        effect_id: None,
        run_id: None,
        assertion_id: None,
        evidence_ids_json: "[]",
        artifact_ids_json: "[]",
        causation_id: None,
        correlation_id: Some(active_version_id),
        idempotency_key: Some(&idempotency_key),
    })?;
    Ok(())
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct StepOptions {
    instance_id: String,
    program_path: String,
    root: Option<String>,
}

impl StepOptions {
    fn parse(args: &[String]) -> Result<Self, String> {
        let mut instance_id = None;
        let mut program_path = None;
        let mut root = None;
        let mut index = 0;
        while index < args.len() {
            match args[index].as_str() {
                "--root" => {
                    index += 1;
                    let Some(value) = args.get(index) else {
                        return Err("expected workflow name after `--root`".to_owned());
                    };
                    root = Some(value.clone());
                }
                "--program" => {
                    index += 1;
                    let Some(path) = args.get(index) else {
                        return Err("expected path after `--program`".to_owned());
                    };
                    program_path = Some(path.clone());
                }
                other if other.starts_with('-') => {
                    return Err(format!("unknown step option `{other}`"));
                }
                value if instance_id.is_none() => instance_id = Some(value.to_owned()),
                _ => return Err("usage: whip step <instance> --program <workflow.whip>".to_owned()),
            }
            index += 1;
        }
        let Some(instance_id) = instance_id else {
            return Err("usage: whip step <instance> --program <workflow.whip>".to_owned());
        };
        let Some(program_path) = program_path else {
            return Err("usage: whip step <instance> --program <workflow.whip>".to_owned());
        };
        Ok(Self {
            instance_id,
            program_path,
            root,
        })
    }
}

