    #[test]
    fn renders_contract_registry_json() {
        let source = r#"
workflow RegistryJson

class Review {
  accepted bool
}

coerce review() -> Review {
  prompt """
  Review it.
  """
}
"#;
        let compiled = whipplescript_parser::compile_program(source);
        let ir = compiled.ir.expect("source compiles");
        let registry = contract_registry_json(&ir);

        assert_eq!(
            registry.get("schema").and_then(Value::as_str),
            Some("whipplescript.contract_registry.v0")
        );
        assert!(registry
            .get("libraries")
            .and_then(Value::as_array)
            .expect("libraries")
            .iter()
            .any(|library| library.get("id").and_then(Value::as_str) == Some("std.coerce")));
        assert!(registry
            .get("effect_contracts")
            .and_then(Value::as_array)
            .expect("effect contracts")
            .iter()
            .any(|contract| {
                contract.get("id").and_then(Value::as_str) == Some("coerce")
                    && contract.get("validation").and_then(Value::as_str)
                        == Some("runtime_boundary")
            }));
        assert_eq!(
            registry
                .get("diagnostics")
                .and_then(Value::as_array)
                .map(Vec::len),
            Some(0)
        );
    }

